package handlers

import (
	"bytes"
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	structure "core-backend/m/v2/openapi_structure"
	"core-backend/m/v2/templates"
	"core-backend/m/v2/utils"
	"encoding/json"
	"errors"
	"fmt"
	"html/template"
	"log"
	"net/http"
	"os"
	"strconv"
	"time"

	"github.com/gin-gonic/gin"
	"gopkg.in/gomail.v2"
	"gorm.io/gorm"
)

func AddEmployee(c *gin.Context) {
	var employee models.UserDetail
	managerid, _ := strconv.ParseUint(c.Param("id"), 10, 0)
	orgIdStr := c.Param("orgId") // Fetching orgId from the route parameter
	orgId, err := strconv.ParseUint(orgIdStr, 10, 32)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if err := c.ShouldBindJSON(&employee); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	// Set date of joining to IST timezone
	ist := utils.ISTLocation()

	// Keep only the date part and set it to IST timezone
	dateOnly := time.Date(
		employee.DateOfJoin.Year(),
		employee.DateOfJoin.Month(),
		employee.DateOfJoin.Day(),
		0, 0, 0, 0,
		ist, // Use IST timezone
	)

	employee.DateOfJoin = dateOnly

	// Create the employee record
	if err := db.DB.Create(&employee).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Create OrganisationUser entry with dynamic orgId
	orgUser := models.OrganisationUser{
		UserId:         employee.ID,
		OrganisationId: uint(orgId), // Dynamically assign orgId
	}
	if employee.Department != 0 {
		var member models.DepartmentMember = models.DepartmentMember{
			UserID:       employee.ID,
			DepartmentID: uint(employee.Department),
		}
		if err := db.DB.Create(&member).Error; err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
			return
		}
	}
	if err := db.DB.Create(&orgUser).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	if managerid != 0 {
		managerUser := models.ManagerUser{
			ManagerId: uint(managerid),
			UserId:    employee.ID,
		}

		if err := db.DB.Create(&managerUser).Error; err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
			return
		}
	}

	newEmployeeEmailTemplate, err := template.New("welcomeEmail").Parse(templates.NewEmployeeTemplate)
	if err != nil {
		fmt.Println("Unable to set template")
	}
	var body bytes.Buffer
	if err := newEmployeeEmailTemplate.Execute(&body, nil); err != nil {
		log.Println("Error executing template:", err)
		c.String(http.StatusInternalServerError, "Error generating email content")
		return
	}

	m := gomail.NewMessage()
	m.SetAddressHeader("From", os.Getenv("FROM"), "NoReply - DST Hub")
	m.SetHeader("To", employee.Email)
	m.SetHeader("Subject", "Welcome!")
	m.SetBody("text/html", body.String())
	var iPort, _ = strconv.ParseInt(os.Getenv("MAIL_PORT"), 10, 0)
	var dialer = gomail.NewDialer(os.Getenv("MAIL_HOST"), int(iPort), os.Getenv("MAIL_FROM"), os.Getenv("MAIL_PASSWORD"))
	errordialer := dialer.DialAndSend(m)
	if errordialer != nil {
		log.Fatal("Error transmitting mail : ", errordialer)
		c.String(http.StatusInternalServerError, "Error while transmitting email.")
	}

	log.Default().Println("Executed Send OTP Email for Email Address : ", employee.Email)
	c.String(http.StatusOK, "Onboarding Email Sent Successfully")
	c.JSON(http.StatusOK, employee)
}
func EditEmployee(c *gin.Context) {
	var details models.UserDetail
	managerid, _ := strconv.ParseUint(c.Param("id"), 10, 0)

	// Bind the incoming JSON to the details struct.
	if err := c.ShouldBindJSON(&details); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	// Fetch the employee record from the database.
	var employee models.UserDetail
	if err := db.DB.Where("id = ?", details.ID).First(&employee).Error; err != nil {
		// If no record is found or any DB error occurs.
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Update the employee details based on the input data.
	employee.Address = details.Address
	employee.FirstName = details.FirstName
	employee.LastName = details.LastName
	employee.City = details.City
	employee.Email = details.Email
	employee.EmploymentType = details.EmploymentType
	employee.EmployeeId = details.EmployeeId
	employee.UserType = details.UserType
	employee.JobTitle = details.JobTitle
	employee.Phone = details.Phone
	employee.State = details.State
	employee.Phone2 = details.Phone2

	// Save the updated employee data to the database.
	if err := db.DB.Save(&employee).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Check if a manager ID is provided to associate the employee with a manager.
	if managerid != 0 {
		var manageruser models.ManagerUser
		// Check if a manager-user relationship already exists.
		err := db.DB.Preload("User").Preload("Manager").Where("user_id = ?", details.ID).First(&manageruser).Error

		if err != nil {
			if err == gorm.ErrRecordNotFound {
				// If no relationship exists, create a new manager-user relationship.
				managerUser := models.ManagerUser{
					ManagerId: uint(managerid),
					UserId:    employee.ID,
				}

				if err := db.DB.Create(&managerUser).Error; err != nil {
					// If creating the relationship fails.
					c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
					return
				}
				// Return the newly created manager-user relationship.
				c.JSON(http.StatusOK, managerUser)
				return
			} else {
				// For other errors in fetching the manager-user relationship.
				c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
				return
			}
		}

		if err := db.DB.Unscoped().Delete(&manageruser).Error; err != nil {
			c.JSON(500, err.Error())
		}

		// Update the existing manager-user relationship.
		newmanagerUser := models.ManagerUser{
			ManagerId: uint(managerid),
			UserId:    employee.ID,
		}
		if err := db.DB.Create(&newmanagerUser).Error; err != nil {
			// If creating the relationship fails.
			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
			return
		}

		// Return the updated manager-user relationship.
		c.JSON(http.StatusOK, newmanagerUser)
		return
	}

	// If no manager ID was provided, just return the updated employee data.
	c.JSON(http.StatusOK, employee)
}

func RemoveEmployee(c *gin.Context) {
	var employee models.UserDetail

	if err := c.ShouldBindJSON(&employee); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if err := db.DB.Where("user_id = ?", employee.ID).Delete(&models.DepartmentMember{}).Error; err != nil {
		c.JSON(500, err.Error())
	}
	if err := db.DB.Where("user_id = ?", employee.ID).Delete(&models.OrganisationUser{}).Error; err != nil {
		c.JSON(500, err.Error())
	}
	if err := db.DB.Where("id = ?", employee.ID).Delete(&models.UserDetail{}).Error; err != nil {
		c.JSON(500, err.Error())
	}

	c.JSON(200, "Employee Removed")

}

func GetEmployeeDetailsById(c *gin.Context) {
	userId, err := strconv.ParseUint(c.Param("userId"), 10, 32)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	var employee models.UserDetail
	if err := db.DB.Where("id = ?", userId).First(&employee).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Get organization details for this employee
	var orgUser models.OrganisationUser
	if err := db.DB.Where("user_id = ?", userId).First(&orgUser).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	var departmentDetails models.DepartmentMember
	if err := db.DB.Preload("Department").Where("user_id = ?", employee.ID).Find(&departmentDetails).Error; err != nil && err != gorm.ErrRecordNotFound {
		c.JSON(500, err.Error())
	}

	var managerUser models.ManagerUser
	db.DB.Preload("Manager").Where("user_id = ?", employee.ID).First(&managerUser)
	// Return both employee and organization details
	response := gin.H{
		"employee_details":   employee,
		"organisation_id":    orgUser.OrganisationId,
		"department":         departmentDetails,
		"manager_first_name": managerUser.Manager.FirstName,
		"manager_last_name":  managerUser.Manager.LastName,
		"manager_id":         managerUser.Manager.ID,
	}

	c.JSON(http.StatusOK, response)
}

func GetManagers(c *gin.Context) {
	org_id := c.Param("id")

	var managers []models.UserDetail

	if err := db.DB.Joins("JOIN organisation_users as ou ON ou.user_id = user_details.id").
		Where("ou.organisation_id = ? AND user_details.user_type = ?", org_id, 200).
		Select("user_details.id, user_details.first_name, user_details.last_name").
		Find(&managers).Error; err != nil {
		c.JSON(500, err.Error())
	}

	var response []structure.UserListOrganisation
	for _, orgUser := range managers {
		response = append(response, structure.UserListOrganisation{
			Id:        orgUser.ID,
			Firstname: orgUser.FirstName,
			Name:      orgUser.FirstName + " " + orgUser.LastName,
			Lastname:  orgUser.LastName,
			JobTitle:  orgUser.JobTitle,
		})
	}
	c.JSON(200, response)
}

func SaveDeviceInfo(c *gin.Context) {
	var receivedInfo models.DeviceInfo
	if err := c.ShouldBindJSON(&receivedInfo); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid request payload: " + err.Error()})
		return
	}

	infoJSONString := ""
	if len(receivedInfo.Info) > 0 {
		data, err := json.Marshal(receivedInfo.Info)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": "Failed to serialize info field: " + err.Error()})
			return
		}
		infoJSONString = string(data)
	}

	if receivedInfo.UserID == 0 || receivedInfo.DeviceID == "" || receivedInfo.DeviceType == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "user_id, device_id, and device_type are required for identification."})
		return
	}

	var existingDeviceInfo models.DeviceInfo
	searchConditions := models.DeviceInfo{
		UserID:     receivedInfo.UserID,
		DeviceID:   receivedInfo.DeviceID,
		DeviceType: receivedInfo.DeviceType,
	}

	err := db.DB.Where(&searchConditions).First(&existingDeviceInfo).Error

	if err == nil {
		updateMap := make(map[string]interface{})
		updateMap["updated_at"] = time.Now()

		if receivedInfo.OrganisationID != 0 {
			updateMap["organisation_id"] = receivedInfo.OrganisationID
		}

		if infoJSONString != "" {
			updateMap["info"] = infoJSONString // Use the serialized string
		}

		if receivedInfo.FcmToken != "" {
			updateMap["fcm_token"] = receivedInfo.FcmToken
		}
		if receivedInfo.LastLoginTimeStamp != 0 {
			updateMap["last_login_time_stamp"] = receivedInfo.LastLoginTimeStamp
		}

		if len(updateMap) > 1 {

			if updateErr := db.DB.Model(&existingDeviceInfo).Updates(updateMap).Error; updateErr != nil {
				c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to update device info: " + updateErr.Error()})
				return
			}
		}

		db.DB.First(&existingDeviceInfo, existingDeviceInfo.ID)
		c.JSON(http.StatusOK, existingDeviceInfo)
		return

	} else if !errors.Is(err, gorm.ErrRecordNotFound) {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Database error during find: " + err.Error()})
		return
	}

	receivedInfo.InfoJSON = infoJSONString

	if err := db.DB.Create(&receivedInfo).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to create new device info: " + err.Error()})
		return
	}

	data, err := json.Marshal(receivedInfo)
	if err != nil {
		log.Default().Println(err.Error())
	}
	log.Default().Println(string(data))

	c.JSON(http.StatusCreated, receivedInfo)
}
func GetDeviceInfo(c *gin.Context) {
	var deviceInfos []models.DeviceInfo
	userId, err := strconv.ParseUint(c.Param("userId"), 10, 32)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"message": "Invalid User ID"})
		return
	}
	if err := db.DB.Where("user_id = ?", userId).Find(&deviceInfos).Error; err != nil {
		c.JSON(500, gin.H{"message": err.Error()})
	}
	c.JSON(200, deviceInfos)
}

