package handlers

import (
	"core-backend/m/v2/LLM_part/config"
	"core-backend/m/v2/LLM_part/models"
	"core-backend/m/v2/LLM_part/services"
	"core-backend/m/v2/LLM_part/utils"
	"fmt"
	"net/http"

	"github.com/gin-gonic/gin"
)

func GetRecommendations(cfg *config.Config) gin.HandlerFunc {
	return func(c *gin.Context) {
		var req models.RecommendationRequest

		if err := c.ShouldBindJSON(&req); err != nil {
			c.JSON(http.StatusBadRequest, gin.H{
				"error": "Invalid request format. Please provide coordinates, org_id, and token.",
			})
			return
		}

		if len(req.Coordinates) == 0 {
			c.JSON(http.StatusBadRequest, gin.H{
				"error": "At least one coordinate pair is required.",
			})
			return
		}

		// Validate org_id
		if req.OrgId <= 0 {
			c.JSON(http.StatusBadRequest, gin.H{
				"error": "Valid org_id is required.",
			})
			return
		}

		// Validate token
		if req.Token == "" {
			c.JSON(http.StatusBadRequest, gin.H{
				"error": "Token is required.",
			})
			return
		}

		// Validate all coordinates
		for i, coord := range req.Coordinates {
			if coord.Latitude < -90 || coord.Latitude > 90 || coord.Longitude < -180 || coord.Longitude > 180 {
				c.JSON(http.StatusBadRequest, gin.H{
					"error": fmt.Sprintf("Invalid coordinates at index %d. Latitude must be between -90 and 90, longitude between -180 and 180.", i),
				})
				return
			}
		}

		// Get current time context
		timeContext := utils.GetTimeContext()

		// Generate recommendations using Gemini with location tags
		geminiService := services.NewGeminiService(cfg.GeminiAPIKey, cfg.OpenCageAPIKey)
		recommendations, err := geminiService.GetRecommendations(req.Coordinates, timeContext, req.OrgId, req.Token)

		if err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{
				"error": "Failed to generate recommendations. Please try again.",
			})
			return
		}

		response := models.RecommendationResponse{
			Recommendations: recommendations,
			Timestamp:       utils.GetCurrentTimestamp(),
		}

		c.JSON(http.StatusOK, response)
	}
}

