package models

import "time"

type StandardQuotationViewModel struct {
	DocumentTitle string // e.g., "Quotation", "Proforma Invoice"

	// Reused configuration VMs (loaded from steel_quotation_configs)
	Company CompanyVM    // From config: company_vm JSON
	Seller  SellerBankVM // From config: seller_vm JSON
	Footer  FooterVM     // From config: footer_vm JSON (company name, authorized signatory, etc.)

	// Party information
	Buyer  BuyerVM          // Bill To (from quotation.customer_model)
	ShipTo StandardShipToVM // Ship To block (can reuse buyer address or separate field)

	// Document metadata
	Meta StandardQuotationMetaVM

	// Line items
	Items []StandardQuotationItemVM

	// Totals section
	Totals StandardQuotationTotalsVM

	// Notes + Terms & Conditions
	Notes StandardQuotationNotesVM
	Terms StandardQuotationTermsVM

	// Display status (e.g., "Draft", "Approved", "Sent")
	StatusText string
}

// StandardQuotationMetaVM holds metadata specific to the standard quotation template.
type StandardQuotationMetaVM struct {
	QuotationNo   string    // e.g., "Q-2026-001"
	Dated         time.Time // Quotation date (alias of EstimateDate)
	EstimateDate  time.Time // Quotation date
	ExpiryDate    time.Time // Valid until
	PlaceOfSupply string    // e.g., "Telangana"
}

// StandardShipToVM represents the "Ship To" address block.
// Can be populated from buyer or a separate shipping address field if available.
type StandardShipToVM struct {
	ShipToLine1 string
	ShipToLine2 string
	ShipToLine3 string
	ShipToLine4 string
}
type StandardQuotationItemVM struct {
	SlNo         int     // Serial number
	Name         string  // Item name (product name)
	Description2 string  // Item description / note to display below product name
	HSNCode      string  // HSN/SAC code
	Quantity     float64 // Quantity
	UnitPrice    float64 // Rate per unit
	CGST         float64 // CGST amount (presentation)
	SGST         float64 // SGST amount (presentation)
	Amount       float64 // Line total (Quantity * UnitPrice + taxes)
}
type StandardQuotationTotalsVM struct {
	SubTotal      string // Subtotal before taxes (string for formatted display)
	TaxableAmount string // Taxable amount (same as subtotal in most cases)
	CGST9         string // Total CGST @ 9% (string formatted)
	SGST9         string // Total SGST @ 9% (string formatted)
	Rounding      string // Rounding adjustment (+/- 0.xx)
	GrandTotal    string // Final amount (string formatted, e.g., "12,345.67")
	TotalInWords  string // Amount in words (e.g., "Twelve Thousand Three Hundred Forty Five Rupees Only")
}
type StandardQuotationNotesVM struct {
	Line1 string // Note line 1
	Line2 string // Note line 2 (optional)
}
type StandardQuotationTermsVM struct {
	Payment  string // Payment terms (e.g., "50% advance, 50% on delivery")
	Delivery string // Delivery terms (e.g., "7-10 working days")
	Warranty string // Warranty terms (e.g., "6 months manufacturer warranty")
}

