package utils

import (
	"math"
	"strings"
)

func AmountToWords(amount float64) string {
	if amount < 0 {
		return "Invalid Amount"
	}

	rupees := int64(math.Floor(amount))
	paise := int64(math.Round((amount - float64(rupees)) * 100))

	rupeesWords := convertToWords(rupees)
	if rupeesWords == "" {
		rupeesWords = "Zero"
	}

	result := rupeesWords + " Rupees"

	if paise > 0 {
		paiseWords := convertToWords(paise)
		result += " and " + paiseWords + " Paise"
	}

	return result + " Only"
}

func convertToWords(num int64) string {
	if num == 0 {
		return ""
	}

	ones := []string{"", "One", "Two", "Three", "Four", "Five", "Six", "Seven", "Eight", "Nine"}
	teens := []string{"Ten", "Eleven", "Twelve", "Thirteen", "Fourteen", "Fifteen", "Sixteen", "Seventeen", "Eighteen", "Nineteen"}
	tens := []string{"", "", "Twenty", "Thirty", "Forty", "Fifty", "Sixty", "Seventy", "Eighty", "Ninety"}

	var parts []string

	// Crores (10,000,000)
	if num >= 10000000 {
		crores := num / 10000000
		parts = append(parts, convertToWords(crores)+" Crore")
		num %= 10000000
	}

	// Lakhs (100,000)
	if num >= 100000 {
		lakhs := num / 100000
		parts = append(parts, convertToWords(lakhs)+" Lakh")
		num %= 100000
	}

	// Thousands (1,000)
	if num >= 1000 {
		thousands := num / 1000
		parts = append(parts, convertToWords(thousands)+" Thousand")
		num %= 1000
	}

	// Hundreds
	if num >= 100 {
		hundreds := num / 100
		parts = append(parts, ones[hundreds]+" Hundred")
		num %= 100
	}

	// Tens and ones
	if num >= 20 {
		parts = append(parts, tens[num/10])
		if num%10 > 0 {
			parts = append(parts, ones[num%10])
		}
	} else if num >= 10 {
		parts = append(parts, teens[num-10])
	} else if num > 0 {
		parts = append(parts, ones[num])
	}

	return strings.Join(parts, " ")
}

