func (b *CacheKeyBuilder) GetRelatedSteelQuotationKeys(orgID, quotationID string) []string {
	return []string{
		b.SteelQuotationListKey(orgID),
		b.SteelQuotationDetailKey(quotationID),
		b.SteelQuotationStreamKey(orgID),
		b.SteelQuotationItemsKey(quotationID),
	}
}

// GetAllOrgRelatedKeys returns all cache keys for an organization
func (b *CacheKeyBuilder) GetAllOrgRelatedKeys(orgID string) []string {
	return []string{
		b.CustomerListKey(orgID),
		b.CustomerStreamKey(orgID),
		b.ProductListKey(orgID),
		b.ProductStreamKey(orgID),
		b.ProductLedgerKey(orgID),
		b.ProductEntryKey(orgID),
		b.QuotationListKey(orgID),
		b.QuotationStreamKey(orgID),
		b.InventoryCategoryKey(orgID),
	}
}

// CacheInvalidator provides methods to invalidate related cache entries
type CacheInvalidator struct {
	cache      *CacheHelper
	keyBuilder *CacheKeyBuilder
}

// NewCacheInvalidator creates a new CacheInvalidator instance
func NewCacheInvalidator() *CacheInvalidator {
	return &CacheInvalidator{
		cache:      NewCacheHelper(),
		keyBuilder: NewCacheKeyBuilder(),
	}
}

// InvalidateCustomerCache invalidates all customer-related cache entries
func (inv *CacheInvalidator) InvalidateCustomerCache(orgID, customerID string) error {
	keys := inv.keyBuilder.GetRelatedCustomerKeys(orgID, customerID)
	return inv.cache.DeleteKeys(keys...)
}

// InvalidateProductCache invalidates all product-related cache entries
func (inv *CacheInvalidator) InvalidateProductCache(orgID, productID string) error {
	keys := inv.keyBuilder.GetRelatedProductKeys(orgID, productID)
	return inv.cache.DeleteKeys(keys...)
}

// InvalidateQuotationCache invalidates all quotation-related cache entries
func (inv *CacheInvalidator) InvalidateQuotationCache(orgID, quotationID string) error {
	keys := inv.keyBuilder.GetRelatedQuotationKeys(orgID, quotationID)
	return inv.cache.DeleteKeys(keys...)
}

// InvalidateSteelProductCache invalidates all steel product-related cache entries
func (inv *CacheInvalidator) InvalidateSteelProductCache(orgID, productID string) error {
	keys := inv.keyBuilder.GetRelatedSteelProductKeys(orgID, productID)
	return inv.cache.DeleteKeys(keys...)
}

// InvalidateSteelQuotationCache invalidates all steel quotation-related cache entries
func (inv *CacheInvalidator) InvalidateSteelQuotationCache(orgID, quotationID string) error {
	keys := inv.keyBuilder.GetRelatedSteelQuotationKeys(orgID, quotationID)
	return inv.cache.DeleteKeys(keys...)
}

// InvalidateOrgCache invalidates all cache entries for an organization
func (inv *CacheInvalidator) InvalidateOrgCache(orgID string) error {
	keys := inv.keyBuilder.GetAllOrgRelatedKeys(orgID)
	return inv.cache.DeleteKeys(keys...)
}

