package utils

import (
	"time"
)

// ISTLocation returns the IST timezone location
func ISTLocation() *time.Location {
	ist, _ := time.LoadLocation("Asia/Kolkata")
	return ist
}

// ToIST converts a UTC time to IST
func ToIST(t *time.Time) time.Time {
	if t == nil || t.IsZero() {
		return time.Time{}
	}
	return t.In(ISTLocation())
}

// FormatIST formats a time in IST timezone using RFC3339 format
func FormatIST(t *time.Time) string {
	if t == nil || t.IsZero() {
		return ""
	}
	return ToIST(t).Format(time.RFC3339)
}

// FormatISTCustom formats a time in IST timezone using a custom format
func FormatISTCustom(t *time.Time, format string) string {
	if t == nil || t.IsZero() {
		return ""
	}
	return ToIST(t).Format(format)
}

// GetCurrentTimeIST returns the current time in IST
func GetCurrentTimeIST() time.Time {
	return time.Now().In(ISTLocation())
}

// GetCurrentTimeISTFormatted returns the current time in IST as a formatted string
func GetCurrentTimeISTFormatted() string {
	currentTime := GetCurrentTimeIST()
	return FormatIST(&currentTime)
}

