)

const Attendance int = 1
const Project int = 2
const Employee int = 3
const Chat int = 4
const Location int = 5
const Inventory int = 6
const AIAttendance int = 7
const CRM int = 8
const SteelCRM int = 9
const LLM int = 10
const WhatsApp int = 11
const NoImageAttendance int = 101
const IsScreenshotsEnabled int = 102

func SubmitForm(c *gin.Context) {
	var jsonData structure.OrganizationRequest

	// Bind JSON request body into a struct
	if err := c.BindJSON(&jsonData); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	firstName := jsonData.Firstname
	lastName := jsonData.Lastname

	// Create UserDetail
	userDetail := models.UserDetail{
		FirstName:  firstName,
		LastName:   lastName,
		Phone:      jsonData.AdminPhone,
		Email:      jsonData.AdminEmail,
		Address:    jsonData.AdminAddress,
		City:       jsonData.AdminCity,
		State:      jsonData.AdminState,
		PostalCode: uint(jsonData.AdminPostalCode),
		UserType:   200,
	}

	if err := db.DB.Create(&userDetail).Error; err != nil {
		c.JSON(500, err.Error())
	}

	// Create Organization
	org := models.Organisation{
		OrganisationCode: jsonData.OrgName,
		Status:           "pending",
		WebsiteUrl:       jsonData.WebsiteURL,
		AdminRegister:    userDetail.ID,
	}

	if err := db.DB.Create(&org).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err})
		return
	}
	print(userDetail.ID)
	if err := db.DB.Create(&userDetail).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to add user detail to database"})
		return
	}

	// Create OrganisationUser
	orgUser := models.OrganisationUser{
		UserId:         userDetail.ID,
		OrganisationId: org.ID,
	}

	// Create OrganisationAddress
	orgAddress := models.OrganisationAddress{
		OrganisationId: org.ID,
		Address:        jsonData.OrgAddress,
	}

	// Create records in the database

	if err := db.DB.Create(&orgUser).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to add organization user to database"})
		return
	}
	if err := db.DB.Create(&orgAddress).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to add organization address to database"})
		return
	}
	subject := "New Organization Registration: " + jsonData.OrgName
	body := "Dear Support Department,\n\n" +
		"We are excited to inform you about a new company registration on our platform!\n\n" +
		"Company Details:\n" +
		"- Company Name: " + org.OrganisationCode + "\n" +
		"- Admin Name: " + jsonData.Firstname + " " + jsonData.Lastname + "\n" +
		"- Admin Email: " + jsonData.AdminEmail + "\n" +
		"- Admin Phone: " + strconv.FormatInt(jsonData.AdminPhone, 10) + "\n\n" +
		"Thank you for your prompt attention to this matter. Your assistance in welcoming our new member is greatly appreciated.\n\n" +
		"Best regards,\n" +
		"dHub Support Department"
	mail_from := os.Getenv("MAIL_FROM")
	org_mail := os.Getenv("ORG_MAIL")
	// Compose the email message
	message := "From: " + mail_from + "\r\n" +
		"To: " + org_mail + "\r\n" +
		"Subject: " + subject + "\r\n" +
		"\r\n" +
		body

	// SMTP server configuration
	smtpHost := os.Getenv("MAIL_HOST")
	smtpPort := os.Getenv("MAIL_PORT")
	auth := smtp.PlainAuth("", mail_from, os.Getenv("MAIL_PASSWORD"), smtpHost)

	// Sending email
	err := smtp.SendMail(smtpHost+":"+smtpPort, auth, mail_from, []string{org_mail}, []byte(message))
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to send email notification"})
		return
	}

	// Respond with success message
	c.JSON(http.StatusCreated, gin.H{"message": "Organization, user, and user detail successfully added to database"})
}

func GetOrganizationsByStatus(c *gin.Context) {
	status := c.Param("status")
