func UpdateOrgDepartment(c *gin.Context) {
	departmentID := c.Param("department_id")
	var request struct {
		DepartmentName string          `json:"department_name"`
		Description    string          `json:"description"`
		Members        []uint          `json:"members"`
		Features       models.Features `json:"features"`
	}

	if err := c.BindJSON(&request); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	var department models.Department
	if err := db.DB.First(&department, "id = ?", departmentID).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Department not found"})
		return
	}

	if request.DepartmentName != "" {
		department.DepartmentName = request.DepartmentName
	}
	if request.Description != "" {
		department.Description = request.Description
	}

	// Update department members
	if len(request.Members) > 0 {
		// Delete existing members
		if err := db.DB.Where("department_id = ?", departmentID).Delete(&models.DepartmentMember{}).Error; err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to delete existing department members"})
			return
		}

		// Add new members
		var members []models.DepartmentMember
		for _, memberID := range request.Members {
			members = append(members, models.DepartmentMember{
				UserID:       memberID,
				DepartmentID: department.ID,
			})
		}
		department.Members = append(department.Members, members...)
	}

	if err := db.DB.Save(&department).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to update department"})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "Department updated successfully"})
}

