func SetOrg() {
	var users []models.UserDetail

	// Fetch users
	if err := db.DB.Where("email LIKE ?", "%@onlyoncloud.com").Find(&users).Error; err != nil {
		log.Fatalf("Error fetching users: %v", err)
	}

	for _, user := range users {

		var orguser models.OrganisationUser

		// Fetch or create organisation user
		err := db.DB.Where("user_id = ?", user.ID).First(&orguser).Error
		if err == gorm.ErrRecordNotFound {
			// Create new OrganisationUser if not found
			org := models.OrganisationUser{
				OrganisationId: 2,
				UserId:         user.ID,
			}
			if err := db.DB.Create(&org).Error; err != nil {
				log.Printf("Error creating OrganisationUser for user %d: %v", user.ID, err)
			}
		} else if err != nil {
			// Log unexpected errors
			log.Printf("Error fetching OrganisationUser for user %d: %v", user.ID, err)
			continue
		} else {
			// If found, update OrganisationUser
			if orguser.OrganisationId != 2 {
				orguser.OrganisationId = 2
				if err := db.DB.Save(&orguser).Error; err != nil {
					log.Printf("Error updating OrganisationUser for user %d: %v", user.ID, err)
				}
			}
		}
	}
}

