func SetOrgCutoff(c *gin.Context) {
	orgID := c.Param("id")

	var payload struct {
		Cutoff string `json:"cutoff"`
	}
	if err := c.BindJSON(&payload); err != nil || payload.Cutoff == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "cutoff required in JSON as HH:MM"})
		return
	}

	// Parse time-of-day HH:MM
	layout := "15:04"
	t, err := time.Parse(layout, payload.Cutoff)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid cutoff format; use HH:MM"})
		return
	}

	currentYear := time.Now().Year()
	validDateTime := time.Date(currentYear, 1, 1, t.Hour(), t.Minute(), 0, 0, time.Local)

	var org models.Organisation
	if err := db.DB.First(&org, orgID).Error; err != nil {
		if err == gorm.ErrRecordNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "organization not found"})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	org.Cutoff = validDateTime
	if err := db.DB.Save(&org).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to save cutoff: " + err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "cutoff updated", "cutoff": org.Cutoff.Format("15:04")})
}

