func UpdateOrganisationTime(c *gin.Context) {
	log.Default().Println("UPDATING ORGANISATION TIME")
	var incomingTime models.OrganisationTime
	var existingTime models.OrganisationTime
	err := db.DB.Transaction(func(tx *gorm.DB) error {
		var user models.OrganisationUser
		err := c.ShouldBindJSON(&incomingTime)
		if err != nil {
			log.Default().Println("ERROR BINDING JSON", err)
			return err
		}

		err = tx.Preload("User").First(&user).Where("organisation_id = ? AND user_id = ?", incomingTime.OrganisationId, incomingTime.ChangedBy).Error
		if err != nil {
			log.Default().Println("ERROR UPDATING ORGANISATION TIME 1", err)

			return err
		}

		if !(user.User.UserType >= 200) {
			log.Default().Println("ERROR UPDATING ORGANISATION TIME 2", user.User.UserType)
			return err
		}

		err = tx.Where("organisation_id = ?", incomingTime.OrganisationId).First(&existingTime).Error

		if err != nil {
			log.Default().Println("ERROR UPDATING ORGANISATION TIME 3", err)

			return err
		}

		if existingTime.ID != incomingTime.ID {
			d, _ := (json.Marshal(existingTime))
			e, _ := (json.Marshal(incomingTime))
			log.Default().Println(string(d), string(e))
			log.Default().Println("ERROR UPDATING ORGANISATION TIME 4", existingTime.ID, incomingTime.ID)
			return err
		}

		err = tx.Model(&existingTime).Updates(incomingTime).Error

		if err != nil {
			log.Default().Println("ERROR UPDATING ORGANISATION TIME 5", err)
			return err
		}
		return nil
	})
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}
	c.JSON(http.StatusOK, gin.H{"message": "Organisation Time Updated"})

}

func GetUsageReport(c *gin.Context) {
	orgID := c.Param("org_id")

	var req models.UsageReportRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "from_date and to_date are required (YYYY-MM-DD format)"})
		return
	}

	// Parse dates
	fromDate, err := time.Parse("2006-01-02", req.FromDate)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid from_date format. Use YYYY-MM-DD"})
		return
	}
	toDate, err := time.Parse("2006-01-02", req.ToDate)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid to_date format. Use YYYY-MM-DD"})
		return
	}
	if toDate.Before(fromDate) {
		c.JSON(http.StatusBadRequest, gin.H{"error": "to_date must be greater than or equal to from_date"})
		return
	}

	var avgSignIns float64
	sub := db.DB.
		Table("user_locations ul").
		Select("DATE(ul.created_at) AS sign_date, COUNT(DISTINCT ul.user_id) AS daily_count").
		Joins("INNER JOIN organisation_users ou ON ou.user_id = ul.user_id").
		Where("ou.organisation_id = ? AND ul.deleted_at IS NULL AND ou.deleted_at IS NULL AND DATE(ul.created_at) BETWEEN ? AND ?", orgID, fromDate, toDate).
		Group("DATE(ul.created_at)")

	if err := db.DB.Table("(?) as daily_counts", sub).
		Select("COALESCE(AVG(daily_count), 0) as average_sign_ins").
		Pluck("average_sign_ins", &avgSignIns).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// 2) location entries count per employee per month
	var locationCounts []models.EmployeeLocationCount
	if err := db.DB.
		Table("user_locations ul").
		Select("o.organisation_code, ud.employee_id, ud.first_name, ud.last_name, YEAR(ul.created_at) as year, MONTH(ul.created_at) as month, COUNT(ul.id) as location_count").
		Joins("INNER JOIN user_details ud ON ud.id = ul.user_id").
		Joins("INNER JOIN organisation_users ou ON ou.user_id = ul.user_id").
		Joins("INNER JOIN organisations o ON o.id = ou.organisation_id").
		Where("o.id = ? AND ul.deleted_at IS NULL AND ud.deleted_at IS NULL AND ou.deleted_at IS NULL AND DATE(ul.created_at) BETWEEN ? AND ?", orgID, fromDate, toDate).
		Group("o.organisation_code, ud.employee_id, YEAR(ul.created_at), MONTH(ul.created_at), ud.first_name, ud.last_name").
		Order("o.organisation_code, ud.employee_id, year, month").
		Scan(&locationCounts).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// 3) last sign-in per employee
	var rawLast []struct {
		OrganisationCode string
		EmployeeID       string
		FirstName        string
		LastName         string
		LastSignIn       time.Time
	}
	if err := db.DB.
		Table("user_locations ul").
		Select("o.organisation_code, ud.employee_id, ud.first_name, ud.last_name, MAX(ul.created_at) as last_sign_in").
		Joins("INNER JOIN user_details ud ON ud.id = ul.user_id").
		Joins("INNER JOIN organisation_users ou ON ou.user_id = ul.user_id").
		Joins("INNER JOIN organisations o ON o.id = ou.organisation_id").
		Where("o.id = ? AND ul.deleted_at IS NULL AND ud.deleted_at IS NULL AND ou.deleted_at IS NULL", orgID).
		Group("o.organisation_code, ud.employee_id, ud.first_name, ud.last_name").
		Order("o.organisation_code, ud.employee_id").
		Scan(&rawLast).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	var lastSignIns []models.EmployeeLastSignIn
	for _, r := range rawLast {
		lastSignIns = append(lastSignIns, models.EmployeeLastSignIn{
			OrganisationCode: r.OrganisationCode,
			EmployeeID:       r.EmployeeID,
			FirstName:        r.FirstName,
			LastName:         r.LastName,
			LastSignIn:       utils.FormatIST(&r.LastSignIn),
		})
	}

	response := models.UsageReportResponse{
		FromDate:               req.FromDate,
		ToDate:                 req.ToDate,
		AverageEmployeeSignIns: avgSignIns,
		EmployeeLocationCounts: locationCounts,
		LastSignInPerEmployee:  lastSignIns,
	}

	c.JSON(http.StatusOK, gin.H{"data": response})
}

func UpdateOrgWeeklyOffs(c *gin.Context) {
	id := c.Param("id")

	var payload struct {
		WeeklyOffs []int `json:"weekly_offs" binding:"required"`
	}
	if err := c.ShouldBindJSON(&payload); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	var org models.Organisation
	if err := db.DB.Where("id = ?", id).First(&org).Error; err != nil {
		if err == gorm.ErrRecordNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "Organisation not found"})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	expected := 7 - int(org.Days)
	if expected < 0 {
		expected = 0
	}

	if len(payload.WeeklyOffs) != expected {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("weekly_offs must contain exactly %d day(s) for organisation with working days %d", expected, org.Days),
		})
		return
	}

	// validate values are unique and in 0..6
	seen := map[int]bool{}
	for _, d := range payload.WeeklyOffs {
		if d < 0 || d > 6 {
			c.JSON(http.StatusBadRequest, gin.H{"error": "weekly_offs values must be in range 0..6 (0=Sunday)"})
			return
		}
		if seen[d] {
			c.JSON(http.StatusBadRequest, gin.H{"error": "weekly_offs contains duplicate days"})
			return
		}
		seen[d] = true
	}

	org.WeeklyOffs = models.Features(payload.WeeklyOffs)
	if err := db.DB.Save(&org).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to save weekly offs: " + err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "Weekly offs updated", "weekly_offs": org.WeeklyOffs})
}

