package services

import (
	"context"
	"log"

	firebase "firebase.google.com/go/v4"
	"firebase.google.com/go/v4/messaging"
	"google.golang.org/api/option"

	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
)

type FirebaseService struct {
	Messaging *messaging.Client
}

// NewFirebaseService now constructs credentials directly from a service account JSON file.
func NewFirebaseService(ctx context.Context, serviceAccountKeyPath string) (*FirebaseService, error) {

	// Use option.WithCredentialsFile to authenticate using the JSON key file.
	opt := option.WithCredentialsFile(serviceAccountKeyPath)
	app, err := firebase.NewApp(ctx, nil, opt)
	if err != nil {
		return nil, err
	}

	messagingClient, err := app.Messaging(ctx)
	if err != nil {
		return nil, err
	}
	return &FirebaseService{
		Messaging: messagingClient,
	}, nil
}

func (s *FirebaseService) SendNotificationToUser(ctx context.Context, userID uint, title, body string) error {
	var userTokens []models.FcmToken
	if err := db.DB.Where("user_id = ?", userID).Find(&userTokens).Error; err != nil {
		return err
	}

	if len(userTokens) == 0 {
		return nil
	}

	var registrationTokens []string
	for _, t := range userTokens {
		registrationTokens = append(registrationTokens, t.Token)
	}

	message := &messaging.MulticastMessage{
		Notification: &messaging.Notification{
			Title: title,
			Body:  body,
		},
		Tokens: registrationTokens,
	}

	br, err := s.Messaging.SendEachForMulticast(ctx, message)
	if err != nil {
		return err
	}

	if br.FailureCount > 0 {
		for idx, resp := range br.Responses {
			if !resp.Success {
				log.Printf("[FCM] Failed to send to token %s: %v", registrationTokens[idx], resp.Error)
			}
		}
	}

	return nil
}

