package handlers

import (
	"core-backend/m/v2/cache"
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"core-backend/m/v2/utils"
	"encoding/base64"
	"log"
	"net/http"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/redis/go-redis/v9"
)

func GetBasicReport(c *gin.Context) {
	id := c.Param("id")
	log.Println("Getting Report for ID", id)

	tasks := fetchTasksByUserID(id)
	leaves := fetchLeavesByUserID(id)
	attendance := fetchAttendanceByUserID(id)
	location := fetchLocationByUserID(id)
	report := gin.H{
		"tasks":      tasks,
		"leaves":     leaves,
		"attendance": attendance,
		"location":   location,
	}

	c.JSON(http.StatusOK, report)
}

func fetchTasksByUserID(userID string) []models.Task {
	var tasks []models.Task
	if err := db.DB.Preload("AssignedBy").Preload("Assignee").Preload("Project").Where("assignee_id = ?", userID).Find(&tasks).Error; err != nil {
		log.Println("Error fetching tasks:", err)
		return []models.Task{}
	}
	return tasks
}

func fetchLeavesByUserID(userID string) []gin.H {
	var leaves []models.UserLeave
	if err := db.DB.Preload("User").Where("user_id = ?", userID).Find(&leaves).Error; err != nil {
		log.Println("Error fetching leaves:", err)
		return []gin.H{}
	}
	// Convert leaves to response format with IST formatted times
	var leavesResponse []gin.H
	for _, leave := range leaves {
		// Parse string dates to time.Time
		startDate, _ := time.Parse(time.RFC3339Nano, leave.StartDate)
		endDate, _ := time.Parse(time.RFC3339Nano, leave.EndDate)

		leavesResponse = append(leavesResponse, gin.H{
			"id":         leave.ID,
			"user_id":    leave.UserId,
			"start_date": utils.FormatIST(&startDate),
			"end_date":   utils.FormatIST(&endDate),
			"type":       leave.Type,
			"status":     leave.Status,
			"reason":     leave.Reason,
			"created_at": utils.FormatIST(&leave.CreatedAt),
			"updated_at": utils.FormatIST(&leave.UpdatedAt),
		})
	}
	return leavesResponse
}

func fetchAttendanceByUserID(userID string) []gin.H {
	var attendance []models.UserAttendance
	if err := db.DB.
		Select("id, created_at, updated_at, deleted_at, user_id, check_in, check_out, check_in_latitude, check_in_longitude, check_out_latitude, check_out_longitude, check_in_img, check_out_img").
		Where("user_id = ?", userID).
		Find(&attendance).Error; err != nil {
		log.Println("Error fetching attendance:", err)
		return []gin.H{}
	}
	// Convert attendance to response format with IST formatted times
	var attendanceResponse []gin.H
	for _, att := range attendance {
		attendanceResponse = append(attendanceResponse, gin.H{
			"ID":                  att.ID,
			"user_id":             att.UserId,
			"check_in":            utils.FormatIST(att.CheckIn),
			"check_out":           utils.FormatIST(att.CheckOut),
			"check_in_latitude":   att.CheckInLatitude,
			"check_in_longitude":  att.CheckInLongitude,
			"check_out_latitude":  att.CheckOutLatitude,
			"check_out_longitude": att.CheckOutLongitude,
			"check_in_img":        string(att.CheckInImg),
			"check_out_img":       string(att.CheckOutImg),
		})
	}
	return attendanceResponse
}

func fetchLocationByUserID(id string) []gin.H {
	var location []models.UserLocation
	if err := db.DB.Preload("User").Where("user_id = ?", id).Find(&location).Error; err != nil {
		log.Println("Error fetching location:", err)
		return []gin.H{}
	}
	// Convert location to response format with IST formatted times
	var locationResponse []gin.H
	for _, loc := range location {
		StartTimestamp := time.Time(loc.StartTimestamp)
		EndTimeStamp := time.Time(loc.EndTimestamp)
		locationResponse = append(locationResponse, gin.H{
			"id":              loc.ID,
			"user_id":         loc.UserId,
			"start_timestamp": utils.FormatIST(&StartTimestamp),
			"end_timestamp":   utils.FormatIST(&EndTimeStamp),
			"latitude":        loc.Latitude,
			"longitude":       loc.Longitude,
			"area_name":       loc.AreaName,
		})
	}
	return locationResponse
}

func GetProductSummaryReport(c *gin.Context) {
	orgID := c.Param("organisation_id")
	log.Println("Getting Product Summary Report for Organisation ID", orgID)

	products := fetchProductSummaryByOrgID(orgID)

	c.JSON(http.StatusOK, gin.H{
		"data": products,
	})
}

func fetchProductSummaryByOrgID(orgID string) []gin.H {
	var products []models.Product
	if err := db.DB.Where("organisation_id = ?", orgID).Find(&products).Error; err != nil {
		log.Println("Error fetching products:", err)
		return []gin.H{}
	}

	var result []gin.H
	for _, p := range products {
		var incomingQuantity int64
		var outgoingQuantity int64
		var blockedQuantity int64

		// Get incoming quantity (Purchase, Return, Unblocked)
		db.DB.Model(&models.ProductLedger{}).
			Where("product_id = ? AND organisation_id = ? AND (status = 'Purchased' OR status = 'Returned' OR status = 'Unblocked')",
				p.ID, orgID).
			Select("COALESCE(SUM(quantity), 0)").Row().Scan(&incomingQuantity)

		// Get outgoing quantity (Sold, Damaged)
		db.DB.Model(&models.ProductLedger{}).
			Where("product_id = ? AND organisation_id = ? AND (status = 'Sold' OR status = 'Damaged')",
				p.ID, orgID).
			Select("COALESCE(SUM(quantity), 0)").Row().Scan(&outgoingQuantity)

		// Get blocked quantity
		db.DB.Model(&models.ProductLedger{}).
			Where("product_id = ? AND organisation_id = ? AND status = 'Blocked'",
				p.ID, orgID).
			Select("COALESCE(SUM(quantity), 0)").Row().Scan(&blockedQuantity)

		// Calculate total available quantity (incoming - outgoing)
		availableQuantity := incomingQuantity - outgoingQuantity

		result = append(result, gin.H{
			"hsn":                p.HSN,
			"product_sku":        p.SKU,
			"product_name":       p.Name,
			"quantity_available": availableQuantity,
			"quantity_blocked":   blockedQuantity,
			"last_updated_date":  p.UpdatedAt,
		})
	}

	return result
}

func GetProductDetailedReport(c *gin.Context) {
	orgID := c.Param("organisation_id")
	log.Println("Getting Product Detailed Report for Organisation ID", orgID)

	products := fetchProductDetailedByOrgID(orgID)

	c.JSON(http.StatusOK, gin.H{
		"data": products,
	})
}

func fetchProductDetailedByOrgID(orgID string) []gin.H {
	var products []models.Product
	if err := db.DB.Where("organisation_id = ?", orgID).Find(&products).Error; err != nil {
		log.Println("Error fetching products:", err)
		return []gin.H{}
	}

	var result []gin.H
	for _, p := range products {
		var incomingQuantity int64
		var outgoingQuantity int64
		var blockedQuantity int64

		// Get incoming quantity (Purchase, Return, Unblocked)
		db.DB.Model(&models.ProductLedger{}).
			Where("product_id = ? AND organisation_id = ? AND (status = 'Purchased' OR status = 'Returned' OR status = 'Unblocked')",
				p.ID, orgID).
			Select("COALESCE(SUM(quantity), 0)").Row().Scan(&incomingQuantity)

		// Get outgoing quantity (Sold, Damaged)
		db.DB.Model(&models.ProductLedger{}).
			Where("product_id = ? AND organisation_id = ? AND (status = 'Sold' OR status = 'Damaged')",
				p.ID, orgID).
			Select("COALESCE(SUM(quantity), 0)").Row().Scan(&outgoingQuantity)

		// Get blocked quantity
		db.DB.Model(&models.ProductLedger{}).
			Where("product_id = ? AND organisation_id = ? AND status = 'Blocked'",
				p.ID, orgID).
			Select("COALESCE(SUM(quantity), 0)").Row().Scan(&blockedQuantity)

		// Calculate total available quantity (incoming - outgoing)
		availableQuantity := incomingQuantity - outgoingQuantity

		type QuotationInfo struct {
			QuotationID    uint    `json:"quotation_id"`
			CustomerName   string  `json:"customer_name"`
			QuotedPrice    float64 `json:"quoted_price"`
			QuantityQuoted int     `json:"quantity_quoted"`
		}

		var quotationItems []QuotationInfo
		var count int64
		db.DB.Model(&models.QuotationItem{}).
			Where("product_id = ?", p.ID).
			Count(&count)

		err := db.DB.Table("quotation_items as qi").
			Select("q.id as quotation_id, CONCAT(cm.first_name, ' ', cm.last_name) as customer_name, qi.unit_price as quoted_price, qi.quantity as quantity_quoted").
			Joins("JOIN quotations q ON qi.quotation_id = q.id").
			Joins("JOIN customer_models cm ON q.customer_id = cm.id").
			Where("qi.product_id = ? AND q.organisation_id = ? AND q.status NOT IN ('Expired', 'Rejected')", p.ID, orgID).
			Scan(&quotationItems).Error

		if err != nil {
			log.Printf("Error fetching quotation info for product %d: %v", p.ID, err)
		}

		productDetail := gin.H{
			"hsn":                p.HSN,
			"product_id":         p.ID,
			"product_sku":        p.SKU,
			"product_name":       p.Name,
			"quantity_available": availableQuantity,
			"quantity_blocked":   blockedQuantity,
			"quotations":         quotationItems,
			"last_updated_date":  p.UpdatedAt,
		}

		result = append(result, productDetail)
	}

	return result
}

// GetDailyAttendanceReport fetches all user attendance for today's date in an organisation
func GetDailyAttendanceReport(c *gin.Context) {
	orgID := c.Param("org_id")
	today := time.Now().Format("2006-01-02")

	log.Println("Getting Daily Attendance Report for Organisation ID", orgID)

	// Try to get from cache first
	attendance, err := cache.GetDailyAttendanceFromCache(orgID, today)
	fromCache := true

	if err != nil {
		if err == redis.Nil {
			log.Printf("Daily attendance not found in cache for org %s on %s, fetching from DB", orgID, today)
		} else {
			log.Printf("Failed to get daily attendance from cache for org %s: %v", orgID, err)
		}
		fromCache = false

		// Fetch from database (returns []gin.H)
		attendanceGinH := fetchDailyAttendanceByOrgID(orgID)

		// Convert []gin.H to []map[string]interface{} for caching
		attendance = make([]map[string]interface{}, len(attendanceGinH))
		for i, v := range attendanceGinH {
			attendance[i] = map[string]interface{}(v)
		}

		// Cache the result
		if len(attendance) > 0 {
			err = cache.SetDailyAttendanceToCache(orgID, today, attendance)
			if err != nil {
				log.Printf("Failed to cache daily attendance for org %s: %v", orgID, err)
			}
		}
	}

	// Add cache debug header
	if fromCache {
		c.Header("X-Cache", "HIT")
	} else {
		c.Header("X-Cache", "MISS")
	}

	c.JSON(http.StatusOK, gin.H{
		"date": today,
		"data": attendance,
	})
}

func fetchDailyAttendanceByOrgID(orgID string) []gin.H {
	type AttendanceRecord struct {
		EmployeeID        string    `json:"employee_id"`
		EmployeeName      string    `json:"employee_name"`
		UserID            uint      `json:"user_id"`
		CheckIn           time.Time `json:"check_in"`
		CheckOut          time.Time `json:"check_out"`
		CheckInLatitude   float64   `json:"check_in_latitude"`
		CheckInLongitude  float64   `json:"check_in_longitude"`
		CheckOutLatitude  float64   `json:"check_out_latitude"`
		CheckOutLongitude float64   `json:"check_out_longitude"`
		CheckInImg        []byte    `json:"check_in_img"`
		CheckOutImg       []byte    `json:"check_out_img"`
		OnLeave           bool      `json:"on_leave"`
		LeaveType         *string   `json:"leave_type"`
		LeaveReason       *string   `json:"leave_reason"`
	}

	var records []AttendanceRecord

	// Get today's date in IST
	today := utils.GetCurrentTimeIST().Format("2006-01-02")

	// Query to fetch daily attendance with employee details
	err := db.DB.Table("user_attendances as ua").
		Select(`
            ud.employee_id,
            CONCAT(ud.first_name, ' ', ud.last_name) as employee_name,
            ud.id as user_id,
            ua.check_in,
            ua.check_out,
            ua.check_in_latitude,
            ua.check_in_longitude,
            ua.check_out_latitude,
            ua.check_out_longitude,
            ua.check_in_img,
            ua.check_out_img,
            false as on_leave,
            NULL as leave_type,
            NULL as leave_reason
        `).
		Joins("INNER JOIN user_details ud ON ud.id = ua.user_id").
		Joins("INNER JOIN organisation_users ou ON ou.user_id = ua.user_id").
		Where("DATE(ua.check_in) = ? AND ou.organisation_id = ?", today, orgID).
		Order("ud.employee_id DESC").
		Scan(&records).Error

	if err != nil {
		log.Println("Error fetching daily attendance:", err)
		return []gin.H{}
	}

	// Fetch users on approved leave today
	type LeaveRecord struct {
		EmployeeID   string `json:"employee_id"`
		EmployeeName string `json:"employee_name"`
		UserID       uint   `json:"user_id"`
		LeaveType    string `json:"leave_type"`
		LeaveReason  string `json:"leave_reason"`
	}

	var leaveRecords []LeaveRecord

	err = db.DB.Table("user_leaves as ul").
		Select(`
            ud.employee_id,
            CONCAT(ud.first_name, ' ', ud.last_name) as employee_name,
            ud.id as user_id,
            ul.type as leave_type,
            ul.reason as leave_reason
        `).
		Joins("INNER JOIN user_details ud ON ud.id = ul.user_id").
		Joins("INNER JOIN organisation_users ou ON ou.user_id = ul.user_id").
		Where("ou.organisation_id = ? AND ul.status = 1 AND DATE(ul.start_date) <= ? AND DATE(ul.end_date) >= ?",
			orgID, today, today).
		Order("ud.employee_id DESC").
		Scan(&leaveRecords).Error

	if err != nil {
		log.Println("Error fetching leave records:", err)
	}

	// Create a map to track users who have checked in
	checkedInUsers := make(map[uint]bool)
	for _, record := range records {
		checkedInUsers[record.UserID] = true
	}

	// Add leave records for users who haven't checked in
	for _, leaveRecord := range leaveRecords {
		if !checkedInUsers[leaveRecord.UserID] {
			records = append(records, AttendanceRecord{
				EmployeeID:   leaveRecord.EmployeeID,
				EmployeeName: leaveRecord.EmployeeName,
				UserID:       leaveRecord.UserID,
				OnLeave:      true,
				LeaveType:    &leaveRecord.LeaveType,
				LeaveReason:  &leaveRecord.LeaveReason,
			})
		}
	}

	// Convert to response format with IST formatted times
	var attendanceResponse []gin.H
	for _, record := range records {
		response := gin.H{
			"employee_id":   record.EmployeeID,
			"employee_name": record.EmployeeName,
			"user_id":       record.UserID,
			"on_leave":      record.OnLeave,
		}

		if record.OnLeave {
			// For users on leave
			response["status"] = "On Leave"
			response["check_in"] = nil
			response["check_out"] = nil
			response["check_in_latitude"] = nil
			response["check_in_longitude"] = nil
			response["check_out_latitude"] = nil
			response["check_out_longitude"] = nil
			response["has_check_in_image"] = false
			response["check_in_image"] = nil
			response["has_check_out_image"] = false
			response["check_out_image"] = nil

			if record.LeaveType != nil {
				response["leave_type"] = *record.LeaveType
			}
			if record.LeaveReason != nil {
				response["leave_reason"] = *record.LeaveReason
			}
		} else {
			// For users with attendance
			response["status"] = "Present"
			response["check_in"] = utils.FormatIST(&record.CheckIn)
			response["check_in_latitude"] = record.CheckInLatitude
			response["check_in_longitude"] = record.CheckInLongitude
			response["leave_type"] = nil
			response["leave_reason"] = nil

			// Add check_out fields only if check_out exists
			if !record.CheckOut.IsZero() {
				response["check_out"] = utils.FormatIST(&record.CheckOut)
				response["check_out_latitude"] = record.CheckOutLatitude
				response["check_out_longitude"] = record.CheckOutLongitude
			} else {
				response["check_out"] = nil
				response["check_out_latitude"] = nil
				response["check_out_longitude"] = nil
			}

			// Add check-in image (base64 encoded)
			if len(record.CheckInImg) > 0 {
				response["has_check_in_image"] = true
				response["check_in_image"] = "data:image/jpeg;base64," + base64.StdEncoding.EncodeToString(record.CheckInImg)
			} else {
				response["has_check_in_image"] = false
				response["check_in_image"] = nil
			}

			// Add check-out image (base64 encoded)
			if len(record.CheckOutImg) > 0 {
				response["has_check_out_image"] = true
				response["check_out_image"] = "data:image/jpeg;base64," + base64.StdEncoding.EncodeToString(record.CheckOutImg)
			} else {
				response["has_check_out_image"] = false
				response["check_out_image"] = nil
			}
		}

		attendanceResponse = append(attendanceResponse, response)
	}

	return attendanceResponse
}

