func BuildSteelQuotationViewModel(org models.Organisation, q models.SteelQuotation, add models.OrganisationAddress) models.SteelQuotationViewModel {
	// Initialize viewmodel with computed parts (these always come from the quotation)
	vm := models.SteelQuotationViewModel{
		DocumentTitle: "Quotation",

		// Company/Seller/Footer will be filled from stored API config (no fallbacks).
		Company: models.CompanyVM{},
		Seller:  models.SellerBankVM{},
		Footer:  models.FooterVM{},

		Buyer: models.BuyerVM{
			Name: safeUpper(q.CustomerModel.CustomerOrg),

			AddressLine1: strings.TrimSpace(q.CustomerModel.AddressLine1),
			AddressLine2: strings.TrimSpace(q.CustomerModel.AddressLine2),
			AddressLine3: formatStatePincode(q.CustomerModel.State, q.CustomerModel.PinCode),
			AddressLine4: strings.TrimSpace(q.CustomerModel.City),
			GSTIN:  	  strings.TrimSpace(q.CustomerModel.GSTIN),
			Mobile: 	  strings.TrimSpace(q.CustomerModel.Phone),
			Email:        strings.TrimSpace(q.CustomerModel.Email),
			PONumber:     "-",
		},

		Meta: models.QuotationMetaVM{
			Dated:       safeTime(q.CreatedAt),
			QuotationNo: fmt.Sprintf("%d", q.ID),
		},
	}

	// PalletTax and FreightTax are percentage values. Compute their actual amounts.
	palletTaxAmt := 0.0
	if q.Pallet != 0 && q.PalletTax != 0 {
		palletTaxAmt = q.Pallet * q.PalletTax / 100.0
	}
	freightTaxAmt := 0.0
	if q.Freight != 0 && q.FreightTax != 0 {
		freightTaxAmt = q.Freight * q.FreightTax / 100.0
	}
	loadingTaxAmt := 0.0
	if q.Loading != 0 && q.LoadingTax != 0 {
		loadingTaxAmt = q.Loading * q.LoadingTax / 100.0
	}

	// Charges and Totals using computed actual tax amounts
	vm.Charges = models.ChargesVM{
		LoadingLabel:   "Loading Charges",
		LoadingAmount:  q.Loading + loadingTaxAmt, // loading tax assumed to be an amount
		PFLabel:        "P&F",
		PFAmountText:   fmt.Sprintf("%.2f", q.Pallet+palletTaxAmt+q.Freight+freightTaxAmt),
		GSTLabel:       "GST",
		GSTAmount:      computeGSTTotal(q),
		RoundOffLabel:  "Round Off",
		RoundOffAmount: computeRoundOff(q),
	}

	vm.Totals = models.TotalsVM{
		GrandTotalLabel:  "Grand Total",
		GrandTotalQty:    computeQtyTotal(q),
		GrandTotalUnit:   "Kgs",
		GrandTotalAmount: computeGrandTotal(q),
	}

	vm.Terms = models.TermsVM{
		DutiesAndTaxes:   "As Indicated",
		DeliverySchedule: "7 Days",
		PlaceOfDelivery:  "Ex-our Godown Dulapally",
		PaymentTerms:     "Immediate against PI",
		Validity:         formatDateOrEmpty(q.ValidUntil),
	}

	// Load organisation config (API) and require it -- fail on any error (no fallbacks).
	var cfg models.SteelQuotationConfig
	if err := db.DB.Where("organisation_id = ?", org.ID).First(&cfg).Error; err != nil {
		panic(err)
	}

	// company vm must be present
	if strings.TrimSpace(cfg.CompanyVM) == "" {
		panic(fmt.Errorf("company_vm is empty for organisation %d", org.ID))
	}
	var storedComp models.CompanyVM
	if err := json.Unmarshal([]byte(cfg.CompanyVM), &storedComp); err != nil {
		panic(err)
	}
	vm.Company = storedComp

	// seller vm must be present
	if strings.TrimSpace(cfg.SellerVM) == "" {
		panic(fmt.Errorf("seller_vm is empty for organisation %d", org.ID))
	}
	var storedSeller models.SellerBankVM
	if err := json.Unmarshal([]byte(cfg.SellerVM), &storedSeller); err != nil {
		panic(err)
	}
	vm.Seller = storedSeller

	// footer vm must be present
	if strings.TrimSpace(cfg.FooterVM) == "" {
		panic(fmt.Errorf("footer_vm is empty for organisation %d", org.ID))
	}
	var storedFooter models.FooterVM
	if err := json.Unmarshal([]byte(cfg.FooterVM), &storedFooter); err != nil {
		panic(err)
	}
	vm.Footer = storedFooter

	// Items mapping (ensure template stays dumb)
	vm.Items = make([]models.SteelQuotationItemVM, 0, len(q.Items))
	for i := range q.Items {
		it := q.Items[i]

		qty := float64(it.Quantity)
		rate := float64(it.UnitPrice)

		// Prefer stored total; fallback to computed quantity*rate.
		amt := qty * rate
		if amt == 0 {
			amt = qty * rate
		}

		vm.Items = append(vm.Items, models.SteelQuotationItemVM{
			SlNo:         i + 1,
			Description:  strings.TrimSpace(it.SteelProductName),
			Size:         "",
			NoOfPcs:      int32OrDefault(it.Quantity, 1),
			Quantity:     qty,
			QuantityUnit: "Kgs",
			UnitPrice:    rate,
			PriceUnit:    "Rs/Kgs",
			Amount:       amt,
		})
	}

	return vm
}

/* ===========================
   Helpers (keep private)
   =========================== */

func safeUpper(s string) string {
	s = strings.TrimSpace(s)
	if s == "" {
		return ""
	}
	return strings.ToUpper(s)
}

func safeTime(t time.Time) time.Time {
	if t.IsZero() {
		return time.Now()
	}
	return t
}

func formatDateOrEmpty(t time.Time) string {
	if t.IsZero() {
		return ""
	}
	return t.Format("02-01-2006")
}

func formatStatePincode(state string, pincode string) string {
	state = strings.TrimSpace(state)
	pincode = strings.TrimSpace(pincode)
	if state == "" && pincode == "" {
		return ""
	}
	if state != "" && pincode != "" {
		return fmt.Sprintf("%s - %s", state, pincode)
	}
	if state != "" {
		return state
	}
	return pincode
}

func computeQtyTotal(q models.SteelQuotation) float64 {
	var total float64
	for i := range q.Items {
		total += float64(q.Items[i].Quantity)
	}
	return total
}

func computeGSTTotal(q models.SteelQuotation) float64 {
	var gst float64
	for i := range q.Items {
		if q.Items[i].IGSTAmount != 0 {
			gst += float64(q.Items[i].IGSTAmount)
		} else {
			gst += float64(q.Items[i].CGSTAmount) + float64(q.Items[i].SGSTAmount)
		}
	}
	return gst
}

func computeGrandTotal(q models.SteelQuotation) float64 {
	if q.TotalAmount > 0 {
		return float64(q.TotalAmount)
	}

	var sum float64
	for i := range q.Items {
		// Prefer stored item totals. If missing, compute from qty*price.
		if q.Items[i].Total != 0 {
			sum += float64(q.Items[i].Total)
		} else {
			sum += float64(q.Items[i].Quantity) * float64(q.Items[i].UnitPrice)
		}
	}
	sum += q.Loading + q.Freight + q.Pallet
	sum += q.LoadingTax + q.FreightTax + q.PalletTax
	return sum
}

func computeRoundOff(q models.SteelQuotation) float64 {
	total := computeGrandTotal(q)
	rounded := math.Round(total*100) / 100
	return rounded - total
}

func int32OrDefault(val int32, def int32) int32 {
	if val != 0 {
		return val
	}
	return def
}

