package handlers

import (
	"bytes"
	"fmt"
	"html/template"
	"log"
	"net/http"
	"strconv"

	"core-backend/m/v2/cache"
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"core-backend/m/v2/services"
	"core-backend/m/v2/templates"
	"core-backend/m/v2/utils"

	"github.com/gin-gonic/gin"
)

// Quotation CRUD routes and handlers
func RegisterQuotationRoutes(router *gin.Engine, authMiddleware gin.HandlerFunc) {
	router.GET("/quotations/public/id/:id/html-standard", RenderStandardQuotationHTML)
	quotationRoutes := router.Group("/quotations")
	quotationRoutes.Use(authMiddleware)

	{
		quotationRoutes.POST("/", CreateQuotation)
		quotationRoutes.POST("/bulk", CreateQuotationBulk)
		quotationRoutes.GET("/:organisation_id", GetQuotations)
		quotationRoutes.GET("/id/:id", GetQuotation)
		quotationRoutes.GET("/stream/:organisation_id", StreamQuotations)
		quotationRoutes.PUT("/:id", EditQuotation)
		quotationRoutes.POST("/items", CreateQuotationItem)
		quotationRoutes.POST("/items/bulk", CreateQuotationItemBulk)
		quotationRoutes.GET("/items/:quotation_id", GetQuotationItems)
		quotationRoutes.PUT("/items/:quotation_id", UpdateQuotationItems)
		quotationRoutes.DELETE("/items/:id", DeleteQuotationItem)
		quotationRoutes.GET("/id/:id/html-standard", RenderStandardQuotationHTML)
	}
}

// CreateQuotation saves a quotation and its items, blocks quantities and invalidates cache.
func CreateQuotation(c *gin.Context) {
	var input models.Quotation
	userID := c.MustGet("id").(uint)
	if err := c.ShouldBindJSON(&input); err != nil {
		c.JSON(400, gin.H{"error": err.Error()})
		return
	}

	tx := db.DB.Begin()

	// Save only the Quotation (without Items)
	quotation := input
	quotation.Items = nil
	if err := tx.Create(&quotation).Error; err != nil {
		tx.Rollback()
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	var totalAmount float64
	createdItems := make([]models.QuotationItem, 0, len(input.Items))

	// Now create the items with the correct QuotationID
	for i := range input.Items {
		item := input.Items[i]
		item.ID = 0
		item.QuotationID = quotation.ID
		item.OrganisationID = quotation.OrganisationID

		if item.ProductID > 0 {
			var product models.Product
			if err := tx.First(&product, item.ProductID).Error; err == nil {
				item.HSN = product.HSN
				item.CGST = product.CGST
				item.SGST = product.SGST
				item.IGST = product.IGST

				item.CGSTAmount = (item.Total * product.CGST) / 100
				item.SGSTAmount = (item.Total * product.SGST) / 100
				item.IGSTAmount = (item.Total * product.IGST) / 100
			}
		}

		if err := tx.Omit("ID").Create(&item).Error; err != nil {
			tx.Rollback()
			c.JSON(500, gin.H{"error": "Failed to create quotation item: " + err.Error()})
			return
		}
		totalAmount += item.Total
		createdItems = append(createdItems, item)
	}
	totalAmount += input.Loading + input.Freight + input.Pallet + input.LoadingTax + input.FreightTax + input.PalletTax

	// Update total_amount if there were items
	if len(createdItems) > 0 {
		if err := tx.Model(&quotation).Update("total_amount", totalAmount).Error; err != nil {
			tx.Rollback()
			c.JSON(500, gin.H{"error": "Failed to update quotation total: " + err.Error()})
			return
		}
	}

	// Block quantities for products in the quotation
	for _, item := range createdItems {
		if item.ProductID > 0 {
			log.Printf("Attempting to block %d units of product ID %d", int(item.Quantity), item.ProductID)
			if err := utils.BlockProductQuantity(item.ProductID, int(item.Quantity), quotation.OrganisationID, quotation.ID, "Quotation", userID); err != nil {
				log.Printf("WARNING: Could not block quantity for product %d: %v", item.ProductID, err)
			} else {
				log.Printf("Successfully blocked %d units of product ID %d", int(item.Quantity), item.ProductID)
			}
		}
	}

	tx.Commit()

	// Invalidate related cache entries
	orgID := strconv.FormatUint(uint64(quotation.OrganisationID), 10)
	quotationID := strconv.FormatUint(uint64(quotation.ID), 10)
	invalidator := cache.NewCacheInvalidator()
	if err := invalidator.InvalidateQuotationCache(orgID, quotationID); err != nil {
		// Log error but don't fail the request
		log.Printf("Failed to invalidate quotation cache: %v", err)
	}

	var result models.Quotation
	db.DB.Preload("CustomerModel").Preload("Items").First(&result, quotation.ID)
	c.JSON(200, gin.H{"data": result})
}

func CreateQuotationBulk(c *gin.Context) {
	var quotations []models.Quotation
	if err := c.ShouldBindJSON(&quotations); err != nil {
		c.JSON(400, gin.H{"error": err.Error()})
		return
	}
	if err := db.DB.Create(&quotations).Error; err != nil {
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	// Invalidate cache for all affected organizations
	invalidator := cache.NewCacheInvalidator()
	orgIDsMap := make(map[string]bool)
	for _, quotation := range quotations {
		orgID := strconv.FormatUint(uint64(quotation.OrganisationID), 10)
		orgIDsMap[orgID] = true
	}

	// Invalidate cache for each organization
	for orgID := range orgIDsMap {
		if err := invalidator.InvalidateQuotationCache(orgID, ""); err != nil {
			// Log error but don't fail the request
			log.Printf("Failed to invalidate quotation cache: %v", err)
		}
	}

	c.JSON(200, gin.H{"data": quotations})
}

func GetQuotations(c *gin.Context) {
	orgID := c.Param("organisation_id")

	// Initialize cache components
	cacheHelper := cache.NewCacheHelper()
	keyBuilder := cache.NewCacheKeyBuilder()
	cacheKey := keyBuilder.QuotationListKey(orgID)

	// Try to get from cache or fetch from DB
	data, fromCache, err := cacheHelper.GetOrSetJSON(cacheKey, db.RedisTTL.CRMRedis.QuotationCachedTTL, func() (interface{}, error) {
		var quotations []models.Quotation
		if err := db.DB.Preload("CustomerModel").Preload("Items").Where("organisation_id = ?", orgID).Find(&quotations).Error; err != nil {
			return nil, err
		}
		return quotations, nil
	})

	if err != nil {
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	// Add cache info to response headers for debugging
	if fromCache {
		c.Header("X-Cache", "HIT")
	} else {
		c.Header("X-Cache", "MISS")
	}

	c.JSON(200, gin.H{"data": data})
}

func GetQuotation(c *gin.Context) {
	id := c.Param("id")

	// Initialize cache components
	cacheHelper := cache.NewCacheHelper()
	keyBuilder := cache.NewCacheKeyBuilder()
	cacheKey := keyBuilder.QuotationDetailKey(id)

	// Try to get from cache or fetch from DB
	data, fromCache, err := cacheHelper.GetOrSetJSON(cacheKey, db.RedisTTL.CRMRedis.QuotationCachedTTL, func() (interface{}, error) {
		var quotation models.Quotation
		if err := db.DB.Preload("CustomerModel").Preload("Items").First(&quotation, "id = ?", id).Error; err != nil {
			return nil, err
		}
		return quotation, nil
	})

	if err != nil {
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	// Add cache info to response headers for debugging
	if fromCache {
		c.Header("X-Cache", "HIT")
	} else {
		c.Header("X-Cache", "MISS")
	}

	c.JSON(200, gin.H{"data": data})
}

func StreamQuotations(c *gin.Context) {
	orgID := c.Param("organisation_id")
	c.Writer.Header().Set("Content-Type", "text/event-stream")
	c.Writer.Header().Set("Cache-Control", "no-cache")
	c.Writer.Header().Set("Connection", "keep-alive")
	c.Writer.Flush()

	rows, err := db.DB.Preload("CustomerModel").Model(&models.Quotation{}).Where("organisation_id = ?", orgID).Rows()
	if err != nil {
		c.SSEvent("error", gin.H{"error": err.Error()})
		return
	}
	defer rows.Close()
	for rows.Next() {
		var quotation models.Quotation
		db.DB.ScanRows(rows, &quotation)
		c.SSEvent("quotation", quotation)
		c.Writer.Flush()
	}
	c.SSEvent("done", "streaming completed")
}

func EditQuotation(c *gin.Context) {
	id := c.Param("id")
	userID := c.MustGet("id").(uint)
	var input models.Quotation
	if err := c.ShouldBindJSON(&input); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}
	var quotation models.Quotation
	var total_amount float64 = 0

	for i := range input.Items {

		if input.Items[i].ID > 0 {
			var model models.QuotationItem
			if err := db.DB.First(&model, input.Items[i].ID).Error; err != nil {
				log.Default().Println("Error", err)
				continue
			}
			if err := db.DB.Model(&model).Updates(input.Items[i]).Error; err != nil {
				log.Default().Println("Error", err)
				continue
			}
		} else {
			if err := db.DB.Create(&input.Items[i]).Error; err != nil {
				log.Default().Println("Error", err)
				continue
			}
		}
		total_amount += input.Items[i].Total

	}
	if input.Status != quotation.Status {
		if input.Status == "Accepted" {
			// Quotation was accepted, convert blocked quantities to actual deductions
			if err := utils.DeductBlockedQuantity(quotation.ID, "Quotation", userID); err != nil {
				log.Printf("Warning: Failed to deduct blocked quantities for quotation #%d: %v", quotation.ID, err)
			}
		} else if input.Status == "Rejected" && quotation.Status == "Open" {
			// Quotation was rejected, unblock quantities
			if err := utils.UnblockProductQuantity(quotation.ID, "Quotation", userID); err != nil {
				log.Printf("Warning: Failed to unblock quantities for quotation #%d: %v", quotation.ID, err)
			}
		}
	}
	updates := map[string]any{
		"customer_id":     input.CustomerID,
		"organisation_id": input.OrganisationID,
		"quotation_date":  input.QuotationDate,
		"valid_until":     input.ValidUntil,
		"status":          input.Status,
		"loading":         input.Loading,
		"freight":         input.Freight,
		"pallet":          input.Pallet,
		"loading_tax":     input.LoadingTax,
		"freight_tax":     input.FreightTax,
		"pallet_tax":      input.PalletTax,
		"total_amount":    total_amount + (input.Loading * input.LoadingTax / 100) + (input.Freight * input.FreightTax / 100) + (input.Pallet * input.PalletTax / 100) + input.Loading + input.Freight + input.Pallet,
		"remarks":         input.Remarks,
	}
	if err := db.DB.Preload("CustomerModel").Preload("Items").First(&quotation, id).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Quotation not found"})
		return
	}
	if err := db.DB.Model(&quotation).Updates(updates).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Invalidate related cache entries
	orgID := strconv.FormatUint(uint64(quotation.OrganisationID), 10)
	invalidator := cache.NewCacheInvalidator()
	if err := invalidator.InvalidateQuotationCache(orgID, id); err != nil {
		// Log error but don't fail the request
		log.Printf("Failed to invalidate quotation cache: %v", err)
	}

	c.JSON(http.StatusOK, gin.H{"message": "Quotation updated successfully", "data": quotation})
}

func CreateQuotationItem(c *gin.Context) {
	var item models.QuotationItem
	if err := c.ShouldBindJSON(&item); err != nil {
		c.JSON(400, gin.H{"error": err.Error()})
		return
	}
	if err := db.DB.Create(&item).Error; err != nil {
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	// Invalidate related cache entries
	orgID := strconv.FormatUint(uint64(item.OrganisationID), 10)
	quotationID := strconv.FormatUint(uint64(item.QuotationID), 10)
	invalidator := cache.NewCacheInvalidator()
	if err := invalidator.InvalidateQuotationCache(orgID, quotationID); err != nil {
		// Log error but don't fail the request
		log.Printf("Failed to invalidate quotation cache: %v", err)
	}

	c.JSON(200, gin.H{"data": item})
}

func CreateQuotationItemBulk(c *gin.Context) {
	var items []models.QuotationItem
	if err := c.ShouldBindJSON(&items); err != nil {
		c.JSON(400, gin.H{"error": err.Error()})
		return
	}
	if err := db.DB.Create(&items).Error; err != nil {
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	// Invalidate cache for all affected quotations/organizations
	invalidator := cache.NewCacheInvalidator()
	orgQuotationMap := make(map[string]map[string]bool)

	for _, item := range items {
		orgID := strconv.FormatUint(uint64(item.OrganisationID), 10)
		quotationID := strconv.FormatUint(uint64(item.QuotationID), 10)

		if orgQuotationMap[orgID] == nil {
			orgQuotationMap[orgID] = make(map[string]bool)
		}
		orgQuotationMap[orgID][quotationID] = true
	}

	// Invalidate cache for each organization/quotation combination
	for orgID, quotationMap := range orgQuotationMap {
		for quotationID := range quotationMap {
			if err := invalidator.InvalidateQuotationCache(orgID, quotationID); err != nil {
				// Log error but don't fail the request
				log.Printf("Failed to invalidate quotation cache: %v", err)
			}
		}
	}

	c.JSON(200, gin.H{"data": items})
}

func GetQuotationItems(c *gin.Context) {
	quotationID := c.Param("quotation_id")

	// Initialize cache components
	cacheHelper := cache.NewCacheHelper()
	keyBuilder := cache.NewCacheKeyBuilder()
	cacheKey := keyBuilder.QuotationItemsKey(quotationID)

	// Try to get from cache or fetch from DB
	data, fromCache, err := cacheHelper.GetOrSetJSON(cacheKey, db.RedisTTL.CRMRedis.QuotationCachedTTL, func() (interface{}, error) {
		var items []models.QuotationItem
		if err := db.DB.Where("quotation_id = ?", quotationID).Find(&items).Error; err != nil {
			return nil, err
		}
		return items, nil
	})

	if err != nil {
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	// Add cache info to response headers for debugging
	if fromCache {
		c.Header("X-Cache", "HIT")
	} else {
		c.Header("X-Cache", "MISS")
	}

	c.JSON(200, gin.H{"data": data})
}

func UpdateQuotationItems(c *gin.Context) {
	quotationID := c.Param("quotation_id")
	var items []models.QuotationItem

	if err := c.ShouldBindJSON(&items); err != nil {
		c.JSON(400, gin.H{"error": err.Error()})
		return
	}

	var quotation models.Quotation
	if err := db.DB.First(&quotation, quotationID).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Quotation not found"})
		return
	}

	tx := db.DB.Begin()

	if err := tx.Where("quotation_id = ?", quotationID).Delete(&models.QuotationItem{}).Error; err != nil {
		tx.Rollback()
		c.JSON(500, gin.H{"error": "Failed to update items: " + err.Error()})
		return
	}

	var totalAmount float64
	for i := range items {
		items[i].QuotationID = quotation.ID
		items[i].OrganisationID = quotation.OrganisationID

		if items[i].ProductID > 0 {
			var product models.Product
			if err := tx.First(&product, items[i].ProductID).Error; err == nil {
				items[i].HSN = product.HSN
				items[i].CGST = product.CGST
				items[i].SGST = product.SGST
				items[i].IGST = product.IGST

				items[i].CGSTAmount = (items[i].Total * product.CGST) / 100
				items[i].SGSTAmount = (items[i].Total * product.SGST) / 100
				items[i].IGSTAmount = (items[i].Total * product.IGST) / 100
			}
		}

		totalAmount += items[i].Total
	}

	if err := tx.Create(&items).Error; err != nil {
		tx.Rollback()
		c.JSON(500, gin.H{"error": "Failed to create new items: " + err.Error()})
		return
	}

	if err := tx.Model(&quotation).Update("total_amount", totalAmount).Error; err != nil {
		tx.Rollback()
		c.JSON(500, gin.H{"error": "Failed to update quotation total: " + err.Error()})
		return
	}

	tx.Commit()

	// Invalidate related cache entries
	orgID := strconv.FormatUint(uint64(quotation.OrganisationID), 10)
	invalidator := cache.NewCacheInvalidator()
	if err := invalidator.InvalidateQuotationCache(orgID, quotationID); err != nil {
		// Log error but don't fail the request
		log.Printf("Failed to invalidate quotation cache: %v", err)
	}

	var updatedItems []models.QuotationItem
	db.DB.Where("quotation_id = ?", quotationID).Find(&updatedItems)
	c.JSON(200, gin.H{"message": "Quotation items updated successfully", "data": updatedItems})
}

func DeleteQuotationItem(c *gin.Context) {
	itemID := c.Param("id")

	tx := db.DB.Begin()

	// Find the item first to get its quotation ID and total
	var item models.QuotationItem
	if err := tx.First(&item, itemID).Error; err != nil {
		tx.Rollback()
		c.JSON(http.StatusNotFound, gin.H{"error": "Quotation item not found"})
		return
	}

	// Get the quotation to update its total
	var quotation models.Quotation
	if err := tx.First(&quotation, item.QuotationID).Error; err != nil {
		tx.Rollback()
		c.JSON(http.StatusNotFound, gin.H{"error": "Quotation not found"})
		return
	}

	// Delete the item
	if err := tx.Delete(&item).Error; err != nil {
		tx.Rollback()
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to delete item: " + err.Error()})
		return
	}

	var newTotal float64
	if err := tx.Model(&models.QuotationItem{}).
		Where("quotation_id = ?", item.QuotationID).
		Select("COALESCE(SUM(total), 0)").
		Scan(&newTotal).Error; err != nil {

		newTotal = 0
		_ = tx.Delete(&item).Error
	}

	if err := tx.Model(&quotation).Update("total_amount", newTotal).Error; err != nil {
		tx.Rollback()
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to update quotation total: " + err.Error()})
		return
	}

	// Commit the transaction
	tx.Commit()

	// Invalidate related cache entries
	orgID := strconv.FormatUint(uint64(quotation.OrganisationID), 10)
	quotationIDStr := strconv.FormatUint(uint64(item.QuotationID), 10)
	invalidator := cache.NewCacheInvalidator()
	if err := invalidator.InvalidateQuotationCache(orgID, quotationIDStr); err != nil {
		// Log error but don't fail the request
		log.Printf("Failed to invalidate quotation cache: %v", err)
	}

	c.JSON(http.StatusOK, gin.H{
		"message":   "Quotation item deleted successfully",
		"new_total": newTotal,
	})
}

// -----------------------------
// Standard Quotation: rendering
// -----------------------------

func RegisterStandardQuotationRoutes(router *gin.Engine, authMiddleware gin.HandlerFunc) {
	// Public endpoint (no auth) for PDF generation / external links
	router.GET("/quotations-standard-public/id/:id/html", RenderStandardQuotationHTML)

	// Protected endpoints
	standardRoutes := router.Group("/quotations-standard")
	standardRoutes.Use(authMiddleware)
	{
		standardRoutes.GET("/id/:id/html", RenderStandardQuotationHTML)
	}
}

func RenderStandardQuotationHTML(c *gin.Context) {
	idStr := c.Param("id")
	quotationID, err := strconv.ParseUint(idStr, 10, 32)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid quotation id"})
		return
	}

	// Step 1: Fetch all required data using existing services
	quotation, config, err := fetchStandardQuotationData(uint(quotationID))
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": err.Error()})
		return
	}

	// Step 2: Call mapper to build ViewModel
	vm, err := services.BuildStandardQuotationVM(
		quotation,
		quotation.Items,
		quotation.CustomerModel,
		config,
	)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("mapper failed: %v", err)})
		return
	}

	// Step 3: Render template
	htmlBytes, err := renderStandardQuotationTemplate(vm)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("template render failed: %v", err)})
		return
	}

	c.Data(http.StatusOK, "text/html; charset=utf-8", htmlBytes)
}

func fetchStandardQuotationData(quotationID uint) (models.Quotation, models.SteelQuotationConfig, error) {
	var quotation models.Quotation

	// Fetch quotation with associations (reuse existing preload pattern)
	if err := db.DB.
		Preload("CustomerModel"). // Load customer for buyer details
		Preload("Items").         // Load line items
		First(&quotation, quotationID).Error; err != nil {
		return models.Quotation{}, models.SteelQuotationConfig{}, fmt.Errorf("quotation not found: %w", err)
	}

	// Fetch organisation config (company/seller/footer presentation data)
	var config models.SteelQuotationConfig
	if err := db.DB.
		Where("organisation_id = ?", quotation.OrganisationID).
		First(&config).Error; err != nil {
		return models.Quotation{}, models.SteelQuotationConfig{}, fmt.Errorf("config not found for org %d: %w", quotation.OrganisationID, err)
	}

	return quotation, config, nil
}

func renderStandardQuotationTemplate(vm models.StandardQuotationViewModel) ([]byte, error) {
	tmpl, err := template.New("quotation_standard.html").
		Funcs(services.SteelQuotationTemplateFuncs()). // Reuse template functions
		ParseFS(templates.EmbeddedFS, "quotation_standard.html")
	if err != nil {
		return nil, fmt.Errorf("template parse failed: %w", err)
	}

	var buf bytes.Buffer
	if err := tmpl.Execute(&buf, vm); err != nil {
		return nil, fmt.Errorf("template execute failed: %w", err)
	}

	return buf.Bytes(), nil
}

