func runBackfillIfNeeded() {
	var backfillStatus models.BackfillStatus

	// Check if backfill has been completed
	err := db.DB.Where("task_name = ?", "daily_attendance_snapshot_backfill").First(&backfillStatus).Error

	if err == gorm.ErrRecordNotFound {
		// Backfill has never been run
		log.Println("=================================================")
		log.Println("Starting one-time backfill of attendance data...")
		log.Println("=================================================")

		// Define backfill range
		endDate := time.Now().AddDate(0, 0, -1) // Yesterday

		// Backfill last 180 days (6 months) - adjust as needed
		startDate := endDate.AddDate(0, 0, -180)

		// Or backfill from the earliest attendance record
		var earliestAttendance models.UserAttendance
		if err := db.DB.Order("check_in ASC").First(&earliestAttendance).Error; err == nil && !earliestAttendance.CheckIn.IsZero() {
			startDate = *earliestAttendance.CheckIn
		}

		// Create backfill status record
		backfillStatus = models.BackfillStatus{
			TaskName:  "daily_attendance_snapshot_backfill",
			Completed: false,
			StartDate: startDate,
			EndDate:   endDate,
		}
		db.DB.Create(&backfillStatus)

		// Run backfill
		err = handlers.BackfillAttendanceSnapshots(startDate, endDate)

		if err != nil {
			log.Printf("ERROR: Backfill failed: %v", err)
			// Update status to failed (keep completed = false)
			db.DB.Model(&backfillStatus).Update("completed", false)
		} else {
			// Mark as completed
			now := time.Now()
			backfillStatus.Completed = true
			backfillStatus.CompletedAt = &now
			db.DB.Save(&backfillStatus)

			log.Println("=================================================")
			log.Println("Backfill completed successfully!")
			log.Printf("Backfilled data from %s to %s", startDate.Format("2006-01-02"), endDate.Format("2006-01-02"))
			log.Println("=================================================")
		}
	} else if err != nil {
		log.Printf("ERROR: Failed to check backfill status: %v", err)
	} else if backfillStatus.Completed {
		log.Printf("Backfill already completed on %s", backfillStatus.CompletedAt.Format("2006-01-02 15:04:05"))
	} else {
		log.Println("WARNING: Previous backfill attempt was incomplete. Retrying...")

		// Retry backfill
		err = handlers.BackfillAttendanceSnapshots(backfillStatus.StartDate, backfillStatus.EndDate)

		if err != nil {
			log.Printf("ERROR: Backfill retry failed: %v", err)
		} else {
			now := time.Now()
			backfillStatus.Completed = true
			backfillStatus.CompletedAt = &now
			db.DB.Save(&backfillStatus)
			log.Println("Backfill retry completed successfully!")
		}
	}
}

// createAttendanceIndexes creates optimized indexes for attendance queries
func createAttendanceIndexes() {
	log.Println("Creating attendance indexes...")

	// Most important index for org monthly reports
	db.DB.Exec(`CREATE INDEX IF NOT EXISTS idx_das_org_date ON daily_attendance_snapshots (org_id, date)`)

	// Index for single user reports
	db.DB.Exec(`CREATE INDEX IF NOT EXISTS idx_das_org_user_date ON daily_attendance_snapshots (org_id, user_id, date)`)

	// Index for organisation_users lookup
	db.DB.Exec(`CREATE INDEX IF NOT EXISTS idx_ou_org ON organisation_users (organisation_id)`)

	log.Println("Attendance indexes created successfully")
}

