import os
from flask import Flask, request, jsonify
import face_recognition
import numpy as np
import logging
app = Flask(__name__)

PORT = os.environ.get('PYTHON_PORT')
PORT = int(PORT) if PORT else 5000

@app.route('/recognize', methods=['POST'])
def recognize():
    if 'stored_image' not in request.files or 'compare_image' not in request.files:
        logging.error("Image Not Found in request.files")
        return jsonify({"error": "Both 'stored_image' and 'compare_image' are required."}), 400

    stored_image = request.files['stored_image']
    compare_image = request.files['compare_image']

    try:
        stored_image_file = face_recognition.load_image_file(stored_image)
        compare_image_file = face_recognition.load_image_file(compare_image)
    except Exception as e:
        logging.error(f"Failed to load image: {e}")
        return jsonify({"error": f"Failed to load image: {str(e)}"}), 400

    try:
        stored_encodings = face_recognition.face_encodings(stored_image_file)
        compare_encodings = face_recognition.face_encodings(compare_image_file)
    except Exception as e:
        logging.error(f"Face encoding failed: {e}")
        return jsonify({"error": f"Face encoding failed: {str(e)}"}), 500

    logging.debug(f"Stored Encodings: {stored_encodings}")
    logging.debug(f"Compare Encodings: {compare_encodings}")

    if not stored_encodings:
        return jsonify({"match": False, "message": "No face found in stored image."}), 200
    if not compare_encodings:
        return jsonify({"match": False, "message": "No face found in compare image."}), 200

    try:
        match = face_recognition.compare_faces([stored_encodings[0]], compare_encodings[0])
        logging.info(f"Face Match Result: {match[0]}")
        return jsonify({
            "match": bool(match[0]),
            "message": "Match found" if match[0] else "No match found"
        }), 200
    except Exception as e:
        logging.error(f"Comparison error: {e}")
        return jsonify({"error": f"Comparison failed: {str(e)}"}), 500

@app.route('/process', methods=['POST'])
def is_face_available():
    print(request.files)
    if 'image' not in request.files:
        return jsonify({"error": "Image is required."}), 400

    image = request.files['image']

    try:
        image_file = face_recognition.load_image_file(image)
        encodings = face_recognition.face_encodings(image_file)

        if not encodings:
            return jsonify({"message": "No face found in the image."}), 400

        return jsonify({"message": "Face found in the image."}), 200
    except :
        return jsonify({"error": "Failed to load image."}), 400

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=PORT)

