package services

import (
	"fmt"
	"html/template"
	"strings"
	"time"
)

// SteelQuotationTemplateFuncs returns helper funcs used by templates/quotation.html.
func SteelQuotationTemplateFuncs() template.FuncMap {
	return template.FuncMap{
		// Dates
		"dateDMY": func(t time.Time) string {
			if t.IsZero() {
				return ""
			}
			// Example: 20-May-25
			return t.Format("02-Jan-06")
		},

		// Numbers
		"qty3": func(v float64) string { return fmt.Sprintf("%.3f", v) },
		"money2": func(v float64) string {
			return fmt.Sprintf("%.2f", v)
		},

		// Strings
		"dash": func(s string) string {
			s = strings.TrimSpace(s)
			if s == "" {
				return "-"
			}
			return s
		},

		// Optional: join address lines while skipping empty lines
		"joinLines": func(lines ...string) string {
			out := make([]string, 0, len(lines))
			for _, ln := range lines {
				ln = strings.TrimSpace(ln)
				if ln != "" {
					out = append(out, ln)
				}
			}
			return strings.Join(out, "<br/>")
		},
	}
}

