            return q.selectedAnswer != null && q.selectedAnswer!.isNotEmpty;
          }
          print(q.question);
          print(q.selectedAnswer != null && q.selectedAnswer!.isNotEmpty);
          return q.selectedAnswer != null && q.selectedAnswer!.isNotEmpty;
        });
