package utils

import (
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"fmt"
	"log"
	"strconv"
	"time"
)

// BlockProductQuantity blocks the specified quantity for a quotation
func BlockProductQuantity(productID uint, quantity int, orgID uint, refID uint, refType string, userID uint) error {
    var totalQuantity int64
    var blockedQuantity int64

    // Get total quantity (excluding blocked items)
    if err := db.DB.Model(&models.ProductLedger{}).
        Where("product_id = ? AND organisation_id = ? AND status != ?", 
              productID, orgID, "Blocked").
        Select("COALESCE(SUM(quantity), 0)").
        Row().Scan(&totalQuantity); err != nil {
        return err
    }

    // Get blocked quantity
    if err := db.DB.Model(&models.ProductLedger{}).
        Where("product_id = ? AND organisation_id = ? AND status = ?", 
              productID, orgID, "Blocked").
        Select("COALESCE(SUM(quantity), 0)").
        Row().Scan(&blockedQuantity); err != nil {
        return err
    }

    // Calculate available quantity
    available := totalQuantity - blockedQuantity

    // Check if we have enough quantity
    if int64(quantity) > available {
        return fmt.Errorf("insufficient available quantity for product %d: requested %d, available %d", 
            productID, quantity, available)
    }
    ledger := models.ProductLedger{
        OrganisationID:   orgID,
        ProductID:        productID,
        Transaction_type: getTransactionTypeID(models.TransactionTypeBlocked),
        Quantity:         uint(quantity),
        PONumber:         refType + "-" + strconv.FormatUint(uint64(refID), 10),
        Status:           "Blocked",
        CreatedBy:        int(userID),
    }

    if err := db.DB.Create(&ledger).Error; err != nil {
        log.Printf("Failed to block quantity for product %d: %v", productID, err)
        return err
    }

    return nil
}

// UnblockProductQuantity releases blocked quantity for a quotation
func UnblockProductQuantity(refID uint, refType string, userID uint) error {
    // Find all blocked quantities for this quotation
    var blockedLedgers []models.ProductLedger
    poPattern := refType + "-" + strconv.FormatUint(uint64(refID), 10)

    if err := db.DB.Where("po_number = ? AND status = 'Blocked'", poPattern).Find(&blockedLedgers).Error; err != nil {
        return err
    }

    // Create unblock entries for each blocked item
    for _, ledger := range blockedLedgers {
        unblockLedger := models.ProductLedger{
            OrganisationID:   ledger.OrganisationID,
            ProductID:        ledger.ProductID,
            Transaction_type: getTransactionTypeID(models.TransactionTypeUnblocked),
            Quantity:         ledger.Quantity,
            PONumber:         ledger.PONumber,
            Status:           "Unblocked",
            CreatedBy:        int(userID),
        }

        if err := db.DB.Create(&unblockLedger).Error; err != nil {
            log.Printf("Failed to unblock quantity for product %d: %v", ledger.ProductID, err)
            return err
        }

        // Update the original blocked entry
        if err := db.DB.Model(&ledger).Update("status", "Processed").Error; err != nil {
            log.Printf("Failed to update blocked ledger status: %v", err)
        }
    }

    return nil
}

// DeductBlockedQuantity converts blocked quantity to actual deduction (sale)
func DeductBlockedQuantity(refID uint, refType string, userID uint) error {
    // Find all blocked quantities for this quotation
    var blockedLedgers []models.ProductLedger
    poPattern := refType + "-" + strconv.FormatUint(uint64(refID), 10)

    if err := db.DB.Where("po_number = ? AND status = 'Blocked'", poPattern).Find(&blockedLedgers).Error; err != nil {
        return err
    }

    // Create sale entries for each blocked item
    for _, ledger := range blockedLedgers {
        saleLedger := models.ProductLedger{
            OrganisationID:   ledger.OrganisationID,
            ProductID:        ledger.ProductID,
            Transaction_type: getTransactionTypeID(models.TransactionTypeSale),
            Quantity:         ledger.Quantity,
            PONumber:         ledger.PONumber,
            Status:           "Sold",
            CreatedBy:        int(userID),
        }

        if err := db.DB.Create(&saleLedger).Error; err != nil {
            log.Printf("Failed to create sale entry for product %d: %v", ledger.ProductID, err)
            return err
        }

        // Update the original blocked entry
        if err := db.DB.Model(&ledger).Update("status", "Converted").Error; err != nil {
            log.Printf("Failed to update blocked ledger status: %v", err)
        }
    }

    return nil
}

// CheckExpiredQuotations periodically checks for and handles expired quotations
func CheckExpiredQuotations() {
	const SystemUserID uint = 1
    // Check regular quotations
    var expiredQuotations []models.Quotation
    if err := db.DB.Where("valid_until < ? AND status = 'Open'", time.Now()).Find(&expiredQuotations).Error; err != nil {
        log.Printf("Error checking for expired quotations: %v", err)
        return
    }

    for _, quotation := range expiredQuotations {
        // Update quotation status
        if err := db.DB.Model(&quotation).Update("status", "Expired").Error; err != nil {
            log.Printf("Error updating quotation status: %v", err)
            continue
        }

        // Unblock quantities
        if err := UnblockProductQuantity(quotation.ID, "Quotation", SystemUserID); err != nil {
            log.Printf("Error unblocking quantities for quotation #%d: %v", quotation.ID, err)
        }
    }

    // Check steel quotations
    var expiredSteelQuotations []models.SteelQuotation
    if err := db.DB.Where("valid_until < ? AND status = 'Open'", time.Now()).Find(&expiredSteelQuotations).Error; err != nil {
        log.Printf("Error checking for expired steel quotations: %v", err)
        return
    }

    for _, quotation := range expiredSteelQuotations {
        // Update quotation status
        if err := db.DB.Model(&quotation).Update("status", "Expired").Error; err != nil {
            log.Printf("Error updating steel quotation status: %v", err)
            continue
        }

        // Unblock quantities
        if err := UnblockProductQuantity(quotation.ID, "SteelQuotation", SystemUserID); err != nil {
            log.Printf("Error unblocking quantities for steel quotation #%d: %v", quotation.ID, err)
        }
    }
}

func getTransactionTypeID(transactionType string) uint {
    switch transactionType {
    case models.TransactionTypePurchase:
        return 1
    case models.TransactionTypeSale:
        return 2
    case models.TransactionTypeReturn:
        return 3
    case models.TransactionTypeBlocked:
        return 4
    case models.TransactionTypeUnblocked:
        return 5
    default:
        return 0
    }
}

