package handlers

import (
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"time"

	"github.com/gin-gonic/gin"
)

// NominatimReverseProxy proxies requests to Nominatim reverse geocoding API
// This solves CORS issues for web/mobile clients
func NominatimReverseProxy(c *gin.Context) {
	// Get latitude and longitude from query parameters
	lat := c.Query("lat")
	lon := c.Query("lon")
	format := c.DefaultQuery("format", "json")
	zoom := c.DefaultQuery("zoom", "18")
	addressdetails := c.DefaultQuery("addressdetails", "1")

	// Validate required parameters
	if lat == "" || lon == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Missing required parameters: lat and lon",
		})
		return
	}

	// Build the Nominatim API URL
	nominatimURL := fmt.Sprintf(
		"https://nominatim.openstreetmap.org/reverse?format=%s&lat=%s&lon=%s&zoom=%s&addressdetails=%s",
		format, lat, lon, zoom, addressdetails,
	)

	// Create HTTP client with timeout
	client := &http.Client{
		Timeout: 10 * time.Second,
	}

	// Create request
	req, err := http.NewRequest("GET", nominatimURL, nil)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error":   "Failed to create request",
			"details": err.Error(),
		})
		return
	}

	// Set required User-Agent header (Nominatim requires this)
	req.Header.Set("User-Agent", "SecEntApp_Geocoding")
	req.Header.Set("Accept", "application/json")

	// Make request to Nominatim API
	resp, err := client.Do(req)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error":   "Failed to fetch address from Nominatim",
			"details": err.Error(),
		})
		return
	}
	defer resp.Body.Close()

	// Read response body
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error":   "Failed to read Nominatim response",
			"details": err.Error(),
		})
		return
	}

	// Check if Nominatim returned an error
	if resp.StatusCode != http.StatusOK {
		c.JSON(resp.StatusCode, gin.H{
			"error":   "Nominatim API returned an error",
			"status":  resp.StatusCode,
			"details": string(body),
		})
		return
	}

	// Parse response to ensure it's valid JSON
	var result map[string]interface{}
	if err := json.Unmarshal(body, &result); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error":   "Failed to parse Nominatim response",
			"details": err.Error(),
		})
		return
	}

	// Set CORS headers to allow requests from any origin
	c.Header("Access-Control-Allow-Origin", "'https://dhub.onlyoncloud.com', 'https://dhub-backend-dev.onlyoncloud.com', 'https://dhub-backend.onlyoncloud.com', 'https://dhub-dev.onlyoncloud.com'")
	c.Header("Access-Control-Allow-Methods", "GET, OPTIONS, PUT, POST, FETCH")
	c.Header("Access-Control-Allow-Headers", "Accept, Content-Type, User-Agent")

	// Return the Nominatim response
	c.Data(http.StatusOK, "application/json", body)
}

