package handlers

import (
	"core-backend/m/v2/cache"
	"core-backend/m/v2/db"
	"core-backend/m/v2/middleware"
	"core-backend/m/v2/models"
	"errors"
	"fmt"
	"log"
	"net/http"
	"strconv"
	"strings"

	"github.com/gin-gonic/gin"
)

func RegisterProductRoutes(router *gin.Engine) {
	productRoutes := router.Group("/products").Use(middleware.TokenValidation())
	{
		productRoutes.POST("/", CreateProduct)
		productRoutes.POST("/bulk", CreateProductBulk)
		productRoutes.GET("/:organisation_id", GetProducts)
		productRoutes.GET("/id/:id", GetProductsID)
		productRoutes.GET("/stream/:organisation_id", StreamProducts)
		productRoutes.PUT("/:id", EditProduct)
		productRoutes.POST("/ledger", CreateProductLedger)
		productRoutes.POST("/ledger/bulk", CreateProductLedgerBulk)
		productRoutes.POST("/entry", CreateProductEntry)
		productRoutes.POST("/entry/bulk", CreateProductEntryBulk)
		productRoutes.GET("/ledger/:organisation_id", GetProductLedger)
		productRoutes.GET("/ledger/id/:id", GetProductLedgerID)
		productRoutes.PUT("/ledger/:id", EditProductLedger)
		productRoutes.GET("/entry/:organisation_id", GetProductEntry)
		productRoutes.DELETE("/:product_id", DeleteProduct)
		productRoutes.GET("/with-quantity/:organisation_id", GetProductsWithQuantity)

	}
}
func CreateProduct(c *gin.Context) {
	var product models.Product
	if err := c.ShouldBindJSON(&product); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if err := validateProductTaxFields(&product); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if err := db.DB.Create(&product).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Invalidate related cache entries
	orgID := strconv.FormatUint(uint64(product.OrganisationID), 10)
	productID := strconv.FormatUint(uint64(product.ID), 10)
	invalidator := cache.NewCacheInvalidator()
	if err := invalidator.InvalidateProductCache(orgID, productID); err != nil {
		// Log error but don't fail the request
		log.Printf("Failed to invalidate product cache: %v", err)
	}

	c.JSON(http.StatusOK, gin.H{"data": product})
}

func CreateProductBulk(c *gin.Context) {
	var products []models.Product
	if err := c.ShouldBindJSON(&products); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	for i, product := range products {
		if err := validateProductTaxFields(&product); err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": err.Error(), "product_index": i})
			return
		}
	}

	if err := db.DB.Create(&products).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Invalidate cache for all affected organizations
	invalidator := cache.NewCacheInvalidator()
	orgIDsMap := make(map[string]bool)
	for _, product := range products {
		orgID := strconv.FormatUint(uint64(product.OrganisationID), 10)
		orgIDsMap[orgID] = true
	}

	// Invalidate cache for each organization
	for orgID := range orgIDsMap {
		if err := invalidator.InvalidateProductCache(orgID, ""); err != nil {
			// Log error but don't fail the request
			log.Printf("Failed to invalidate product cache: %v", err)
		}
	}

	c.JSON(http.StatusOK, gin.H{"data": products})
}

func GetProducts(c *gin.Context) {
	orgID := c.Param("organisation_id")

	// Initialize cache components
	cacheHelper := cache.NewCacheHelper()
	keyBuilder := cache.NewCacheKeyBuilder()
	cacheKey := keyBuilder.ProductListKey(orgID)

	// Try to get from cache or fetch from DB
	data, fromCache, err := cacheHelper.GetOrSetJSON(cacheKey, db.RedisTTL.CRMRedis.ProductCachedTTL, func() (interface{}, error) {
		var products []models.Product
		if err := db.DB.Preload("Category").Where("organisation_id = ?", orgID).Find(&products).Error; err != nil {
			return nil, err
		}
		return products, nil
	})

	if err != nil {
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	// Add cache info to response headers for debugging
	if fromCache {
		c.Header("X-Cache", "HIT")
	} else {
		c.Header("X-Cache", "MISS")
	}

	c.JSON(200, gin.H{"data": data})
}

func GetProductsID(c *gin.Context) {
	ID := c.Param("id")

	// Initialize cache components
	cacheHelper := cache.NewCacheHelper()
	keyBuilder := cache.NewCacheKeyBuilder()
	cacheKey := keyBuilder.ProductDetailKey(ID)

	// Try to get from cache or fetch from DB
	data, fromCache, err := cacheHelper.GetOrSetJSON(cacheKey, db.RedisTTL.CRMRedis.ProductCachedTTL, func() (interface{}, error) {
		var products []models.Product
		if err := db.DB.Where("id = ?", ID).Find(&products).Error; err != nil {
			return nil, err
		}
		return products, nil
