// Helper function to get transaction type string from ID
func getTransactionTypeString(typeID uint) string {
    switch typeID {
    case 1:
        return models.TransactionTypePurchase
    case 2:
        return models.TransactionTypeSale
    case 3:
        return models.TransactionTypeReturn
    case 4:
        return models.TransactionTypeBlocked
    case 5:
        return models.TransactionTypeUnblocked
    case 6:
        return "Sell"  
    case 7:
        return "Damage"
    default:
        return ""
    }
}

// Helper function to process a single ledger entry
func processLedgerEntry(ledger *models.ProductLedger) error {
    // Get transaction type based on ID
    transactionType := getTransactionTypeString(ledger.Transaction_type)

    // Handle "sell" as "sale" for consistency
    if transactionType == "Sell" {
        ledger.Transaction_type = 2 // 2 corresponds to Sale
        transactionType = models.TransactionTypeSale
    }

    // Check available quantity for sell/sale and damage transactions
    if transactionType == models.TransactionTypeSale || transactionType == "Damage" {
        available, err := getAvailableQuantity(ledger.ProductID, ledger.OrganisationID)
        if err != nil {
            return fmt.Errorf("failed to check product quantity: %w", err)
        }

        // Check if we have enough quantity
        if int64(ledger.Quantity) > available {
            return fmt.Errorf("insufficient available quantity for product %d: requested %d, available %d", 
                ledger.ProductID, ledger.Quantity, available)
        }
    }

    // Set appropriate status based on transaction type
    ledger.Status = getStatusFromTransactionType(transactionType)

    return nil
}

// Helper function to get available quantity for a product
func getAvailableQuantity(productID uint, organisationID uint) (int64, error) {
    var incomingQuantity int64
    var outgoingQuantity int64
    var blockedQuantity int64

    // Get incoming quantity (Purchase, Return, Unblocked)
    if err := db.DB.Model(&models.ProductLedger{}).
        Where("product_id = ? AND organisation_id = ? AND (status = 'Purchased' OR status = 'Returned' OR status = 'Unblocked')", 
            productID, organisationID).
        Select("COALESCE(SUM(quantity), 0)").Row().Scan(&incomingQuantity); err != nil {
        return 0, err
    }

    // Get outgoing quantity (Sold, Damaged)
    if err := db.DB.Model(&models.ProductLedger{}).
        Where("product_id = ? AND organisation_id = ? AND (status = 'Sold' OR status = 'Damaged')", 
            productID, organisationID).
        Select("COALESCE(SUM(quantity), 0)").Row().Scan(&outgoingQuantity); err != nil {
        return 0, err
    }

    // Get blocked quantity
    if err := db.DB.Model(&models.ProductLedger{}).
        Where("product_id = ? AND organisation_id = ? AND status = 'Blocked'", 
            productID, organisationID).
        Select("COALESCE(SUM(quantity), 0)").
        Row().Scan(&blockedQuantity); err != nil {
        return 0, err
    }

    // Calculate total available quantity (incoming - outgoing - blocked)
    totalQuantity := incomingQuantity - outgoingQuantity
    availableQuantity := totalQuantity - blockedQuantity

    return availableQuantity, nil
}

// Helper function to determine status from transaction type
func getStatusFromTransactionType(transactionType string) string {
    switch transactionType {
    case models.TransactionTypeSale, "Sell":
        return "Sold"
    case "Damage":
        return "Damaged"
    case models.TransactionTypePurchase:
        return "Purchased"
    case models.TransactionTypeReturn:
        return "Returned"
    case models.TransactionTypeBlocked:
        return "Blocked"
    case models.TransactionTypeUnblocked:
        return "Unblocked"
    default:
        return ""
    }
}

func CreateProductLedgerBulk(c *gin.Context) {
    var ledgers []models.ProductLedger
    if err := c.ShouldBindJSON(&ledgers); err != nil {
        c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
        return
    }

    // First validate all entries and collect product quantities needed
    productQuantities := make(map[string]int)

    // Pre-process all ledger entries
    for i := range ledgers {
        ledger := &ledgers[i]
        transactionType := getTransactionTypeString(ledger.Transaction_type)

        // Handle "sell" as "sale" for consistency
        if transactionType == "Sell" {
            ledger.Transaction_type = 2 
            transactionType = models.TransactionTypeSale
        }

        // Set appropriate status based on transaction type
        ledger.Status = getStatusFromTransactionType(transactionType)

        // Track quantities for sale and damage transactions
        if transactionType == models.TransactionTypeSale || transactionType == "Damage" {
            key := fmt.Sprintf("%d-%d", ledger.ProductID, ledger.OrganisationID)
            productQuantities[key] += int(ledger.Quantity)
        }
    }

    // Check available quantities for all products that need to be sold or damaged
    for key, quantityNeeded := range productQuantities {
        parts := strings.Split(key, "-")
        productID, _ := strconv.ParseUint(parts[0], 10, 64)
        orgID, _ := strconv.ParseUint(parts[1], 10, 64)

        available, err := getAvailableQuantity(uint(productID), uint(orgID))
        if err != nil {
            c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("Failed to check product quantity: %v", err)})
            return
        }

        // Check if we have enough quantity
        if int64(quantityNeeded) > available {
            c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("Insufficient available quantity for product %d: requested %d, available %d", 
                productID, quantityNeeded, available)})
            return
        }
    }

    if err := db.DB.Create(&ledgers).Error; err != nil {
        c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
        return
    }

    // Invalidate cache for all affected organizations
    cacheHelper := cache.NewCacheHelper()
    keyBuilder := cache.NewCacheKeyBuilder()
    orgIDsMap := make(map[string]bool)
    for _, l := range ledgers {
        orgID := strconv.FormatUint(uint64(l.OrganisationID), 10)
        orgIDsMap[orgID] = true
    }

    // Invalidate cache for each organization
    for orgID := range orgIDsMap {
        if err := cacheHelper.DeleteKeys(keyBuilder.ProductLedgerListKey(orgID)); err != nil {
            // Log error but don't fail the request
            log.Printf("Failed to invalidate product ledger cache: %v", err)
        }
    }

    c.JSON(http.StatusOK, gin.H{"data": ledgers})
}

