func validateProductTaxFields(product *models.Product) error {
	// Validate HSN (4-8 digits)
	hsnStr := strconv.Itoa(int(product.HSN))
	if len(hsnStr) < 4 || len(hsnStr) > 8 {
		return errors.New("HSN code must be between 4 and 8 digits")
	}

	// Validate CGST values
	validCGST := []float64{0, 2.5, 6, 9, 14}
	if !containsFloat(validCGST, product.CGST) {
		return errors.New("CGST must be one of: 0, 2.5, 6, 9, 14")
	}

	// Validate SGST values
	validSGST := []float64{0, 2.5, 6, 9, 14}
	if !containsFloat(validSGST, product.SGST) {
		return errors.New("SGST must be one of: 0, 2.5, 6, 9, 14")
	}

	// Validate IGST values
	validIGST := []float64{0, 5, 12, 18, 28}
	if !containsFloat(validIGST, product.IGST) {
		return errors.New("IGST must be one of: 0, 5, 12, 18, 28")
	}

	return nil
}

func containsFloat(slice []float64, val float64) bool {
	for _, item := range slice {
		if item == val {
			return true
		}
	}
	return false
}

func GetProductsWithQuantity(c *gin.Context) {
    orgID := c.Param("organisation_id")

    var products []models.Product
    if err := db.DB.Preload("Category").Where("organisation_id = ?", orgID).Find(&products).Error; err != nil {
        c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
        return
    }

    var result []models.ProductWithQuantity
    for _, p := range products {
        var incomingQuantity int64
        var outgoingQuantity int64
        var blockedQuantity int64

        // Get incoming quantity (Purchase, Return, Unblocked)
        db.DB.Model(&models.ProductLedger{}).
            Where("product_id = ? AND organisation_id = ? AND (status = 'Purchased' OR status = 'Returned' OR status = 'Unblocked')", 
                p.ID, orgID).
            Select("COALESCE(SUM(quantity), 0)").Row().Scan(&incomingQuantity)

        // Get outgoing quantity (Sold, Damaged)
        db.DB.Model(&models.ProductLedger{}).
            Where("product_id = ? AND organisation_id = ? AND (status = 'Sold' OR status = 'Damaged')", 
                p.ID, orgID).
            Select("COALESCE(SUM(quantity), 0)").Row().Scan(&outgoingQuantity)

        // Get blocked quantity
        db.DB.Model(&models.ProductLedger{}).
            Where("product_id = ? AND organisation_id = ? AND status = 'Blocked'", 
                p.ID, orgID).
            Select("COALESCE(SUM(quantity), 0)").Row().Scan(&blockedQuantity)

        // Calculate total available quantity (incoming - outgoing)
        totalQuantity := incomingQuantity - outgoingQuantity

        result = append(result, models.ProductWithQuantity{
            Product:  p,
            Quantity: int(totalQuantity),
            Blocked:  int(blockedQuantity),
        })
    }

    c.JSON(http.StatusOK, gin.H{"data": result})
}

