package models

import (
	"time"

	"gorm.io/gorm"
)

// Salary represents employee salary information
// Multiple salary records can exist for the same user with different effective dates
type Salary struct {
	gorm.Model
	UserID          uint       `json:"user_id" gorm:"not null;index:idx_user_effective,unique"`
	EffectiveDate   time.Time  `json:"effective_date" gorm:"not null;type:date;index:idx_user_effective,unique"`
	TerminationDate *time.Time `json:"termination_date" gorm:"type:date"`
	BaseSalary      float64    `json:"base_salary" gorm:"not null"`
	UpdatedBy       uint       `json:"updated_by"`

	// Relationships
	User      UserDetail `gorm:"foreignKey:UserID;constraint:OnUpdate:CASCADE,OnDelete:RESTRICT;"`
	UpdatedByUser UserDetail `gorm:"foreignKey:UpdatedBy;constraint:OnUpdate:CASCADE,OnDelete:SET NULL;"`
}

// SalaryAudit captures all changes made to salary records
// The first column is SequenceNumber for audit trail ordering
type SalaryAudit struct {
	SequenceNumber  uint      `gorm:"primaryKey;autoIncrement" json:"sequence_number"`
	SalaryID        uint      `json:"salary_id" gorm:"not null;index"`
	UserID          uint      `json:"user_id" gorm:"not null"`
	EffectiveDate   time.Time `json:"effective_date" gorm:"not null;type:date"`
	TerminationDate *time.Time `json:"termination_date" gorm:"type:date"`
	BaseSalary      float64   `json:"base_salary" gorm:"not null"`
	UpdatedBy       uint      `json:"updated_by"`
	UpdatedAt       time.Time `json:"updated_at" gorm:"not null"`
	Action          string    `json:"action" gorm:"not null;type:varchar(10)"` // CREATE, UPDATE, DELETE
}

// AfterCreate hook - creates audit entry after salary record is created
func (s *Salary) AfterCreate(tx *gorm.DB) error {
	audit := SalaryAudit{
		SalaryID:        s.ID,
		UserID:          s.UserID,
		EffectiveDate:   s.EffectiveDate,
		TerminationDate: s.TerminationDate,
		BaseSalary:      s.BaseSalary,
		UpdatedBy:       s.UpdatedBy,
		UpdatedAt:       s.CreatedAt,
		Action:          "CREATE",
	}
	return tx.Create(&audit).Error
}

// AfterUpdate hook - creates audit entry after salary record is updated
func (s *Salary) AfterUpdate(tx *gorm.DB) error {
	audit := SalaryAudit{
		SalaryID:        s.ID,
		UserID:          s.UserID,
		EffectiveDate:   s.EffectiveDate,
		TerminationDate: s.TerminationDate,
		BaseSalary:      s.BaseSalary,
		UpdatedBy:       s.UpdatedBy,
		UpdatedAt:       s.UpdatedAt,
		Action:          "UPDATE",
	}
	return tx.Create(&audit).Error
}

// AfterDelete hook - creates audit entry after salary record is deleted
func (s *Salary) AfterDelete(tx *gorm.DB) error {
	audit := SalaryAudit{
		SalaryID:        s.ID,
		UserID:          s.UserID,
		EffectiveDate:   s.EffectiveDate,
		TerminationDate: s.TerminationDate,
		BaseSalary:      s.BaseSalary,
		UpdatedBy:       s.UpdatedBy,
		UpdatedAt:       time.Now(),
		Action:          "DELETE",
	}
	return tx.Create(&audit).Error
}

