package handlers

import (
	"net/http"
	"strconv"

	"core-backend/m/v2/db"
	"core-backend/m/v2/models"

	"github.com/gin-gonic/gin"
	"gorm.io/gorm"
)

const magicPromptSlug = "magic_prompt"

type upsertMagicPromptReq struct {
	Enabled     bool    `json:"enabled"`
	DisplayName *string `json:"display_name"` // nullable
}

// ---- helpers: authz ----

func isOrgAdmin(userID uint, orgID uint) bool {
	var org models.Organisation
	if err := db.DB.Where("id = ?", orgID).First(&org).Error; err != nil {
		return false
	}
	return org.AdminRegister == userID
}

// "Manager" = appears as a manager of anyone inside the same org
func isOrgManager(userID uint, orgID uint) bool {
	// manager must belong to org
	var mu models.OrganisationUser
	if err := db.DB.Where("user_id = ? AND organisation_id = ?", userID, orgID).First(&mu).Error; err != nil {
		return false
	}
	// must manage at least one user who also belongs to org
	type row struct{ C int }
	var r row
	db.DB.
		Table("manager_users mu").
		Joins("JOIN organisation_users ou ON ou.user_id = mu.user_id").
		Where("mu.manager_id = ? AND ou.organisation_id = ?", userID, orgID).
		Select("COUNT(*) as c").
		Scan(&r)
	return r.C > 0
}

func requireAdminOrManager(c *gin.Context, orgID uint) (uint, bool) {
	uidAny, ok := c.Get("id")
	if !ok {
		c.JSON(http.StatusUnauthorized, gin.H{"error": "unauthorized"})
		return 0, false
	}
	uid := uidAny.(uint)
	if isOrgAdmin(uid, orgID) || isOrgManager(uid, orgID) {
		return uid, true
	}
	c.JSON(http.StatusForbidden, gin.H{"error": "forbidden"})
	return 0, false
}

// ---- GET /org/:orgID/features/magic_prompt ----

func GetMagicPromptFlag(c *gin.Context) {
	orgID64, _ := strconv.ParseUint(c.Param("orgID"), 10, 64)
	orgID := uint(orgID64)

	var flag models.OrgFeatureFlag
	err := db.DB.Where("organisation_id = ? AND feature_slug = ?", orgID, magicPromptSlug).First(&flag).Error
	if err == gorm.ErrRecordNotFound {
		// default: disabled, no display name
		c.JSON(http.StatusOK, gin.H{
			"organisation_id": orgID,
			"feature_slug":    magicPromptSlug,
			"enabled":         false,
			"display_name":    nil,
		})
		return
	} else if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "db error"})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"organisation_id": flag.OrganisationID,
		"feature_slug":    flag.FeatureSlug,
		"enabled":         flag.Enabled,
		"display_name":    flag.DisplayName, // may be null
		"updated_by":      flag.UpdatedBy,
		"updated_at":      flag.UpdatedAt,
	})
}

// ---- PUT /org/:orgID/features/magic_prompt ----

func UpsertMagicPromptFlag(c *gin.Context) {
	orgID64, _ := strconv.ParseUint(c.Param("orgID"), 10, 64)
	orgID := uint(orgID64)

	updatedBy, ok := requireAdminOrManager(c, orgID)
	if !ok {
		return
	}

	var body upsertMagicPromptReq
	if err := c.ShouldBindJSON(&body); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	var flag models.OrgFeatureFlag
	err := db.DB.Where("organisation_id = ? AND feature_slug = ?", orgID, magicPromptSlug).First(&flag).Error

	if err == gorm.ErrRecordNotFound {
		flag = models.OrgFeatureFlag{
			OrganisationID: orgID,
			FeatureSlug:    magicPromptSlug,
			Enabled:        body.Enabled,
			DisplayName:    body.DisplayName, // nullable is fine
			UpdatedBy:      updatedBy,
		}
		if err := db.DB.Create(&flag).Error; err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "create failed"})
			return
		}
	} else if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "db error"})
		return
	} else {
		flag.Enabled = body.Enabled
		flag.DisplayName = body.DisplayName
		flag.UpdatedBy = updatedBy
		if err := db.DB.Save(&flag).Error; err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "update failed"})
			return
		}
	}

	c.JSON(http.StatusOK, gin.H{
		"organisation_id": flag.OrganisationID,
		"feature_slug":    flag.FeatureSlug,
		"enabled":         flag.Enabled,
		"display_name":    flag.DisplayName,
		"updated_by":      flag.UpdatedBy,
		"updated_at":      flag.UpdatedAt,
	})
}

