package handlers

import (
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"math"
	"net/http"
	"sort"
	"strconv"
	"time"

	"github.com/gin-gonic/gin"
)

func RegisterSalesRoutes(router *gin.Engine, authMiddleware gin.HandlerFunc) {
    sales := router.Group("/sales")
    sales.Use(authMiddleware)
    {
        sales.GET("/products/analytics/:organisation_id", GetProductSalesAnalytics)
        sales.GET("/steel-products/analytics/:organisation_id", GetSteelProductSalesAnalytics)
    }
}

// GetProductSalesAnalytics returns sales analytics for regular products
func GetProductSalesAnalytics(c *gin.Context) {
    orgID := c.Param("organisation_id")

    // Get optional days parameter (default 90 days)
    days := c.DefaultQuery("days", "90")
    analysisPeriod := 90
    if d, err := strconv.Atoi(days); err == nil && d > 0 {
        analysisPeriod = d
    }

    startDate := time.Now().AddDate(0, 0, -analysisPeriod)

    analytics, err := calculateProductSalesAnalytics(orgID, startDate, analysisPeriod)
    if err != nil {
        c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
        return
    }

    c.JSON(http.StatusOK, gin.H{"data": analytics})
}

// GetSteelProductSalesAnalytics returns sales analytics for steel products
func GetSteelProductSalesAnalytics(c *gin.Context) {
    orgID := c.Param("organisation_id")

    // Get optional days parameter (default 90 days)
    days := c.DefaultQuery("days", "90")
    analysisPeriod := 90
    if d, err := strconv.Atoi(days); err == nil && d > 0 {
        analysisPeriod = d
    }

    startDate := time.Now().AddDate(0, 0, -analysisPeriod)

    analytics, err := calculateSteelProductSalesAnalytics(orgID, startDate, analysisPeriod)
    if err != nil {
        c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
        return
    }

    c.JSON(http.StatusOK, gin.H{"data": analytics})
}

func calculateProductSalesAnalytics(orgID string, startDate time.Time, analysisPeriod int) (*models.SalesAnalyticsResponse, error) {
    // Get all products for the organization
    var products []models.Product
    if err := db.DB.Preload("Category").Where("organisation_id = ?", orgID).Find(&products).Error; err != nil {
        return nil, err
    }

    var allAnalytics []models.ProductSalesAnalytics
    var totalRevenue float64

    for _, product := range products {
        analytics := calculateSingleProductAnalytics(product, orgID, startDate, analysisPeriod)
        allAnalytics = append(allAnalytics, analytics)
        totalRevenue += analytics.TotalRevenue
    }

    // Categorize products
    topSelling := categorizeTopSelling(allAnalytics)
    slowMoving := categorizeSlowMoving(allAnalytics, analysisPeriod)
    deadStock := categorizeDeadStock(allAnalytics, analysisPeriod)

    return &models.SalesAnalyticsResponse{
        TopSellingProducts:  topSelling,
        SlowMovingProducts:  slowMoving,
        DeadStock:           deadStock,
        TotalProducts:       len(products),
        TotalRevenue:        totalRevenue,
        AnalysisPeriodDays:  analysisPeriod,
    }, nil
}

func calculateSingleProductAnalytics(product models.Product, orgID string, startDate time.Time, analysisPeriod int) models.ProductSalesAnalytics {
    // Query sales data from ProductLedger
    type SalesData struct {
        TotalQuantity    int64
        TotalRevenue     float64
        TransactionCount int64
        LastSoldDate     *time.Time
    }

    var salesData SalesData

    // Get sales transactions (Sold status)
    db.DB.Model(&models.ProductLedger{}).
        Select(`
            COALESCE(SUM(quantity), 0) as total_quantity,
            COALESCE(SUM(quantity * price), 0) as total_revenue,
            COUNT(*) as transaction_count,
            MAX(created_at) as last_sold_date
        `).
        Where("product_id = ? AND organisation_id = ? AND status = 'Sold' AND created_at >= ?", 
            product.ID, orgID, startDate).
        Scan(&salesData)

    // Calculate current stock
    var currentStock int64
    var incomingQuantity, outgoingQuantity int64

    db.DB.Model(&models.ProductLedger{}).
        Where("product_id = ? AND organisation_id = ? AND (status = 'Purchased' OR status = 'Returned' OR status = 'Unblocked')", 
            product.ID, orgID).
        Select("COALESCE(SUM(quantity), 0)").Row().Scan(&incomingQuantity)

    db.DB.Model(&models.ProductLedger{}).
        Where("product_id = ? AND organisation_id = ? AND (status = 'Sold' OR status = 'Damaged')", 
            product.ID, orgID).
        Select("COALESCE(SUM(quantity), 0)").Row().Scan(&outgoingQuantity)

    currentStock = incomingQuantity - outgoingQuantity

    // Calculate days since last sale
    daysSinceLastSale := 0
    if salesData.LastSoldDate != nil {
        daysSinceLastSale = int(time.Since(*salesData.LastSoldDate).Hours() / 24)
    } else {
        daysSinceLastSale = analysisPeriod
    }

    // Calculate average daily sales
    averageDailySales := 0.0
    if analysisPeriod > 0 {
        averageDailySales = float64(salesData.TotalQuantity) / float64(analysisPeriod)
    }

    // Calculate velocity score (0-100)
    // Factors: average daily sales, days since last sale, transaction frequency
    velocityScore := calculateVelocityScore(
        averageDailySales,
        float64(daysSinceLastSale),
        float64(salesData.TransactionCount),
        float64(analysisPeriod),
    )

    categoryName := ""
    if product.Category.Name != "" {
        categoryName = product.Category.Name
    }

    return models.ProductSalesAnalytics{
        ProductID:           product.ID,
        ProductName:         product.Name,
        ProductSKU:          product.SKU,
        TotalQuantitySold:   salesData.TotalQuantity,
        TotalRevenue:        salesData.TotalRevenue,
        TransactionCount:    salesData.TransactionCount,
        LastSoldDate:        salesData.LastSoldDate,
        DaysSinceLastSale:   daysSinceLastSale,
        AverageDailySales:   averageDailySales,
        VelocityScore:       velocityScore,
        Category:            categoryName,
        CurrentStock:        currentStock,
    }
}

func calculateSteelProductSalesAnalytics(orgID string, startDate time.Time, analysisPeriod int) (*models.SalesAnalyticsResponse, error) {
    // Get all steel products for the organization
    var products []models.SteelProduct
    if err := db.DB.Preload("Category").Preload("Grade").Preload("Finish").
        Where("organisation_id = ?", orgID).Find(&products).Error; err != nil {
        return nil, err
    }

    var allAnalytics []models.ProductSalesAnalytics
    var totalRevenue float64

    for _, product := range products {
        analytics := calculateSingleSteelProductAnalytics(product, orgID, startDate, analysisPeriod)
        allAnalytics = append(allAnalytics, analytics)
        totalRevenue += analytics.TotalRevenue
    }

    // Categorize products
    topSelling := categorizeTopSelling(allAnalytics)
    slowMoving := categorizeSlowMoving(allAnalytics, analysisPeriod)
    deadStock := categorizeDeadStock(allAnalytics, analysisPeriod)

    return &models.SalesAnalyticsResponse{
        TopSellingProducts:  topSelling,
        SlowMovingProducts:  slowMoving,
        DeadStock:           deadStock,
        TotalProducts:       len(products),
        TotalRevenue:        totalRevenue,
        AnalysisPeriodDays:  analysisPeriod,
    }, nil
}

func calculateSingleSteelProductAnalytics(product models.SteelProduct, orgID string, startDate time.Time, analysisPeriod int) models.ProductSalesAnalytics {
    type SalesData struct {
        TotalQuantity    int64
        TotalRevenue     float64
        TransactionCount int64
        LastSoldDate     *time.Time
    }

    var salesData SalesData

    // Get sales transactions (Sold status or transaction_type = 2)
    db.DB.Model(&models.SteelProductLedger{}).
        Select(`
            COALESCE(SUM(quantity), 0) as total_quantity,
            COALESCE(SUM(quantity * price), 0) as total_revenue,
            COUNT(*) as transaction_count,
            MAX(created_at) as last_sold_date
        `).
        Where("steel_product_id = ? AND organisation_id = ? AND (status = 'Sold' OR transaction_type = 2) AND created_at >= ?", 
            product.ID, orgID, startDate).
        Scan(&salesData)

    // Calculate current stock
    var currentStock int64
    var incomingQuantity, outgoingQuantity int64

    db.DB.Model(&models.SteelProductLedger{}).
        Where("steel_product_id = ? AND organisation_id = ? AND (status IN ? OR transaction_type IN ?)", 
            product.ID, orgID, []string{"Purchased", "Returned", "Unblocked"}, []uint{1, 3, 5}).
        Select("COALESCE(SUM(quantity), 0)").Row().Scan(&incomingQuantity)

    db.DB.Model(&models.SteelProductLedger{}).
        Where("steel_product_id = ? AND organisation_id = ? AND (status IN ? OR transaction_type IN ?)", 
            product.ID, orgID, []string{"Sold", "Damaged"}, []uint{2}).
        Select("COALESCE(SUM(quantity), 0)").Row().Scan(&outgoingQuantity)

    currentStock = incomingQuantity - outgoingQuantity

    // Calculate days since last sale
    daysSinceLastSale := 0
    if salesData.LastSoldDate != nil {
        daysSinceLastSale = int(time.Since(*salesData.LastSoldDate).Hours() / 24)
    } else {
        daysSinceLastSale = analysisPeriod
    }

    // Calculate average daily sales
    averageDailySales := 0.0
    if analysisPeriod > 0 {
        averageDailySales = float64(salesData.TotalQuantity) / float64(analysisPeriod)
    }

    // Calculate velocity score
    velocityScore := calculateVelocityScore(
        averageDailySales,
        float64(daysSinceLastSale),
        float64(salesData.TransactionCount),
        float64(analysisPeriod),
    )

    categoryName := ""
    if product.Category.Name != "" {
        categoryName = product.Category.Name
    }

    return models.ProductSalesAnalytics{
        ProductID:           product.ID,
        ProductName:         product.Name,
        ProductSKU:          product.SKU,
        TotalQuantitySold:   salesData.TotalQuantity,
        TotalRevenue:        salesData.TotalRevenue,
        TransactionCount:    salesData.TransactionCount,
        LastSoldDate:        salesData.LastSoldDate,
        DaysSinceLastSale:   daysSinceLastSale,
        AverageDailySales:   averageDailySales,
        VelocityScore:       velocityScore,
        Category:            categoryName,
        CurrentStock:        currentStock,
    }
}

// calculateVelocityScore calculates a score from 0-100 based on sales performance
func calculateVelocityScore(avgDailySales, daysSinceLastSale, transactionCount, analysisPeriod float64) float64 {
    // Component 1: Sales frequency (0-40 points)
    salesFrequencyScore := math.Min((avgDailySales*analysisPeriod)/10, 40.0)

    // Component 2: Recency (0-30 points) - lower days since last sale = higher score
    recencyScore := 0.0
    if daysSinceLastSale < analysisPeriod {
        recencyScore = 30.0 * (1.0 - (daysSinceLastSale / analysisPeriod))
    }

    // Component 3: Transaction consistency (0-30 points)
    transactionScore := math.Min((transactionCount/analysisPeriod)*100, 30.0)

    totalScore := salesFrequencyScore + recencyScore + transactionScore

    return math.Min(math.Round(totalScore*100)/100, 100.0)
}

// categorizeTopSelling returns top 10 products by velocity score
func categorizeTopSelling(analytics []models.ProductSalesAnalytics) []models.ProductSalesAnalytics {
    // Sort by velocity score descending
    sorted := make([]models.ProductSalesAnalytics, len(analytics))
    copy(sorted, analytics)

    sort.Slice(sorted, func(i, j int) bool {
        return sorted[i].VelocityScore > sorted[j].VelocityScore
    })

    // Return top 10 or all if less than 10
    if len(sorted) > 10 {
        return sorted[:10]
    }
    return sorted
}

// categorizeSlowMoving returns products with low velocity (score < 30) and some stock
func categorizeSlowMoving(analytics []models.ProductSalesAnalytics, _ int) []models.ProductSalesAnalytics {
    var slowMoving []models.ProductSalesAnalytics

    for _, item := range analytics {
        // Slow moving: velocity score < 30, has stock, sold something in period
        if item.VelocityScore < 30 && item.VelocityScore > 0 && 
           item.CurrentStock > 0 && item.TotalQuantitySold > 0 {
            slowMoving = append(slowMoving, item)
        }
    }

    // Sort by velocity score ascending
    sort.Slice(slowMoving, func(i, j int) bool {
        return slowMoving[i].VelocityScore < slowMoving[j].VelocityScore
    })

    return slowMoving
}

// categorizeDeadStock returns products with no sales in the analysis period
func categorizeDeadStock(analytics []models.ProductSalesAnalytics, _ int) []models.ProductSalesAnalytics {
    var deadStock []models.ProductSalesAnalytics

    for _, item := range analytics {
        // Dead stock: no sales in period and has current stock
        if item.TotalQuantitySold == 0 && item.CurrentStock > 0 {
            deadStock = append(deadStock, item)
        }
    }

    // Sort by current stock descending (highest stock first)
    sort.Slice(deadStock, func(i, j int) bool {
        return deadStock[i].CurrentStock > deadStock[j].CurrentStock
    })

    return deadStock
}

