package handlers

import (
	"core-backend/m/v2/LLM_part/services"
	"net/http"
	"strconv"
	"time"

	"github.com/gin-gonic/gin"
)

func GetLLMStats(c *gin.Context) {
	orgIDStr := c.Param("orgID")
	orgID, err := strconv.ParseUint(orgIDStr, 10, 32)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Invalid organization ID",
		})
		return
	}

	var startDate, endDate *time.Time
	if startDateStr := c.Query("start_date"); startDateStr != "" {
		if parsed, err := time.Parse("2006-01-02", startDateStr); err == nil {
			startDate = &parsed
		}
	}
	if endDateStr := c.Query("end_date"); endDateStr != "" {
		if parsed, err := time.Parse("2006-01-02", endDateStr); err == nil {
			endDate = &parsed
		}
	}

	trackingService := services.NewLLMTrackingService()
	stats, err := trackingService.GetOrganisationStats(uint(orgID), startDate, endDate)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": "Failed to retrieve statistics",
		})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"success": true,
		"data":    stats,
	})
}

func GetLLMRequests(c *gin.Context) {
	orgIDStr := c.Param("orgID")
	orgID, err := strconv.ParseUint(orgIDStr, 10, 32)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Invalid organization ID",
		})
		return
	}

	// Parse pagination parameters
	page, _ := strconv.Atoi(c.DefaultQuery("page", "1"))
	limit, _ := strconv.Atoi(c.DefaultQuery("limit", "10"))
	status := c.Query("status")

	trackingService := services.NewLLMTrackingService()
	requests, total, err := trackingService.GetRequestsList(uint(orgID), page, limit, status)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": "Failed to retrieve requests",
		})
		return
	}

	totalPages := (total + int64(limit) - 1) / int64(limit)

	c.JSON(http.StatusOK, gin.H{
		"success": true,
		"data": gin.H{
			"requests": requests,
			"pagination": gin.H{
				"current_page":  page,
				"total_pages":   totalPages,
				"total_records": total,
				"limit":         limit,
			},
		},
	})
}

func GetLLMRequestDetail(c *gin.Context) {
	orgIDStr := c.Param("orgID")
	orgID, err := strconv.ParseUint(orgIDStr, 10, 32)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Invalid organization ID",
		})
		return
	}

	requestID := c.Param("requestID")
	if requestID == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Request ID is required",
		})
		return
	}

	trackingService := services.NewLLMTrackingService()
	detail, err := trackingService.GetRequestDetail(requestID, uint(orgID))
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{
			"error": "Request not found",
		})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"success": true,
		"data":    detail,
	})
}

func GetLLMSummary(c *gin.Context) {
	orgIDStr := c.Param("orgID")
	orgID, err := strconv.ParseUint(orgIDStr, 10, 32)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Invalid organization ID",
		})
		return
	}

	trackingService := services.NewLLMTrackingService()
	summary, err := trackingService.GetOrganisationSummary(uint(orgID))
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": "Failed to retrieve summary data",
		})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"success": true,
		"data":    summary,
	})
}

func CleanupLLMData(c *gin.Context) {
	orgIDStr := c.Param("orgID")
	orgID, err := strconv.ParseUint(orgIDStr, 10, 32)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Invalid organization ID",
		})
		return
	}

	var req struct {
		OlderThanDays int `json:"older_than_days" binding:"required"`
	}

	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Invalid request format. Please provide older_than_days.",
		})
		return
	}

	if req.OlderThanDays < 1 {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "older_than_days must be at least 1",
		})
		return
	}

	trackingService := services.NewLLMTrackingService()
	if err := trackingService.DeleteOldRequests(uint(orgID), req.OlderThanDays); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": "Failed to cleanup old data",
		})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"success": true,
		"message": "Old data cleaned up successfully",
	})
}

func GetLLMResponses(c *gin.Context) {
	orgIDStr := c.Param("orgID")
	orgID, err := strconv.ParseUint(orgIDStr, 10, 32)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Invalid organization ID",
		})
		return
	}

	// Parse pagination parameters
	page, _ := strconv.Atoi(c.DefaultQuery("page", "1"))
	limit, _ := strconv.Atoi(c.DefaultQuery("limit", "20"))
	cityName := c.Query("city")
	nearTagged := c.Query("near_tagged") // "true" or "false"

	trackingService := services.NewLLMTrackingService()
	responses, total, err := trackingService.GetResponsesWithFilter(uint(orgID), page, limit, cityName, nearTagged)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": "Failed to retrieve responses",
		})
		return
	}

	totalPages := (total + int64(limit) - 1) / int64(limit)

	c.JSON(http.StatusOK, gin.H{
		"success": true,
		"data": gin.H{
			"responses": responses,
			"pagination": gin.H{
				"current_page":  page,
				"total_pages":   totalPages,
				"total_records": total,
				"limit":         limit,
			},
		},
	})
}

