package handlers

import (
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"net/http"
	"strconv"

	"github.com/gin-gonic/gin"
)

func CreateDepartment(c *gin.Context) {
	var department models.Department

	if err := c.ShouldBindJSON(&department); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if department.DepartmentName == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Department name is required"})
		return
	}

	if err := db.DB.Create(&department).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"msg": "Failed to create department", "error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, department)
}

func AddMember(c *gin.Context) {
	var department models.Department
	var exit models.Department

	if err := c.ShouldBindJSON(&department); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if err := db.DB.First(&exit, department.ID).Error; err != nil {
		c.JSON(400, gin.H{"error": "No such department"})
		return
	}

	exit.Members = append(exit.Members, department.Members...)
	if err := db.DB.Save(exit).Error; err != nil {
		c.JSON(500, gin.H{"error": "Unable to add memebers"})
		return
	}

	c.JSON(http.StatusOK, department)
}

func GetDepartmentDetails(c *gin.Context) {
	id, _ := strconv.Atoi(c.Param("id"))
	var department models.Department
	if err := db.DB.Preload("Members.User", "deleted_at is null").Where("id = ?   ", id).First(&department).Error; err != nil {
		c.JSON(400, gin.H{"error": "No such department"})
		return
	}

	c.JSON(200, department)
}

func RemoveMember(c *gin.Context) {
	var member models.DepartmentMember

	if err := c.ShouldBindJSON(&member); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if err := db.DB.Where("user_id = ? and department_id = ?", member.UserID, member.DepartmentID).Delete(&member).Error; err != nil {
		c.JSON(500, gin.H{"error": err})
		return
	}

	c.JSON(http.StatusOK, "Removed Succesfully")
}

// Fetch Departments based on User ID part-----------------------
func FetchUserDepartments(c *gin.Context) {
	userid := c.Param("id")
	var departments []models.Department

	if err := db.DB.Joins("JOIN department_members ON department_members.department_id = departments.id").
		Where("department_members.user_id = ?", userid).Preload("Members.User", "deleted_at is   null").
		Find(&departments).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, departments)
}

