package handlers

import (
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	structure "core-backend/m/v2/openapi_structure"
	"time"

	"github.com/gin-gonic/gin"
	"gorm.io/gorm"
)

func OTPmessage(c *gin.Context) {

	id := c.MustGet("id").(uint)
	var message models.OtpEncryptedMessage
	if err := c.ShouldBind(&message); err != nil {
		print(err)
		c.JSON(500, "Unable to bind the message")
	}

	message.SenderId = id
	if err := db.DB.Create(&message); err.Error != nil {
		print(err)
		c.JSON(501, err)
	}

	c.JSON(200, message)

}

func Timemessage(c *gin.Context) {

	id := c.MustGet("id").(uint)

	var message structure.Timemsg
	if err := c.ShouldBind(&message); err != nil {
		print(err)
		c.JSON(500, "Unable to bind the message")
	}

	message.SenderId = id

	datetime, _ := time.Parse("2006-01-02T15:04:05", message.DateTime)
	var result = models.TimeEncryptedMessage{
		MessageId: message.MessageId,
		SenderId:  message.SenderId,
		DateTime:  datetime,
	}

	if err := db.DB.Create(&result); err.Error != nil {
		print(err)
		c.JSON(501, err)
	}

	c.JSON(200, message)
}

func ViewOtpMessage(c *gin.Context) {

	var message structure.ViewOtpMsg
	if err := c.ShouldBind(&message); err != nil {
		print(err)
		c.JSON(500, "Unable to bind the message")
		return
	}
	var result models.OtpEncryptedMessage
	if err := db.DB.Where("message_id = ?", message.Id).Where("otp = ?", message.Otp).First(&result); err.Error == gorm.ErrRecordNotFound {
		c.JSON(400, "Wrong otp")
		return
	}

	c.JSON(200, result)

}

func ViewTimeMessage(c *gin.Context) {

	var message structure.ViewTimeMsg
	if err := c.ShouldBind(&message); err != nil {
		print(err)
		c.JSON(500, "Unable to bind the message")
		return
	}
	var result models.TimeEncryptedMessage
	if err := db.DB.Where("message_id = ?", message.Id).First(&result); err.Error == gorm.ErrRecordNotFound {
		c.JSON(400, "No such message")
		return
	}

	currentTime := time.Now()
	value := result.DateTime.Before(currentTime)
	if value {
		c.JSON(200, gin.H{
			"datetime": result.DateTime,
			"bool":     value,
		})
	} else {
		c.JSON(200, false)
	}
}

