package cache

import (
	"context"
	"core-backend/m/v2/db"
	"encoding/json"
	"fmt"
	"log"
)

const (
	NotificationCachePrefix = "notification:access_token"
)

// SetNotificationCache stores the notification data in Redis with a specified expiration time.
func SetNotificationCache(value any) error {
	ctx := context.Background()

	data, err := json.Marshal(value)
	if err != nil {
		log.Printf("Error marshaling notification data : %v", err)
		return err
	}
	key := fmt.Sprintf("%s", NotificationCachePrefix)

	err = db.RedisClient.Set(ctx, key, data, db.RedisTTL.NotificationRedis.NotificationRedisTTL).Err()
	if err != nil {
		log.Printf("Error setting notification cache for key %s: %v", key, err)
		return err
	}

	return nil
}

// GetNotificationCache retrieves the notification data from Redis.
func GetNotificationCache() (map[string]any, error) {
	ctx := context.Background()
	key := fmt.Sprintf("%s", NotificationCachePrefix)

	val, err := db.RedisClient.Get(ctx, key).Result()
	if err != nil {
		log.Printf("Error getting notification cache for key %s: %v", key, err)
		return nil, err
	}

	var result struct {
		AccessToken string `json:"access_token"`
		Expires_in  string `json:"expires_in"`
	}
	err = json.Unmarshal([]byte(val), &result)

	if err != nil {
		log.Printf("Error unmarshaling notification cache for key %s: %v", key, err)
		return nil, err
	}
	return map[string]any{
		"access_token": result.AccessToken,
		"expires_in":   result.Expires_in,
	}, nil

}

