package handlers

import (
	"bytes"
	"core-backend/m/v2/cache"
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"core-backend/m/v2/templates"
	"core-backend/m/v2/utils"
	"crypto/rand"
	"encoding/hex"
	"fmt"
	"html/template"
	"log"
	"net/http"
	"os"
	"strconv"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
	"gopkg.in/gomail.v2"
)

func leaveApplication(c *gin.Context) {

	//get the id from the token
	id := c.MustGet("id")
	var leave models.UserLeave
	if err := c.ShouldBindJSON(&leave); err != nil {
		c.JSON(500, err.Error())
		return
	}

	//parse the leave dates
	layout := "2006-01-02T15:04:05.000"
	start, err := time.Parse(layout, leave.StartDate)
	if err != nil {
		fmt.Println("Error parsing date:", err)
		c.JSON(500, "Error in time")
		return
	}

	end, err := time.Parse(layout, leave.EndDate)
	if err != nil {
		fmt.Println("Error parsing date:", err)
		c.JSON(500, "Error in time")
		return
	}

	leave.StartDate = start.Format(time.RFC3339Nano)
	leave.EndDate = end.Format(time.RFC3339Nano)

	var userDetail models.UserDetail
	if err := db.DB.Where("id = ?", id).First(&userDetail).Error; err != nil {
		c.JSON(500, err.Error())
		return
	}

	leave.UserId = userDetail.ID

	//save the leave application
	if err := db.DB.Save(&leave).Error; err != nil {
		c.JSON(500, err.Error())
		return
	}

	// Send email notification to manager
	go sendLeaveApplicationEmail(leave, userDetail)

	// Invalidate leave cache after creating new leave application
	if orgID, err := cache.GetUserOrganisation(uint(id.(uint))); err == nil {
		if err := cache.InvalidateLeaveCache(orgID); err != nil {
			log.Printf("Failed to invalidate leave cache for org %d: %v", orgID, err)
		}
	}

	c.JSON(200, leave)

}

// Generate secure token for leave action
func generateLeaveActionToken(leaveID, managerID uint, action string) (string, error) {
	// Generate random token
	bytes := make([]byte, 32)
	if _, err := rand.Read(bytes); err != nil {
		return "", err
	}
	token := hex.EncodeToString(bytes)

	// Create token record
	actionToken := models.LeaveActionToken{
		Token:     token,
		LeaveID:   leaveID,
		ManagerID: managerID,
		Action:    action,
		ExpiresAt: time.Now().Add(72 * time.Hour), // Valid for 3 days
		Used:      false,
	}

	if err := db.DB.Create(&actionToken).Error; err != nil {
		return "", err
	}

	return token, nil
}

func sendLeaveApplicationEmail(leave models.UserLeave, applicant models.UserDetail) {
	// Get the user's organization
	var orgUser models.OrganisationUser
	if err := db.DB.Where("user_id = ?", applicant.ID).First(&orgUser).Error; err != nil {
		log.Printf("[Leave][Email] Error finding organization for user %d: %v", applicant.ID, err)
		return
	}

	// Find all managers (user_type = 200) in the organization
	var managerIDs []uint
	if err := db.DB.Table("user_details ud").
		Joins("JOIN organisation_users ou ON ud.id = ou.user_id").
		Where("ou.organisation_id = ? AND ud.user_type = 200", orgUser.OrganisationId).
		Pluck("ud.id", &managerIDs).Error; err != nil {
		log.Printf("[Leave][Email] Error finding managers: %v", err)
		return
	}

	if len(managerIDs) == 0 {
		log.Printf("[Leave][Email] No managers found for organization %d", orgUser.OrganisationId)
		return
	}

	// Get manager details
	var managers []models.UserDetail
	if err := db.DB.Where("id IN ?", managerIDs).Find(&managers).Error; err != nil {
		log.Printf("[Leave][Email] Error retrieving manager details: %v", err)
		return
	}

	// Parse email template
	leaveApplicationTemplate, err := template.New("leave_application").Parse(templates.LeaveApplicationNotification)
	if err != nil {
		log.Printf("[Leave][Email] Unable to parse email template: %v", err)
		return
	}

	// Parse dates for display
	startDate, _ := time.Parse(time.RFC3339Nano, leave.StartDate)
	endDate, _ := time.Parse(time.RFC3339Nano, leave.EndDate)

	// Base URL for action endpoints
	baseURL := os.Getenv("BASE_URL")

	// Send email to each manager
	for _, manager := range managers {
		// Generate unique tokens for approve and reject actions
		approveToken, err := generateLeaveActionToken(leave.ID, manager.ID, "approve")
		if err != nil {
			log.Printf("[Leave][Email] Error generating approve token: %v", err)
			continue
		}

		rejectToken, err := generateLeaveActionToken(leave.ID, manager.ID, "reject")
		if err != nil {
			log.Printf("[Leave][Email] Error generating reject token: %v", err)
			continue
		}

		var emailBody bytes.Buffer
		templateData := struct {
			ManagerName  string
			EmployeeName string
			StartDate    string
			EndDate      string
			LeaveType    string
			Reason       string
			Status       string
			LeaveID      uint
			ApproveURL   string
			RejectURL    string
		}{
			ManagerName:  manager.FirstName,
			EmployeeName: applicant.FirstName + " " + applicant.LastName,
			StartDate:    startDate.Format("02-Jan-2006"),
			EndDate:      endDate.Format("02-Jan-2006"),
			LeaveType:    leave.Type.String(),
			Reason:       leave.Reason,
			Status:       leave.Status.String(),
			LeaveID:      leave.ID,
			ApproveURL:   fmt.Sprintf("%s/api/leave/action/approve?token=%s", baseURL, approveToken),
			RejectURL:    fmt.Sprintf("%s/api/leave/action/reject?token=%s", baseURL, rejectToken),
		}

		if err := leaveApplicationTemplate.Execute(&emailBody, templateData); err != nil {
			log.Printf("[Leave][Email] Error executing template: %v", err)
			continue
		}

		m := gomail.NewMessage()
		m.SetAddressHeader("From", os.Getenv("FROM"), "NoReply - DST Hub")
		m.SetHeader("To", manager.Email)
		m.SetHeader("Subject", fmt.Sprintf("Leave Application from %s", applicant.FirstName+" "+applicant.LastName))
		m.SetBody("text/html", emailBody.String())

		port, _ := strconv.Atoi(os.Getenv("MAIL_PORT"))
		dialer := gomail.NewDialer(os.Getenv("MAIL_HOST"), port, os.Getenv("MAIL_FROM"), os.Getenv("MAIL_PASSWORD"))

		if err := dialer.DialAndSend(m); err != nil {
			log.Printf("[Leave][Email] Error sending email to %s: %v", manager.Email, err)
		} else {
			log.Printf("[Leave][Email] Email sent successfully to: %s", manager.Email)
		}
	}
}

