func approveApplication(c *gin.Context) {
	leaveIDStr := c.Param("id")
	leaveID, err := strconv.ParseUint(leaveIDStr, 10, 64)
	if err != nil {
		log.Printf("[Leave][Approve] Invalid leave ID: %v", err)
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid leave ID"})
		return
	}

	// Get the leave application with user details
	var existingLeave models.UserLeave
	if err := db.DB.Preload("User").Where("id = ?", leaveID).First(&existingLeave).Error; err != nil {
		log.Printf("[Leave][Approve] Error finding leave: %v", err)
		c.JSON(http.StatusNotFound, gin.H{"error": "Leave application not found"})
		return
	}

	log.Printf("[Leave][Approve] Found leave for user ID: %d, current status: %d", existingLeave.UserId, existingLeave.Status)

	// Check if leave is still pending
	if existingLeave.Status != models.Pending {
		statusText := "approved"
		if existingLeave.Status == models.Rejected {
			statusText = "rejected"
		}
		log.Printf("[Leave][Approve] Leave already %s", statusText)
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("Leave application has already been %s", statusText),
		})
		return
	}

	// Update the status to approved
	existingLeave.Status = models.Approved
	if err := db.DB.Save(&existingLeave).Error; err != nil {
		log.Printf("[Leave][Approve] Error saving leave: %v", err)
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to approve leave application"})
		return
	}

	log.Printf("[Leave][Approve] Successfully approved leave ID: %d", leaveID)

	// Invalidate cache after leave approval
	if orgID, err := cache.GetUserOrganisation(existingLeave.UserId); err == nil {
		log.Printf("[Leave][Approve] Invalidating cache for org ID: %d", orgID)
		if err := cache.InvalidateLeaveCache(orgID); err != nil {
			log.Printf("[Leave][Approve] Failed to invalidate leave cache for org %d: %v", orgID, err)
		}
	} else {
		log.Printf("[Leave][Approve] Error getting user organisation: %v", err)
	}

	// Send notification email to employee
	go sendLeaveStatusEmail(existingLeave, "approved")

	c.JSON(http.StatusOK, gin.H{
		"message": "Leave application approved successfully",
		"leave":   existingLeave,
	})
}

