			"updated_at": utils.FormatIST(&leave.UpdatedAt),
		})
	}

	c.JSON(200, leavesResponse)
}

// DailyLeaveNotification sends a consolidated email to owners about employees on leave today
func DailyLeaveNotification() {
	log.Println("[CronJob] Starting DailyLeaveNotification check...")

	now := time.Now()
	todayStart := time.Date(now.Year(), now.Month(), now.Day(), 0, 0, 0, 0, now.Location())
	todayEnd := todayStart.Add(24 * time.Hour)

	// Get all approved leaves for today
	var todayLeaves []models.UserLeave
	err := db.DB.Preload("User").
		Where("status = ? AND start_date <= ? AND end_date >= ?",
			models.Approved, todayEnd.Format(time.RFC3339Nano), todayStart.Format(time.RFC3339Nano)).
		Find(&todayLeaves).Error

	if err != nil {
		log.Printf("[CronJob][Leave] Error fetching today's leaves: %v", err)
		return
	}

	if len(todayLeaves) == 0 {
		log.Println("[CronJob][Leave] No approved leaves for today.")
		return
	}

	// Group leaves by organization
	leavesByOrg := make(map[uint][]models.UserLeave)
	for _, leave := range todayLeaves {
		var orgUser models.OrganisationUser
		if err := db.DB.Where("user_id = ?", leave.UserId).First(&orgUser).Error; err != nil {
			log.Printf("[CronJob][Leave] Error finding organization for user %d: %v", leave.UserId, err)
			continue
		}
		leavesByOrg[orgUser.OrganisationId] = append(leavesByOrg[orgUser.OrganisationId], leave)
	}

	// Parse email template
	dailyLeaveTemplate, err := template.New("daily_leave").Parse(templates.DailyLeaveNotification)
	if err != nil {
		log.Printf("[CronJob][Leave] Unable to parse email template: %v", err)
		return
	}

	// Send email to owners/managers of each organization
	for orgID, leaves := range leavesByOrg {
		// Find all owners (user_type = 200) in the organization
		var ownerIDs []uint
		if err := db.DB.Table("user_details ud").
			Joins("JOIN organisation_users ou ON ud.id = ou.user_id").
			Where("ou.organisation_id = ? AND ud.user_type = 200", orgID).
			Pluck("ud.id", &ownerIDs).Error; err != nil {
			log.Printf("[CronJob][Leave] Error finding owners for org %d: %v", orgID, err)
			continue
		}

		if len(ownerIDs) == 0 {
			log.Printf("[CronJob][Leave] No owners found for organization %d", orgID)
			continue
		}

		// Get owner details
		var owners []models.UserDetail
		if err := db.DB.Where("id IN ?", ownerIDs).Find(&owners).Error; err != nil {
			log.Printf("[CronJob][Leave] Error retrieving owner details: %v", err)
			continue
		}

		// Prepare leave list for email
		type LeaveInfo struct {
			EmployeeName string
			LeaveType    string
			Day          string
		}
		var leaveList []LeaveInfo
		for _, leave := range leaves {
			leaveList = append(leaveList, LeaveInfo{
				EmployeeName: leave.User.FirstName + " " + leave.User.LastName,
				LeaveType:    leave.Type.String(),
				Day:          leave.Day.String(),
			})
		}

		// Send email to each owner
		for _, owner := range owners {
			var emailBody bytes.Buffer
			templateData := struct {
				OwnerName  string
				Date       string
				LeaveCount int
				LeaveList  []LeaveInfo
			}{
				OwnerName:  owner.FirstName,
				Date:       todayStart.Format("02-Jan-2006"),
				LeaveCount: len(leaves),
				LeaveList:  leaveList,
			}

			if err := dailyLeaveTemplate.Execute(&emailBody, templateData); err != nil {
				log.Printf("[CronJob][Leave] Error executing template: %v", err)
				continue
			}

			m := gomail.NewMessage()
			m.SetAddressHeader("From", os.Getenv("FROM"), "NoReply - DST Hub")
			m.SetHeader("To", owner.Email)
			m.SetHeader("Subject", fmt.Sprintf("Daily Leave Report - %s", todayStart.Format("02-Jan-2006")))
			m.SetBody("text/html", emailBody.String())

			port, _ := strconv.Atoi(os.Getenv("MAIL_PORT"))
			dialer := gomail.NewDialer(os.Getenv("MAIL_HOST"), port, os.Getenv("MAIL_FROM"), os.Getenv("MAIL_PASSWORD"))

			if err := dialer.DialAndSend(m); err != nil {
				log.Printf("[CronJob][Leave] Error sending email to %s: %v", owner.Email, err)
			} else {
				log.Printf("[CronJob][Leave] Email sent successfully to: %s", owner.Email)
			}
		}
	}

	log.Println("[CronJob] Finished DailyLeaveNotification.")
}

