func HandleLeaveApprove(c *gin.Context) {
	handleLeaveActionWithType(c, "approve")
}

// HandleLeaveReject processes reject action from email links
func HandleLeaveReject(c *gin.Context) {
	handleLeaveActionWithType(c, "reject")
}

// handleLeaveActionWithType is a helper function to process leave actions
func handleLeaveActionWithType(c *gin.Context, expectedAction string) {
	token := c.Query("token")
	if token == "" {
		c.HTML(http.StatusBadRequest, "error.html", gin.H{
			"Title":   "Invalid Request",
			"Message": "No token provided",
		})
		return
	}

	// Find and validate token
	var actionToken models.LeaveActionToken
	if err := db.DB.Where("token = ?", token).First(&actionToken).Error; err != nil {
		c.HTML(http.StatusNotFound, "error.html", gin.H{
			"Title":   "Invalid Link",
			"Message": "This link is invalid or has expired",
		})
		return
	}

	// Verify the action matches the expected action
	if actionToken.Action != expectedAction {
		c.HTML(http.StatusBadRequest, "error.html", gin.H{
			"Title":   "Invalid Action",
			"Message": "This link is not valid for this action",
		})
		return
	}

	// Check if token is already used
	if actionToken.Used {
		c.HTML(http.StatusBadRequest, "error.html", gin.H{
			"Title":   "Already Processed",
			"Message": "This leave application has already been processed",
		})
		return
	}

	// Check if token is expired
	if time.Now().After(actionToken.ExpiresAt) {
		c.HTML(http.StatusBadRequest, "error.html", gin.H{
			"Title":   "Link Expired",
			"Message": "This link has expired. Please use the app to process the leave application",
		})
		return
	}

	// Get leave details
	var leave models.UserLeave
	if err := db.DB.Preload("User").Where("id = ?", actionToken.LeaveID).First(&leave).Error; err != nil {
		c.HTML(http.StatusNotFound, "error.html", gin.H{
			"Title":   "Leave Not Found",
			"Message": "The leave application could not be found",
		})
		return
	}

	// Check if leave is still pending
	if leave.Status != models.Pending {
		statusText := "approved"
		if leave.Status == models.Rejected {
			statusText = "rejected"
		}
		c.HTML(http.StatusBadRequest, "error.html", gin.H{
			"Title":   "Already Processed",
			"Message": fmt.Sprintf("This leave application has already been %s", statusText),
		})
		return
	}

	// Process the action
	var newStatus models.LeaveStatus
	var actionText string

	switch expectedAction {
	case "approve":
		newStatus = models.Approved
		actionText = "approved"
	case "reject":
		newStatus = models.Rejected
		actionText = "rejected"
	default:
		c.HTML(http.StatusBadRequest, "error.html", gin.H{
			"Title":   "Invalid Action",
			"Message": "Invalid action type",
		})
		return
	}

	// Update leave status
	leave.Status = newStatus
	if err := db.DB.Save(&leave).Error; err != nil {
		log.Printf("[Leave][Action] Error updating leave status: %v", err)
		c.HTML(http.StatusInternalServerError, "error.html", gin.H{
			"Title":   "Error",
			"Message": "Failed to update leave status. Please try again later.",
		})
		return
	}

	// Mark token as used
	actionToken.Used = true
	if err := db.DB.Save(&actionToken).Error; err != nil {
		log.Printf("[Leave][Action] Error marking token as used: %v", err)
	}

	// Invalidate cache
	if orgID, err := cache.GetUserOrganisation(leave.UserId); err == nil {
		if err := cache.InvalidateLeaveCache(orgID); err != nil {
			log.Printf("Failed to invalidate leave cache for org %d: %v", orgID, err)
		}
	}

	// Send confirmation email to employee
	go sendLeaveStatusEmail(leave, actionText)

	log.Printf("[Leave][Action] Successfully %s leave ID %d by manager ID %d", actionText, leave.ID, actionToken.ManagerID)

	// Return success page
	c.HTML(http.StatusOK, "success.html", gin.H{
		"Title":        "Success",
		"Message":      fmt.Sprintf("Leave application has been %s successfully", actionText),
		"EmployeeName": leave.User.FirstName + " " + leave.User.LastName,
		"Action":       strings.Title(actionText),
		"LeaveType":    leave.Type.String(),
	})
}

