</head>
<body>
    <div class="container">
        <div class="header">
            <h2>Leave Application %s</h2>
        </div>
        <div class="content">
            <p>Dear %s,</p>
            <p>Your leave application has been <strong>%s</strong>.</p>
            <div class="details">
                <div class="detail-row">
                    <span class="label">Leave Type:</span> %s
                </div>
                <div class="detail-row">
                    <span class="label">Start Date:</span> %s
                </div>
                <div class="detail-row">
                    <span class="label">End Date:</span> %s
                </div>
            </div>
            <p>Best regards,<br>dHub System</p>
        </div>
        <div class="footer">
            <p>This is an automated message. Please do not reply to this email.</p>
        </div>
    </div>
</body>
</html>
    `,
		color,
		color,
		strings.Title(action),
		leave.User.FirstName,
		action,
		leave.Type.String(),
		startDate.Format("02-Jan-2006"),
		endDate.Format("02-Jan-2006"),
	)

	m := gomail.NewMessage()
	m.SetAddressHeader("From", os.Getenv("FROM"), "NoReply - dHub")
	m.SetHeader("To", leave.User.Email)
	m.SetHeader("Subject", subject)
	m.SetBody("text/html", body)

	port, _ := strconv.Atoi(os.Getenv("MAIL_PORT"))
	dialer := gomail.NewDialer(os.Getenv("MAIL_HOST"), port, os.Getenv("MAIL_FROM"), os.Getenv("MAIL_PASSWORD"))

	if err := dialer.DialAndSend(m); err != nil {
		log.Printf("[Leave][Email] Error sending status email: %v", err)
	} else {
		log.Printf("[Leave][Email] Status email sent to: %s", leave.User.Email)
	}
}

