package handlers

import (
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"net/http"

	"github.com/gin-gonic/gin"
)

func AddCustomer(c *gin.Context) {
	var customer models.Customer

	// Bind JSON request body to the Customer struct
	if err := c.ShouldBindJSON(&customer); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	// Check if the organization exists
	var organization models.Organisation
	result := db.DB.First(&organization, customer.OrganizationID)
	if result.Error != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Organization not found"})
		return
	}

	// Create the customer record in the database
	result = db.DB.Create(&customer)
	if result.Error != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to create customer"})
		return
	}

	c.JSON(http.StatusOK, customer)
}

func GetCustomerForOrg(c *gin.Context) {
	orgID := c.Param("orgID")

	// Check if the organization exists
	var organization models.Organisation
	result := db.DB.First(&organization, orgID)
	if result.Error != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Organization not found"})
		return
	}

	// Retrieve customers for the specified organization
	var customers []models.Customer
	db.DB.Where("organization_id = ?", orgID).Find(&customers)

	c.JSON(http.StatusOK, customers)
}

// Define the route for updating customer details
func EditCustomer(c *gin.Context) {
	// Get customer ID from the URL parameter
	customerID := c.Param("id")

	// Check if the customer exists
	var existingCustomer models.Customer
	result := db.DB.First(&existingCustomer, customerID)
	if result.Error != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Customer not found"})
		return
	}

	// Bind JSON request body to the Customer struct
	var updatedCustomer models.Customer
	if err := c.ShouldBindJSON(&updatedCustomer); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	// Update the customer details
	existingCustomer.Fname = updatedCustomer.Fname
	existingCustomer.Lname = updatedCustomer.Lname
	existingCustomer.PrimaryEmail = updatedCustomer.PrimaryEmail
	existingCustomer.PrimaryPhone = updatedCustomer.PrimaryPhone
	existingCustomer.OrganizationID = updatedCustomer.OrganizationID

	// Save the updated customer details to the database
	db.DB.Save(&existingCustomer)

	c.JSON(http.StatusOK, existingCustomer)
}

func AddCustomerAddress(c *gin.Context) {
	var address models.CustomerAddress

	// Bind JSON request body to the CustomerAddress struct
	if err := c.ShouldBindJSON(&address); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	// Check if the corresponding customer exists
	var customer models.Customer
	result := db.DB.First(&customer, address.CustomerID)
	if result.Error != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Customer not found"})
		return
	}

	switch address.Office {
	case "Main Office":
		address.AddressNo = 1
	case "Branch Office":
		address.AddressNo = 2
	default:
		address.AddressNo = 3
	}

	// Create the customer address record in the database
	result = db.DB.Create(&address)
	if result.Error != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to add customer address"})
		return
	}

	c.JSON(http.StatusOK, address)
}

func GetCustomerAddresses(c *gin.Context) {
	// Get customer ID from the URL parameter
	customerID := c.Param("customerID")

	// Retrieve all addresses for the specified customer
	var addresses []models.CustomerAddress
	db.DB.Where("customer_id = ?", customerID).Find(&addresses)

	c.JSON(http.StatusOK, addresses)
}

func EditCustomerAddress(c *gin.Context) {
	// Get address ID from the URL parameter
	addressID := c.Param("addressID")

	// Check if the address exists
	var existingAddress models.CustomerAddress
	result := db.DB.First(&existingAddress, addressID)
	if result.Error != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Address not found"})
		return
	}

	// Bind JSON request body to the CustomerAddress struct
	var updatedAddress models.CustomerAddress
	if err := c.ShouldBindJSON(&updatedAddress); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	// Update the address details
	existingAddress.Email = updatedAddress.Email
	existingAddress.Office = updatedAddress.Office
	existingAddress.Address = updatedAddress.Address
	existingAddress.City = updatedAddress.City
	existingAddress.State = updatedAddress.State
	existingAddress.PostalCode = updatedAddress.PostalCode
	existingAddress.PhoneNumber = updatedAddress.PhoneNumber
	existingAddress.Latitude = updatedAddress.Latitude
	existingAddress.Longitude = updatedAddress.Longitude

	// Save the updated address to the database
