package handlers

import (
	"bytes"
	"context"
	"fmt"
	"html/template"
	"log"
	"os"
	"strconv"
	"time"

	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"core-backend/m/v2/services"
	"core-backend/m/v2/templates"

	"gopkg.in/gomail.v2"
)

func PendingTask(firebaseService *services.FirebaseService) {
	log.Println("[CronJob] Starting PendingTask check...")

	now := time.Now()
	today_start := time.Date(now.Year(), now.Month(), now.Day(), 0, 0, 0, 0, now.Location())
	yesterday_start := today_start.AddDate(0, 0, -1)
	tomorrow_start := today_start.AddDate(0, 0, 1)

	var allTasks []models.Task
	err := db.DB.Preload("Assignee").
		Where("due_date >= ? AND due_date < ? AND status IN ?", yesterday_start, tomorrow_start, []int{0, 1}).
		Find(&allTasks).Error

	if err != nil {
		log.Printf("[CronJob][DB] Error fetching tasks: %v", err)
		return
	}
	if len(allTasks) == 0 {
		log.Println("[CronJob] No tasks due today or yesterday were found.")
		return
	}

	tasksByUser := make(map[uint][]models.Task)
	for _, task := range allTasks {
		if task.Assignee != nil {
			tasksByUser[task.Assignee.ID] = append(tasksByUser[task.Assignee.ID], task)
		}
	}

	pendingTaskEmailTemplate, err := template.New("pending_task").Parse(templates.PendingTaskNotification)
	if err != nil {
		log.Printf("[CronJob][Template] Unable to parse email template: %v", err)
		return
	}

	for userId, userTasks := range tasksByUser {
		assignee := userTasks[0].Assignee

		dueTodayCount := 0
		dueYesterdayCount := 0
		for _, task := range userTasks {
			if task.DueDate.Before(today_start) {
				dueYesterdayCount++
			} else {
				dueTodayCount++
			}
		}

		var notificationTitle, notificationBody, emailSubject, reminderMessage string

		if dueTodayCount > 0 {
			notificationTitle = "Task Reminder!"
			notificationBody = fmt.Sprintf("You have %d task(s) due today.", dueTodayCount)
			emailSubject = "You have tasks due today!"
			reminderMessage = notificationBody
		} else if dueYesterdayCount > 0 {
			notificationTitle = "Overdue Task Alert!"
			notificationBody = fmt.Sprintf("%d task(s) from yesterday are now overdue.", dueYesterdayCount)
			emailSubject = "You have overdue tasks!"
			reminderMessage = notificationBody
		} else {
			continue
		}

		if err := firebaseService.SendNotificationToUser(context.Background(), userId, notificationTitle, notificationBody); err != nil {
			log.Printf("[CronJob][FCM] Error sending push notification to user %d: %v", userId, err)
		} else {
			log.Printf("[CronJob][FCM] Consolidated push notification sent to user: %d", userId)
		}

		var emailBody bytes.Buffer
		templateData := struct {
			AssigneeName    string
			ReminderMessage string
		}{
			AssigneeName:    assignee.FirstName,
			ReminderMessage: reminderMessage,
		}

		if err := pendingTaskEmailTemplate.Execute(&emailBody, templateData); err != nil {
			log.Printf("[CronJob][Template] Error executing template for user %d: %v", userId, err)
			continue
		}

		m := gomail.NewMessage()
		m.SetAddressHeader("From", os.Getenv("FROM"), "NoReply - DST Hub")
		m.SetHeader("To", assignee.Email)
		m.SetHeader("Subject", emailSubject)
		m.SetBody("text/html", emailBody.String())

		port, _ := strconv.Atoi(os.Getenv("MAIL_PORT"))
		dialer := gomail.NewDialer(os.Getenv("MAIL_HOST"), port, os.Getenv("MAIL_FROM"), os.Getenv("MAIL_PASSWORD"))

		if err := dialer.DialAndSend(m); err != nil {
			log.Printf("[CronJob][Mail] Error sending consolidated email to %s: %v", assignee.Email, err)
		} else {
			log.Printf("[CronJob][Mail] Consolidated email sent successfully to: %s", assignee.Email)
		}
	}

	log.Println("[CronJob] Finished processing PendingTask.")
}

