	c.Writer.Header().Set("Connection", "keep-alive")
	c.Writer.Flush()

	rows, err := db.DB.Model(&models.SteelProduct{}).Where("organisation_id = ?", orgID).Rows()
	if err != nil {
		c.SSEvent("error", gin.H{"error": err.Error()})
		return
	}
	defer rows.Close()
	for rows.Next() {
		var product models.SteelProduct
		db.DB.ScanRows(rows, &product)
		c.SSEvent("product", product)
		c.Writer.Flush()
	}
	c.SSEvent("done", "streaming completed")
}

