func GetSteelProductsWithQuantity(c *gin.Context) {
	orgIDStr := c.Param("organisation_id")
	orgID64, err := strconv.ParseUint(orgIDStr, 10, 64)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid organisation_id"})
		return
	}
	orgID := uint(orgID64)

	var products []models.SteelProduct
	if err := db.DB.Preload("Category").Preload("Grade").Preload("Finish").
		Where("organisation_id = ?", orgID).
		Find(&products).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	type respItem struct {
		Product  models.SteelProduct `json:"product"`
		Quantity int                 `json:"quantity"`
		Blocked  int                 `json:"blocked"`
		Price    uint                `json:"price"`
	}

	// numeric mapping used in CreateSteelProductLedger above (keep in sync)
	const (
		TxPurchase  = 1
		TxSale      = 2
		TxReturn    = 3
		TxBlocked   = 4
		TxUnblocked = 5
	)

	var result []respItem
	for _, p := range products {
		var incoming int64
		var outgoing int64
		var blocked int64

		// incoming: purchases, returns, unblocked
		db.DB.Model(&models.SteelProductLedger{}).
			Where("steel_product_id = ? AND organisation_id = ? AND (status IN ? OR transaction_type IN ?)",
				p.ID, orgID, []string{"Purchased", "Returned", "Unblocked"}, []uint{TxPurchase, TxReturn, TxUnblocked}).
			Select("COALESCE(SUM(quantity),0)").Row().Scan(&incoming)

		// outgoing: sold, damaged (status 'Sold' or 'Damaged' OR transaction_type for sale)
		db.DB.Model(&models.SteelProductLedger{}).
			Where("steel_product_id = ? AND organisation_id = ? AND (status IN ? OR transaction_type IN ?)",
				p.ID, orgID, []string{"Sold", "Damaged"}, []uint{TxSale}).
			Select("COALESCE(SUM(quantity),0)").Row().Scan(&outgoing)

		// blocked
		db.DB.Model(&models.SteelProductLedger{}).
			Where("steel_product_id = ? AND organisation_id = ? AND (status = ? OR transaction_type = ?)",
				p.ID, orgID, "Blocked", TxBlocked).
			Select("COALESCE(SUM(quantity),0)").Row().Scan(&blocked)

		available := incoming - outgoing - blocked
		if available < 0 {
			available = 0
		}

		var price uint
		// latest price from ledger for this product/org
		_ = db.DB.Model(&models.SteelProductLedger{}).
			Where("steel_product_id = ? AND organisation_id = ?", p.ID, orgID).
			Order("created_at desc").
			Limit(1).
			Select("price").Row().Scan(&price)

		result = append(result, respItem{
			Product:  p,
			Quantity: int(available),
			Blocked:  int(blocked),
			Price:    price,
		})
	}

	c.JSON(http.StatusOK, gin.H{"data": result})
}

