package handlers

import (
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"fmt"
	"io"
	"log"
	"net/http"
	"strconv"
	"time"

	"github.com/gin-gonic/gin"
	"gorm.io/gorm"
)

func GetOrgSettingsData(c *gin.Context) {

	orgID := c.Param("orgId")
	userID, _ := strconv.ParseInt(c.Param("userId"), 10, 64)
	userType, _ := strconv.ParseInt(c.Param("type"), 10, 64)

	log.Default().Println("Fetching organization settings data", orgID, userID, userType)
	responseData := gin.H{}
	var errors []string

	var departments []models.Department
	if err := db.DB.Where("organisation_id = ?", orgID).Preload("Members.User").Find(&departments).Error; err != nil {
		errors = append(errors, fmt.Sprintf("Error fetching departments: %s", err.Error()))
	} else {
		responseData["departments"] = departments
	}

	var leaves []models.Leave

	if err := db.DB.Where("organisation_id = ?", orgID).Find(&leaves).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}
	responseData["leaves"] = leaves

	var org models.Organisation
	if err := db.DB.Where("id = ?", orgID).First(&org).Error; err != nil {
		if err == gorm.ErrRecordNotFound {
			errors = append(errors, "Organization not found for days/cutoff")
		} else {
			errors = append(errors, fmt.Sprintf("Error fetching organization data for days/cutoff: %s", err.Error()))
		}
	} else {
		responseData["days"] = org.Days
		responseData["organisation_code"] = org.OrganisationCode // Add organization name
		responseData["has_logo"] = len(org.Logo) > 0             // Add logo existence flag
		responseData["weekly_offs"] = org.WeeklyOffs             // Add weekly offs

		if org.Cutoff.IsZero() {
			responseData["cutoff"] = ""
		} else {
			responseData["cutoff"] = org.Cutoff.Format("15:04")
		}
	}

	var orgTime models.OrganisationTime
	// Send Default values of time
	result := db.DB.Where("organisation_id = ?", orgID).Order("created_at DESC").First(&orgTime)

	if result.Error != nil && result.Error != gorm.ErrRecordNotFound {
		errors = append(errors, fmt.Sprintf("Error fetching organisation time data: %s", result.Error.Error()))
	}

	// Add holidays to response
	var holidays []models.OrganisationHoliday
	if err := db.DB.Where("organisation_id = ?", orgID).Order("date ASC").Find(&holidays).Error; err != nil {
		errors = append(errors, fmt.Sprintf("Error fetching holidays: %s", err.Error()))
	} else {
		responseData["holidays"] = holidays
	}

	responseData["organisation_time"] = orgTime

	if len(errors) > 0 {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error":        "Failed to load all settings data.",
			"details":      errors,
			"partial_data": responseData,
		})
		return
	}

	c.JSON(http.StatusOK, responseData)
}

func DeleteLeaves(c *gin.Context) {
	userType, ok := c.Get("type")
	if !ok {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "User Type Invalid"})
		return
	}

	if userType.(float64) <= 100 {
		c.JSON(http.StatusUnauthorized, gin.H{"error": "Unauthorized"})
		return
	}

	leaveId := c.Param("leave_id")
	err := db.DB.Where("id = ?", leaveId).Delete(&models.Leave{}).Error

	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "Record Deleted"})
}

// GetOrgHolidays retrieves all holidays for an organization
func GetOrgHolidays(c *gin.Context) {
	orgID := c.Param("orgID")

	var holidays []models.OrganisationHoliday
	if err := db.DB.Where("organisation_id = ?", orgID).Order("date ASC").Find(&holidays).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to fetch holidays"})
		return
	}

	c.JSON(http.StatusOK, gin.H{"holidays": holidays})
}

// AddOrgHoliday adds a new holiday for an organization
func AddOrgHoliday(c *gin.Context) {
	userType, ok := c.Get("type")
	if !ok {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "User Type Invalid"})
		return
	}

	// Only owners and admins can add holidays
	if userType.(float64) < 200 {
		c.JSON(http.StatusUnauthorized, gin.H{"error": "Unauthorized"})
		return
	}

	var holiday models.OrganisationHoliday
	if err := c.ShouldBindJSON(&holiday); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	// Normalize to date-

	// Validate that the date is not in the past (optional)
	today := time.Now()
	if holiday.Date.Before(today) {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Cannot add holidays in the past"})
		return
	}

	// Check for duplicate holidays on the same date for the same organization (compare by date string)
	var existingHoliday models.OrganisationHoliday
	if err := db.DB.Where("organisation_id = ? AND DATE(date) = ?", holiday.OrganisationId, holiday.Date.Format("2006-01-02")).First(&existingHoliday).Error; err == nil {
		c.JSON(http.StatusConflict, gin.H{"error": "A holiday already exists on this date"})
		return
	}

	if err := db.DB.Create(&holiday).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to create holiday"})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"message": "Holiday added successfully",
		"holiday": holiday,
	})
}

// UpdateOrgHoliday updates an existing holiday
func UpdateOrgHoliday(c *gin.Context) {
	userType, ok := c.Get("type")
	if !ok {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "User Type Invalid"})
		return
	}

	if userType.(float64) < 200 {
		c.JSON(http.StatusUnauthorized, gin.H{"error": "Unauthorized"})
		return
	}

	holidayID := c.Param("holiday_id")

	var holiday models.OrganisationHoliday
	if err := db.DB.First(&holiday, holidayID).Error; err != nil {
		if err == gorm.ErrRecordNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "Holiday not found"})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	var updateData models.OrganisationHoliday
	if err := c.ShouldBindJSON(&updateData); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	// Optional: check duplicate date for same org (exclude current holiday ID)
	var dup models.OrganisationHoliday
	if err := db.DB.Where("organisation_id = ? AND DATE(date) = ? AND id != ?", holiday.OrganisationId, updateData.Date.Format("2006-01-02"), holiday.ID).First(&dup).Error; err == nil {
		c.JSON(http.StatusConflict, gin.H{"error": "Another holiday already exists on this date"})
		return
	}

	// Update fields
	holiday.Date = updateData.Date
	holiday.Name = updateData.Name
	holiday.Description = updateData.Description
	holiday.IsRecurring = updateData.IsRecurring

	if err := db.DB.Save(&holiday).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to update holiday"})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"message": "Holiday updated successfully",
		"holiday": holiday,
	})
}

// DeleteOrgHoliday deletes a holiday
func DeleteOrgHoliday(c *gin.Context) {
	userType, ok := c.Get("type")
	if !ok {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "User Type Invalid"})
		return
	}

	if userType.(float64) < 200 {
		c.JSON(http.StatusUnauthorized, gin.H{"error": "Unauthorized"})
		return
	}

	holidayID := c.Param("holiday_id")

	var holiday models.OrganisationHoliday
	if err := db.DB.First(&holiday, holidayID).Error; err != nil {
		if err == gorm.ErrRecordNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "Holiday not found"})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	if err := db.DB.Delete(&holiday).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to delete holiday"})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "Holiday deleted successfully"})
}

// UploadOrgLogo uploads or updates organization logo
func UploadOrgLogo(c *gin.Context) {
	userType, ok := c.Get("type")
	if !ok {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "User Type Invalid"})
		return
	}

	if userType.(float64) < 200 {
		c.JSON(http.StatusUnauthorized, gin.H{"error": "Unauthorized"})
		return
	}

	orgID := c.Param("orgID") // Changed from "org_id" to "orgID"

	var org models.Organisation
	if err := db.DB.First(&org, orgID).Error; err != nil {
		if err == gorm.ErrRecordNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "Organization not found"})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Retrieve the uploaded logo file from the form
	file, header, err := c.Request.FormFile("logo")
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Logo file is required"})
		return
	}
	defer file.Close()

	// Validate file type (only images allowed)
	allowedTypes := map[string]bool{
		"image/jpeg": true,
		"image/jpg":  true,
		"image/png":  true,
	}

	contentType := header.Header.Get("Content-Type")
	if !allowedTypes[contentType] {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Only image files (JPEG, PNG, GIF, WebP) are allowed"})
		return
	}

	// Validate file size (max 5MB)
	const maxFileSize = 5 * 1024 * 1024 // 5MB
	if header.Size > maxFileSize {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Logo file size must not exceed 5MB"})
		return
	}

	// Read the logo data
	logoData, err := io.ReadAll(file)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to read logo file"})
		return
	}

	// Update the logo in the organization
	org.Logo = logoData

	// Save the updated organization to the database
	if err := db.DB.Save(&org).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to update organization logo"})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"message": "Organization logo updated successfully",
		"org_id":  org.ID,
	})
}

// GetOrgLogo retrieves the organization logo
func GetOrgLogo(c *gin.Context) {
	orgID := c.Param("orgID") // Changed from "org_id" to "orgID"

	var org models.Organisation
	if err := db.DB.First(&org, orgID).Error; err != nil {
		if err == gorm.ErrRecordNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "Organization not found"})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	if len(org.Logo) == 0 {
		c.JSON(http.StatusNotFound, gin.H{"error": "No logo found for this organization"})
		return
	}

	contentType := http.DetectContentType(org.Logo)
	c.Data(http.StatusOK, contentType, org.Logo)
}

// UpdateOrgName updates the organization name
func UpdateOrgName(c *gin.Context) {
	userType, ok := c.Get("type")
	if !ok {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "User Type Invalid"})
		return
	}

	if userType.(float64) < 200 {
		c.JSON(http.StatusUnauthorized, gin.H{"error": "Unauthorized"})
		return
	}

	orgID := c.Param("orgID") // Changed from "org_id" to "orgID"

	var requestBody struct {
		OrganisationCode string `json:"organisation_code" binding:"required"`
	}

	if err := c.ShouldBindJSON(&requestBody); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Organization name is required"})
		return
	}

	var org models.Organisation
	if err := db.DB.First(&org, orgID).Error; err != nil {
		if err == gorm.ErrRecordNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "Organization not found"})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	var existingOrg models.Organisation
	if err := db.DB.Where("organisation_code = ? AND id != ?", requestBody.OrganisationCode, orgID).First(&existingOrg).Error; err == nil {
		c.JSON(http.StatusConflict, gin.H{"error": "Organization name already exists"})
		return
	}

	org.OrganisationCode = requestBody.OrganisationCode

	if err := db.DB.Save(&org).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to update organization name"})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"message":           "Organization name updated successfully",
		"organisation_code": org.OrganisationCode,
	})
}

// RemoveOrgLogo removes the organization logo
func RemoveOrgLogo(c *gin.Context) {
	userType, ok := c.Get("type")
	if !ok {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "User Type Invalid"})
		return
	}

	if userType.(float64) < 200 {
		c.JSON(http.StatusUnauthorized, gin.H{"error": "Unauthorized"})
		return
	}

	orgID := c.Param("orgID") // Changed from "org_id" to "orgID"

	var org models.Organisation
	if err := db.DB.First(&org, orgID).Error; err != nil {
		if err == gorm.ErrRecordNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "Organization not found"})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	org.Logo = nil

	if err := db.DB.Save(&org).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to remove organization logo"})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "Organization logo removed successfully"})
}

