package cache

import (
	"context"
	"core-backend/m/v2/db"
	"encoding/json"
	"fmt"
	"log"
	"time"

	"github.com/redis/go-redis/v9"
)

type CacheHelper struct {
	client *redis.Client
	ctx    context.Context
}

func NewCacheHelper() *CacheHelper {
	return &CacheHelper{
		client: db.RedisClient,
		ctx:    context.Background(),
	}
}

type FetchFunction func() (interface{}, error)

// GetOrSetJSON retrieves data from cache or fetches from DB and caches it
// Returns the data and a boolean indicating if it was found in cache
func (c *CacheHelper) GetOrSetJSON(key string, ttl time.Duration, fetchFunc FetchFunction) (interface{}, bool, error) {
	// Try to get from Redis first
	cached, err := c.client.Get(c.ctx, key).Result()
	if err == nil {

		var result interface{}
		if err := json.Unmarshal([]byte(cached), &result); err != nil {
			log.Printf("Error unmarshaling cached data for key %s: %v", key, err)

		} else {
			log.Printf("Cache HIT for key: %s", key)
			return result, true, nil
		}
	} else if err != redis.Nil {
		// Redis error (not key not found)
		log.Printf("Redis error for key %s: %v", key, err)
		// Continue to fetch from DB in case of Redis errors
	}

	// Cache miss or error - fetch from database
	log.Printf("Cache MISS for key: %s", key)
	data, err := fetchFunc()
	if err != nil {
		return nil, false, fmt.Errorf("failed to fetch data: %w", err)
	}

	// Store in cache
	if err := c.setJSON(key, data, ttl); err != nil {
		log.Printf("Failed to cache data for key %s: %v", key, err)

	}

	return data, false, nil
}

// setJSON stores data in Redis as JSON with TTL
func (c *CacheHelper) setJSON(key string, data interface{}, ttl time.Duration) error {
	jsonData, err := json.Marshal(data)
	if err != nil {
		return fmt.Errorf("failed to marshal data: %w", err)
	}

	return c.client.Set(c.ctx, key, jsonData, ttl).Err()
}

// DeleteKeys removes one or more keys from Redis
func (c *CacheHelper) DeleteKeys(keys ...string) error {
	if len(keys) == 0 {
		return nil
	}

	deleted, err := c.client.Del(c.ctx, keys...).Result()
	if err != nil {
		return fmt.Errorf("failed to delete keys: %w", err)
	}

	log.Printf("Deleted %d cache keys: %v", deleted, keys)
	return nil
}

// DeletePattern deletes all keys matching a pattern
func (c *CacheHelper) DeletePattern(pattern string) error {
	keys, err := c.client.Keys(c.ctx, pattern).Result()
	if err != nil {
		return fmt.Errorf("failed to get keys for pattern %s: %w", pattern, err)
	}

	if len(keys) == 0 {
		log.Printf("No keys found for pattern: %s", pattern)
		return nil
	}

	return c.DeleteKeys(keys...)
}

// Set stores data in Redis with TTL
func (c *CacheHelper) Set(key string, value interface{}, ttl time.Duration) error {
	return c.client.Set(c.ctx, key, value, ttl).Err()
}

// Get retrieves data from Redis
func (c *CacheHelper) Get(key string) (string, error) {
	return c.client.Get(c.ctx, key).Result()
}

// Exists checks if a key exists in Redis
func (c *CacheHelper) Exists(keys ...string) (int64, error) {
	return c.client.Exists(c.ctx, keys...).Result()
}

// Expire sets TTL for an existing key
func (c *CacheHelper) Expire(key string, ttl time.Duration) error {
	return c.client.Expire(c.ctx, key, ttl).Err()
}

