    required this.startTime,
    required this.onDateChanged,
    required this.onTimeChanged,
    super.key,
    this.dateLabel,
    this.timeLabel,
    this.spacing = 8.0,
    this.validator,
  });


  final DateTime? startDate;


  final TimeOfDay? startTime;


