package handlers

import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"time"

	"core-backend/m/v2/db"
	"core-backend/m/v2/models/tally_models"

	"github.com/gin-gonic/gin"
)

// SyncPayload matches the C# payload structure
type SyncPayload struct {
	TableName    string       `json:"tableName"`
	Records      []SyncRecord `json:"records"`
	Timestamp    time.Time    `json:"timestamp"`
	SourceID     string       `json:"sourceIdentifier"`
	TotalRecords int          `json:"totalRecords"`
	ChunkNumber  int          `json:"chunkNumber"`
	TotalChunks  int          `json:"totalChunks"`
	SyncMode     string       `json:"syncMode"`
	CompanyName  string       `json:"companyName"`
}

type SyncRecord struct {
	ID           string                 `json:"id"`
	Operation    string                 `json:"operation"` // INSERT, UPDATE, DELETE
	Data         map[string]interface{} `json:"data"`
	Hash         string                 `json:"hash"`
	ModifiedDate *time.Time             `json:"modifiedDate"`
}

// HandleTallySync is the main endpoint for receiving Tally data
func HandleTallySync(c *gin.Context) {
	var payload SyncPayload

	if err := c.ShouldBindJSON(&payload); err != nil {
		log.Printf("Error parsing sync payload: %v", err)
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid payload", "details": err.Error()})
		return
	}

	log.Printf("Received Tally sync: Table=%s, Company=%s, Records=%d, Chunk=%d/%d, Mode=%s",
		payload.TableName, payload.CompanyName, len(payload.Records),
		payload.ChunkNumber, payload.TotalChunks, payload.SyncMode)

	// Get organisation ID from company name (or create if doesn't exist)
	OrgID, err := getOrCreateOrganisation(payload.CompanyName)
	if err != nil {
		log.Printf("Error getting organisation: %v", err)
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to process organisation"})
		return
	}

	// Process records based on table type
	processedCount := 0
	errorCount := 0

	for _, record := range payload.Records {
		if err := processSyncRecord(OrgID, payload.TableName, record); err != nil {
			log.Printf("Error processing record %s: %v", record.ID, err)
			errorCount++
		} else {
			processedCount++
		}
	}

	log.Printf("Sync completed: %d processed, %d errors", processedCount, errorCount)

	c.JSON(http.StatusOK, gin.H{
		"success":        true,
		"processed":      processedCount,
		"errors":         errorCount,
		"tableName":      payload.TableName,
		"chunkNumber":    payload.ChunkNumber,
		"totalChunks":    payload.TotalChunks,
		"organisationId": OrgID,
	})
}

// getOrCreateOrganisation finds or creates an organisation by company name
func getOrCreateOrganisation(companyName string) (uint, error) {
	// For now, return a default org ID or implement your org lookup logic
	// You can extend this to create/lookup organisations in your system

	// Example: Return org ID 1 for testing
	// In production, you'd query your organisations table
	return 1, nil
}

// processSyncRecord routes the record to the appropriate table handler
func processSyncRecord(OrgID uint, tableName string, record SyncRecord) error {
	switch tableName {
	case "Ledgers":
		return processLedger(OrgID, record)
	case "Groups":
		return processGroup(OrgID, record)
	case "Vouchers":
		return processVoucher(OrgID, record)
	case "StockItems":
		return processStockItem(OrgID, record)
	case "StockGroups":
		return processStockGroup(OrgID, record)
	case "Units":
		return processUnit(OrgID, record)
	case "CostCentres":
		return processCostCentre(OrgID, record)
	case "Godowns":
		return processGodown(OrgID, record)
	case "VoucherTypes":
		return processVoucherType(OrgID, record)
	default:
		return fmt.Errorf("unsupported table: %s", tableName)
	}
}

// processLedger handles ledger records
func processLedger(OrgID uint, record SyncRecord) error {
	var ledger tally_models.MstLedger

	// Convert map to struct
	jsonData, _ := json.Marshal(record.Data)
	if err := json.Unmarshal(jsonData, &ledger); err != nil {
		return fmt.Errorf("failed to parse ledger data: %v", err)
	}

	// Set GUID from record ID
	if ledger.GUID == "" {
		ledger.GUID = record.ID
	}

	switch record.Operation {
	case "INSERT", "UPDATE":
		result := db.DB.Save(&ledger)
		return result.Error
	case "DELETE":
		result := db.DB.Where("guid = ?", record.ID).Delete(&tally_models.MstLedger{})
		return result.Error
	default:
		return fmt.Errorf("unknown operation: %s", record.Operation)
	}
}

// processGroup handles group records
func processGroup(OrgID uint, record SyncRecord) error {
	var group tally_models.MstGroup

	jsonData, _ := json.Marshal(record.Data)
	if err := json.Unmarshal(jsonData, &group); err != nil {
