	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to get organisation"})
		return
	}

	// Get record counts
	var ledgerCount, voucherCount, stockItemCount int64
	db.DB.Model(&tally_models.MstLedger{}).Count(&ledgerCount)
	db.DB.Model(&tally_models.TrnVoucher{}).Where("organisation_id = ?", OrgID).Count(&voucherCount)
	db.DB.Model(&tally_models.MstStockItem{}).Count(&stockItemCount)

	c.JSON(http.StatusOK, gin.H{
