package models

import (
	"database/sql/driver"
	"encoding/json"
	"fmt"
	"log"
	"strconv"
	"strings"
	"time"

	"gorm.io/gorm"
)

type WorkingDays uint

const (
	Weekdays = 5
	Sat      = 6
	All      = 7
)

type ISTTime struct {
	time.Time
}

func (t *ISTTime) UnmarshalJSON(data []byte) error {
	// Remove quotes from JSON string
	str := strings.Trim(string(data), `"`)
	if str == "null" || str == "" {
		t.Time = time.Time{}
		return nil
	}

	// Try to parse as RFC3339 (with timezone)
	parsed, err := time.Parse(time.RFC3339, str)
	if err == nil {
		// If it has timezone, convert to IST
		ist, _ := time.LoadLocation("Asia/Kolkata")
		t.Time = parsed.In(ist)
		return nil
	}

	parsed, err = time.Parse(time.RFC3339Nano, str)
	if err == nil {
		ist, _ := time.LoadLocation("Asia/Kolkata")
		t.Time = parsed.In(ist)
		return nil
	}
	layouts := []string{
		"2006-01-02T15:04:05.999999999",
		"2006-01-02T15:04:05.999999",
		"2006-01-02T15:04:05.999",
		"2006-01-02T15:04:05",
	}

	ist, _ := time.LoadLocation("Asia/Kolkata")
	for _, layout := range layouts {
		parsed, err = time.ParseInLocation(layout, str, ist)
		if err == nil {
			t.Time = parsed
			return nil
		}
	}

	if len(str) > 19 && str[19] == '.' {
		baseStr := str[:19]
		rest := str[19:]
		var fractionalPart string
		for _, r := range rest {
			if r >= '0' && r <= '9' {
				fractionalPart += string(r)
			} else {
				break
			}
		}

		// Try parsing with the fractional part
		if len(fractionalPart) > 0 {
			// Pad or truncate to 9 digits (nanoseconds)
			for len(fractionalPart) < 9 {
				fractionalPart += "0"
			}
			if len(fractionalPart) > 9 {
				fractionalPart = fractionalPart[:9]
			}
			fullStr := baseStr + "." + fractionalPart
			parsed, err = time.ParseInLocation("2006-01-02T15:04:05.999999999", fullStr, ist)
			if err == nil {
				t.Time = parsed
				return nil
			}
		}
	}

	// If all parsing attempts fail, return the last error
	return err
}

// MarshalJSON implements json.Marshaler interface
func (t ISTTime) MarshalJSON() ([]byte, error) {
	if t.Time.IsZero() {
		return []byte("null"), nil
	}
	// Return in RFC3339 format with IST timezone
	ist, _ := time.LoadLocation("Asia/Kolkata")
	return []byte(`"` + t.Time.In(ist).Format(time.RFC3339) + `"`), nil
}

func (t ISTTime) Value() (driver.Value, error) {
	if t.Time.IsZero() {
		return nil, nil
	}
	return t.Time, nil
}

func (t *ISTTime) Scan(value interface{}) error {
	if value == nil {
		t.Time = time.Time{}
		return nil
	}
	switch v := value.(type) {
	case time.Time:
		// Convert to IST when reading from database
		ist, _ := time.LoadLocation("Asia/Kolkata")
		t.Time = v.In(ist)
		return nil
	case []byte:
		return t.UnmarshalJSON(v)
	case string:
		return t.UnmarshalJSON([]byte(v))
	default:
		return nil
	}
}

type Leave struct {
	gorm.Model
	Title          string       `json:"title"`
	OrganisationId uint         `json:"org_id"`
	Organisation   Organisation `gorm:"foreignKey:OrganisationId"`
}

type leaveDay int

const (
	half = iota
	full
)

type leaveType int

const (
	Sick = iota
	Casual
	Annual
	NoPay
)

type LeaveStatus int

const (
	Pending = iota
	Approved
	Rejected
)

func (l leaveType) String() string {
	switch l {
	case Sick:
		return "Sick"
	case Casual:
		return "Casual"
	case Annual:
		return "Annual"
	case NoPay:
		return "NoPay"
	default:
		return "Unknown"
	}
}

func (l LeaveStatus) String() string {
	switch l {
	case Pending:
		return "Pending"
	case Approved:
		return "Aprroved"
	case Rejected:
		return "Rejected"
	default:
		return "Unknown"
	}
}

