const TimeOnlyFormat = "15:04:05"

type Time time.Time

func (t Time) MarshalJSON() ([]byte, error) {
	tt := time.Time(t)

	if tt.IsZero() {
		return json.Marshal(nil) // Return null for zero time
	}

	// Format the time as a simple HH:MM:SS string
	return json.Marshal(tt.Format(TimeOnlyFormat))
}

// UnmarshalJSON parses a time-only string from JSON into the Time type.
func (t *Time) UnmarshalJSON(data []byte) error {
	s := strings.Trim(string(data), "\"")

	if s == "" || s == "null" {
		*t = Time(time.Time{})
		return nil
	}

	var parsedTime time.Time
	var err error

	// Try parsing using the defined time-only format (assumes time is local/no timezone info)
	parsedTime, err = time.Parse(TimeOnlyFormat, s)
	if err == nil {
		*t = Time(parsedTime)
		return nil
	}

	// Fallback: Check if the incoming string is a full RFC3339 timestamp (e.g., from another system)
	parsedTime, err = time.Parse(time.RFC3339, s)
	if err == nil {
		*t = Time(parsedTime)
		return nil
	}

	return fmt.Errorf("error unmarshalling JSON: failed to parse time string %q using expected formats", s)
}

// --- GORM/SQL Interfaces ---

// Value implements the driver.Valuer interface.
// It converts the Go Time type to a database value (string format for TIME column).
func (t Time) Value() (driver.Value, error) {
	tt := time.Time(t)

	if tt.IsZero() {
		return nil, nil // Return NULL for zero value, allowing DB default to apply if needed
	}

	// Convert the time to a string suitable for the SQL TIME column
	return tt.Format(TimeOnlyFormat), nil
}

// Scan implements the sql.Scanner interface.
// It converts a database value (which might be time.Time or bytes) back into the Time type.
func (t *Time) Scan(value any) error {
	if value == nil {
		*t = Time(time.Time{})
		return nil
	}

	// Case 1: Database driver returns a standard time.Time (most common for modern drivers)
	if tt, ok := value.(time.Time); ok {
		*t = Time(tt)
		return nil
	}

	// Case 2: Database driver returns a byte slice (or string) containing the time string
	if b, ok := value.([]byte); ok {
		s := string(b)
		// Try parsing the string using the expected format
		tt, err := time.Parse(TimeOnlyFormat, s)
		if err != nil {
			return fmt.Errorf("Time Scan failed to parse time string %q: %w", s, err)
		}
		*t = Time(tt)
		return nil
	}

	return fmt.Errorf("cannot scan %T into Time type", value)
}

