func MigrateExistingOrganisations(db *gorm.DB) {
	log.Println("Starting migration: Creating default OrganisationTime entries for existing organisations...")

	// 1. Fetch all existing Organisation IDs and AdminRegister IDs
	//
	var existingOrganisations []Organisation
	checkInString := "09:00:00"
	checkOutString := "17:00:00"
	// Convert to your custom pointer type
	// Select only the necessary columns for efficiency
	if err := db.Select("id", "admin_register").Find(&existingOrganisations).Error; err != nil {
		log.Fatalf("Failed to retrieve existing organisations: %v", err)
		return
	}

	if len(existingOrganisations) == 0 {
		log.Println("No existing organisations found. Migration complete.")
		return
	}

	// 2. Iterate and create the corresponding OrganisationTime entry
	for _, org := range existingOrganisations {
		// Check if an OrganisationTime entry already exists (to avoid duplicates)
		var count int64
		db.Model(&OrganisationTime{}).Where("organisation_id = ?", org.ID).Count(&count)

		if count > 0 {
			// Skip if entry already exists
			log.Printf("OrganisationTime already exists for Org ID: %d. Skipping.", org.ID)
			continue
		}

		// Create the new entry with default values
		newOrgTime := OrganisationTime{
			OrganisationId: org.ID,
			ChangedBy:      org.AdminRegister,
			CheckIn:        &checkInString, // Pass the address of the custom time value
			CheckOut:       &checkOutString,
		}
		log.Println("Creating OrganisationTime for Org ID:", newOrgTime)
		if err := db.Create(&newOrgTime).Error; err != nil {
			log.Printf("Failed to create OrganisationTime for Org ID %d: %v", org.ID, err)
			// Continue to the next organization rather than failing the whole migration
		} else {
			log.Printf("Successfully created OrganisationTime for Org ID: %d", org.ID)
		}
	}

	log.Println("Migration complete: All existing organisations processed.")
}

