func (u *UserID) UnmarshalJSON(data []byte) error {
	// First try to unmarshal as number
	var num uint64
	if err := json.Unmarshal(data, &num); err == nil {
		*u = UserID(num)
		return nil
	}

	// If that fails, try to unmarshal as string
	var str string
	if err := json.Unmarshal(data, &str); err != nil {
		return fmt.Errorf("user_id must be a number or string, got: %s", string(data))
	}

	// Convert string to uint64
	parsed, err := strconv.ParseUint(str, 10, 32)
	if err != nil {
		return fmt.Errorf("invalid user_id format: %v", err)
	}

	*u = UserID(parsed)
	return nil
}

type LocationTime time.Time

const CustomTimeFormat = "2006-01-02T15:04:05.999999"

func (l LocationTime) MarshalJSON() ([]byte, error) {

	t := time.Time(l)

	if t.IsZero() {
		return json.Marshal("")
	}

	return json.Marshal(t.In(time.UTC).Format(time.RFC3339Nano))
}
func (l *LocationTime) UnmarshalJSON(data []byte) error {
	s := strings.Trim(string(data), "\"")
	if s == "" {
		*l = LocationTime(time.Time{})
		return nil
	}

	var t time.Time
	var err error

	// 1. Try parsing with RFC3339Nano (standard format with Z/timezone)
	t, err = time.Parse(time.RFC3339Nano, s)
	if err == nil {
		*l = LocationTime(t)
		return nil
	}

	t, err = time.ParseInLocation(CustomTimeFormat, s, time.Local)
	if err == nil {
		*l = LocationTime(t)
		return nil
	}

	// 3. Fallback to trying RFC3339 which is less precise
	t, err = time.Parse(time.RFC3339, s)
	if err == nil {
		*l = LocationTime(t)
		return nil
	}

	return fmt.Errorf("error unmarshalling JSON: failed to parse time string %q", s)
}
func (l LocationTime) Value() (driver.Value, error) {
	// Convert the custom type back to time.Time
	t := time.Time(l)

	if t.IsZero() {
		return nil, nil
	}

	return t.In(time.UTC), nil
}
func (l *LocationTime) Scan(value any) error {
	if value == nil {
		*l = LocationTime(time.Time{})
		return nil
	}
	if t, ok := value.(time.Time); ok {
		*l = LocationTime(t)
		return nil
	}

	return fmt.Errorf("cannot scan %T into LocationTime", value)
}

