type DateOnly struct {
	time.Time
}

func (d *DateOnly) UnmarshalJSON(b []byte) error {
	s := strings.Trim(string(b), "\"")
	t, err := time.Parse("2006-01-02", s)
	if err != nil {
		return err
	}
	d.Time = t
	return nil
}

func (d DateOnly) MarshalJSON() ([]byte, error) {
	return []byte(fmt.Sprintf("\"%s\"", d.Time.Format("2006-01-02"))), nil
}

// Value implements driver.Valuer so GORM/DB can convert DateOnly to a DB value
func (d DateOnly) Value() (driver.Value, error) {
	if d.Time.IsZero() {
		return nil, nil
	}
	// store as YYYY-MM-DD (DATE column)
	return d.Time.Format("2006-01-02"), nil
}

// Scan implements sql.Scanner so DB values can be scanned back into DateOnly
func (d *DateOnly) Scan(value any) error {
	if value == nil {
		*d = DateOnly{time.Time{}}
		return nil
	}
	switch v := value.(type) {
	case time.Time:
		d.Time = v
		return nil
	case []byte:
		s := string(v)
		t, err := time.Parse("2006-01-02", s)
		if err == nil {
			d.Time = t
			return nil
		}
		// fallback: try parse full timestamp
		t2, err2 := time.Parse(time.RFC3339, s)
		if err2 == nil {
			d.Time = t2
			return nil
		}
		return fmt.Errorf("DateOnly.Scan: cannot parse value %q", s)
	case string:
		t, err := time.Parse("2006-01-02", v)
		if err == nil {
			d.Time = t
			return nil
		}
		t2, err2 := time.Parse(time.RFC3339, v)
		if err2 == nil {
			d.Time = t2
			return nil
		}
		return fmt.Errorf("DateOnly.Scan: cannot parse value %q", v)
	default:
		return fmt.Errorf("DateOnly.Scan: unsupported type %T", value)
	}
}

type OrganisationHoliday struct {
	gorm.Model
	OrganisationId uint     `json:"organisation_id" gorm:"index"`
	Date           DateOnly `json:"date" gorm:"type:date;not null"`
	Name           string   `json:"name" gorm:"not null"`
