package handlers

import (
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"

	"github.com/gin-gonic/gin"
	"gorm.io/gorm"
)

func SaveToken(c *gin.Context) {
	var req models.FcmToken

	if err := c.BindJSON(&req); err != nil {
		c.JSON(400, gin.H{"error": "Invalid request: " + err.Error()})
		return
	}

	if req.Token == "" || req.UserID == 0 {
		c.JSON(400, gin.H{"error": "Token and UserID are required fields"})
		return
	}

	err := db.DB.Transaction(func(tx *gorm.DB) error {
		if err := tx.Where("token = ? AND user_id != ?", req.Token, req.UserID).Delete(&models.FcmToken{}).Error; err != nil {
			return err
		}

		var existingToken models.FcmToken
		err := tx.Where("user_id = ? AND type = ?", req.UserID, req.Type).First(&existingToken).Error

		if err != nil && err != gorm.ErrRecordNotFound {
			return err
		}

		if err == gorm.ErrRecordNotFound {
			if createErr := tx.Create(&req).Error; createErr != nil {
				return createErr
			}
		} else {
			if updateErr := tx.Model(&existingToken).Update("token", req.Token).Error; updateErr != nil {
				return updateErr
			}
		}

		return nil
	})

	if err != nil {
		c.JSON(500, gin.H{"error": "Failed to save token: " + err.Error()})
		return
	}

	c.JSON(200, gin.H{"status": "success", "message": "Token registered successfully"})
}

