package handlers

import (
	"bytes"
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"fmt"
	"net/http"
	"strconv"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/jung-kurt/gofpdf"
	"gorm.io/gorm"
)

// LeaveDeductionInput represents leave deduction data from client
type LeaveDeductionInput struct {
	LeaveID         uint      `json:"leave_id" binding:"required"`
	LeaveType       string    `json:"leave_type" binding:"required"`
	LeaveDate       time.Time `json:"leave_date" binding:"required"`
	DeductionAmount float64   `json:"deduction_amount" binding:"required"`
}

// CalculatePayslipRequest represents request to calculate payslip
type CalculatePayslipRequest struct {
	UserID uint `json:"user_id" binding:"required"`
	Month  int  `json:"month" binding:"required,min=1,max=12"`
	Year   int  `json:"year" binding:"required"`
}

// GeneratePayslipRequest represents request to generate payslip PDF
type GeneratePayslipRequest struct {
	UserID           uint                  `json:"user_id" binding:"required"`
	Month            int                   `json:"month" binding:"required,min=1,max=12"`
	Year             int                   `json:"year" binding:"required"`
	OrganisationID   uint                  `json:"organisation_id" binding:"required"`
	BaseSalary       float64               `json:"base_salary" binding:"required"`
	WorkingDays      int                   `json:"working_days" binding:"required"`
	LeaveDeductions  []LeaveDeductionInput `json:"leave_deductions"`
}

// LeaveDeductionResponse represents leave deduction in response
type LeaveDeductionResponse struct {
	LeaveID             uint      `json:"leave_id"`
	LeaveType           string    `json:"leave_type"`
	LeaveDate           time.Time `json:"leave_date"`
	SuggestedDeduction  float64   `json:"suggested_deduction"`
	Deduct              bool      `json:"deduct"`
}

// CalculatePayslipResponse represents the payslip calculation response
type CalculatePayslipResponse struct {
	EmployeeName    string                   `json:"employee_name"`
	EmployeeID      string                   `json:"employee_id"`
	JobTitle        string                   `json:"job_title"`
	Department      string                   `json:"department"`
	BaseSalary      float64                  `json:"base_salary"`
	WorkingDays     int                      `json:"working_days"`
	Leaves          []LeaveDeductionResponse `json:"leaves"`
	TotalDeduction  float64                  `json:"total_deduction"`
	NetPay          float64                  `json:"net_pay"`
	Exists          bool                     `json:"exists"`
	ExistingPayslip *models.Payslip          `json:"existing_payslip,omitempty"`
}

// CalculatePayslip calculates payslip data for preview
func CalculatePayslip(c *gin.Context) {
	var req CalculatePayslipRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	// Verify user has manager access
	currentUserID := c.MustGet("id").(uint)
	if !checkManagerAccess(currentUserID) {
		c.JSON(http.StatusForbidden, gin.H{"error": "Only managers and above can generate payslips"})
		return
	}

	// Check if payslip already exists
	var existingPayslip models.Payslip
	err := db.DB.Preload("LeaveDeductions").
		Where("user_id = ? AND month = ? AND year = ?", req.UserID, req.Month, req.Year).
		First(&existingPayslip).Error

	if err == nil {
		// Payslip exists, return existing data
		var user models.UserDetail
		db.DB.First(&user, req.UserID)

		var dept models.DepartmentMember
		db.DB.Preload("Department").Where("user_id = ?", req.UserID).First(&dept)

		leaves := make([]LeaveDeductionResponse, len(existingPayslip.LeaveDeductions))
		for i, ld := range existingPayslip.LeaveDeductions {
			leaves[i] = LeaveDeductionResponse{
				LeaveID:            ld.LeaveID,
				LeaveType:          ld.LeaveType,
				LeaveDate:          ld.LeaveDate,
				SuggestedDeduction: ld.DeductionAmount,
				Deduct:             true,
			}
		}

		response := CalculatePayslipResponse{
			EmployeeName:    user.FirstName + " " + user.LastName,
			EmployeeID:      user.EmployeeId,
			JobTitle:        user.JobTitle,
			Department:      dept.Department.DepartmentName,
			BaseSalary:      existingPayslip.BaseSalary,
			WorkingDays:     existingPayslip.WorkingDays,
			Leaves:          leaves,
			TotalDeduction:  existingPayslip.TotalLeaveDeduction,
			NetPay:          existingPayslip.NetPay,
			Exists:          true,
			ExistingPayslip: &existingPayslip,
		}

		c.JSON(http.StatusOK, response)
		return
	}

	// Payslip doesn't exist, calculate new
	// Get employee details
	var user models.UserDetail
	if err := db.DB.First(&user, req.UserID).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Employee not found"})
		return
	}

	// Get department
	var dept models.DepartmentMember
	db.DB.Preload("Department").Where("user_id = ?", req.UserID).First(&dept)

	// Get active salary for the month
	baseSalary, err := getActiveSalary(req.UserID, req.Month, req.Year)
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "No active salary record found for this employee"})
		return
	}

	// Get organisation for working days
	var orgUser models.OrganisationUser
	if err := db.DB.Where("user_id = ?", req.UserID).First(&orgUser).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Employee organization not found"})
		return
	}

	workingDays := calculateWorkingDays(req.Month, req.Year, orgUser.OrganisationId)

	// Get approved leaves for the month
	leaves, err := getApprovedLeaves(req.UserID, req.Month, req.Year)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to fetch leaves"})
		return
	}

	// Calculate deductions
	leaveResponses := make([]LeaveDeductionResponse, len(leaves))
	totalDeduction := 0.0
	for i, leave := range leaves {
		deduction := calculateDeduction(baseSalary, float64(workingDays))
		leaveResponses[i] = LeaveDeductionResponse{
			LeaveID:            leave.ID,
			LeaveType:          leave.Type.String(),
			LeaveDate:          parseLeaveDate(leave.StartDate),
			SuggestedDeduction: deduction,
			Deduct:             true, // Default to true
		}
		totalDeduction += deduction
	}

	netPay := baseSalary - totalDeduction

	response := CalculatePayslipResponse{
		EmployeeName:   user.FirstName + " " + user.LastName,
		EmployeeID:     user.EmployeeId,
		JobTitle:       user.JobTitle,
		Department:     dept.Department.DepartmentName,
		BaseSalary:     baseSalary,
		WorkingDays:    workingDays,
		Leaves:         leaveResponses,
		TotalDeduction: totalDeduction,
		NetPay:         netPay,
		Exists:         false,
	}

	c.JSON(http.StatusOK, response)
}

// GeneratePayslip generates PDF and saves payslip data
func GeneratePayslip(c *gin.Context) {
	var req GeneratePayslipRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	// Verify user has manager access
	currentUserID := c.MustGet("id").(uint)
	if !checkManagerAccess(currentUserID) {
		c.JSON(http.StatusForbidden, gin.H{"error": "Only managers and above can generate payslips"})
		return
	}

	// Get employee details
	var user models.UserDetail
	if err := db.DB.First(&user, req.UserID).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Employee not found"})
		return
	}

	// Get organization details
	var org models.Organisation
	if err := db.DB.Preload("User").First(&org, req.OrganisationID).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Organization not found"})
		return
	}

	// Get organization address
	var orgAddress models.OrganisationAddress
	db.DB.Where("organisation_id = ?", req.OrganisationID).First(&orgAddress)

	// Get admin user details for organization contact info
	var adminUser models.UserDetail
	db.DB.Where("id = ?", org.AdminRegister).First(&adminUser)

	// Get department
	var dept models.DepartmentMember
	db.DB.Preload("Department").Where("user_id = ?", req.UserID).First(&dept)

	// Calculate total deduction
	totalDeduction := 0.0
	for _, ld := range req.LeaveDeductions {
		totalDeduction += ld.DeductionAmount
	}
	netPay := req.BaseSalary - totalDeduction

	// Save or update payslip
	var payslip models.Payslip
	err := db.DB.Where("user_id = ? AND month = ? AND year = ?", req.UserID, req.Month, req.Year).
		First(&payslip).Error

	if err == gorm.ErrRecordNotFound {
		// Create new payslip
		payslip = models.Payslip{
			UserID:              req.UserID,
			OrganisationID:      req.OrganisationID,
			Month:               req.Month,
			Year:                req.Year,
			BaseSalary:          req.BaseSalary,
			WorkingDays:         req.WorkingDays,
			TotalLeaveDeduction: totalDeduction,
			NetPay:              netPay,
			GeneratedBy:         currentUserID,
		}
		if err := db.DB.Create(&payslip).Error; err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to create payslip"})
			return
		}
	} else {
		// Update existing payslip
		payslip.BaseSalary = req.BaseSalary
		payslip.WorkingDays = req.WorkingDays
		payslip.TotalLeaveDeduction = totalDeduction
		payslip.NetPay = netPay
		payslip.GeneratedBy = currentUserID

		// Delete old leave deductions
		db.DB.Where("payslip_id = ?", payslip.ID).Delete(&models.PayslipLeaveDeduction{})

		if err := db.DB.Save(&payslip).Error; err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to update payslip"})
			return
		}
	}

	// Save leave deductions
	for _, ld := range req.LeaveDeductions {
		leaveDeduction := models.PayslipLeaveDeduction{
			PayslipID:       payslip.ID,
			LeaveID:         ld.LeaveID,
			LeaveType:       ld.LeaveType,
			LeaveDate:       ld.LeaveDate,
			DeductionAmount: ld.DeductionAmount,
		}
		if err := db.DB.Create(&leaveDeduction).Error; err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to save leave deduction"})
			return
		}
	}

	// Generate PDF
	pdfBytes, err := generatePayslipPDF(payslip, user, org, orgAddress, adminUser, dept.Department.DepartmentName, req.LeaveDeductions)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to generate PDF: " + err.Error()})
		return
	}

	// Return PDF
	filename := fmt.Sprintf("Payslip_%s_%s_%d.pdf", user.EmployeeId, time.Month(req.Month).String(), req.Year)
	c.Header("Content-Type", "application/pdf")
	c.Header("Content-Disposition", fmt.Sprintf("attachment; filename=%s", filename))
	c.Header("Content-Length", strconv.Itoa(len(pdfBytes)))
	c.Data(http.StatusOK, "application/pdf", pdfBytes)
}

// GetPayslip retrieves existing payslip
func GetPayslip(c *gin.Context) {
	userID, _ := strconv.ParseUint(c.Param("userId"), 10, 32)
	month, _ := strconv.Atoi(c.Param("month"))
	year, _ := strconv.Atoi(c.Param("year"))

	var payslip models.Payslip
	err := db.DB.Preload("LeaveDeductions").
		Where("user_id = ? AND month = ? AND year = ?", userID, month, year).
		First(&payslip).Error

	if err != nil {
		if err == gorm.ErrRecordNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "Payslip not found"})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, payslip)
}

// Helper functions

func checkManagerAccess(userID uint) bool {
	var user models.UserDetail
	if err := db.DB.First(&user, userID).Error; err != nil {
		return false
	}
	return user.UserType >= 200
}

func getActiveSalary(userID uint, month, year int) (float64, error) {
	// Create date for the month
	date := time.Date(year, time.Month(month), 1, 0, 0, 0, 0, time.UTC)

	var salary models.Salary
	err := db.DB.Where("user_id = ? AND effective_date <= ? AND (termination_date IS NULL OR termination_date >= ?)",
		userID, date, date).
		Order("effective_date DESC").
		First(&salary).Error

	if err != nil {
		return 0, err
	}

	return salary.BaseSalary, nil
}

func getApprovedLeaves(userID uint, month, year int) ([]models.UserLeave, error) {
	startDate := fmt.Sprintf("%d-%02d-01", year, month)
	endDate := fmt.Sprintf("%d-%02d-%02d", year, month, getDaysInMonth(month, year))

	var leaves []models.UserLeave
	err := db.DB.Where("user_id = ? AND status = ? AND start_date >= ? AND start_date <= ?",
		userID, models.Approved, startDate, endDate).
		Find(&leaves).Error

	return leaves, err
}

func calculateWorkingDays(month, year int, orgID uint) int {
	// Get organization's working days setting
	var org models.Organisation
	if err := db.DB.First(&org, orgID).Error; err != nil {
		return 22 // Default fallback
	}

	daysInMonth := getDaysInMonth(month, year)

	switch org.Days {
	case models.Weekdays: // 5 days
		return (daysInMonth / 7) * 5
	case models.Sat: // 6 days
		return (daysInMonth / 7) * 6
	case models.All: // 7 days
		return daysInMonth
	default:
		return 22
	}
}

func calculateDeduction(baseSalary float64, workingDays float64) float64 {
	if workingDays <= 0 {
		return 0
	}
	return baseSalary / workingDays
}

func getDaysInMonth(month, year int) int {
	t := time.Date(year, time.Month(month+1), 0, 0, 0, 0, 0, time.UTC)
	return t.Day()
}

func parseLeaveDate(dateStr string) time.Time {
	t, _ := time.Parse("2006-01-02", dateStr)
	return t
}

func generatePayslipPDF(payslip models.Payslip, employee models.UserDetail, org models.Organisation,
	orgAddress models.OrganisationAddress, adminUser models.UserDetail, department string, leaveDeductions []LeaveDeductionInput) ([]byte, error) {

	pdf := gofpdf.New("P", "mm", "A4", "")
	pdf.AddPage()

	// Organization Header Section with border
	pdf.SetFillColor(63, 81, 181) // Blue background color
	pdf.SetTextColor(255, 255, 255) // White text
	pdf.SetFont("Arial", "B", 18)

	// Organization Name (Centered with background)
	pdf.CellFormat(0, 12, org.OrganisationCode, "1", 1, "C", true, 0, "")

	// Reset text color for address
	pdf.SetTextColor(0, 0, 0) // Black text
	pdf.SetFont("Arial", "", 10)

	// Organization Address (Centered) - Build full address
	address := orgAddress.Address
	if address == "" {
		address = org.Address
	}

	// Build complete address with city, state, postal code if available
	fullAddress := address
	if orgAddress.City != "" {
		if fullAddress != "" {
			fullAddress += ", "
		}
		fullAddress += orgAddress.City
	}
	if orgAddress.State != "" {
		if fullAddress != "" {
			fullAddress += ", "
		}
		fullAddress += orgAddress.State
	}
	if orgAddress.PostalCode > 0 {
		if fullAddress != "" {
			fullAddress += " - "
		}
		fullAddress += fmt.Sprintf("%d", orgAddress.PostalCode)
	}
	if fullAddress == "" {
		fullAddress = address
	}

	pdf.CellFormat(0, 6, fullAddress, "0", 1, "C", false, 0, "")

	// Organization Contact Details (Centered)
	pdf.SetFont("Arial", "", 9)
	contactInfo := ""
	if org.WebsiteUrl != "" {
		contactInfo += "Website: " + org.WebsiteUrl
	}
	if adminUser.Email != "" {
		if contactInfo != "" {
			contactInfo += " | "
		}
		contactInfo += "Email: " + adminUser.Email
	}
	if adminUser.Phone > 0 {
		if contactInfo != "" {
			contactInfo += " | "
		}
		contactInfo += fmt.Sprintf("Phone: %d", adminUser.Phone)
	}
	if contactInfo != "" {
		pdf.CellFormat(0, 5, contactInfo, "0", 1, "C", false, 0, "")
	}

	// Admin Contact Person (if available)
	if adminUser.FirstName != "" || adminUser.LastName != "" {
		adminName := adminUser.FirstName + " " + adminUser.LastName
		if adminName != " " {
			pdf.SetFont("Arial", "", 9)
			pdf.CellFormat(0, 5, fmt.Sprintf("Contact Person: %s", adminName), "0", 1, "C", false, 0, "")
		}
	}

	pdf.Ln(5)

	// Draw a line separator
	pdf.SetDrawColor(200, 200, 200)
	pdf.Line(10, pdf.GetY(), 200, pdf.GetY())
	pdf.Ln(5)

	// Payslip Title
	pdf.SetFont("Arial", "B", 14)
	monthName := time.Month(payslip.Month).String()
	pdf.CellFormat(0, 10, fmt.Sprintf("PAYSLIP - %s %d", monthName, payslip.Year), "0", 1, "C", false, 0, "")
	pdf.Ln(5)

	// Employee Details Section
	pdf.SetFont("Arial", "B", 12)
	pdf.Cell(0, 8, "Employee Details")
	pdf.Ln(8)

	pdf.SetFont("Arial", "", 10)
	pdf.Cell(50, 6, "Employee Name:")
	pdf.Cell(0, 6, employee.FirstName+" "+employee.LastName)
	pdf.Ln(6)

	pdf.Cell(50, 6, "Employee ID:")
	pdf.Cell(0, 6, employee.EmployeeId)
	pdf.Ln(6)

	pdf.Cell(50, 6, "Job Title:")
	pdf.Cell(0, 6, employee.JobTitle)
	pdf.Ln(6)

	pdf.Cell(50, 6, "Department:")
	pdf.Cell(0, 6, department)
	pdf.Ln(10)

	// Salary Details Section
	pdf.SetFont("Arial", "B", 12)
	pdf.Cell(0, 8, "Salary Details")
	pdf.Ln(8)

	pdf.SetFont("Arial", "", 10)
	pdf.Cell(100, 6, "Base Salary:")
	pdf.Cell(0, 6, fmt.Sprintf("Rs. %.2f", payslip.BaseSalary))
	pdf.Ln(6)

	pdf.Cell(100, 6, "Working Days:")
	pdf.Cell(0, 6, fmt.Sprintf("%d", payslip.WorkingDays))
	pdf.Ln(10)

	// Leave Deductions Section
	if len(leaveDeductions) > 0 {
		pdf.SetFont("Arial", "B", 12)
		pdf.Cell(0, 8, "Leave Deductions")
		pdf.Ln(8)

		// Table header
		pdf.SetFont("Arial", "B", 10)
		pdf.Cell(40, 7, "Date")
		pdf.Cell(40, 7, "Type")
		pdf.Cell(0, 7, "Amount")
		pdf.Ln(7)

		// Table rows
		pdf.SetFont("Arial", "", 10)
		for _, ld := range leaveDeductions {
			pdf.Cell(40, 6, ld.LeaveDate.Format("02-Jan-06"))
			pdf.Cell(40, 6, ld.LeaveType)
			pdf.Cell(0, 6, fmt.Sprintf("Rs. %.2f", ld.DeductionAmount))
			pdf.Ln(6)
		}

		pdf.Ln(3)
		pdf.SetFont("Arial", "B", 10)
		pdf.Cell(100, 6, "Total Deduction:")
		pdf.Cell(0, 6, fmt.Sprintf("Rs. %.2f", payslip.TotalLeaveDeduction))
		pdf.Ln(10)
	}

	// Net Pay
	pdf.SetFont("Arial", "B", 14)
	pdf.SetFillColor(240, 240, 240)
	pdf.CellFormat(100, 10, "NET PAY:", "1", 0, "L", true, 0, "")
	pdf.CellFormat(0, 10, fmt.Sprintf("Rs. %.2f", payslip.NetPay), "1", 1, "R", true, 0, "")

	// Output PDF to bytes
	var buf bytes.Buffer
	err := pdf.Output(&buf)
	if err != nil {
		return nil, err
	}

	return buf.Bytes(), nil
}

