// GetUsers godoc
// @Summary Retrieves a list of users
// @Description Retrieves a list of all users from the database
// @Produce json
// @Success 200 {object} structure.UserListResponse
// @Router /users [get]
func GetUsers(c *gin.Context) {
	var users []models.UserDetail
	db.DB.Find(&users)

	var usersForResponse []structure.UserWithoutGORM
	for _, user := range users {
		usersForResponse = append(usersForResponse, structure.UserWithoutGORM{
			Id:        user.ID,
			FirstName: user.FirstName,
			LastName:  user.LastName,
		})
	}

	c.JSON(http.StatusOK, structure.UserListResponse{Data: usersForResponse})
	log.Default().Println("Executed GetUsers by user: ", c.Request.Header.Get("Authorization"))
}

// CreateUser godoc
// @Summary Creates a new user
// @Description Creates a new user with the provided details
// @Accept json
// @Produce json
// @Param request body structure.CreateUserRequest true "Create User Request"
// @Success 200 {object} structure.CreateUserResponse
// @Router /users [post]
func CreateUser(c *gin.Context) {
	var createUser structure.CreateUserRequest
	log.Default().Println("Started creating new user for email: ", createUser.Email, c.Request.Header.Get("Authorization"))
	if err := c.ShouldBindJSON(&createUser); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	// Checking for soft delete
	// Remove it later
	var newEmail models.UserDetail
	softdelete := db.DB.Where("email = ?", createUser.Email).First(&newEmail)
	if softdelete.Error != gorm.ErrRecordNotFound {
		db.DB.Delete(&newEmail)
	}
	var codeMap models.CodeMap
	if err := db.DB.Where("v = ? AND code_label = ?", createUser.AccessCode, "Access_Level").First(&codeMap).Error; err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	var organisation models.Organisation
	if err := db.DB.First(&organisation, createUser.OrganisationId).Error; err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Organization not found"})
		return
	}

	// Create UserEmail model instance with associated access code
	userEmail := models.UserDetail{
		FirstName: "",
		LastName:  "",
		Email:     createUser.Email,
		Phone:     createUser.Phone,
	}

	db.DB.Create(&userEmail)

	orgUser := models.OrganisationUser{
		UserId:         userEmail.ID,
		OrganisationId: createUser.OrganisationId,
	}
	db.DB.Create(&orgUser)

	c.JSON(http.StatusOK, gin.H{"message": "User Created"})

	log.Default().Println("Executed Post Users by user: ", c.Request.Header.Get("Authorization"))
}

func UserDetails(c *gin.Context) {
	var UserDetails structure.UserDetials
	log.Default().Println("Started updating  user for email: ", UserDetails.Email, c.Request.Header.Get("Authorization"))
