// GetUserDetailsByToken godoc
// @Summary Retrieves user details by jwttoken
// @Description Retrieves user details based on the provided email address.
// @Accept json
// @Produce json
// @Param email path string true "Email address of the user"
// @Success 200 {object} structure.UserDetailsResponse "Successfully retrieved user details"
// @Failure 400 {object} structure.ErrorResponse "Bad request format or missing parameters"
// @Failure 404 {object} structure.ErrorResponse "User or user details not found"
// @Router /users/email [get]
func GetUserDetailsByToken(c *gin.Context) {

	//getting the email from token
	//check middleware for info

	id := c.MustGet("id").(uint)
	log.Default().Println("Started execution of Get User Details by id: ", id)

	var userDetail models.UserDetail
	if err := db.DB.Where("id = ?", id).First(&userDetail); err.Error == gorm.ErrRecordNotFound {
		c.JSON(404, gin.H{"error": "User email not found"})
		return
	}

	var user models.UserDetail
	if err := db.DB.Where("id = ?", id).First(&user).Error; err != nil {
		c.JSON(404, gin.H{"error": "User not found"})
		return
	}
	var organisationUser models.OrganisationUser
	if strings.Contains(userDetail.Email, "onlyoncloud") {
		if err := db.DB.Where("user_id = ?", id).Find(&organisationUser).Error; err == gorm.ErrRecordNotFound {
			organisationUser.UserId = id
			organisationUser.OrganisationId = 1
		}
	} else {
		if err := db.DB.Where("user_id = ?", id).Find(&organisationUser).Error; err != nil {
			c.JSON(http.StatusNotFound, gin.H{"error": "Organisation not found for the user"})
			return
		}
	}

	// Prepare the UserDetailsResponse
	response := structure.UserDetailsResponse{
		Id:             userDetail.ID,
		FirstName:      userDetail.FirstName,
		LastName:       userDetail.LastName,
		Email:          userDetail.Email,
		Address:        userDetail.Address,
		City:           userDetail.City,
		UserType:       userDetail.UserType,
		State:          userDetail.State,
		PostalCode:     userDetail.PostalCode,
		Phone:          userDetail.Phone,
		OrganisationID: organisationUser.OrganisationId,
		StartTime:      userDetail.StartTime,
		EndTime:        userDetail.EndTime,
	}

	c.JSON(200, response)
	log.Default().Println("Executed Get User Details by id: ", id)
}

func GetUserOrgByToken(c *gin.Context) {
	id := c.MustGet("id").(uint)
	userEmail := c.MustGet("email")

	log.Println("User Email: ", userEmail)
	var userIDs []uint
	if err := db.DB.Model(&[]models.UserDetail{}).Where("email Like ?", userEmail).Select("id").Find(&userIDs).Error; err != nil {
		c.JSON(404, gin.H{"error": "User not found"})
		return
	}
	var org_users []models.OrganisationUser
	if err := db.DB.Model(&[]models.OrganisationUser{}).Where("user_id in ?", userIDs).Find(&org_users).Error; err != nil {
		c.JSON(404, gin.H{"error": "Organisation User not found "})
		return
	}
	log.Println("User IDs: ", userIDs)
	log.Println("Org Users: ", org_users)
	for _, t := range org_users {
		log.Println("Org User: ", t.ID)
	}
	var userOrgs []models.UserOrganisations
	for _, org_user := range org_users {
		var orgCode string
		if err := db.DB.Model(&models.Organisation{}).Where("id = ?", org_user.OrganisationId).Pluck("organisation_code", &orgCode).Error; err != nil {
			c.JSON(404, gin.H{"error": "Organisation not found for : " + strconv.Itoa(int(org_user.OrganisationId))})
			return
		}
		userOrgs = append(userOrgs, models.UserOrganisations{
			OrganisationId:   org_user.OrganisationId,
			OrganisationCode: orgCode,
			UserId:           org_user.UserId,
		})
	}

	c.JSON(200, userOrgs)
	log.Default().Println("Executed Get User Details by id: ", id)
}

func publickey(c *gin.Context) {

	pubkey := auth.PubKey()
	key := string(pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PUBLIC KEY",
		Bytes: x509.MarshalPKCS1PublicKey(pubkey),
	}))

	c.JSON(http.StatusOK, gin.H{"key": key})

}

