}

// Function to get the list of users from an organisation
func GetUserList(c *gin.Context) {
	var orgusers []models.OrganisationUser // organisation users
	orgid := c.Param("id")
	db.DB.Preload("User").Where("organisation_id = ?", orgid).Find(&orgusers)

	var response []structure.UserListOrganisation

	// Iterate through organisation users and check if the user exists in the users list
	for _, orgUser := range orgusers {
		// If the user ID exists in the users list, add it to the response along with the full name
		response = append(response, structure.UserListOrganisation{
			Id:         orgUser.UserId,
			Firstname:  orgUser.User.FirstName,
			Name:       orgUser.User.FirstName + " " + orgUser.User.LastName,
			Lastname:   orgUser.User.LastName, // Append the full name
			EmployeeId: orgUser.User.EmployeeId,
			JobTitle:   orgUser.User.JobTitle,
		})
	}

	// Check if the response is empty
	if len(response) == 0 {
		// If the response is empty, return an error message
		c.JSON(http.StatusNotFound, gin.H{"error": "User list not found for the given organisation"})
		return
	}

	// Send out the response
	c.JSON(http.StatusOK, response)
	log.Default().Println("Executed GetUserList by id: ", orgid)
}

// Define endpoint to update start time and end time
func UpdateStartAndEndTime(c *gin.Context) {
	var userDetail models.UserDetail
	userID := c.Param("user_id")

	// Find user detail by user ID
	if err := db.DB.Where("user_id = ?", userID).First(&userDetail).Error; err != nil {
		c.JSON(404, gin.H{"error": "Record not found"})
		return
	}

	// Parse input JSON
	var input struct {
		StartTime time.Time `json:"start_time"`
		EndTime   time.Time `json:"end_time"`
	}
	if err := c.ShouldBindJSON(&input); err != nil {
		c.JSON(400, gin.H{"error": "Invalid input"})
		return
	}

	// Update start time and end time
	userDetail.StartTime = input.StartTime
	userDetail.EndTime = input.EndTime

	// Save updated user detail
	if err := db.DB.Save(&userDetail).Error; err != nil {
		c.JSON(500, gin.H{"error": "Failed to update user detail"})
		return
	}

	c.JSON(200, gin.H{"message": "User detail updated successfully"})
}

func RemoveUserImage(c *gin.Context) {
