package services

import (
	"encoding/json"
	"fmt"
	"math"
	"strings"

	"core-backend/m/v2/models"
	"core-backend/m/v2/utils"
)

func BuildStandardQuotationVM(
	quotation models.Quotation, // Reusing steel quotation model as input (generic quotation data)
	items []models.QuotationItem,
	customer models.CustomerModel,
	config models.SteelQuotationConfig,
) (models.StandardQuotationViewModel, error) {

	// Parse stored config JSON (company, seller, footer)
	companyVM, sellerVM, footerVM, err := parseQuotationConfig(config)
	if err != nil {
		return models.StandardQuotationViewModel{}, fmt.Errorf("failed to parse config: %w", err)
	}

	// Build buyer VM from customer
	buyerVM := buildBuyerVM(customer)

	// Build ship-to VM (reuse buyer for now; can be extended if separate shipping address exists)
	shipToVM := buildShipToVM(customer)

	// Build meta (quotation number, dates, status)
	metaVM := buildStandardMetaVM(quotation)

	// Map items and compute line-level totals
	itemVMs, subtotal := buildStandardItemVMs(items)

	// Compute tax totals (CGST, SGST)
	cgstTotal, sgstTotal := computeTaxTotals(itemVMs)

	// Compute rounding adjustment
	beforeRounding := subtotal + cgstTotal + sgstTotal
	rounding := computeRounding(beforeRounding)
	grandTotal := beforeRounding + rounding

	// Build totals VM
	totalsVM := buildStandardTotalsVM(subtotal, cgstTotal, sgstTotal, rounding, grandTotal)

	// Build notes and terms (can be extended to pull from DB or config)
	notesVM := buildNotesVM(quotation.Remarks)
	termsVM := buildTermsVM()

	// Assemble final ViewModel
	vm := models.StandardQuotationViewModel{
		DocumentTitle: "Quotation",
		Company:       companyVM,
		Seller:        sellerVM,
		Footer:        footerVM,
		Buyer:         buyerVM,
		ShipTo:        shipToVM,
		Meta:          metaVM,
		Items:         itemVMs,
		Totals:        totalsVM,
		Notes:         notesVM,
		Terms:         termsVM,
		StatusText:    quotation.Status,
	}

	return vm, nil
}

// parseQuotationConfig deserializes stored JSON config into Go structs.
func parseQuotationConfig(config models.SteelQuotationConfig) (models.CompanyVM, models.SellerBankVM, models.FooterVM, error) {
	var company models.CompanyVM
	var seller models.SellerBankVM
	var footer models.FooterVM

	if err := unmarshalJSON(config.CompanyVM, &company); err != nil {
		return models.CompanyVM{}, models.SellerBankVM{}, models.FooterVM{}, fmt.Errorf("company_vm: %w", err)
	}

	if err := unmarshalJSON(config.SellerVM, &seller); err != nil {
		return models.CompanyVM{}, models.SellerBankVM{}, models.FooterVM{}, fmt.Errorf("seller_vm: %w", err)
	}

	if err := unmarshalJSON(config.FooterVM, &footer); err != nil {
		return models.CompanyVM{}, models.SellerBankVM{}, models.FooterVM{}, fmt.Errorf("footer_vm: %w", err)
	}

	return company, seller, footer, nil
}

func unmarshalJSON(jsonStr string, target interface{}) error {
	if strings.TrimSpace(jsonStr) == "" {
		return fmt.Errorf("empty JSON string")
	}
	return json.Unmarshal([]byte(jsonStr), target)
}

/* ========================================
   Party (Buyer / Ship-To)
   ======================================== */

func buildBuyerVM(customer models.CustomerModel) models.BuyerVM {
	return models.BuyerVM{
		Name:         strings.ToUpper(strings.TrimSpace(customer.CustomerOrg)),
		AddressLine1: strings.TrimSpace(customer.AddressLine1),
		AddressLine2: strings.TrimSpace(customer.AddressLine2),
		AddressLine3: formatCityState(customer.City, customer.State),
		AddressLine4: "", // Reserved for additional line if needed
		GSTIN:        strings.TrimSpace(customer.GSTIN),
		Mobile:       strings.TrimSpace(customer.Phone),
		Email:        strings.TrimSpace(customer.Email),
		PONumber:     "-", // Can be populated from quotation if PO tracking added
	}
}

func buildShipToVM(customer models.CustomerModel) models.StandardShipToVM {
	// For now, ship-to = bill-to
	// Extend this if separate shipping address field exists in CustomerModel
	return models.StandardShipToVM{
		ShipToLine1: strings.TrimSpace(customer.AddressLine1),
		ShipToLine2: strings.TrimSpace(customer.AddressLine2),
		ShipToLine3: formatCityState(customer.City, customer.State),
		ShipToLine4: "",
	}
}

func formatCityState(city, state string) string {
	city = strings.TrimSpace(city)
	state = strings.TrimSpace(state)
	if city == "" && state == "" {
		return ""
	}
	if city != "" && state != "" {
		return fmt.Sprintf("%s, %s", city, state)
	}
	if city != "" {
		return city
	}
	return state
}

/* ========================================
   Meta (Quotation Number, Dates, Status)
   ======================================== */

func buildStandardMetaVM(quotation models.Quotation) models.StandardQuotationMetaVM {
	d := safeTime(quotation.CreatedAt)
	exp := safeTime(quotation.ValidUntil)
	return models.StandardQuotationMetaVM{
		QuotationNo:   fmt.Sprintf("Q-%d", quotation.ID),
		Dated:         d, // populate the field used by template
		EstimateDate:  d, // keep old field populated too for compatibility
		ExpiryDate:    exp,
		PlaceOfSupply: "Telangana", // Can be made dynamic from organisation or customer state
	}
}

/* ========================================
   Items (Line-level mapping + totals)
   ======================================== */

// buildStandardItemVMs maps DB items to presentation items and computes subtotal.
//
// Returns:
// - itemVMs: Slice of StandardQuotationItemVM
// - subtotal: Sum of all line amounts (before tax)
func buildStandardItemVMs(items []models.QuotationItem) ([]models.StandardQuotationItemVM, float64) {
	itemVMs := make([]models.StandardQuotationItemVM, 0, len(items))
	subtotal := 0.0

	for i, item := range items {
		qty := float64(item.Quantity)
		rate := item.UnitPrice

		// Line base amount (before tax)
		baseAmount := qty * rate

		// CGST and SGST (stored as percentages in DB, e.g., 9.0 for 9%)
		cgstPercent := item.CGST
		sgstPercent := item.SGST

		// Compute tax amounts
		cgstAmount := (baseAmount * cgstPercent) / 100.0
		sgstAmount := (baseAmount * sgstPercent) / 100.0

		// Line total (base + taxes)
		lineAmount := baseAmount + cgstAmount + sgstAmount

		itemVM := models.StandardQuotationItemVM{
			SlNo:         i + 1, // Auto-increment
			Name:         strings.TrimSpace(item.ProductName),
			Description2: strings.TrimSpace(item.Note),
			HSNCode:      fmt.Sprintf("%d", item.HSN),
			Quantity:     qty,
			UnitPrice:    rate,
			CGST:         cgstAmount,
			SGST:         sgstAmount,
			Amount:       lineAmount,
		}

		itemVMs = append(itemVMs, itemVM)
		subtotal += lineAmount
	}

	return itemVMs, subtotal
}

/* ========================================
   Tax Computation
   ======================================== */

// computeTaxTotals sums CGST and SGST across all items.
func computeTaxTotals(items []models.StandardQuotationItemVM) (cgstTotal, sgstTotal float64) {
	for _, item := range items {
		cgstTotal += item.CGST
		sgstTotal += item.SGST
	}
	return
}
func computeRounding(beforeRounding float64) float64 {
	rounded := math.Round(beforeRounding)
	return rounded - beforeRounding
}

