	// Store as UTC in database (GORM expects UTC)
	// GetCurrentTimeIST() returns IST time, convert to UTC for storage
	var checkinTime time.Time
	const layout = time.RFC3339Nano
	checkinTime, err := time.Parse(layout, checkin.CheckIn)
	if err != nil {
		istTime := utils.GetCurrentTimeIST()
		checkinTime = istTime.UTC()

	}

	attendance := &models.UserAttendance{
		UserId:           checkin.UserId,
