	if err := db.DB.Where("id = ?", user.OrganisationId).First(&Organisation).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Organisation not found"})
		return
	}
	if contains(Organisation.Features, AIAttendance) { // Send the image to the Python server for processing
		var buf bytes.Buffer
		writer := multipart.NewWriter(&buf)

		// Write check-in image
		imageWriter, err := writer.CreateFormFile("image", "checkin.jpg")
		if err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to create form file for check-in image: " + err.Error()})
