		if err := writer.Close(); err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to close writer: " + err.Error()})
			return
		}

		// Send HTTP POST request
		req, err := http.NewRequest("POST", "http://localhost:5000/process", &buf)
		if err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to create request: " + err.Error()})
			return
		}
		req.Header.Set("Content-Type", writer.FormDataContentType())

		client := &http.Client{}
		resp, err := client.Do(req)
		if err != nil {
			log.Default().Println("error: Failed to send request: ", err.Error())

		} else {

			defer resp.Body.Close()
		}
		// TODO: Removing the validity check for now
		// Optionally handle the response from the Python server
		// if resp.StatusCode != http.StatusOK {
		// body, _ := io.ReadAll(resp.Body)
		// c.JSON(http.StatusInternalServerError, gin.H{"error": "Python server error: " + string(body)})
		// return
		// }
	}

	//enter the user
	result = db.DB.Create(&attendance)
	if result.Error != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": result.Error.Error()})
		return
	}

	// Also store location in user_locations table for live location tracking
	location := &models.UserLocation{
		UserId:         models.UserID(checkin.UserId),
		Latitude:       checkin.CheckInLatitude,
		Longitude:      checkin.CheckInLongitude,
		StartTimestamp: models.LocationTime(utils.GetCurrentTimeIST()),
		EndTimestamp:   models.LocationTime(utils.GetCurrentTimeIST()),
		AreaName:       "", // Will be populated by reverse geocoding if needed
	}

	if err := db.DB.Create(&location).Error; err != nil {
		log.Printf("Failed to store location during check-in: %v", err)
		// Don't fail the check-in if location storage fails
	}

	c.JSON(200, gin.H{"id": attendance.ID})
