func GetAttendance(c *gin.Context) {
	userId := c.MustGet("id")
	month, _ := strconv.Atoi(c.Param("month"))
	var user models.UserDetail
	var org models.OrganisationUser

	// Retrieve user details from the database
	if err := db.DB.Where("id = ?", userId).Find(&user).Error; err != nil {
		c.JSON(500, err.Error())
		return
	}

	//Get user org to get working days
	if err := db.DB.Preload("Organisation").Where("user_id = ?", user.ID).First(&org).Error; err != nil {
		c.JSON(500, err.Error())
	}

	// Get all days in the specified month
	var alldays []time.Time

	switch org.Organisation.Days {
	case models.Weekdays:
		alldays = getWeekdaysInMonth(time.Now().Year(), time.Month(month))
	case models.Sat:
		alldays = sixDayWork(time.Now().Year(), time.Month(month))
	case models.All:
		alldays = allDays(time.Now().Year(), time.Month(month))
	default:
		alldays = getWeekdaysInMonth(time.Now().Year(), time.Month(month))
	}

	var days []time.Time
	for _, day := range alldays {
		if day.Before(time.Now()) { // Only include past or current days
			days = append(days, day)
		}
	}

	total := len(days) // Total number of days in the month

	// Retrieve user attendance and leave data
	var attendance []models.UserAttendance
	var leaves []models.UserLeave

	if err := db.DB.Where("user_id = ?", userId).Find(&attendance).Error; err != nil {
		c.JSON(500, err.Error())
		return
	}
	//fetching only the approved leaves
	if err := db.DB.Where("user_id = ? AND status = ?", userId, 1).Find(&leaves).Error; err != nil {
		c.JSON(500, err.Error())
		return
	}

	// Maps to track unique attendance and leave dates
	presentDays := make(map[string]struct{})
	leaveDays := make(map[string]struct{})

	// Record attendance (present days)
	for _, att := range attendance {
		presentDays[att.CheckIn.Truncate(24*time.Hour).Format("2006-01-02")] = struct{}{}
	}

	// Record leave days (range of dates between start and end)
	for _, leave := range leaves {
		start, _ := time.Parse(time.RFC3339, leave.StartDate)
		end, _ := time.Parse(time.RFC3339, leave.EndDate)
		for currentDate := start; !currentDate.After(end); currentDate = currentDate.AddDate(0, 0, 1) {
			leaveDays[currentDate.Format("2006-01-02")] = struct{}{}
		}
	}

	var absentDays []time.Time
	var leaveDates []struct {
		LeaveDate time.Time `json:"leave_date"`
		Reason    string    `json:"reason"`
	}

	// Classify days as absent or leave days
	for _, day := range days {
		dayStr := day.Format("2006-01-02")

		if _, isPresent := presentDays[dayStr]; !isPresent {
			if _, isOnLeave := leaveDays[dayStr]; isOnLeave {
				// If the day is on leave, add to leaveDates
				for _, leave := range leaves {
					start, _ := time.Parse(time.RFC3339, leave.StartDate)
					end, _ := time.Parse(time.RFC3339, leave.EndDate)
					if day.After(start) && day.Before(end) || day.Equal(start) || day.Equal(end) {
						leaveDates = append(leaveDates, struct {
							LeaveDate time.Time `json:"leave_date"`
							Reason    string    `json:"reason"`
						}{
							LeaveDate: day,
							Reason:    leave.Type.String(),
						})
					}
				}
			} else {
				// Otherwise, it's an absent day
				absentDays = append(absentDays, day)
			}
		}
	}

	// Remove duplicate leave days
	uniqueLeaveDates := make(map[string]struct{})
	var finalLeaveDates []struct {
		LeaveDate time.Time `json:"leave_date"`
		Reason    string    `json:"reason"`
	}

	for _, leave := range leaveDates {
		if _, exists := uniqueLeaveDates[leave.LeaveDate.Format("2006-01-02")]; !exists {
			uniqueLeaveDates[leave.LeaveDate.Format("2006-01-02")] = struct{}{}
			finalLeaveDates = append(finalLeaveDates, leave)
		}
	}

	// Calculate total leave count (absent + leave days)
	totalLeaveCount := len(absentDays) + len(finalLeaveDates)

	// Convert attendance to response format with IST formatted times
	var attendanceResponse []structure.AttendanceResponse
	for _, att := range attendance {
		attendanceResponse = append(attendanceResponse, structure.AttendanceResponse{
			ID:                att.ID,
			UserID:            att.UserId,
			CheckIn:           utils.FormatIST(att.CheckIn),
			CheckOut:          utils.FormatIST(att.CheckOut),
			CheckInLatitude:   att.CheckInLatitude,
			CheckInLongitude:  att.CheckInLongitude,
			CheckOutLatitude:  att.CheckOutLatitude,
			CheckOutLongitude: att.CheckOutLongitude,
			CheckInImg:        []byte(att.CheckInImg),
			CheckOutImg:       []byte(att.CheckOutImg),
		})
	}

	// Return the response with the total attendance, absent days, leave records, and total leave count
	c.JSON(200, gin.H{
		"total":       total,                // Total number of days in the month
		"absent":      len(absentDays),      // Number of absent days
		"absent_days": absentDays,           // List of absent days
		"leave_days":  finalLeaveDates,      // List of unique leave days with reasons
		"leaves":      len(finalLeaveDates), // Number of unique leave days
		"leave_count": totalLeaveCount,      // Total leave count (absent + leave days)
		"attendance":  attendanceResponse,   // List of attendance records with IST formatted times
	})
}

func getWeekdaysInMonth(year int, month time.Month) []time.Time {
	var weekdays []time.Time

	firstDay := time.Date(year, month, 1, 0, 0, 0, 0, time.UTC)

	lastDay := firstDay.AddDate(0, 1, 0).Add(-time.Hour * 24)

	for current := firstDay; current.Before(lastDay) || current.Equal(lastDay); current = current.AddDate(0, 0, 1) {
		if current.Weekday() != time.Saturday && current.Weekday() != time.Sunday {
			weekdays = append(weekdays, current)
		}
	}

	return weekdays
}

func sixDayWork(year int, month time.Month) []time.Time {
	var weekdays []time.Time

	firstDay := time.Date(year, month, 1, 0, 0, 0, 0, time.UTC)

	lastDay := firstDay.AddDate(0, 1, 0).Add(-time.Hour * 24)

	for current := firstDay; current.Before(lastDay) || current.Equal(lastDay); current = current.AddDate(0, 0, 1) {
		if current.Weekday() != time.Sunday {
			weekdays = append(weekdays, current)
		}
	}

	return weekdays
}

func allDays(year int, month time.Month) []time.Time {
	var all []time.Time

	firstDay := time.Date(year, month, 1, 0, 0, 0, 0, time.UTC)

	lastDay := firstDay.AddDate(0, 1, 0).Add(-time.Hour * 24)

	for current := firstDay; current.Before(lastDay) || current.Equal(lastDay); current = current.AddDate(0, 0, 1) {
		all = append(all, current)
	}

	return all
}

func getCheckInCheckOut(c *gin.Context) {
	id := c.MustGet("id").(uint)

	var user models.UserDetail
	result := db.DB.First(&user, id)
	if result.Error != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "user not found"})
		return
	}

	now := time.Now()
	todayStart := time.Date(now.Year(), now.Month(), now.Day(), 0, 0, 0, 0, now.Location())
	todayEnd := todayStart.Add(24 * time.Hour)

	var present models.UserAttendance
	err := db.DB.Where("user_id = ? AND check_in >= ? AND check_in < ?",
		id, todayStart, todayEnd).First(&present).Error

	if err != nil {
		if err == gorm.ErrRecordNotFound {
			c.JSON(http.StatusOK, nil)
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	if present.CheckOut != nil && !present.CheckOut.IsZero() {
		if present.CheckOut.Before(todayStart) || present.CheckOut.After(todayEnd) {
			present.CheckOut = &time.Time{}
		}
	}

	// Format times to IST before returning
	response := gin.H{
		"ID":                  present.ID,
		"user_id":             present.UserId,
		"check_in":            utils.FormatIST(present.CheckIn),
		"check_out":           utils.FormatIST(present.CheckOut),
		"check_in_latitude":   present.CheckInLatitude,
		"check_in_longitude":  present.CheckInLongitude,
		"check_out_latitude":  present.CheckOutLatitude,
		"check_out_longitude": present.CheckOutLongitude,
		"check_in_img":        string(present.CheckInImg),
		"check_out_img":       string(present.CheckOutImg),
	}

	// Return today's attendance
	c.JSON(http.StatusOK, response)
}

// StoreFirstCheckInImage stores the first check-in image for a user (one-time only)--------------
func StoreFirstCheckInImage(c *gin.Context) {
	id := c.MustGet("id").(uint)

	// Check if user already has a stored image-------------------
	var existingImage models.UserCheckInImage
	result := db.DB.Where("user_id = ?", id).First(&existingImage)
	if result.Error == nil {
		// Image already exists for this user---------------
		c.JSON(http.StatusBadRequest, gin.H{"error": "User already has a check-in image"})
		return
	}
	if result.Error != gorm.ErrRecordNotFound {
		c.JSON(http.StatusInternalServerError, gin.H{"error": result.Error.Error()})
		return
	}

	// Verify user exists---------------
	var user models.UserDetail
	if err := db.DB.First(&user, id).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "User not found"})
		return
	}

	var orgUser models.OrganisationUser
	var organizationID uint
	if err := db.DB.Where("user_id = ?", id).First(&orgUser).Error; err == nil {
		organizationID = orgUser.ID
	} else if err != gorm.ErrRecordNotFound {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Retrieve the uploaded image file----------------------
	file, _, err := c.Request.FormFile("image")
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}
	defer file.Close()

	// Read the image data----------------
	imageData, err := io.ReadAll(file)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Validate image format-------------------
	_, format, err := image.DecodeConfig(bytes.NewReader(imageData))
	if err != nil || (format != "jpeg" && format != "png" && format != "jpg") {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid image format, only JPEG or PNG allowed", "message": err.Error()})
		return
	}

	// Create new check-in image record----------------------
	checkInImage := &models.UserCheckInImage{
		UserID:         id,
		OrganizationID: organizationID,
		CheckInImage:   imageData,
	}

	// Save to database----------------------
	if err := db.DB.Create(checkInImage).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"message": "First check-in image stored successfully",
		"user_id": id,
	})
}

// CompareCheckInOutImage compares check-in/check-out images for a user----------------
func CompareCheckInOutImage(c *gin.Context) {
	id := c.MustGet("id").(uint)

	// Retrieve the uploaded image file--------------------
	file, fileHeader, err := c.Request.FormFile("image")
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Failed to get image file: " + err.Error()})
		return
	}
	defer file.Close()

	log.Printf("Received file: %s, Size: %d, Content-Type: %s",
		fileHeader.Filename, fileHeader.Size, fileHeader.Header.Get("Content-Type"))

	// Read the uploaded image data----------------------
	uploadedImageData, err := io.ReadAll(file)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to read image data: " + err.Error()})
		return
	}

	contentType := http.DetectContentType(uploadedImageData)
	log.Printf("Detected content type: %s", contentType)

	if !strings.HasPrefix(contentType, "image/") {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid file format. Only images are allowed. Detected: " + contentType})
		return
	}

	// Retrieve stored reference image-------------------------
	var storedImage models.UserCheckInImage
	if err := db.DB.Where("user_id = ?", id).First(&storedImage).Error; err != nil {
		if err == gorm.ErrRecordNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "No reference image found for user"})
		} else {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "Database error: " + err.Error()})
		}
		return
	}

	// Compare images with more robust error handling------------------------
	isMatch, err := compareImages(storedImage.CheckInImage, uploadedImageData)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Image comparison failed: " + err.Error()})
		return
	}

	if isMatch {
		c.JSON(http.StatusOK, gin.H{
			"status":  "success",
			"message": "Image matched successfully",
		})
	} else {
		c.JSON(http.StatusUnauthorized, gin.H{
			"status":  "error",
			"message": "Different person detected",
		})
	}
}

// compareImages compares two images by pixel difference------------------
func compareImages(stored, uploaded []byte) (bool, error) {
	var buf bytes.Buffer
	writer := multipart.NewWriter(&buf)

	// Write stored image
	storedWriter, err := writer.CreateFormFile("stored_image", "stored.jpg")
	if err != nil {
		return false, fmt.Errorf("failed to create form file for stored_image: %v", err)
	}
	_, err = storedWriter.Write(stored)
	if err != nil {
		return false, fmt.Errorf("failed to write stored image: %v", err)
	}

	// Write compared image
	comparedWriter, err := writer.CreateFormFile("compare_image", "uploaded.jpg")
	if err != nil {
		return false, fmt.Errorf("failed to create form file for compare_image: %v", err)
	}
	_, err = comparedWriter.Write(uploaded)
	if err != nil {
		return false, fmt.Errorf("failed to write uploaded image: %v", err)
	}

	err = writer.Close()
	if err != nil {
		return false, fmt.Errorf("failed to close writer: %v", err)
	}

	// Send HTTP POST request
	req, err := http.NewRequest("POST", "http://localhost:5000/recognize", &buf)
	if err != nil {
		return false, fmt.Errorf("failed to create request: %v", err)
	}
	req.Header.Set("Content-Type", writer.FormDataContentType())

	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		return false, fmt.Errorf("failed to send request: %v", err)
	}
	defer resp.Body.Close()

	// Decode response
	var result struct {
		Match   bool   `json:"match"`
		Message string `json:"message"`
	}
	err = json.NewDecoder(resp.Body).Decode(&result)
	if err != nil {
		return false, fmt.Errorf("failed to decode response: %v", err)
	}

	log.Printf("Python Response: %v", result.Message)
	return result.Match, nil
}

