// ComputeDailyAttendanceSnapshot computes and stores daily attendance data for all organizations
func ComputeDailyAttendanceSnapshot() {
	log.Println("[CronJob] Starting ComputeDailyAttendanceSnapshot...")

	// Get yesterday's date (we compute for the previous day)
	now := time.Now()
	yesterday := now.AddDate(0, 0, -1)
	targetDate := time.Date(yesterday.Year(), yesterday.Month(), yesterday.Day(), 0, 0, 0, 0, yesterday.Location())
	dateOnly := targetDate.Format("2006-01-02")

	log.Printf("[CronJob] Computing attendance snapshot for date: %s", dateOnly)

	// Get all organizations
	var orgs []models.Organisation
	if err := db.DB.Find(&orgs).Error; err != nil {
		log.Printf("[CronJob] Error fetching organizations: %v", err)
		return
	}

	for _, org := range orgs {
		log.Printf("[CronJob] Processing organization: %d (%s)", org.ID, org.OrganisationCode)
		processOrganizationAttendance(org.ID, targetDate, dateOnly)
	}

	log.Println("[CronJob] Completed ComputeDailyAttendanceSnapshot.")
}

// isWeeklyOff returns true if date falls on an org configured weekly-off weekday (0=Sun..6=Sat)
func isWeeklyOff(org models.Organisation, date time.Time) bool {
	wd := int(date.Weekday()) // Go: Sunday=0 ... Saturday=6 (matches your convention)
	for _, d := range []int(org.WeeklyOffs) {
		if d == wd {
			return true
		}
	}
	return false
}

// processOrganizationAttendance processes attendance for all employees in an organization
func processOrganizationAttendance(orgID uint, targetDate time.Time, dateStr string) {
	// Get org once (needed for weekly offs)
	var org models.Organisation
	if err := db.DB.Select("id, days, weekly_offs").Where("id = ?", orgID).First(&org).Error; err != nil {
		log.Printf("[CronJob] Error fetching org %d: %v", orgID, err)
		return
	}

	// Top-level day classification for the org/date
	isOrgHoliday := isHoliday(orgID, targetDate)
	isOrgWeeklyOff := isWeeklyOff(org, targetDate)

	// Get all users in the organization
	var orgUsers []models.OrganisationUser
	if err := db.DB.Where("organisation_id = ?", orgID).Find(&orgUsers).Error; err != nil {
		log.Printf("[CronJob] Error fetching users for org %d: %v", orgID, err)
		return
	}

	for _, orgUser := range orgUsers {
		// Get user details
		var user models.UserDetail
		if err := db.DB.Where("id = ?", orgUser.UserId).First(&user).Error; err != nil {
			log.Printf("[CronJob] Error fetching user %d: %v", orgUser.UserId, err)
			continue
		}

		// Check if snapshot already exists for this date
		var existingSnapshot models.DailyAttendanceSnapshot
		_ = db.DB.Where("org_id = ? AND user_id = ? AND DATE(date) = ?", orgID, user.ID, dateStr).
			First(&existingSnapshot).Error

		// NEW: Holiday / Weekly Off snapshots (do not mark absent)
		if isOrgHoliday || isOrgWeeklyOff {
			status := "Weekly Off"
			if isOrgHoliday {
				status = "Holiday"
			}

			snapshot := models.DailyAttendanceSnapshot{
				UserID:     user.ID,
				OrgID:      orgID,
				EmployeeID: user.EmployeeId,
				Date:       targetDate,
				Status:     status,
			}

			if existingSnapshot.ID != 0 {
				snapshot.ID = existingSnapshot.ID
				db.DB.Save(&snapshot)
			} else {
				db.DB.Create(&snapshot)
			}

			log.Printf("[CronJob] Processed user %d (%s) - Status: %s for %s",
				user.ID, user.EmployeeId, status, dateStr)
			continue
		}

		// Check if snapshot already exists for this date
		var existingSnapshot2 models.DailyAttendanceSnapshot
		_ = db.DB.Where("org_id = ? AND user_id = ? AND DATE(date) = ?", orgID, user.ID, dateStr).
			First(&existingSnapshot2).Error

		// Check if user is on leave
		var leave models.UserLeave
		isOnLeave := false
		var leaveType, leaveReason string

		err := db.DB.Where("user_id = ? AND status = ? AND DATE(start_date) <= ? AND DATE(end_date) >= ?",
			user.ID, models.Approved, dateStr, dateStr).First(&leave).Error

		if err == nil {
			isOnLeave = true
			leaveType = leave.Type.String()
			leaveReason = leave.Reason
		}

		if isOnLeave {
			// User is on leave
			snapshot := models.DailyAttendanceSnapshot{
				UserID:      user.ID,
				OrgID:       orgID,
				EmployeeID:  user.EmployeeId,
				Date:        targetDate,
				Status:      "On Leave",
				LeaveType:   &leaveType,
				LeaveReason: &leaveReason,
			}

			if existingSnapshot2.ID != 0 {
				// Update existing snapshot
				snapshot.ID = existingSnapshot2.ID
				db.DB.Save(&snapshot)
			} else {
				// Create new snapshot
				db.DB.Create(&snapshot)
			}

			log.Printf("[CronJob] User %d (%s) is on leave for %s", user.ID, user.EmployeeId, dateStr)
			continue
		}

		// Get attendance record
		var attendance models.UserAttendance
		err = db.DB.Where("user_id = ? AND DATE(check_in) = ?", user.ID, dateStr).First(&attendance).Error

		if err == gorm.ErrRecordNotFound {
			// User is absent
			snapshot := models.DailyAttendanceSnapshot{
				UserID:     user.ID,
				OrgID:      orgID,
				EmployeeID: user.EmployeeId,
				Date:       targetDate,
				Status:     "Absent",
			}

			if existingSnapshot2.ID != 0 {
				snapshot.ID = existingSnapshot2.ID
				db.DB.Save(&snapshot)
			} else {
				db.DB.Create(&snapshot)
			}

			log.Printf("[CronJob] User %d (%s) is absent for %s", user.ID, user.EmployeeId, dateStr)
			continue
		}

		if err != nil {
			log.Printf("[CronJob] Error fetching attendance for user %d: %v", user.ID, err)
			continue
		}

		// User is present - compute distance travelled
		distanceTravelled := computeDistanceForUser(user.ID, targetDate)

		// Compute work duration (in minutes)
		var workDuration *int
		if !attendance.CheckOut.IsZero() {
			duration := int(attendance.CheckOut.Sub(*attendance.CheckIn).Minutes())
			workDuration = &duration
		}

		// Create snapshot
		snapshot := models.DailyAttendanceSnapshot{
			UserID:            user.ID,
			OrgID:             orgID,
			EmployeeID:        user.EmployeeId,
			Date:              targetDate,
			CheckIn:           attendance.CheckIn,
			CheckOut:          nilIfZero(*attendance.CheckOut),
			CheckInImg:        attendance.CheckInImg,
			CheckOutImg:       attendance.CheckOutImg,
			CheckInLatitude:   floatPtr(attendance.CheckInLatitude),
			CheckInLongitude:  floatPtr(attendance.CheckInLongitude),
			CheckOutLatitude:  floatPtr(attendance.CheckOutLatitude),
			CheckOutLongitude: floatPtr(attendance.CheckOutLongitude),
			DistanceTravelled: distanceTravelled,
			WorkDuration:      workDuration,
			Status:            "Present",
		}

		if existingSnapshot2.ID != 0 {
			// Update existing snapshot
			snapshot.ID = existingSnapshot2.ID
			db.DB.Save(&snapshot)
		} else {
			// Create new snapshot
			db.DB.Create(&snapshot)
		}

		log.Printf("[CronJob] Processed user %d (%s) - Status: Present, Distance: %.2f km",
			user.ID, user.EmployeeId, valueOrZero(distanceTravelled))
	}
}

// computeDistanceForUser calculates total distance travelled by user on a given date
func computeDistanceForUser(userID uint, targetDate time.Time) *float64 {
	// Format dates for query
	startTime := targetDate
	endTime := targetDate.Add(24 * time.Hour)

	// Get all locations for the user on that date
	var locations []models.UserLocation
	result := db.DB.Where(`
        user_id = ?
        AND DATE(start_timestamp) >= DATE(?)
        AND DATE(start_timestamp) <= DATE(?)`,
		userID, startTime, endTime,
	).Order("start_timestamp asc").Find(&locations)

	if result.Error != nil {
		log.Printf("[CronJob] Error fetching locations for user %d: %v", userID, result.Error)
		return nil
	}

	if len(locations) == 0 {
		zero := 0.0
		return &zero
	}

	// Segment into journeys
	journeySegments := segmentIntoJourneys(locations)

	if len(journeySegments) == 0 {
		zero := 0.0
		return &zero
	}

	// Calculate total distance across all journeys
	var totalDistance float64 = 0.0
	for _, segment := range journeySegments {
		if len(segment) < 1 {
			continue
		}
		journeyDistance := calculateJourneyDistance(segment)
		totalDistance += journeyDistance
	}

	return &totalDistance
}

// Helper functions
func nilIfZero(t time.Time) *time.Time {
	if t.IsZero() {
		return nil
	}
	return &t
}

func floatPtr(f float64) *float64 {
	if f == 0 {
		return nil
	}
	return &f
}

func valueOrZero(ptr *float64) float64 {
	if ptr == nil {
		return 0.0
	}
	return *ptr
}

// GetMonthlyAttendanceReport fetches monthly attendance report for a specific employee (OPTIMIZED)
func GetMonthlyAttendanceReport(c *gin.Context) {
	orgID := c.Param("org_id")
	userID := c.Param("user_id")
	year := c.Query("year")
	month := c.Query("month")

	log.Printf("Getting Monthly Attendance Report for Org: %s, User: %s, Year: %s, Month: %s",
		orgID, userID, year, month)

	// Validate parameters
	if orgID == "" || userID == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Organization ID and User ID are required"})
		return
	}

	// Default to current year and month if not provided
	var targetYear, targetMonth int
	now := time.Now()

	if year == "" || month == "" {
		targetYear = now.Year()
		targetMonth = int(now.Month())
	} else {
		var err error
		targetYear, err = strconv.Atoi(year)
		if err != nil || targetYear < 2000 || targetYear > 2100 {
			c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid year"})
			return
		}

		targetMonth, err = strconv.Atoi(month)
		if err != nil || targetMonth < 1 || targetMonth > 12 {
			c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid month (1-12)"})
			return
		}
	}

	// Single query to verify user belongs to organization and get details
	// Use the package-level UserOrgInfo struct directly
	var userOrgInfo UserOrgInfo
	err := db.DB.Table("organisation_users ou").
		Select(`
            ou.user_id,
            ou.organisation_id as org_id,
            ud.first_name,
            ud.last_name,
            ud.email,
            ud.employee_id,
            o.organisation_code as org_code,
            o.days
        `).
		Joins("JOIN user_details ud ON ud.id = ou.user_id").
		Joins("JOIN organisations o ON o.id = ou.organisation_id").
		Where("ou.organisation_id = ? AND ou.user_id = ?", orgID, userID).
		First(&userOrgInfo).Error

	if err != nil {
		if err == gorm.ErrRecordNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "User not found in organization"})
		} else {
			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		}
		return
	}

	report := generateMonthlyReportOptimized(userOrgInfo, targetYear, targetMonth, now)
	c.JSON(http.StatusOK, report)
}

// generateMonthlyReportOptimized generates monthly report for a SINGLE user
func generateMonthlyReportOptimized(userInfo UserOrgInfo, year, month int, now time.Time) gin.H {
	info := userInfo

	firstDay := time.Date(year, time.Month(month), 1, 0, 0, 0, 0, time.UTC)
	lastDay := time.Date(year, time.Month(month)+1, 1, 0, 0, 0, 0, time.UTC)

	// Get org weekly offs (used to label weekly off days)
	var org models.Organisation
	_ = db.DB.Select("id, weekly_offs").Where("id = ?", info.OrgID).First(&org).Error

	// CHANGE: Do not use sixDayWork/getWeekdaysInMonth for iteration.
	// Iterate all calendar days, and treat "workday" as: not holiday AND not weekly-off.
	var daysToShow []time.Time
	for _, day := range allDays(year, time.Month(month)) {
		if day.Before(now) || day.Format("2006-01-02") == now.Format("2006-01-02") {
			daysToShow = append(daysToShow, day)
		}
	}

	// snapshots for user
	var snapshots []struct {
		Date              time.Time
		Status            string
		CheckIn           *time.Time
		CheckOut          *time.Time
		WorkDuration      *int
		DistanceTravelled *float64
		LeaveType         *string
		LeaveReason       *string
		CheckInLatitude   *float64
		CheckInLongitude  *float64
		CheckOutLatitude  *float64
		CheckOutLongitude *float64
		CheckInImg        []byte
		CheckOutImg       []byte
	}

	db.DB.Model(&models.DailyAttendanceSnapshot{}).
		Select(`
            date, status, check_in, check_out, work_duration, distance_travelled,
            leave_type, leave_reason,
            check_in_latitude, check_in_longitude, check_out_latitude, check_out_longitude,
            check_in_img, check_out_img
        `).
		Where("org_id = ? AND user_id = ? AND date >= ? AND date < ?", info.OrgID, info.UserID, firstDay, lastDay).
		Scan(&snapshots)

	snapshotMap := make(map[string]struct {
		Date              time.Time
		Status            string
		CheckIn           *time.Time
		CheckOut          *time.Time
		WorkDuration      *int
		DistanceTravelled *float64
		LeaveType         *string
		LeaveReason       *string
		CheckInLatitude   *float64
		CheckInLongitude  *float64
		CheckOutLatitude  *float64
		CheckOutLongitude *float64
		CheckInImg        []byte
		CheckOutImg       []byte
	})
	for _, s := range snapshots {
		snapshotMap[s.Date.Format("2006-01-02")] = s
	}

	var totalPresent, totalAbsent, totalLeave int
	var totalWorkDuration int64
	var totalDistance float64

	presentDays := make([]gin.H, 0)
	absentDays := make([]string, 0)
	leaveDays := make([]gin.H, 0)
	weeklyOffDays := make([]string, 0)
	holidayDays := make([]string, 0)

	// totalWorkingDays := "work days" excluding holidays and weekly offs
	totalWorkingDays := 0

	for _, day := range daysToShow {
		dayStr := day.Format("2006-01-02")
		dayIsHoliday := isHoliday(info.OrgID, day)
		dayIsWeeklyOff := isWeeklyOff(org, day)

		// Always show weekly off / holiday classification...
		if dayIsHoliday {
			holidayDays = append(holidayDays, dayStr)
		}
		if dayIsWeeklyOff {
			weeklyOffDays = append(weeklyOffDays, dayStr)
		}

		// ...but if user checked-in / has snapshot for the day, still show attendance details (even on weekly-off/holiday)
		if snapshot, exists := snapshotMap[dayStr]; exists {
			switch snapshot.Status {
			case "Present":
				totalPresent++
				if snapshot.WorkDuration != nil {
					totalWorkDuration += int64(*snapshot.WorkDuration)
				}
				if snapshot.DistanceTravelled != nil {
					totalDistance += *snapshot.DistanceTravelled
				}

				pd := gin.H{
					"date":                dayStr,
					"work_duration":       snapshot.WorkDuration,
					"distance_travelled":  snapshot.DistanceTravelled,
					"check_in_latitude":   snapshot.CheckInLatitude,
					"check_in_longitude":  snapshot.CheckInLongitude,
					"check_out_latitude":  snapshot.CheckOutLatitude,
					"check_out_longitude": snapshot.CheckOutLongitude,
					"is_weekly_off":       dayIsWeeklyOff,
					"is_holiday":          dayIsHoliday,
				}

				if snapshot.CheckIn != nil {
					pd["check_in"] = utils.FormatIST(snapshot.CheckIn)
				} else {
					pd["check_in"] = nil
				}
				if snapshot.CheckOut != nil {
					pd["check_out"] = utils.FormatIST(snapshot.CheckOut)
				} else {
					pd["check_out"] = nil
				}

				if len(snapshot.CheckInImg) > 0 {
					pd["has_check_in_image"] = true
					pd["check_in_image"] = "data:image/jpeg;base64," + base64.StdEncoding.EncodeToString(snapshot.CheckInImg)
				} else {
					pd["has_check_in_image"] = false
					pd["check_in_image"] = nil
				}

				if len(snapshot.CheckOutImg) > 0 {
					pd["has_check_out_image"] = true
					pd["check_out_image"] = "data:image/jpeg;base64," + base64.StdEncoding.EncodeToString(snapshot.CheckOutImg)
				} else {
					pd["has_check_out_image"] = false
					pd["check_out_image"] = nil
				}

				presentDays = append(presentDays, pd)

			case "On Leave":
				// Count leave only if it is a working day
				if !dayIsHoliday && !dayIsWeeklyOff {
					totalLeave++
				}
				leaveDays = append(leaveDays, gin.H{
					"date":          dayStr,
					"type":          snapshot.LeaveType,
					"reason":        snapshot.LeaveReason,
					"is_weekly_off": dayIsWeeklyOff,
					"is_holiday":    dayIsHoliday,
				})

			default: // Absent or other statuses
				// Count absent only if it is a working day
				if !dayIsHoliday && !dayIsWeeklyOff {
					totalAbsent++
					absentDays = append(absentDays, dayStr)
				}
			}
		} else {
			// No snapshot -> consider absent only if it is a working day
			if !dayIsHoliday && !dayIsWeeklyOff {
				totalAbsent++
				absentDays = append(absentDays, dayStr)
			}
		}

		// total working day count excludes weekly-off and holidays
		if !dayIsHoliday && !dayIsWeeklyOff {
			totalWorkingDays++
		}
	}

	attendancePercentage := 0.0
	if totalWorkingDays > 0 {
		attendancePercentage = (float64(totalPresent) / float64(totalWorkingDays)) * 100
	}

	totalWorkHours := int(totalWorkDuration) / 60
	totalWorkMinutes := int(totalWorkDuration) % 60

	return gin.H{
		"year":  year,
		"month": month,
		"employee": gin.H{
			"user_id":     info.UserID,
			"employee_id": info.EmployeeId,
			"name":        info.FirstName + " " + info.LastName,
			"email":       info.Email,
		},
		"organization": gin.H{
			"org_id":   info.OrgID,
			"org_code": info.OrgCode,
		},
		"summary": gin.H{
			"total_working_days":       totalWorkingDays,
			"total_present":            totalPresent,
			"total_absent":             totalAbsent,
			"total_leave":              totalLeave,
			"attendance_percentage":    fmt.Sprintf("%.2f", attendancePercentage),
			"total_work_duration":      fmt.Sprintf("%dh %dm", totalWorkHours, totalWorkMinutes),
			"total_distance_travelled": fmt.Sprintf("%.2f km", totalDistance),
		},
		"details": gin.H{
			"present_days":    presentDays,
			"absent_days":     absentDays,
			"leave_days":      leaveDays,
			"weekly_off_days": weeklyOffDays,
			"holiday_days":    holidayDays,
		},
	}
}

// GetOrganizationMonthlyAttendanceReport fetches monthly attendance for all employees (FULLY OPTIMIZED)
func GetOrganizationMonthlyAttendanceReport(c *gin.Context) {
	orgID := c.Param("org_id")
	year := c.Query("year")
	month := c.Query("month")

	log.Printf("Getting Organization Monthly Attendance Report for Org: %s", orgID)

	if orgID == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Organization ID is required"})
		return
	}

	// Parse year and month
	var targetYear, targetMonth int
	now := time.Now()

	if year == "" || month == "" {
		targetYear = now.Year()
		targetMonth = int(now.Month())
	} else {
		var err error
		targetYear, err = strconv.Atoi(year)
		if err != nil || targetYear < 2000 || targetYear > 2100 {
			c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid year"})
			return
		}

		targetMonth, err = strconv.Atoi(month)
		if err != nil || targetMonth < 1 || targetMonth > 12 {
			c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid month (1-12)"})
			return
		}
	}

	// QUERY 1: Get organization with working days pattern
	var org models.Organisation
	if err := db.DB.Select("id, organisation_code, days, weekly_offs").Where("id = ?", orgID).First(&org).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Organization not found"})
		return
	}

	// Calculate date range
	firstDay := time.Date(targetYear, time.Month(targetMonth), 1, 0, 0, 0, 0, time.UTC)
	lastDay := time.Date(targetYear, time.Month(targetMonth)+1, 1, 0, 0, 0, 0, time.UTC)

	var daysToShow []time.Time
	for _, day := range allDays(targetYear, time.Month(targetMonth)) {
		if day.Before(now) || day.Format("2006-01-02") == now.Format("2006-01-02") {
			daysToShow = append(daysToShow, day)
		}
	}

	// totalWorkingDays excludes org holidays and weekly offs
	totalWorkingDays := 0
	for _, day := range daysToShow {
		if isHoliday(org.ID, day) {
			continue
		}
		if isWeeklyOff(org, day) {
			continue
		}
		totalWorkingDays++
	}

	// QUERY 2: Get all users in the organization
	var users []UserOrgInfo
	err := db.DB.Table("organisation_users ou").
		Select(`
            ou.user_id,
            ou.organisation_id as org_id,
            ud.first_name,
            ud.last_name,
            ud.email,
            ud.employee_id,
            ? as org_code,
            ? as days
        `, org.OrganisationCode, org.Days).
		Joins("JOIN user_details ud ON ud.id = ou.user_id").
		Where("ou.organisation_id = ?", orgID).
		Scan(&users).Error

	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	if len(users) == 0 {
		c.JSON(http.StatusOK, gin.H{
			"year":             targetYear,
			"month":            targetMonth,
			"organization":     gin.H{"org_id": org.ID, "org_code": org.OrganisationCode},
			"total_employees":  0,
			"employee_reports": []gin.H{},
		})
		return
	}

	// QUERY 3: Get ALL snapshots for ALL users in ONE query (without images first for speed)
	type SnapshotRow struct {
		UserID            uint
		Date              time.Time
		Status            string
		CheckIn           *time.Time
		CheckOut          *time.Time
		WorkDuration      *int
		DistanceTravelled *float64
		LeaveType         *string
		LeaveReason       *string
		CheckInLatitude   *float64
		CheckInLongitude  *float64
		CheckOutLatitude  *float64
		CheckOutLongitude *float64
		CheckInImg        []byte
		CheckOutImg       []byte
	}

	var allSnapshots []SnapshotRow
	db.DB.Model(&models.DailyAttendanceSnapshot{}).
		Select(`
            user_id, date, status, check_in, check_out, work_duration, distance_travelled,
            leave_type, leave_reason,
            check_in_latitude, check_in_longitude, check_out_latitude, check_out_longitude,
            check_in_img, check_out_img
        `).
		Where("org_id = ? AND date >= ? AND date < ?", orgID, firstDay, lastDay).
		Scan(&allSnapshots)

	// Build a nested map: user_id -> date_string -> snapshot for O(1) lookup
	userSnapshotMap := make(map[uint]map[string]SnapshotRow)
	for _, s := range allSnapshots {
		if userSnapshotMap[s.UserID] == nil {
			userSnapshotMap[s.UserID] = make(map[string]SnapshotRow)
		}
		userSnapshotMap[s.UserID][s.Date.Format("2006-01-02")] = s
	}

	// Process all users in memory (NO more DB queries!)
	employeeReports := make([]gin.H, 0, len(users))

	for _, user := range users {
		userSnapshots := userSnapshotMap[user.UserID]
		if userSnapshots == nil {
			userSnapshots = make(map[string]SnapshotRow)
		}

		// Calculate stats for this user
		var totalPresent, totalAbsent, totalLeave int
		var totalWorkDuration int64
		var totalDistance float64

		presentDays := make([]gin.H, 0)
		absentDays := make([]string, 0)
		leaveDays := make([]gin.H, 0)
		weeklyOffDays := make([]string, 0)
		holidayDays := make([]string, 0)

		for _, day := range daysToShow {
			dayStr := day.Format("2006-01-02")
			dayIsHoliday := isHoliday(org.ID, day)
			dayIsWeeklyOff := isWeeklyOff(org, day)

			// Always include classification lists
			if dayIsHoliday {
				holidayDays = append(holidayDays, dayStr)
			}
			if dayIsWeeklyOff {
				weeklyOffDays = append(weeklyOffDays, dayStr)
			}

			// If user has data on weekly-off/holiday, still show it
			if snapshot, exists := userSnapshots[dayStr]; exists {
				switch snapshot.Status {
				case "Present":
					totalPresent++
					if snapshot.WorkDuration != nil {
						totalWorkDuration += int64(*snapshot.WorkDuration)
					}
					if snapshot.DistanceTravelled != nil {
						totalDistance += *snapshot.DistanceTravelled
					}

					pd := gin.H{
						"date":                dayStr,
						"work_duration":       snapshot.WorkDuration,
						"distance_travelled":  snapshot.DistanceTravelled,
						"check_in_latitude":   snapshot.CheckInLatitude,
						"check_in_longitude":  snapshot.CheckInLongitude,
						"check_out_latitude":  snapshot.CheckOutLatitude,
						"check_out_longitude": snapshot.CheckOutLongitude,
						"is_weekly_off":       dayIsWeeklyOff,
						"is_holiday":          dayIsHoliday,
					}

					if snapshot.CheckIn != nil {
						pd["check_in"] = utils.FormatIST(snapshot.CheckIn)
					} else {
						pd["check_in"] = nil
					}

					if snapshot.CheckOut != nil {
						pd["check_out"] = utils.FormatIST(snapshot.CheckOut)
					} else {
						pd["check_out"] = nil
					}

					if len(snapshot.CheckInImg) > 0 {
						pd["has_check_in_image"] = true
						pd["check_in_image"] = "data:image/jpeg;base64," + base64.StdEncoding.EncodeToString(snapshot.CheckInImg)
					} else {
						pd["has_check_in_image"] = false
						pd["check_in_image"] = nil
					}

					if len(snapshot.CheckOutImg) > 0 {
						pd["has_check_out_image"] = true
						pd["check_out_image"] = "data:image/jpeg;base64," + base64.StdEncoding.EncodeToString(snapshot.CheckOutImg)
					} else {
						pd["has_check_out_image"] = false
						pd["check_out_image"] = nil
					}

					presentDays = append(presentDays, pd)

				case "On Leave":
					if !dayIsHoliday && !dayIsWeeklyOff {
						totalLeave++
					}
					leaveDays = append(leaveDays, gin.H{
						"date":          dayStr,
						"type":          snapshot.LeaveType,
						"reason":        snapshot.LeaveReason,
						"is_weekly_off": dayIsWeeklyOff,
						"is_holiday":    dayIsHoliday,
					})

				case "Absent":
					if !dayIsHoliday && !dayIsWeeklyOff {
						totalAbsent++
						absentDays = append(absentDays, dayStr)
					}
				}
			} else {
				// No snapshot: absent only on working days
				if !dayIsHoliday && !dayIsWeeklyOff {
					totalAbsent++
					absentDays = append(absentDays, dayStr)
				}
			}
		}

		// Calculate attendance percentage
		attendancePercentage := 0.0
		if totalWorkingDays > 0 {
			attendancePercentage = (float64(totalPresent) / float64(totalWorkingDays)) * 100
		}

		totalWorkHours := int(totalWorkDuration) / 60
		totalWorkMinutes := int(totalWorkDuration) % 60

		report := gin.H{
			"year":  targetYear,
			"month": targetMonth,
			"employee": gin.H{
				"user_id":     user.UserID,
				"employee_id": user.EmployeeId,
				"name":        user.FirstName + " " + user.LastName,
				"email":       user.Email,
			},
			"organization": gin.H{
				"org_id":   user.OrgID,
				"org_code": user.OrgCode,
			},
			"summary": gin.H{
				"total_working_days":       totalWorkingDays,
				"total_present":            totalPresent,
				"total_absent":             totalAbsent,
				"total_leave":              totalLeave,
				"attendance_percentage":    fmt.Sprintf("%.2f", attendancePercentage),
				"total_work_duration":      fmt.Sprintf("%dh %dm", totalWorkHours, totalWorkMinutes),
				"total_distance_travelled": fmt.Sprintf("%.2f km", totalDistance),
			},
			"details": gin.H{
				"present_days":    presentDays,
				"absent_days":     absentDays,
				"leave_days":      leaveDays,
				"weekly_off_days": weeklyOffDays,
				"holiday_days":    holidayDays,
			},
		}

		employeeReports = append(employeeReports, report)
	}

	c.JSON(http.StatusOK, gin.H{
		"year":  targetYear,
		"month": targetMonth,
		"organization": gin.H{
			"org_id":   org.ID,
			"org_code": org.OrganisationCode,
		},
		"total_employees":  len(employeeReports),
		"employee_reports": employeeReports,
	})
}

// TriggerAttendanceSnapshotManually - Admin endpoint to manually trigger snapshot computation
func TriggerAttendanceSnapshotManually(c *gin.Context) {
	// Get date from query parameter or use yesterday
	dateParam := c.Query("date") // Format: YYYY-MM-DD

	var targetDate time.Time
	if dateParam != "" {
		parsedDate, err := time.Parse("2006-01-02", dateParam)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid date format. Use YYYY-MM-DD"})
			return
		}
		targetDate = parsedDate
	} else {
		// Default to yesterday
		now := time.Now()
		targetDate = now.AddDate(0, 0, -1)
	}

	targetDate = time.Date(targetDate.Year(), targetDate.Month(), targetDate.Day(), 0, 0, 0, 0, targetDate.Location())
	dateOnly := targetDate.Format("2006-01-02")

	log.Printf("[Manual Trigger] Computing attendance snapshot for date: %s", dateOnly)

	// Get all organizations
	var orgs []models.Organisation
	if err := db.DB.Find(&orgs).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to fetch organizations"})
		return
	}

	results := make([]gin.H, 0)

	for _, org := range orgs {
		log.Printf("[Manual Trigger] Processing organization: %d (%s)", org.ID, org.OrganisationCode)

		// Count snapshots before
		var countBefore int64
		db.DB.Model(&models.DailyAttendanceSnapshot{}).Where("org_id = ? AND DATE(date) = ?", org.ID, dateOnly).Count(&countBefore)

		processOrganizationAttendance(org.ID, targetDate, dateOnly)

		// Count snapshots after
		var countAfter int64
		db.DB.Model(&models.DailyAttendanceSnapshot{}).Where("org_id = ? AND DATE(date) = ?", org.ID, dateOnly).Count(&countAfter)

		results = append(results, gin.H{
			"org_id":           org.ID,
			"org_code":         org.OrganisationCode,
			"snapshots_before": countBefore,
			"snapshots_after":  countAfter,
			"new_snapshots":    countAfter - countBefore,
		})
	}

	c.JSON(http.StatusOK, gin.H{
		"message":             "Snapshot computation completed",
		"date":                dateOnly,
		"organizations_count": len(orgs),
		"results":             results,
	})
}

// BackfillAttendanceSnapshots backfills historical attendance data for a date range
func BackfillAttendanceSnapshots(startDate, endDate time.Time) error {
	log.Printf("[Backfill] Starting backfill from %s to %s", startDate.Format("2006-01-02"), endDate.Format("2006-01-02"))

	// Get all organizations
	var orgs []models.Organisation
	if err := db.DB.Find(&orgs).Error; err != nil {
		log.Printf("[Backfill] Error fetching organizations: %v", err)
		return err
	}

	// Iterate through each date
	currentDate := startDate
	for currentDate.Before(endDate) || currentDate.Equal(endDate) {
		dateOnly := currentDate.Format("2006-01-02")
		log.Printf("[Backfill] Processing date: %s", dateOnly)

		for _, org := range orgs {
			log.Printf("[Backfill] Processing org: %d (%s) for date: %s", org.ID, org.OrganisationCode, dateOnly)
			processOrganizationAttendance(org.ID, currentDate, dateOnly)
		}

		// Move to next day
		currentDate = currentDate.AddDate(0, 0, 1)
	}

	log.Printf("[Backfill] Completed backfill from %s to %s", startDate.Format("2006-01-02"), endDate.Format("2006-01-02"))
	return nil
}

// BackfillAttendanceSnapshotsForOrg backfills data for a specific organization
func BackfillAttendanceSnapshotsForOrg(orgID uint, startDate, endDate time.Time) error {
	log.Printf("[Backfill] Starting backfill for org %d from %s to %s", orgID, startDate.Format("2006-01-02"), endDate.Format("2006-01-02"))

	currentDate := startDate
	for currentDate.Before(endDate) || currentDate.Equal(endDate) {
		dateOnly := currentDate.Format("2006-01-02")
		processOrganizationAttendance(orgID, currentDate, dateOnly)
		currentDate = currentDate.AddDate(0, 0, 1)
	}

	log.Printf("[Backfill] Completed backfill for org %d", orgID)
	return nil
}

// BackfillAttendanceSnapshotsEndpoint - Admin endpoint to backfill historical data
func BackfillAttendanceSnapshotsEndpoint(c *gin.Context) {
	startDateStr := c.Query("start_date") // Format: YYYY-MM-DD
	endDateStr := c.Query("end_date")     // Format: YYYY-MM-DD
	orgIDStr := c.Query("org_id")         // Optional: specific organization

	// Validate dates
	if startDateStr == "" || endDateStr == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "start_date and end_date are required (YYYY-MM-DD format)"})
		return
	}

	startDate, err := time.Parse("2006-01-02", startDateStr)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid start_date format. Use YYYY-MM-DD"})
		return
	}

	endDate, err := time.Parse("2006-01-02", endDateStr)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid end_date format. Use YYYY-MM-DD"})
		return
	}

	// Validate date range
	if endDate.Before(startDate) {
		c.JSON(http.StatusBadRequest, gin.H{"error": "end_date must be after or equal to start_date"})
		return
	}

	// Check if date range is too large (prevent server overload)
	daysDiff := int(endDate.Sub(startDate).Hours() / 24)
	if daysDiff > 365 {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Date range cannot exceed 365 days"})
		return
	}

	// If org_id is provided, backfill for specific organization
	if orgIDStr != "" {
		orgID, err := strconv.ParseUint(orgIDStr, 10, 32)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid org_id"})
			return
		}

		log.Printf("[Backfill] Starting backfill for org %d from %s to %s", orgID, startDateStr, endDateStr)

		err = BackfillAttendanceSnapshotsForOrg(uint(orgID), startDate, endDate)
		if err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
			return
		}

		c.JSON(http.StatusOK, gin.H{
			"message":    "Backfill completed successfully",
			"org_id":     orgID,
			"start_date": startDateStr,
			"end_date":   endDateStr,
			"days":       daysDiff + 1,
		})
		return
	}

	// Backfill for all organizations
	log.Printf("[Backfill] Starting backfill for all organizations from %s to %s", startDateStr, endDateStr)

	err = BackfillAttendanceSnapshots(startDate, endDate)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"message":    "Backfill completed successfully",
		"start_date": startDateStr,
		"end_date":   endDateStr,
		"days":       daysDiff + 1,
	})
}

// GetBackfillStatus - Check backfill progress
func GetBackfillStatus(c *gin.Context) {
	// Get the earliest attendance record
	var earliestAttendance models.UserAttendance
	db.DB.Order("check_in ASC").First(&earliestAttendance)

	// Get the earliest snapshot
	var earliestSnapshot models.DailyAttendanceSnapshot
	db.DB.Order("date ASC").First(&earliestSnapshot)

	// Get the latest snapshot
	var latestSnapshot models.DailyAttendanceSnapshot
	db.DB.Order("date DESC").First(&latestSnapshot)

	// Count total snapshots
	var totalSnapshots int64
	db.DB.Model(&models.DailyAttendanceSnapshot{}).Count(&totalSnapshots)

	// Get snapshots by organization
	var orgSnapshots []struct {
		OrgID uint
		Count int64
	}
	db.DB.Model(&models.DailyAttendanceSnapshot{}).
		Select("org_id, COUNT(*) as count").
		Group("org_id").
		Scan(&orgSnapshots)

	response := gin.H{
		"total_snapshots":          totalSnapshots,
		"earliest_attendance_date": "",
		"earliest_snapshot_date":   "",
		"latest_snapshot_date":     "",
		"snapshots_by_org":         orgSnapshots,
	}

	if !earliestAttendance.CheckIn.IsZero() {
		response["earliest_attendance_date"] = earliestAttendance.CheckIn.Format("2006-01-02")
	}

	if !earliestSnapshot.Date.IsZero() {
		response["earliest_snapshot_date"] = earliestSnapshot.Date.Format("2006-01-02")
	}

	if !latestSnapshot.Date.IsZero() {
		response["latest_snapshot_date"] = latestSnapshot.Date.Format("2006-01-02")
	}

	c.JSON(http.StatusOK, response)
}

func isHoliday(orgID uint, date time.Time) bool {
	var count int64
	db.DB.Model(&models.OrganisationHoliday{}).
		Where("organisation_id = ? AND date = ?", orgID, date.Format("2006-01-02")).
		Count(&count)
	return count > 0
}

