package config

import (
	"os"
)

type Config struct {
	GeminiAPIKey   string
	Port           string
	OpenCageAPIKey string
}

func New() *Config {
	return &Config{
		GeminiAPIKey:   os.Getenv("GeminiAPIKey"),
		Port:           getEnv("PORT", "8080"),
		OpenCageAPIKey: os.Getenv("OpenCageAPIKey"),
	}
}

func getEnv(key, defaultValue string) string {
	if value := os.Getenv(key); value != "" {
		return value
	}
	return defaultValue
}

