import 'package:flutter/material.dart';
import 'package:health_connector/health_connector_internal.dart'
    as hc
    show SpeedSample, Velocity;
import 'package:ai_health/src/common/constants/app_icons.dart';
import 'package:ai_health/src/common/constants/app_texts.dart';
import 'package:ai_health/src/features/write_health_record/widgets/write_form_fields/record_sample_form_field_group.dart';


@immutable
final class SpeedSampleWriteFormFieldGroup extends StatelessWidget {
  const SpeedSampleWriteFormFieldGroup({
    required this.startDateTime,
    required this.endDateTime,
    required this.onChanged,
    super.key,
    this.initialSamples,
    this.validator,
  });

  final DateTime? startDateTime;
  final DateTime? endDateTime;
  final ValueChanged<List<hc.SpeedSample>?> onChanged;
  final List<hc.SpeedSample>? initialSamples;
  final String? Function(List<hc.SpeedSample>?)? validator;

  @override
  Widget build(BuildContext context) {
    return RecordSampleFormFieldGroup<hc.SpeedSample, double>(
      title: AppTexts.speedSamples,
      startDateTime: startDateTime,
      endDateTime: endDateTime,
      onChanged: onChanged,
      initialSamples: initialSamples,
      validator: validator,
      defaultValue: 1.0,
      valueInputBuilder: (index, speed, onSpeedChanged) {
        return TextFormField(
          initialValue: speed?.toStringAsFixed(2),
          decoration: InputDecoration(
            labelText: AppTexts.withUnit(
              AppTexts.speed,
              AppTexts.metersPerSecond,
            ),
            border: const OutlineInputBorder(),
            prefixIcon: const Icon(AppIcons.speed),
          ),
          keyboardType: const TextInputType.numberWithOptions(decimal: true),
          onChanged: (value) {
            final parsedSpeed = double.tryParse(value);
            if (parsedSpeed != null) {
              onSpeedChanged(parsedSpeed);
            }
          },
        );
      },
      sampleFactory: (time, _, speed) => hc.SpeedSample(
        time: time,
        speed: hc.Velocity.metersPerSecond(speed),
      ),
      sampleExtractor: (sample) => (
        time: sample.time,
        endTime: null as DateTime?,
        value: sample.speed.inMetersPerSecond,
      ),
      valueValidator: (speed) => speed != null && speed > 0,
    );
  }
}

