package utils

import (
	"fmt"
	"time"
)

func GetTimeContext() string {
	now := time.Now()
	hour := now.Hour()

	switch {
	case hour >= 5 && hour < 12:
		return fmt.Sprintf("Morning (%s) - great time for breakfast, coffee, parks, or sightseeing", now.Format("3:04 PM"))
	case hour >= 12 && hour < 17:
		return fmt.Sprintf("Afternoon (%s) - perfect for lunch, shopping, museums, or outdoor activities", now.Format("3:04 PM"))
	case hour >= 17 && hour < 21:
		return fmt.Sprintf("Evening (%s) - ideal for dinner, entertainment, bars, or sunset spots", now.Format("3:04 PM"))
	default:
		return fmt.Sprintf("Night (%s) - good for late dining, bars, nightlife, or 24/7 spots", now.Format("3:04 PM"))
	}
}

func GetCurrentTimestamp() string {
	return time.Now().Format("2006-01-02 15:04:05")
}

