package handlers

import (
	"core-backend/m/v2/cache"
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	structure "core-backend/m/v2/openapi_structure"
	"core-backend/m/v2/utils"
	"fmt"
	"log"
	"net/http"
	"strconv"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/redis/go-redis/v9"
)

func GetDashboard(c *gin.Context) {
	orgid := c.Param("id")
	id, err := strconv.ParseUint(orgid, 10, 64)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid org ID"})
		return
	}

	var org models.Organisation
	if err := db.DB.Where("id = ?", orgid).First(&org).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Organisation not found"})
		return
	}

	var user models.UserDetail
	if err := db.DB.Where("id = ?", org.AdminRegister).First(&user).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to retrieve admin details"})
		return
	}

	// Try to get tasks from cache
	tasks, err := cache.GetDashboardTasksFromCache(uint(id))
	cachedTasks := true
	if err != nil {
		if err == redis.Nil {
			log.Printf("Tasks not found in cache for org %d, fetching from DB", id)
		} else {
			log.Printf("Failed to get tasks from cache for org %d: %v", id, err)
		}
		cachedTasks = false
	}

	// Try to get leaves from cache
	leaves, err := cache.GetDashboardLeavesFromCache(uint(id))
	cachedLeaves := true
	if err != nil {
		if err == redis.Nil {
			log.Printf("Leaves not found in cache for org %d, fetching from DB", id)
		} else {
			log.Printf("Failed to get leaves from cache for org %d: %v", id, err)
		}
		cachedLeaves = false
	}

	// Filter today's leaves regardless of where the leaves come from (cache or DB)
	var todaysLeaves []models.UserLeave
	today := utils.GetCurrentTimeIST().Format("2006-01-02")

	// If either data is not cached, fetch from database
	if !cachedTasks || !cachedLeaves {
		var users []models.OrganisationUser
		if err := db.DB.Where("organisation_id = ?", id).Find(&users).Error; err != nil {
			fmt.Print(err.Error())
			c.JSON(500, err.Error())
			return
		}

		// Fetch leaves if not cached
		if !cachedLeaves {
			leaves = []models.UserLeave{}
			for _, a := range users {
				var leave []models.UserLeave
				if err := db.DB.
					Preload("User").
					Joins("JOIN user_details AS ud ON ud.id = user_leaves.user_id").
					Where("user_leaves.user_id = ? AND status = 1", a.UserId).
					Find(&leave).Error; err != nil {
					fmt.Print(err.Error())
					c.JSON(500, err.Error())
					return
				}
				for i := range leave {
					startDate, _ := time.Parse(time.RFC3339, leave[i].StartDate)
					endDate, _ := time.Parse(time.RFC3339, leave[i].EndDate)
					startDateStr := startDate.Format("2006-01-02")
					endDateStr := endDate.Format("2006-01-02")

					if today >= startDateStr && today <= endDateStr {
						todaysLeaves = append(todaysLeaves, leave[i])
					}
				}
				leaves = append(leaves, leave...)
			}

			// Cache the leaves
			err = cache.SetDashboardLeavesToCache(uint(id), leaves)
			if err != nil {
				log.Printf("Failed to cache leaves for org %d: %v", id, err)
			}
		}

		// Fetch tasks if not cached
		if !cachedTasks {
			tasks = []models.Task{}
			for _, user := range users {
				var usertasks []models.Task
				if err := db.DB.Preload("Project").Preload("Assignee").Preload("AssignedBy").
					Where("assignee_id = ?", user.UserId).Find(&usertasks).Error; err != nil {
					c.JSON(404, err.Error())
					return
				}
				tasks = append(tasks, usertasks...)
			}

			// Cache the tasks
			err = cache.SetDashboardTasksToCache(uint(id), tasks)
			if err != nil {
				log.Printf("Failed to cache tasks for org %d: %v", id, err)
			}
		}
	} else {
		for i := range leaves {
			startDate, _ := time.Parse(time.RFC3339, leaves[i].StartDate)
			endDate, _ := time.Parse(time.RFC3339, leaves[i].EndDate)
			startDateStr := startDate.Format("2006-01-02")
			endDateStr := endDate.Format("2006-01-02")

			if today >= startDateStr && today <= endDateStr {
				todaysLeaves = append(todaysLeaves, leaves[i])
			}
		}
	}

	var response *structure.OrganizationResponse = &structure.OrganizationResponse{
		ID:         org.ID,
		OrgName:    org.OrganisationCode,
		Firstname:  user.FirstName,
		Lastname:   user.LastName,
		CreatedAt:  org.CreatedAt.String(),
		WebsiteURL: org.WebsiteUrl,
		Status:     org.Status,
		AdminPhone: user.Phone,
		AdminEmail: user.Email,
		OrgAddress: org.Address,
		Size:       org.OrgSize,
		Features:   org.Features,
		Days:       org.Days,
	}

	c.JSON(http.StatusOK, gin.H{
		"organisation": response,
		"tasks":        tasks,
		"leaves":       todaysLeaves,
	})
}

// UpdateDashboardLocation stores user location when they open the dashboard/app
func UpdateDashboardLocation(c *gin.Context) {
	userId := c.MustGet("id").(uint)

	var req struct {
		Latitude  float64 `json:"latitude" binding:"required"`
		Longitude float64 `json:"longitude" binding:"required"`
	}

	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	// Store location in user_locations table
	location := &models.UserLocation{
		UserId:         models.UserID(userId),
		Latitude:       req.Latitude,
		Longitude:      req.Longitude,
		StartTimestamp: models.LocationTime(utils.GetCurrentTimeIST()),
		EndTimestamp:   models.LocationTime(utils.GetCurrentTimeIST()),
		AreaName:       "", // Will be populated by reverse geocoding if needed
	}

	if err := db.DB.Create(&location).Error; err != nil {
		log.Printf("Failed to store dashboard location for user %d: %v", userId, err)
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to store location"})
		return
	}

	log.Printf("Dashboard location stored for user %d: lat=%.6f, lng=%.6f", userId, req.Latitude, req.Longitude)
	c.JSON(http.StatusOK, gin.H{"message": "Location updated successfully"})
}

