package handlers

import (
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"net/http"
	"strconv"
	"time"

	"github.com/gin-gonic/gin"
	"gorm.io/gorm"
)

// SalaryResponse represents the salary data returned to client with employee details
type SalaryResponse struct {
	ID              uint       `json:"id"`
	UserID          uint       `json:"user_id"`
	EmployeeName    string     `json:"employee_name"`
	EmployeeID      string     `json:"employee_id"`
	EffectiveDate   time.Time  `json:"effective_date"`
	TerminationDate *time.Time `json:"termination_date,omitempty"`
	BaseSalary      float64    `json:"base_salary"`
	UpdatedBy       uint       `json:"updated_by"`
	CreatedAt       time.Time  `json:"created_at"`
	UpdatedAt       time.Time  `json:"updated_at"`
}

// CreateSalary creates a new salary record
func CreateSalary(c *gin.Context) {
	var input struct {
		UserID          uint       `json:"user_id" binding:"required"`
		EffectiveDate   time.Time  `json:"effective_date" binding:"required"`
		TerminationDate *time.Time `json:"termination_date"`
		BaseSalary      float64    `json:"base_salary" binding:"required"`
	}

	if err := c.ShouldBindJSON(&input); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	// Get the user ID from token for UpdatedBy
	updatedBy := c.MustGet("id").(uint)

	// Verify user exists
	var user models.UserDetail
	if err := db.DB.Where("id = ?", input.UserID).First(&user).Error; err != nil {
		if err == gorm.ErrRecordNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "User not found"})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Create salary record
	salary := models.Salary{
		UserID:          input.UserID,
		EffectiveDate:   input.EffectiveDate,
		TerminationDate: input.TerminationDate,
		BaseSalary:      input.BaseSalary,
		UpdatedBy:       updatedBy,
	}

	if err := db.DB.Create(&salary).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Load user details for response
	db.DB.Preload("User").First(&salary, salary.ID)

	response := SalaryResponse{
		ID:              salary.ID,
		UserID:          salary.UserID,
		EmployeeName:    salary.User.FirstName + " " + salary.User.LastName,
		EmployeeID:      salary.User.EmployeeId,
		EffectiveDate:   salary.EffectiveDate,
		TerminationDate: salary.TerminationDate,
		BaseSalary:      salary.BaseSalary,
		UpdatedBy:       salary.UpdatedBy,
		CreatedAt:       salary.CreatedAt,
		UpdatedAt:       salary.UpdatedAt,
	}

	c.JSON(http.StatusCreated, response)
}

// UpdateSalary updates an existing salary record
func UpdateSalary(c *gin.Context) {
	salaryID, err := strconv.ParseUint(c.Param("id"), 10, 32)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid salary ID"})
		return
	}

	var input struct {
		EffectiveDate   *time.Time `json:"effective_date"`
		TerminationDate *time.Time `json:"termination_date"`
		BaseSalary      *float64   `json:"base_salary"`
	}

	if err := c.ShouldBindJSON(&input); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	// Get the user ID from token for UpdatedBy
	updatedBy := c.MustGet("id").(uint)

	// Find existing salary record
	var salary models.Salary
	if err := db.DB.First(&salary, salaryID).Error; err != nil {
		if err == gorm.ErrRecordNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "Salary record not found"})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Update fields if provided
	updates := make(map[string]interface{})
	if input.EffectiveDate != nil {
		updates["effective_date"] = *input.EffectiveDate
	}
	if input.TerminationDate != nil {
		updates["termination_date"] = *input.TerminationDate
	}
	if input.BaseSalary != nil {
		updates["base_salary"] = *input.BaseSalary
	}
	updates["updated_by"] = updatedBy

	if err := db.DB.Model(&salary).Updates(updates).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Reload with user details
	db.DB.Preload("User").First(&salary, salaryID)

	response := SalaryResponse{
		ID:              salary.ID,
		UserID:          salary.UserID,
		EmployeeName:    salary.User.FirstName + " " + salary.User.LastName,
		EmployeeID:      salary.User.EmployeeId,
		EffectiveDate:   salary.EffectiveDate,
		TerminationDate: salary.TerminationDate,
		BaseSalary:      salary.BaseSalary,
		UpdatedBy:       salary.UpdatedBy,
		CreatedAt:       salary.CreatedAt,
		UpdatedAt:       salary.UpdatedAt,
	}

	c.JSON(http.StatusOK, response)
}

// GetSalaryByUser retrieves all salary records for a specific user
func GetSalaryByUser(c *gin.Context) {
	userID, err := strconv.ParseUint(c.Param("userId"), 10, 32)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid user ID"})
		return
	}

	// Verify user exists
	var user models.UserDetail
	if err := db.DB.Where("id = ?", userID).First(&user).Error; err != nil {
		if err == gorm.ErrRecordNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "User not found"})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Get all salary records for user
	var salaries []models.Salary
	if err := db.DB.Preload("User").Where("user_id = ?", userID).Order("effective_date DESC").Find(&salaries).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Build response with employee details
	var response []SalaryResponse
	for _, salary := range salaries {
		response = append(response, SalaryResponse{
			ID:              salary.ID,
			UserID:          salary.UserID,
			EmployeeName:    salary.User.FirstName + " " + salary.User.LastName,
			EmployeeID:      salary.User.EmployeeId,
			EffectiveDate:   salary.EffectiveDate,
			TerminationDate: salary.TerminationDate,
			BaseSalary:      salary.BaseSalary,
			UpdatedBy:       salary.UpdatedBy,
			CreatedAt:       salary.CreatedAt,
			UpdatedAt:       salary.UpdatedAt,
		})
	}

	c.JSON(http.StatusOK, response)
}

// GetSalaryByID retrieves a specific salary record by ID
func GetSalaryByID(c *gin.Context) {
	salaryID, err := strconv.ParseUint(c.Param("id"), 10, 32)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid salary ID"})
		return
	}

	var salary models.Salary
	if err := db.DB.Preload("User").First(&salary, salaryID).Error; err != nil {
		if err == gorm.ErrRecordNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "Salary record not found"})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	response := SalaryResponse{
		ID:              salary.ID,
		UserID:          salary.UserID,
		EmployeeName:    salary.User.FirstName + " " + salary.User.LastName,
		EmployeeID:      salary.User.EmployeeId,
		EffectiveDate:   salary.EffectiveDate,
		TerminationDate: salary.TerminationDate,
		BaseSalary:      salary.BaseSalary,
		UpdatedBy:       salary.UpdatedBy,
		CreatedAt:       salary.CreatedAt,
		UpdatedAt:       salary.UpdatedAt,
	}

	c.JSON(http.StatusOK, response)
}

// GetSalaryAudit retrieves the complete audit trail for a salary record
func GetSalaryAudit(c *gin.Context) {
	salaryID, err := strconv.ParseUint(c.Param("salaryId"), 10, 32)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid salary ID"})
		return
	}

	// Verify salary record exists
	var salary models.Salary
	if err := db.DB.First(&salary, salaryID).Error; err != nil {
		if err == gorm.ErrRecordNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "Salary record not found"})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Get audit trail
	var auditRecords []models.SalaryAudit
	if err := db.DB.Where("salary_id = ?", salaryID).Order("sequence_number ASC").Find(&auditRecords).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, auditRecords)
}

// DeleteSalary soft deletes a salary record
func DeleteSalary(c *gin.Context) {
	salaryID, err := strconv.ParseUint(c.Param("id"), 10, 32)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid salary ID"})
		return
	}

	// Get the user ID from token for UpdatedBy
	updatedBy := c.MustGet("id").(uint)

	// Find salary record
	var salary models.Salary
	if err := db.DB.First(&salary, salaryID).Error; err != nil {
		if err == gorm.ErrRecordNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "Salary record not found"})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Set UpdatedBy before deletion so it's recorded in audit
	salary.UpdatedBy = updatedBy
	db.DB.Save(&salary)

	// Soft delete
	if err := db.DB.Delete(&salary).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "Salary record deleted successfully"})
}

