package services

import (
	"core-backend/m/v2/LLM_part/models"
	"core-backend/m/v2/db"
	"fmt"
	"time"

	"github.com/google/uuid"
)

type LLMTrackingService struct{}

func (s *LLMTrackingService) GetResponsesWithFilter(orgID uint, page, limit int, cityName, nearTagged string) ([]models.LLMResponse, int64, error) {
	if page < 1 {
		page = 1
	}
	if limit < 1 {
		limit = 20
	}

	query := db.DB.Model(&models.LLMResponse{}).Where("organisation_id = ?", orgID)

	if cityName != "" {
		query = query.Where("city_name ILIKE ?", "%"+cityName+"%")
	}

	if nearTagged == "true" {
		query = query.Where("is_near_tagged_place = ?", true)
	} else if nearTagged == "false" {
		query = query.Where("is_near_tagged_place = ?", false)
	}

	var total int64
	if err := query.Count(&total).Error; err != nil {
		return nil, 0, err
	}

	var responses []models.LLMResponse
	offset := (page - 1) * limit

	err := query.Order("created_at DESC").
		Offset(offset).
		Limit(limit).
		Find(&responses).Error

	return responses, total, err
}

func NewLLMTrackingService() *LLMTrackingService {
	return &LLMTrackingService{}
}

// CreateRequest creates a new LLM request record
func (s *LLMTrackingService) CreateRequest(orgID uint, coordinatesCount int, timeContext string) (*models.LLMRequest, error) {
	requestID := uuid.New().String()

	request := &models.LLMRequest{
		OrganisationID:   orgID,
		RequestID:        requestID,
		CoordinatesCount: coordinatesCount,
		TimeContext:      timeContext,
		RequestTimestamp: time.Now(),
		Status:           "processing",
	}

	if err := db.DB.Create(request).Error; err != nil {
		return nil, fmt.Errorf("failed to create LLM request: %v", err)
	}

	return request, nil
}

// UpdateRequestStatus updates the request with final results
func (s *LLMTrackingService) UpdateRequestStatus(requestID string, status string, processingTime int64, totalLocations, taggedLocations int, errorMsg string) error {
	updates := map[string]interface{}{
		"status":           status,
		"processing_time":  processingTime,
		"total_locations":  totalLocations,
		"tagged_locations": taggedLocations,
	}

	if errorMsg != "" {
		updates["error_message"] = errorMsg
	}

	return db.DB.Model(&models.LLMRequest{}).
		Where("request_id = ?", requestID).
		Updates(updates).Error
}

// SaveResponses saves all location recommendations for a request
func (s *LLMTrackingService) SaveResponses(requestID string, orgID uint, recommendations []models.LocationRecommendation) error {
	var responses []models.LLMResponse

	for _, rec := range recommendations {
		response := models.LLMResponse{
			RequestID:         requestID,
			OrganisationID:    orgID,
			Latitude:          rec.Latitude,
			Longitude:         rec.Longitude,
			CityName:          rec.CityName,
			Recommendation:    rec.Recommendation,
			IsNearTaggedPlace: rec.IsNearTaggedPlace,
		}

		// Add nearby location info if available
		if len(rec.NearbyLocations) > 0 {
			nearest := rec.NearbyLocations[0]
			for _, loc := range rec.NearbyLocations {
				if loc.Distance < nearest.Distance {
					nearest = loc
				}
			}
			nearbyID := uint(nearest.LocationTag.ID)
			response.NearbyLocationID = &nearbyID
			response.Distance = nearest.Distance
			response.LocationName = nearest.LocationTag.LocationName
		}

		responses = append(responses, response)
	}

	if len(responses) > 0 {
		return db.DB.CreateInBatches(responses, 100).Error
	}

	return nil
}

func (s *LLMTrackingService) GetOrganisationStats(orgID uint, startDate, endDate *time.Time) (*models.LLMStats, error) {
	stats := &models.LLMStats{
		OrganisationID: orgID,
	}

	query := db.DB.Model(&models.LLMRequest{}).Where("organisation_id = ?", orgID)

	// Apply date filters if provided
	if startDate != nil {
		query = query.Where("request_timestamp >= ?", startDate)
	}
	if endDate != nil {
		query = query.Where("request_timestamp <= ?", endDate)
	}

	// Get basic counts
	if err := query.Count(&stats.TotalRequests).Error; err != nil {
		return nil, err
	}

	// Get successful/failed counts using the same filtered query
	query.Where("status = ?", "success").Count(&stats.SuccessfulRequests)
	query.Where("status != ?", "success").Count(&stats.FailedRequests)

	// Get sum statistics using the same filtered query
	var result struct {
		TotalLocations    *int64   `json:"total_locations"`
		TaggedLocations   *int64   `json:"tagged_locations"`
		AvgProcessingTime *float64 `json:"avg_processing_time"`
	}

	queryBase := db.DB.Model(&models.LLMRequest{}).Where("organisation_id = ?", orgID)
	if startDate != nil {
		queryBase = queryBase.Where("request_timestamp >= ?", startDate)
	}
	if endDate != nil {
		queryBase = queryBase.Where("request_timestamp <= ?", endDate)
	}

	queryBase.Select(
		"SUM(total_locations) as total_locations",
		"SUM(tagged_locations) as tagged_locations",
		"AVG(processing_time) as avg_processing_time",
	).Scan(&result)

	if result.TotalLocations != nil {
		stats.TotalLocations = *result.TotalLocations
	}
	if result.TaggedLocations != nil {
		stats.TaggedLocations = *result.TaggedLocations
	}
	if result.AvgProcessingTime != nil {
		stats.AvgProcessingTime = *result.AvgProcessingTime
	}

	baseQuery := db.DB.Model(&models.LLMRequest{}).Where("organisation_id = ?", orgID)

	var firstReq models.LLMRequest
	if err := baseQuery.Order("request_timestamp ASC").First(&firstReq).Error; err == nil {
		stats.FirstRequestDate = &firstReq.RequestTimestamp
	} else {
		fmt.Printf("[WARNING] No requests found for organization %d: %v\n", orgID, err)
	}

	var lastReq models.LLMRequest
	if err := baseQuery.Order("request_timestamp DESC").First(&lastReq).Error; err == nil {
		stats.LastRequestDate = &lastReq.RequestTimestamp
	} else {
		fmt.Printf("[WARNING] No requests found for organization %d: %v\n", orgID, err)
	}

	return stats, nil
}

func (s *LLMTrackingService) GetRequestsList(orgID uint, page, limit int, status string) ([]models.LLMRequest, int64, error) {
	if page < 1 {
		page = 1
	}
	if limit < 1 {
		limit = 10
	}

	query := db.DB.Model(&models.LLMRequest{}).Where("organisation_id = ?", orgID)

	if status != "" {
		query = query.Where("status = ?", status)
	}

	var total int64
	if err := query.Count(&total).Error; err != nil {
		return nil, 0, err
	}

	var requests []models.LLMRequest
	offset := (page - 1) * limit

	err := query.Order("request_timestamp DESC").
		Offset(offset).
		Limit(limit).
		Find(&requests).Error

	return requests, total, err
}

func (s *LLMTrackingService) GetRequestDetail(requestID string, orgID uint) (*models.LLMRequestDetail, error) {
	var request models.LLMRequest
	if err := db.DB.Where("request_id = ? AND organisation_id = ?", requestID, orgID).First(&request).Error; err != nil {
		return nil, err
	}

	var responses []models.LLMResponse
	if err := db.DB.Where("request_id = ?", requestID).Find(&responses).Error; err != nil {
		return nil, err
	}

	return &models.LLMRequestDetail{
		LLMRequest: request,
		Responses:  responses,
	}, nil
}

func (s *LLMTrackingService) GetOrganisationSummary(orgID uint) (*models.LLMOrganisationSummary, error) {
	// Get basic stats
	stats, err := s.GetOrganisationStats(orgID, nil, nil)
	if err != nil {
		return nil, err
	}

	// Get recent requests (last 10)
	recentRequests, _, err := s.GetRequestsList(orgID, 1, 10, "")
	if err != nil {
		return nil, err
	}

	// Get top cities
	var topCities []models.CityUsageCount
	db.DB.Model(&models.LLMResponse{}).
		Select("city_name, COUNT(*) as count").
		Where("organisation_id = ?", orgID).
		Group("city_name").
		Order("count DESC").
		Limit(10).
		Find(&topCities)

	// Get requests by day (last 30 days)
	var requestsByDay []models.DailyRequestCount
	thirtyDaysAgo := time.Now().AddDate(0, 0, -30)

	db.DB.Model(&models.LLMRequest{}).
		Select("DATE(request_timestamp) as date, COUNT(*) as count").
		Where("organisation_id = ? AND request_timestamp >= ?", orgID, thirtyDaysAgo).
		Group("DATE(request_timestamp)").
		Order("date DESC").
		Find(&requestsByDay)

	return &models.LLMOrganisationSummary{
		Stats:          *stats,
		RecentRequests: recentRequests,
		TopCities:      topCities,
		RequestsByDay:  requestsByDay,
	}, nil
}

func (s *LLMTrackingService) DeleteOldRequests(orgID uint, olderThanDays int) error {
	cutoffDate := time.Now().AddDate(0, 0, -olderThanDays)

	if err := db.DB.Where("organisation_id = ? AND created_at < ?", orgID, cutoffDate).Delete(&models.LLMResponse{}).Error; err != nil {
		return err
	}

	// Delete requests
	return db.DB.Where("organisation_id = ? AND created_at < ?", orgID, cutoffDate).Delete(&models.LLMRequest{}).Error
}

