package auth

import (
	"bytes"
	"context"
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"core-backend/m/v2/templates"
	"crypto/rsa"
	"crypto/sha256"
	"encoding/base64"
	"encoding/json"
	"fmt"
	"html/template"
	"log"
	"net/http"
	"os"
	"strconv"
	"strings"
	"time"

	"github.com/cristalhq/otp"
	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
	"github.com/xlzd/gotp"
	"golang.org/x/crypto/ssh"
	"golang.org/x/oauth2"
	"gopkg.in/gomail.v2"
	"gorm.io/gorm"
)

var clientConfig *oauth2.Config
var algo = otp.AlgorithmSHA256
var config = otp.TOTPConfig{Algo: algo, Digits: 6, Issuer: "DSTHub", Period: 300, Skew: 5}
var totp, _ = otp.NewTOTP(config)
var otpEmailTemplate, _ = template.New("").Parse(templates.OtpEmailTemplate)

// parsing private key from pem file
var keybytes, _ = os.ReadFile("RSA/ooc-keypair.pem")
var privkey, _ = ssh.ParseRawPrivateKey(keybytes)

func GetAuthorizationURL() string {
	// This is moved to the main function itself
	/*
		envErr := godotenv.Load(".env")
		if envErr != nil {
			log.Fatalf("Some error occured. Err: %s", envErr)
		}
	*/
	client_id := os.Getenv("GOOGLE_CLIENT_ID")
	client_secret := os.Getenv("GOOGLE_CLIENT_SECRET")
	redirect_url := os.Getenv("GOOGLE_REDIRECT_URL")
	clientConfig = &oauth2.Config{
		ClientID:     client_id,
		ClientSecret: client_secret,

		RedirectURL: redirect_url,
		Scopes:      []string{"profile", "email"},
		Endpoint: oauth2.Endpoint{
			AuthURL:  "https://accounts.google.com/o/oauth2/auth",
			TokenURL: "https://accounts.google.com/o/oauth2/token",
		},
	}
	authURL := clientConfig.AuthCodeURL("state")
	log.Default().Println("Authorization URL:", authURL)
	return authURL
}

func HandleCallback(c *gin.Context) {
	log.Println("Callback request received.")
	code := c.Query("code")
	log.Println("Authorization code:", code)

	token, err := clientConfig.Exchange(context.Background(), code)
	if err != nil {
		log.Printf("Error exchanging authorization code: %s", err)
		c.String(http.StatusInternalServerError, "Error exchanging authorization code: %s", err.Error())
		return
	}
	type GoogleUser struct {
		Name  string `json:"name"`
		Email string `json:"email"`
	}

	var googleUser GoogleUser
	client := clientConfig.Client(context.Background(), token)
	resp, err := client.Get("https://www.googleapis.com/oauth2/v3/userinfo")
	if err != nil {
		log.Printf("Error getting user profile: %s", err)
		c.String(http.StatusInternalServerError, "Error getting user profile: %s", err.Error())
		return
	}

	defer resp.Body.Close()
	err = json.NewDecoder(resp.Body).Decode(&googleUser)
	if err != nil {
		log.Printf("Error parsing user profile: %s", err)
		c.String(http.StatusInternalServerError, "Error parsing user profile: %s", err.Error())
		return
	}

	log.Printf("Google User profile: %+v", googleUser)

	// Check if the user's email already exists in the UserEmail table
	var existingUserEmail models.UserDetail
	result := db.DB.Where("email = ?", googleUser.Email).First(&existingUserEmail)

	if result.Error == gorm.ErrRecordNotFound {
		// Email not found, create a new user in GormUser
		names := strings.Split(googleUser.Name, " ")
		var newUser models.UserDetail

		switch len(names) {
		case 1:
			newUser.FirstName = names[0]
		case 2:
			newUser.FirstName = names[0]
			newUser.LastName = names[1]
		default:
			log.Println("Invalid name format")
			c.String(http.StatusBadRequest, "Invalid name format")
			return
		}

		// Create a new UserEmail record with the association
		newUser.Email = googleUser.Email
		db.DB.Create(&newUser)
	} else {
		// Email already exists
		log.Printf("Email already exists: %s", googleUser.Email)
	}

	c.String(http.StatusOK, "Name: %s %s\nEmail: %s\n", googleUser.Name, googleUser.Email)
}

func SendOTPEmail(c *gin.Context) {
	log.Default().Println("Started Send OTP Email for Email Address.")
	secret := gotp.RandomSecret(16)
	code, err := totp.GenerateCode(secret, time.Now())
	if err != nil {
		c.String(http.StatusInternalServerError, "Error while generating the OTP.")
		log.Fatal("Error creating a code:", err.Error())
		return
	}

	var mail map[string]string
	var body bytes.Buffer
	json.NewDecoder(c.Request.Body).Decode(&mail)

	email := decrypt(mail["email"])

	otpEmailTemplate.Execute(&body, struct{ Code string }{Code: code})

	//first verify the email with the db to ensure if it's a new entry or a retry
	var newEmailOTP models.EmailOTPVerification

	//checking for soft delete
	//remove it later
	softdelete := db.DB.Where("email = ?", email).First(&newEmailOTP)
	if softdelete.Error != gorm.ErrRecordNotFound {
		db.DB.Unscoped().Delete(&newEmailOTP)
	}

	//check email exist in table
	result := db.DB.Where("email = ?", email).First(&newEmailOTP)
	//doesn't exist create a new model in db

	//will set the inital retry count to 0
	if result.Error == gorm.ErrRecordNotFound {
		newEmailOTP = models.EmailOTPVerification{
			Email:       email,
			Code:        code,
			Secret:      secret,
			Retry_Count: 0,
		}
		db.DB.Create(&newEmailOTP)
	} else {
		//exist
		//increment the retry count
		//check the retry count if it exceeds send a timeout
		//current max retry count is 1

		if newEmailOTP.Retry_Count > 0 {
			//this will update the retry count to 0
			c.String(http.StatusRequestTimeout, "Wait for 60 seconds to resend otp")
			newEmailOTP.Retry_Count = 0
			db.DB.Where("email = ?", email).Save(&newEmailOTP)
			return
		}
		newEmailOTP.Retry_Count = newEmailOTP.Retry_Count + 1
		newEmailOTP.Code = code
		newEmailOTP.Secret = secret
		db.DB.Where("email = ?", email).Save(&newEmailOTP)
	}

	m := gomail.NewMessage()
	m.SetAddressHeader("From", os.Getenv("FROM"), "NoReply - DST Hub")
	m.SetHeader("To", email)
	m.SetHeader("Subject", "Email Verification OTP")
	m.SetBody("text/html", body.String())
	var iPort, _ = strconv.ParseInt(os.Getenv("MAIL_PORT"), 10, 0)
	var dialer = gomail.NewDialer(os.Getenv("MAIL_HOST"), int(iPort), os.Getenv("MAIL_FROM"), os.Getenv("MAIL_PASSWORD"))
	errordialer := dialer.DialAndSend(m)
	if errordialer != nil {
		log.Fatal("Error transmitting mail : ", errordialer)
		c.String(http.StatusInternalServerError, "Error while transmitting email.")
		return
	}

	log.Default().Println("Executed Send OTP Email for Email Address : ", email, " , OTP Generated is : ", code)
	c.String(http.StatusOK, "OTP Sent Successfully")
	fmt.Println("created at :", newEmailOTP.CreatedAt)
}

func ValidateOtp(c *gin.Context) {
	var mail map[string]string
	json.NewDecoder(c.Request.Body).Decode(&mail)

	log.Default().Println("Starting validate otp")
	email := decrypt(mail["email"])
	code := decrypt(mail["code"])

	if email == os.Getenv("superemail") && code == os.Getenv("superotp") {
		log.Default().Println("Logged in using the superemail credentials.")
		log.Default().Println("Exception flow for the superuser")
	} else {
		log.Default().Println("Regular flow")
		var validemail models.EmailOTPVerification
		//check email exist in table
		result := db.DB.Where("email = ?", email).First(&validemail)

		//doesn't exist Unauthorized access
		if result.Error == gorm.ErrRecordNotFound {
			log.Default().Print(result.Error)
			c.String(http.StatusUnauthorized, "Error Email doesn't match: %v", result.Error)
			return
		}
		//exist continue validation
		log.Default().Println("Started OTP Validation")

		//validate totp code using the secret from database
		err := totp.Validate(code, time.Now(), validemail.Secret)
		if err != nil {
			log.Default().Print(err)
			c.String(http.StatusUnauthorized, "Error validating otp,Wrong otp: %v", err.Error())
			return
		}

		//delete the otp record after verification
		db.DB.Where("email = ?", email).Unscoped().Delete(&validemail)
	}

	//code validated and email validated allow access
	token := GenerateJWT(email)
	if token == "error" {
		c.JSON(401, gin.H{
			"err": "No user with this email",
		})
	}
	c.JSON(http.StatusOK, gin.H{
		"token": token,
	})
	log.Default().Println("Validate OTP Completed for OTP : ", code)
	// var user models.UserEmail
	// db.DB.Select("id").Where("email = ? ", email).Find(&user)
}

func PubKey() *rsa.PublicKey {
	var privatekey = privkey.(*rsa.PrivateKey)
	return &privatekey.PublicKey
}

// generate a jwt token
// sign the token with the rsa key
func GenerateJWT(email string) string {
	log.Default().Println("Generating the JWT Token for Email : ", email)
	var privatekey = privkey.(*rsa.PrivateKey)
	var id models.UserDetail

	db.DB.Where("email = ?", email).First(&id)
	if id.ID == 0 {
		return "error"
	} else {
		user_type := id.UserType
		token, err := jwt.NewWithClaims(jwt.SigningMethodRS256, jwt.MapClaims{
			"id":   id.ID,
			"user": email,
			"type": user_type,
			"exp":  time.Now().Add(time.Hour * 24 * 30).Unix(),
		}).SignedString(privatekey)

		if err != nil {
			log.Default().Println(err)
		}

		return token
	}
}
func GenerateJWTwithEmail(c *gin.Context) {
	email, ok := c.Get("email")
	if !ok {
		c.JSON(400, gin.H{"error": "Email not provided"})
		return
	}
	orgid := c.Param("org")

	log.Default().Println("Generating JWT Token for Email:", email)

	// Ensure private key is available

	privatekey, ok := privkey.(*rsa.PrivateKey)
	if !ok {
		c.JSON(500, gin.H{"error": "Invalid private key"})
		return
	}
	if privkey == nil {
		c.JSON(500, gin.H{"error": "Private key is missing"})
		return
	}
	// Query organisation user with preload
	var id models.OrganisationUser
	err := db.DB.Joins("JOIN user_details ON user_details.id = organisation_users.user_id").
		Preload("User").
		Where("user_details.email = ? AND organisation_id = ?", email, orgid).
		First(&id).Error

	if err != nil {
		c.JSON(500, gin.H{"error": "Database error: " + err.Error()})
		return
	}
	token, err := jwt.NewWithClaims(jwt.SigningMethodRS256, jwt.MapClaims{
		"id":   id.UserId,
		"user": email,
		"type": id.User.UserType,
		"exp":  time.Now().Add(time.Hour * 24 * 30).Unix(),
	}).SignedString(privatekey)

	if err != nil {
		log.Default().Println("Error signing token:", err)
		c.JSON(500, gin.H{"error": "Failed to generate token"})
		return
	}

	// Return token
	log.Default().Println("Generated JWT Token:", token)
	c.JSON(200, gin.H{"token": token})
}

//superadmin
//admin
//manager
//employee

/*function to decrypt rsa encrypted messages */
func decrypt(msg string) string {
	var privatekey = privkey.(*rsa.PrivateKey)
	mail, _ := base64.StdEncoding.DecodeString(msg)

	decrypted, err := rsa.DecryptOAEP(sha256.New(), nil, privatekey, mail, nil)
	if err != nil {
		log.Default().Print(err)
	}
	return string(decrypted)
}

