package tally_models

import (
	"time"
)

// Diff represents the _diff table for tracking alterations
type Diff struct {
	GUID    string `gorm:"column:guid;type:varchar(64);not null" json:"guid"`
	AlterID int    `gorm:"column:alterid;not null" json:"alterid"`
}

func (Diff) TableName() string {
	return "_diff"
}

// Delete represents the _delete table for tracking deletions
type Delete struct {
	GUID string `gorm:"column:guid;type:varchar(64);not null" json:"guid"`
}

func (Delete) TableName() string {
	return "_delete"
}

// VchNumber represents the _vchnumber table for voucher numbers
type VchNumber struct {
	GUID          string `gorm:"column:guid;type:varchar(64);not null" json:"guid"`
	VoucherNumber string `gorm:"column:voucher_number;type:varchar(256);not null" json:"voucher_number"`
}

func (VchNumber) TableName() string {
	return "_vchnumber"
}

// Config represents the config table for key-value configuration
type Config struct {
	Name  string  `gorm:"column:name;type:varchar(64);primaryKey;not null" json:"name"`
	Value *string `gorm:"column:value;type:varchar(1024)" json:"value"`
}

func (Config) TableName() string {
	return "config"
}

// MstGroup represents the mst_group table for account groups
type MstGroup struct {
	GUID               string `gorm:"column:guid;type:varchar(64);primaryKey;not null" json:"guid"`
	AlterID            int    `gorm:"column:alterid;not null;default:0" json:"alterid"`
	Name               string `gorm:"column:name;type:varchar(1024);not null;default:''" json:"name"`
	Parent             string `gorm:"column:parent;type:varchar(1024);not null;default:''" json:"parent"`
	ParentGUID         string `gorm:"column:_parent;type:varchar(64);not null;default:''" json:"_parent"`
	PrimaryGroup       string `gorm:"column:primary_group;type:varchar(1024);not null;default:''" json:"primary_group"`
	IsRevenue          *bool  `gorm:"column:is_revenue;type:tinyint" json:"is_revenue"`
	IsDeemedPositive   *bool  `gorm:"column:is_deemedpositive;type:tinyint" json:"is_deemedpositive"`
	IsReserved         *bool  `gorm:"column:is_reserved;type:tinyint" json:"is_reserved"`
	AffectsGrossProfit *bool  `gorm:"column:affects_gross_profit;type:tinyint" json:"affects_gross_profit"`
	SortPosition       *int   `gorm:"column:sort_position" json:"sort_position"`
}

func (MstGroup) TableName() string {
	return "mst_group"
}

// MstLedger represents the mst_ledger table for ledger accounts
type MstLedger struct {
	GUID                string   `gorm:"column:guid;type:varchar(64);primaryKey;not null" json:"guid"`
	AlterID             int      `gorm:"column:alterid;not null;default:0" json:"alterid"`
	Name                string   `gorm:"column:name;type:varchar(1024);not null;default:''" json:"name"`
	Parent              string   `gorm:"column:parent;type:varchar(1024);not null;default:''" json:"parent"`
	ParentGUID          string   `gorm:"column:_parent;type:varchar(64);not null;default:''" json:"_parent"`
	Alias               string   `gorm:"column:alias;type:varchar(256);not null;default:''" json:"alias"`
