package steel_crm_handlers

import (
	"bytes"
	"core-backend/m/v2/cache"
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"core-backend/m/v2/services"
	"core-backend/m/v2/templates"
	"html/template"
	"log"
	"net/http"
	"strconv"

	"core-backend/m/v2/utils"

	"github.com/gin-gonic/gin"
	"gorm.io/gorm"
)

func RegisterSteelQuotationRoutes(router *gin.Engine, authMiddleware gin.HandlerFunc) {
	router.GET("/steel-quotations-public/id/:id/html", RenderSteelQuotationHTML)
	quotationRoutes := router.Group("/steel-quotations")
	quotationRoutes.Use(authMiddleware)
	{
		quotationRoutes.POST("/", CreateSteelQuotation)
		quotationRoutes.GET("/:organisation_id", GetSteelQuotations)
		quotationRoutes.GET("/id/:id", GetSteelQuotation)

		// NEW: HTML render endpoint
		quotationRoutes.GET("/id/:id/html", RenderSteelQuotationHTML)

		quotationRoutes.PUT("/:id", EditSteelQuotation)
		quotationRoutes.POST("/items", CreateSteelQuotationItem)
		quotationRoutes.POST("/items/bulk", CreateSteelQuotationItemBulk)
		quotationRoutes.GET("/items/:quotation_id", GetSteelQuotationItems)
		quotationRoutes.PUT("/items/:quotation_id", UpdateSteelQuotationItems)
		quotationRoutes.DELETE("/items/:id", DeleteSteelQuotationItem)

		quotationRoutes.GET("/config/:organisation_id", GetSteelQuotationConfig)
		quotationRoutes.POST("/config/:organisation_id", CreateOrUpdateSteelQuotationConfig)

	}
}

// RenderSteelQuotationHTML renders the steel quotation print template as HTML.
// GET /steel-quotations/id/:id/html
func RenderSteelQuotationHTML(c *gin.Context) {
	idStr := c.Param("id")
	id64, err := strconv.ParseUint(idStr, 10, 32)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid quotation id"})
		return
	}
	quotationID := uint(id64)

	q, org, addr, err := services.FetchSteelQuotationForRender(nil, quotationID)
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": err.Error()})
		return
	}

	vm := services.BuildSteelQuotationViewModel(org, q, addr)

	htmlBytes, err := services.RenderSteelQuotationHTML(vm)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.Data(http.StatusOK, "text/html; charset=utf-8", htmlBytes)
}

func CreateSteelQuotation(c *gin.Context) {
	var input models.SteelQuotation
	userID := c.MustGet("id").(uint)
	if err := c.ShouldBindJSON(&input); err != nil {
		c.JSON(400, gin.H{"error": err.Error()})
		return
	}

	tx := db.DB.Begin()

	// Save only the SteelQuotation (without Items)
	quotation := input
	quotation.Items = nil
	if err := tx.Create(&quotation).Error; err != nil {
		tx.Rollback()
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	var totalAmount float64
	createdItems := make([]models.SteelQuotationItem, 0, len(input.Items))

	// Now create the items with the correct SteelQuotationID
	for i := range input.Items {
		item := input.Items[i]
		item.ID = 0
		item.SteelQuotationID = quotation.ID
		item.OrganisationID = quotation.OrganisationID

		if item.SteelProductID > 0 {
			var product models.Product
			if err := tx.First(&product, item.SteelProductID).Error; err == nil {
				item.HSN = product.HSN
				item.CGST = product.CGST
				item.SGST = product.SGST
				item.IGST = product.IGST

				item.CGSTAmount = (item.Total * product.CGST) / 100
				item.SGSTAmount = (item.Total * product.SGST) / 100
				item.IGSTAmount = (item.Total * product.IGST) / 100
			}
		}

		if err := tx.Omit("ID").Create(&item).Error; err != nil {
			tx.Rollback()
			c.JSON(500, gin.H{"error": "Failed to create quotation item: " + err.Error()})
			return
		}
		totalAmount += item.Total
		createdItems = append(createdItems, item)
	}
	totalAmount += input.Loading + input.Freight + input.Pallet + input.LoadingTax + input.FreightTax + input.PalletTax

	// Update total_amount if there were items
	if len(createdItems) > 0 {
		if err := tx.Model(&quotation).Update("total_amount", totalAmount).Error; err != nil {
			tx.Rollback()
			c.JSON(500, gin.H{"error": "Failed to update quotation total: " + err.Error()})
			return
		}
	}

	tx.Commit()

	for _, item := range createdItems {
		if item.SteelProductID > 0 {
			if err := utils.BlockProductQuantity(item.SteelProductID, int(item.Quantity), quotation.OrganisationID, quotation.ID, "SteelQuotation", userID); err != nil {
				log.Printf("Warning: Failed to block quantity for steel product %d: %v", item.SteelProductID, err)
				// Continue anyway to avoid failing the entire quotation
			}
		}
	}

	// Invalidate related cache entries
	orgID := strconv.FormatUint(uint64(quotation.OrganisationID), 10)
	quotationID := strconv.FormatUint(uint64(quotation.ID), 10)
	invalidator := cache.NewCacheInvalidator()
	if err := invalidator.InvalidateSteelQuotationCache(orgID, quotationID); err != nil {
		// Log error but don't fail the request
		log.Printf("Failed to invalidate steel quotation cache: %v", err)
	}

	var result models.SteelQuotation
	db.DB.Preload("CustomerModel").Preload("Items").First(&result, quotation.ID)
	c.JSON(200, gin.H{"data": result})
}

func GetSteelQuotationConfig(c *gin.Context) {
	orgIDStr := c.Param("organisation_id")
	orgID, err := strconv.ParseUint(orgIDStr, 10, 32)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid organisation id"})
		return
	}

	var cfg models.SteelQuotationConfig
	if err := db.DB.Where("organisation_id = ?", uint(orgID)).First(&cfg).Error; err != nil {
		if err == gorm.ErrRecordNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "config not found"})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{"data": cfg})
}

func GetSteelQuotations(c *gin.Context) {
	orgID := c.Param("organisation_id")

	// Initialize cache components
	cacheHelper := cache.NewCacheHelper()
	keyBuilder := cache.NewCacheKeyBuilder()
	cacheKey := keyBuilder.SteelQuotationListKey(orgID)

	// Try to get from cache or fetch from DB
	data, fromCache, err := cacheHelper.GetOrSetJSON(cacheKey, db.RedisTTL.CRMRedis.QuotationCachedTTL, func() (interface{}, error) {
		var quotations []models.SteelQuotation
		if err := db.DB.Preload("CustomerModel").Preload("Items").Where("organisation_id = ?", orgID).Find(&quotations).Error; err != nil {
			return nil, err
		}
		return quotations, nil
	})

	if err != nil {
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	// Add cache info to response headers for debugging
	if fromCache {
		c.Header("X-Cache", "HIT")
	} else {
		c.Header("X-Cache", "MISS")
	}

	c.JSON(200, gin.H{"data": data})
}

func GetSteelQuotation(c *gin.Context) {
	id := c.Param("id")

	// Initialize cache components
	cacheHelper := cache.NewCacheHelper()
	keyBuilder := cache.NewCacheKeyBuilder()
	cacheKey := keyBuilder.SteelQuotationDetailKey(id)

	// Try to get from cache or fetch from DB
	data, fromCache, err := cacheHelper.GetOrSetJSON(cacheKey, db.RedisTTL.CRMRedis.QuotationCachedTTL, func() (interface{}, error) {
		var quotation models.SteelQuotation
		if err := db.DB.Preload("CustomerModel").Preload("Items").First(&quotation, "id = ?", id).Error; err != nil {
			return nil, err
		}
		return quotation, nil
	})

	if err != nil {
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	// Add cache info to response headers for debugging
	if fromCache {
		c.Header("X-Cache", "HIT")
	} else {
		c.Header("X-Cache", "MISS")
	}

	c.JSON(200, gin.H{"data": data})
}

func CreateOrUpdateSteelQuotationConfig(c *gin.Context) {
	orgIDStr := c.Param("organisation_id")
	orgID, err := strconv.ParseUint(orgIDStr, 10, 32)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid organisation id"})
		return
	}

	var input models.SteelQuotationConfig
	if err := c.ShouldBindJSON(&input); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}
	input.OrganisationID = uint(orgID)

	// Try to find existing config
	var existing models.SteelQuotationConfig
	tx := db.DB.Where("organisation_id = ?", input.OrganisationID).First(&existing)
	if tx.Error != nil {
		if tx.Error == gorm.ErrRecordNotFound {
			// Create new
			if err := db.DB.Create(&input).Error; err != nil {
				c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
				return
			}
			c.JSON(http.StatusCreated, gin.H{"data": input})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": tx.Error.Error()})
		return
	}

	// Update allowed fields from input (keep primary keys / other columns intact)
	existing.CompanyVM = input.CompanyVM
	existing.SellerVM = input.SellerVM
	existing.FooterVM = input.FooterVM

	if err := db.DB.Save(&existing).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{"data": existing})
}

func EditSteelQuotation(c *gin.Context) {
	id := c.Param("id")
	userID := c.MustGet("id").(uint)
	var input models.SteelQuotation
	if err := c.ShouldBindJSON(&input); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}
	log.Println("Quotation items  ::", len(input.Items))
	if err := db.DB.Transaction(func(tx *gorm.DB) error {
		var quotation models.SteelQuotation
		var total_amount float64 = 0
		log.Println("Quotation items len::", len(input.Items))
		for i := range input.Items {

			if input.Items[i].ID > 0 {
				var model models.SteelQuotationItem
				if err := db.DB.First(&model, input.Items[i].ID).Error; err != nil {
					log.Default().Println("Error", err)
					continue
				}
				if err := db.DB.Model(&model).Updates(input.Items[i]).Error; err != nil {
					log.Default().Println("Error", err)
					continue
				}
			} else {
				if err := db.DB.Create(&input.Items[i]).Error; err != nil {
					log.Default().Println("Error", err)
					continue
				}
			}
			total_amount += input.Items[i].Total
		}

		if input.Status != quotation.Status {
			if input.Status == "Accepted" {
				// Quotation was accepted, convert blocked quantities to actual deductions
				if err := utils.DeductBlockedQuantity(quotation.ID, "SteelQuotation", userID); err != nil {
					log.Printf("Warning: Failed to deduct blocked quantities for steel quotation #%d: %v", quotation.ID, err)
				}
			} else if input.Status == "Rejected" && quotation.Status == "Open" {
				// Quotation was rejected, unblock quantities
				if err := utils.UnblockProductQuantity(quotation.ID, "SteelQuotation", userID); err != nil {
					log.Printf("Warning: Failed to unblock quantities for steel quotation #%d: %v", quotation.ID, err)
				}
			}
		}

		updates := map[string]any{
			"customer_id":          input.CustomerID,
			"organisation_id":      input.OrganisationID,
			"steel_quotation_date": input.SteelQuotationDate,
			"valid_until":          input.ValidUntil,
			"status":               input.Status,
			"loading":              input.Loading,
			"freight":              input.Freight,
			"pallet":               input.Pallet,
			"loading_tax":          input.LoadingTax,
			"freight_tax":          input.FreightTax,
			"pallet_tax":           input.PalletTax,
			"total_amount":         total_amount + (input.Loading * input.LoadingTax / 100) + (input.Freight * input.FreightTax / 100) + (input.Pallet * input.PalletTax / 100) + input.Loading + input.Freight + input.Pallet,
			"remarks":              input.Remarks,
		}
		if err := db.DB.First(&quotation, id).Error; err != nil {
			c.JSON(http.StatusNotFound, gin.H{"error": "SteelQuotation not found"})
			return err
		}
		if err := db.DB.Model(&quotation).Updates(updates).Error; err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
			return err
		}
		if err := db.DB.Preload("CustomerModel").Preload("Items").First(&quotation, id).Error; err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
			return err
		}

		// Invalidate related cache entries after successful update
		orgID := strconv.FormatUint(uint64(quotation.OrganisationID), 10)
		quotationID := strconv.FormatUint(uint64(quotation.ID), 10)
		invalidator := cache.NewCacheInvalidator()
		if err := invalidator.InvalidateSteelQuotationCache(orgID, quotationID); err != nil {
			// Log error but don't fail the request
			log.Printf("Failed to invalidate steel quotation cache: %v", err)
		}

		c.JSON(http.StatusOK, gin.H{"message": "SteelQuotation updated successfully", "data": quotation})

		return nil
	}); err != nil {
		log.Panicln(err)
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}
}

