func UpdateSteelQuotationItems(c *gin.Context) {
	quotationID := c.Param("quotation_id")
	var items []models.SteelQuotationItem

	if err := c.ShouldBindJSON(&items); err != nil {
		c.JSON(400, gin.H{"error": err.Error()})
		return
	}

	var quotation models.SteelQuotation
	if err := db.DB.First(&quotation, quotationID).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "SteelQuotation not found"})
		return
	}

	tx := db.DB.Begin()

	if err := tx.Where("steel_quotation_id = ?", quotationID).Delete(&models.SteelQuotationItem{}).Error; err != nil {
		tx.Rollback()
		c.JSON(500, gin.H{"error": "Failed to update items: " + err.Error()})
		return
	}

	var totalAmount float64
	for i := range items {
		items[i].SteelQuotationID = quotation.ID
		items[i].OrganisationID = quotation.OrganisationID

		if items[i].SteelProductID > 0 {
			var product models.Product
			if err := tx.First(&product, items[i].SteelProductID).Error; err == nil {
				items[i].HSN = product.HSN
				items[i].CGST = product.CGST
				items[i].SGST = product.SGST
				items[i].IGST = product.IGST

				items[i].CGSTAmount = (items[i].Total * product.CGST) / 100
				items[i].SGSTAmount = (items[i].Total * product.SGST) / 100
				items[i].IGSTAmount = (items[i].Total * product.IGST) / 100
			}
		}

		totalAmount += items[i].Total
	}

	if err := tx.Create(&items).Error; err != nil {
		tx.Rollback()
		c.JSON(500, gin.H{"error": "Failed to create new items: " + err.Error()})
		return
	}

	if err := tx.Model(&quotation).Update("total_amount", totalAmount).Error; err != nil {
		tx.Rollback()
		c.JSON(500, gin.H{"error": "Failed to update quotation total: " + err.Error()})
		return
	}

	tx.Commit()

	// Invalidate related cache entries
	orgID := strconv.FormatUint(uint64(quotation.OrganisationID), 10)
	quotationIDStr := strconv.FormatUint(uint64(quotation.ID), 10)
	invalidator := cache.NewCacheInvalidator()
	if err := invalidator.InvalidateSteelQuotationCache(orgID, quotationIDStr); err != nil {
		// Log error but don't fail the request
		log.Printf("Failed to invalidate steel quotation cache: %v", err)
	}

	var updatedItems []models.SteelQuotationItem
	db.DB.Where("steel_quotation_id = ?", quotationID).Find(&updatedItems)
	c.JSON(200, gin.H{"message": "SteelQuotation items updated successfully", "data": updatedItems})
}
func DeleteSteelQuotationItem(c *gin.Context) {
	itemID := c.Param("id")

	tx := db.DB.Begin()

	// Find the item first to get its quotation ID and total
	var item models.SteelQuotationItem
	if err := tx.First(&item, itemID).Error; err != nil {
		tx.Rollback()
		c.JSON(http.StatusNotFound, gin.H{"error": "SteelQuotation item not found"})
		return
	}

	// Get the quotation to update its total
	var quotation models.SteelQuotation
	if err := tx.First(&quotation, item.SteelQuotationID).Error; err != nil {
		tx.Rollback()
		c.JSON(http.StatusNotFound, gin.H{"error": "SteelQuotation not found"})
		return
	}

	// Delete the item
	if err := tx.Delete(&item).Error; err != nil {
		tx.Rollback()
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to delete item: " + err.Error()})
		return
	}

	var newTotal float64
	if err := tx.Model(&models.SteelQuotationItem{}).
		Where("steel_quotation_id = ?", item.SteelQuotationID).
		Select("COALESCE(SUM(total), 0)").
		Scan(&newTotal).Error; err != nil {

		newTotal = 0
		_ = tx.Delete(&item).Error
	}

	if err := tx.Model(&quotation).Update("total_amount", newTotal).Error; err != nil {
		tx.Rollback()
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to update quotation total: " + err.Error()})
		return
	}

	// Commit the transaction
	tx.Commit()

	// Invalidate related cache entries
	orgID := strconv.FormatUint(uint64(quotation.OrganisationID), 10)
	quotationIDStr := strconv.FormatUint(uint64(quotation.ID), 10)
	invalidator := cache.NewCacheInvalidator()
	if err := invalidator.InvalidateSteelQuotationCache(orgID, quotationIDStr); err != nil {
		// Log error but don't fail the request
		log.Printf("Failed to invalidate steel quotation cache: %v", err)
	}

	c.JSON(http.StatusOK, gin.H{
		"message":   "SteelQuotation item deleted successfully",
		"new_total": newTotal,
	})
}

// parseSteelQuotationTemplate parses templates/quotation.html with SteelQuotationTemplateFuncs().
// Uses embedded templates.EmbeddedFS for Docker/runtime consistency.
func parseSteelQuotationTemplate() (*template.Template, error) {
	return template.New("quotation.html").
		Funcs(services.SteelQuotationTemplateFuncs()).
		ParseFS(templates.EmbeddedFS, "quotation.html")
}

// renderHTML is a small helper so we can return text/html.
func renderHTML(c *gin.Context, tmpl *template.Template, data any) {
	var buf bytes.Buffer
	if err := tmpl.Execute(&buf, data); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}
	c.Data(http.StatusOK, "text/html; charset=utf-8", buf.Bytes())
}

