package handlers

import (
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"log"
	"strconv"

	"github.com/gin-gonic/gin"
	"gorm.io/gorm"
)

func RegisterPermissionHandlers(c gin.IRoutes) {
	c.POST("/permission", AddPermission)
	c.GET("/permission/:email/:organisation_id", GetPermission)
}

func AddPermission(c *gin.Context) {
	var permission models.UserPermissions
	c.ShouldBindJSON(&permission)
	err := db.DB.Transaction(func(tx *gorm.DB) error {
		var dbPermission models.UserPermissions
		tx.Where("email = ? AND organisation_id = ?", permission.Email, permission.OrganisationID).First(&dbPermission)

		if dbPermission.ID != 0 {
			dbPermission.Permission = permission.Permission
			if err := tx.Save(&dbPermission).Error; err != nil {
				return err
			}
		} else {
			if err := tx.Create(&permission).Error; err != nil {
				return err
			}

		}
		return nil
	})
	if err != nil {
		c.JSON(500, gin.H{"message": "Unable to perform the operations",
			"error": err.Error()})
		return
	}
	c.JSON(200, permission)

}

func GetPermission(c *gin.Context) {
	var permission models.UserPermissions
	email := c.Param("email")
	organisation_id := c.Param("organisation_id")
	var orgUser models.OrganisationUser
	if err := db.DB.Preload("User").Where("organisation_id = ?", organisation_id).Joins("JOIN user_details ON user_details.id = organisation_users.user_id").Where("user_details.email = ?", email).First(&orgUser).Error; err == gorm.ErrRecordNotFound {
		log.Println(err)
		c.JSON(500, gin.H{"message": "User not found"})
		return
	}
	if err := db.DB.Where("email = ? AND organisation_id = ?", email, organisation_id).First(&permission).Error; err == gorm.ErrRecordNotFound {
		organisation_id, _ := strconv.ParseInt(organisation_id, 10, 64)

		permission.ID = 0
		permission.OrganisationID = uint(organisation_id)
		permission.Email = email
		permission.Permission = models.Features{}
		c.JSON(200, permission)
		return
	} else {
		c.JSON(200, permission)
		return
	}
}

