package handlers

import (
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"net/http"
	"time"

	"github.com/gin-gonic/gin"
)

// CreateStore - Handler for creating a new store-----------------
func CreateStore(c *gin.Context) {
	var store models.Store
	if err := c.ShouldBindJSON(&store); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	// Set created and modified dates------------------------
	store.CreatedDate = time.Now()
	store.ModifiedDate = time.Now()

	if err := db.DB.Create(&store).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, store)
}

// GetStores - Handler for retrieving all stores---------------------------
func GetStores(c *gin.Context) {
	var stores []models.Store

	if err := db.DB.Find(&stores).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, stores)
}

// GetStoreByID - Handler for retrieving a specific store by its ID-------------------------------
func GetStoreByID(c *gin.Context) {
	storeID := c.Param("id")
	var store models.Store

	if err := db.DB.First(&store, storeID).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Store not found"})
		return
	}

	c.JSON(http.StatusOK, store)
}

// UpdateStore - Handler for updating a store's information--------------------------------
func UpdateStore(c *gin.Context) {
	storeID := c.Param("id")
	var store models.Store

	// Check if the store exists----------------------------------
	if err := db.DB.First(&store, storeID).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Store not found"})
		return
	}

	// Bind updated fields------------------------------
	if err := c.ShouldBindJSON(&store); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	// Update modified date-----------------------------------
	store.ModifiedDate = time.Now()

	if err := db.DB.Save(&store).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, store)
}

// DeleteStore - Handler for deleting a store----------------------------------
func DeleteStore(c *gin.Context) {
	storeID := c.Param("id")
	if err := db.DB.Delete(&models.Store{}, storeID).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "Store deleted successfully"})
}

// item part-----------------------------------------------------------------------------
// CreateItem - Handler for creating a new item
func CreateItem(c *gin.Context) {
	var item models.Item
	if err := c.ShouldBindJSON(&item); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	// Set created and modified dates
	item.CreatedDate = time.Now()
	item.ModifiedDate = time.Now()

	if err := db.DB.Create(&item).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, item)
}

// GetItems - Handler for retrieving all items
func GetAllItems(c *gin.Context) {
	userID := c.Param("id")
	var items []models.Item

	if err := db.DB.Where("user_id = ?", userID).Find(&items).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, items)
}

// GetItemByID - Handler for retrieving a specific item by its ID
func GetItemByID(c *gin.Context) {
	itemID := c.Param("id")
	var item models.Item

	if err := db.DB.First(&item, itemID).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Item not found"})
		return
	}

	c.JSON(http.StatusOK, item)
}

// UpdateItem - Handler for updating an item's information
func UpdateItem(c *gin.Context) {
	itemID := c.Param("id")
	var item models.Item

	// Check if the item exists
	if err := db.DB.First(&item, itemID).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Item not found"})
		return
	}

	// Bind updated fields
	if err := c.ShouldBindJSON(&item); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	// Update modified date
	item.ModifiedDate = time.Now()

	if err := db.DB.Save(&item).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, item)
}

// DeleteItem - Handler for deleting an item
func DeleteItem(c *gin.Context) {
	itemID := c.Param("id")

	result := db.DB.Delete(&models.Item{}, "id = ?", itemID)
	if result.Error != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": result.Error.Error()})
		return
	}

	if result.RowsAffected == 0 {
		c.JSON(http.StatusNotFound, gin.H{"error": "Item not found"})
		return
	}
	c.JSON(http.StatusOK, gin.H{"message": "Item deleted successfully"})
