func UpdateItemQuantityLedger(c *gin.Context) {
	ledgerID := c.Param("id")
	var ledger models.ItemQuantityLedger

	// Check if the ledger entry exists--------------
	if err := db.DB.First(&ledger, ledgerID).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Ledger entry not found"})
		return
	}

	// Bind updated fields--------------
	if err := c.ShouldBindJSON(&ledger); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	// Update modified date
	ledger.ModifiedDate = time.Now()

	if err := db.DB.Save(&ledger).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, ledger)
}

// Handler for deleting a ledger entry------------
func DeleteItemQuantityLedger(c *gin.Context) {
	ledgerID := c.Param("id")

	if err := db.DB.Delete(&models.ItemQuantityLedger{}, ledgerID).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "Ledger entry deleted successfully"})
}

