      BodyTemperatureDataType() => bodyTemperature,
      BasalBodyTemperatureDataType() => basalBodyTemperature,
      CervicalMucusDataType() => cervicalMucus,
      BloodPressureDataType() => bloodPressure,
      SystolicBloodPressureDataType() => systolic,
