    this.initialSamples,
    this.validator,
  });

  final DateTime? startDateTime;
  final DateTime? endDateTime;
  final ValueChanged<List<hc.PowerSample>?> onChanged;
  final List<hc.PowerSample>? initialSamples;
  final String? Function(List<hc.PowerSample>?)? validator;

