package handlers

import (
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"net/http"
	"time"

	"github.com/gin-gonic/gin"
)

func CreateProject(c *gin.Context) {
	var project models.ProjectTemplate
	if err := c.ShouldBindJSON(&project); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if err := db.DB.Create(&project); err.Error != nil {
		c.JSON(500, gin.H{"error": err.Error.Error()})
		return
	}

	c.JSON(200, project)
}

func GetProjects(c *gin.Context) {

	id := c.MustGet("id")
	var projects []models.Project

	var org models.OrganisationUser

	if err := db.DB.Where("user_id = ?", id).Find(&org); err.Error != nil {
		c.JSON(500, err.Error.Error())
		return
	}

	if err := db.DB.Preload("Tasks").Where("organisation_id = ?", org.OrganisationId).Find(&projects).Error; err != nil {
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	c.JSON(200, projects)
}

func GetProjectTemplates(c *gin.Context) {

	id := c.MustGet("id")

	var projectTemplates []models.ProjectTemplate
	var org models.OrganisationUser

	if err := db.DB.Where("user_id = ?", id).Find(&org); err.Error != nil {
		c.JSON(500, err.Error.Error())
		return
	}

	if err := db.DB.Preload("Tasks").Preload("Tasks.Assignee").Preload("Tasks.AssignedBy").Where("organisation_id = ?", org.OrganisationId).Find(&projectTemplates).Error; err != nil {
		c.JSON(500, err.Error())
		return
	}

	c.JSON(200, projectTemplates)
}

func StartTemplate(c *gin.Context) {
	var body models.ProjectTemplate
	var project models.Project
	var projectTemplate models.ProjectTemplate

	// Parse the body
	if err := c.ShouldBindJSON(&body); err != nil {
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	// layout := "2006-01-02T15:04:05.999999"

	// Retrieve the project
	if err := db.DB.Preload("Tasks").Preload("Tasks.Assignee").Preload("Tasks.AssignedBy").Preload("Organisation").Where("id = ?", body.ID).First(&projectTemplate).Error; err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "No such project  template"})
		return
	}

	tx := db.DB.Begin()
	var cur time.Time = time.Now()

	//Save project start date
	project.StartDate = &cur
	project.Name = body.Name
	project.Description = projectTemplate.Description
	project.OrganisationId = projectTemplate.OrganisationId
	project.Status = 1
	// Set all task start dates to the current date
	// for i := range project.Tasks {
	// 	project.Tasks[i].StartDate = &cur
	// 	if err := db.DB.Save(&project.Tasks[i]).Error; err != nil {
	// 		tx.Rollback()
	// 		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
	// 		return
	// 	}
	// }

	for _, i := range projectTemplate.Tasks {
		dueDate := cur.AddDate(0, 0, i.Duration)
		// Convert time.Time to ISTTime
		startDateIST := models.ISTTime{Time: cur}
		dueDateIST := models.ISTTime{Time: dueDate}
		task := models.Task{
			TaskName:     i.TaskName,
			Description:  i.Description,
			AssigneeID:   i.AssigneeID,
			AssignedByID: i.AssignedByID,
			Status:       i.Status,
			Priority:     1,
			StartAt:      i.StartAt,
			Duration:     i.Duration,
			StartDate:    &startDateIST,
			DueDate:      &dueDateIST,
		}
		project.Tasks = append(project.Tasks, task)
	}

	// Save the changes
	if err := db.DB.Preload("tasks").Create(&project).Error; err != nil {
		tx.Rollback()
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	tx.Commit()
	c.JSON(http.StatusOK, project)

}

func UpdateProjectTemplates(c *gin.Context) {
	var body, project models.Project
	if err := c.ShouldBindJSON(&body); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if err := db.DB.Preload("Tasks").Where("id = ?", body.ID).First(&project).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Project not found"})
		return
	}

	project.Name = body.Name
	project.Description = body.Description
	project.Priority = body.Priority

	//begin transaction to undo all changes if needed
	tx := db.DB.Begin()

	// Create a map of tasks in the update body for easy lookup
	updatedTaskMap := make(map[uint]*models.Task)
	for i := range body.Tasks {
		updatedTaskMap[body.Tasks[i].ID] = &body.Tasks[i]
	}

	// Identify tasks to delete
	var tasksToDelete []uint
	for _, task := range project.Tasks {
		if _, exists := updatedTaskMap[task.ID]; !exists {
			tasksToDelete = append(tasksToDelete, task.ID)
		}
	}

	// Delete tasks and associated task files that are not present in the updated list
	if len(tasksToDelete) > 0 {
		if err := tx.Where("task_id IN ?", tasksToDelete).Delete(&models.TaskFile{}).Error; err != nil {
			tx.Rollback()
			c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to delete task files: " + err.Error()})
			return
		}

		if err := tx.Where("id IN ?", tasksToDelete).Delete(&models.Task{}).Error; err != nil {
			tx.Rollback()
			c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to delete tasks: " + err.Error()})
			return
		}
	}

	// Update existing tasks and add new ones
	for i := range body.Tasks {
		task := &body.Tasks[i]
		if task.ID == 0 {
			// This is a new task
			task.ProjectId = &project.ID
			if err := tx.Create(task).Error; err != nil {
				tx.Rollback()
				c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to create new task: " + err.Error()})
				return
			}
		} else {
			// This is an existing task
			if err := tx.Model(&models.Task{}).Where("id = ?", task.ID).Updates(task).Error; err != nil {
				tx.Rollback()
				c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to update task: " + err.Error()})
				return
			}
		}
	}

	// Update the project
	if err := tx.Save(&project).Error; err != nil {
		tx.Rollback()
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to update project: " + err.Error()})
		return
	}

	if err := tx.Commit().Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to commit transaction: " + err.Error()})
		return
	}

	// Fetch the updated project with its tasks
	if err := db.DB.Preload("Tasks").First(&project, project.ID).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to fetch updated project: " + err.Error()})
		return
	}

	c.JSON(http.StatusOK, project)
}

func DeleteProject(c *gin.Context) {
	var project models.Project
	projectID := c.Param("project_id")

	if err := db.DB.Where("id = ?", projectID).First(&project).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Project not found"})
		return
	}
	db.DB.Where("project_id = ?", projectID).Delete(&models.Task{})
	db.DB.Where("project_id = ?", projectID).Delete(&models.ProjectFile{})

	db.DB.Delete(&project)

	c.JSON(http.StatusOK, gin.H{"message": "Project deleted successfully"})
}

func DeleteProjectTemplate(c *gin.Context) {
	var projectTemplate models.ProjectTemplate
	projectTemplateID := c.Param("project_template_id")

	if err := db.DB.Where("id = ?", projectTemplateID).First(&projectTemplate).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Project Template not found"})
		return
	}
	db.DB.Where("template_id = ?", projectTemplateID).Delete(&models.TaskTemplates{})
	db.DB.Delete(&projectTemplate)

	c.JSON(http.StatusOK, gin.H{"message": "Project Template deleted successfully"})
}

