    return switch (metric) {
      AggregationMetric.avg => avgFn(),
      AggregationMetric.min => minFn(),
      AggregationMetric.max => maxFn(),
      AggregationMetric.sum => throw UnsupportedError(
        'SUM is not supported for this data type',
      ),
    };
  }

