import 'package:flutter/material.dart';
import 'package:ai_health/src/common/constants/app_texts.dart';
import 'package:ai_health/src/features/incremental_data_sync/incremental_data_sync_change_notifier.dart';
import 'package:provider/provider.dart';




class SyncConsoleLogCard extends StatefulWidget {
  const SyncConsoleLogCard({super.key});

  @override
  State<SyncConsoleLogCard> createState() => _SyncConsoleLogCardState();
}

class _SyncConsoleLogCardState extends State<SyncConsoleLogCard> {
  final _scrollController = ScrollController();

  @override
  void dispose() {
    _scrollController.dispose();
    super.dispose();
  }

  void _scrollToBottom() {
    if (_scrollController.hasClients) {
      _scrollController.animateTo(
        _scrollController.position.maxScrollExtent,
        duration: const Duration(milliseconds: 300),
        curve: Curves.easeOut,
      );
    }
  }

  @override
  Widget build(BuildContext context) {
    return Selector<IncrementalDataSyncChangeNotifier, List<String>>(
      selector: (_, notifier) => notifier.logs.toList(),
      builder: (context, logs, _) {
        // Auto-scroll when new logs are added
        WidgetsBinding.instance.addPostFrameCallback((_) => _scrollToBottom());

        return Card(
          shape: RoundedRectangleBorder(
            borderRadius: BorderRadius.circular(16),
          ),
          child: Padding(
            padding: const EdgeInsets.all(16.0),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Row(
                  children: [
                    const Icon(Icons.terminal),
                    const SizedBox(width: 8),
                    Text(
                      AppTexts.consoleLog,
                      style: Theme.of(context).textTheme.titleLarge,
                    ),
                  ],
                ),
                const SizedBox(height: 12),
                Container(
                  height: 200,
                  decoration: BoxDecoration(
                    color: Colors.black87,
                    borderRadius: BorderRadius.circular(8),
                  ),
                  child: logs.isEmpty
                      ? const Center(
                          child: Text(
                            AppTexts.noLogsYet,
                            style: TextStyle(color: Colors.grey),
                          ),
                        )
                      : ListView.builder(
                          controller: _scrollController,
                          padding: const EdgeInsets.all(8),
                          itemCount: logs.length,
                          itemBuilder: (context, index) {
                            return Padding(
                              padding: const EdgeInsets.only(bottom: 4),
                              child: Text(
                                logs[index],
                                style: const TextStyle(
                                  color: Colors.greenAccent,
                                  fontFamily: 'monospace',
                                  fontSize: 12,
                                ),
                              ),
                            );
                          },
                        ),
                ),
              ],
            ),
          ),
        );
      },
    );
  }
}

