package handlers

import (
	"core-backend/m/v2/cache"
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"log"
	"net/http"
	"strconv"

	"github.com/gin-gonic/gin"
	"gorm.io/gorm"
)

func RegisterCustomerRoutes(router *gin.Engine) {
	customer := router.Group("/customers")
	{

		customer.POST("/", CreateCustomer)
		customer.POST("/bulk", CreateCustomerList)

		customer.GET("/organisation/:organisation_id", GetCustomers)
		customer.GET("/:id", GetCustomer)

		customer.GET("/stream/:organisation_id", StreamCustomers)

		customer.PUT("/:id", EditCustomerModel)

		// New combined data endpoints
		customer.GET("/with-org/:customer_id", GetCustomerWithOrgDetails)
		customer.GET("/with-org/organisation/:organisation_id", GetAllCustomersWithOrgDetails)
	}
}

// Create a single customer
func CreateCustomer(c *gin.Context) {
	var customer models.CustomerModel
	if err := c.ShouldBindJSON(&customer); err != nil {
		c.JSON(400, gin.H{"error": err.Error()})
		return
	}
	if err := db.DB.Create(&customer).Error; err != nil {
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	// Invalidate related cache entries
	orgID := strconv.FormatUint(uint64(customer.OrganisationID), 10)
	customerID := strconv.FormatUint(uint64(customer.ID), 10)
	invalidator := cache.NewCacheInvalidator()
	if err := invalidator.InvalidateCustomerCache(orgID, customerID); err != nil {
		// Log error but don't fail the request
		log.Printf("Failed to invalidate customer cache: %v", err)
	}

	c.JSON(200, gin.H{
		"data":           customer,
		"select_default": true,
	})
}

// Create a list of customers
func CreateCustomerList(c *gin.Context) {
	var customers []models.CustomerModel
	if err := c.ShouldBindJSON(&customers); err != nil {
		c.JSON(400, gin.H{"error": "Invalid payload", "details": err.Error()})
		return
	}
	if err := db.DB.Create(&customers).Error; err != nil {
		c.JSON(500, gin.H{"error": "Failed to create customers", "details": err.Error()})
		return
	}

	// Invalidate cache for all affected organizations
	invalidator := cache.NewCacheInvalidator()
	orgIDsMap := make(map[string]bool)
	for _, customer := range customers {
		orgID := strconv.FormatUint(uint64(customer.OrganisationID), 10)
		orgIDsMap[orgID] = true
	}

	// Invalidate cache for each organization
	for orgID := range orgIDsMap {
		if err := invalidator.InvalidateCustomerCache(orgID, ""); err != nil {
			// Log error but don't fail the request
			log.Printf("Failed to invalidate customer cache for org %s: %v", orgID, err)
		}
	}

	c.JSON(200, gin.H{"message": "Customers created successfully", "data": customers})
}

// Get all customers for an organisation
func GetCustomers(c *gin.Context) {
	orgID := c.Param("organisation_id")

	// Initialize cache components
	cacheHelper := cache.NewCacheHelper()
	keyBuilder := cache.NewCacheKeyBuilder()
	cacheKey := keyBuilder.CustomerListKey(orgID)

	// Try to get from cache or fetch from DB
	data, fromCache, err := cacheHelper.GetOrSetJSON(cacheKey, db.RedisTTL.CRMRedis.CustomerCachedTTL, func() (interface{}, error) {
		var customers []models.CustomerModel
		if err := db.DB.Where("organisation_id = ?", orgID).Find(&customers).Error; err != nil {
			return nil, err
		}
		return customers, nil
	})

	if err != nil {
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	// Add cache info to response headers for debugging
	if fromCache {
		c.Header("X-Cache", "HIT")
	} else {
		c.Header("X-Cache", "MISS")
	}

	c.JSON(200, gin.H{"data": data})
}

// Get a single customer by ID
func GetCustomer(c *gin.Context) {
	id := c.Param("id")

	// Initialize cache components
	cacheHelper := cache.NewCacheHelper()
	keyBuilder := cache.NewCacheKeyBuilder()
	cacheKey := keyBuilder.CustomerDetailKey(id)

	// Try to get from cache or fetch from DB
	data, fromCache, err := cacheHelper.GetOrSetJSON(cacheKey, db.RedisTTL.CRMRedis.CustomerCachedTTL, func() (interface{}, error) {
		var customer models.CustomerModel
		if err := db.DB.First(&customer, "id = ?", id).Error; err != nil {
			return nil, err
		}
		return customer, nil
	})

	if err != nil {
		c.JSON(500, gin.H{"error": err.Error()})
		return
	}

	// Add cache info to response headers for debugging
	if fromCache {
		c.Header("X-Cache", "HIT")
	} else {
		c.Header("X-Cache", "MISS")
	}

	c.JSON(200, gin.H{"data": data})
}

// StreamCustomers
func StreamCustomers(c *gin.Context) {
	orgID := c.Param("organisation_id")

	// Set headers for SSE
	c.Writer.Header().Set("Content-Type", "text/event-stream")
	c.Writer.Header().Set("Cache-Control", "no-cache")
	c.Writer.Header().Set("Connection", "keep-alive")
	c.Writer.Flush()

	// Query
	rows, err := db.DB.Model(&models.CustomerModel{}).
		Where("organisation_id = ?", orgID).
		Rows()
	if err != nil {
		c.SSEvent("error", gin.H{"error": err.Error()})
		return
	}
	defer rows.Close()

	// Iterating row by row
	for rows.Next() {
		var customer models.CustomerModel
		if err := db.DB.ScanRows(rows, &customer); err != nil {
			c.SSEvent("error", gin.H{"error": err.Error()})
			return
		}
		c.SSEvent("customer", customer)
		c.Writer.Flush() // Flush after each item
	}
	c.SSEvent("done", "streaming completed")
}

func EditCustomerModel(c *gin.Context) {
	var input models.CustomerModel
	customerID := c.Param("id")

	// Bind request JSON to input struct
	if err := c.ShouldBindJSON(&input); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid JSON", "details": err.Error()})
		return
	}

	var existingCustomer models.CustomerModel
	if err := db.DB.Where("id = ?", customerID).First(&existingCustomer).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Customer not found"})
		return
	}

	updateData := map[string]interface{}{
		"first_name":    input.FirstName,
		"last_name":     input.LastName,
		"email":         input.Email,
		"phone":         input.Phone,
		"address":       input.Address,
		"gstin":         input.GSTIN,
		"latitude":      input.Latitude,
		"longitude":     input.Longitude,
		"remarks":       input.Remarks,
		"customer_org":  input.CustomerOrg,
		"address_line1": input.AddressLine1,
		"address_line2": input.AddressLine2,
		"city":          input.City,
		"state":         input.State,
		"pin_code":      input.PinCode,
	}

	if err := db.DB.Model(&existingCustomer).Updates(updateData).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to update customer", "details": err.Error()})
		return
	}

	// Invalidate related cache entries
	orgID := strconv.FormatUint(uint64(existingCustomer.OrganisationID), 10)
	invalidator := cache.NewCacheInvalidator()
	if err := invalidator.InvalidateCustomerCache(orgID, customerID); err != nil {
		// Log error but don't fail the request
		// log.Printf("Failed to invalidate customer cache: %v", err)
	}

	c.JSON(http.StatusOK, gin.H{"message": "Customer updated successfully", "data": existingCustomer})
}

// GetCustomerWithOrgDetails retrieves customer information combined with organization details
func GetCustomerWithOrgDetails(c *gin.Context) {
	customerID := c.Param("customer_id")

	type CustomerOrgResponse struct {
		// Customer fields
		CustomerPhone        string `json:"customer_phone"`
		CustomerEmail        string `json:"customer_email"`
		CustomerGSTIN        string `json:"customer_gstin"`
		CustomerOrg          string `json:"customer_org"`
		CustomerAddress      string `json:"customer_address"`
		CustomerAddressLine1 string `json:"customer_address_line1"`
		CustomerAddressLine2 string `json:"customer_address_line2"`
		CustomerCity         string `json:"customer_city"`
		CustomerState        string `json:"customer_state"`
		CustomerPinCode      string `json:"customer_pin_code"`

		// Organization address fields
		OrgAddress    string `json:"org_address"`
		OrgCity       string `json:"org_city"`
		OrgState      string `json:"org_state"`
		OrgPostalCode uint   `json:"org_postal_code"`

		// Organization fields
		OrganisationCode string `json:"organisation_code"`
		WebsiteUrl       string `json:"website_url"`
		Logo             string `json:"logo"`
	}

	var result CustomerOrgResponse

	err := db.DB.Table("customer_models AS cm").
		Select(`
			cm.phone AS customer_phone,
			cm.email AS customer_email,
			cm.gstin AS customer_gstin,
			cm.customer_org,
			cm.address AS customer_address,
			cm.address_line1 AS customer_address_line1,
			cm.address_line2 AS customer_address_line2,
			cm.city AS customer_city,
			cm.state AS customer_state,
			cm.pin_code AS customer_pin_code,
			oa.address AS org_address,
			oa.city AS org_city,
			oa.state AS org_state,
			oa.postal_code AS org_postal_code,
			o.organisation_code,
			o.website_url,
			o.logo
		`).
		Joins("JOIN organisations o ON o.id = cm.organisation_id").
		Joins("LEFT JOIN organisation_addresses oa ON oa.organisation_id = cm.organisation_id").
		Where("cm.id = ? AND cm.deleted_at IS NULL", customerID).
		Scan(&result).Error

	if err != nil {
		if err == gorm.ErrRecordNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "Customer not found"})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{"data": result})
}

// GetAllCustomersWithOrgDetails retrieves all customers for an organization with combined details
func GetAllCustomersWithOrgDetails(c *gin.Context) {
	orgID := c.Param("organisation_id")

	type CustomerOrgResponse struct {
		CustomerID           uint   `json:"customer_id"`
		CustomerPhone        string `json:"customer_phone"`
		CustomerEmail        string `json:"customer_email"`
		CustomerGSTIN        string `json:"customer_gstin"`
		CustomerOrg          string `json:"customer_org"`
		CustomerAddress      string `json:"customer_address"`
		CustomerAddressLine1 string `json:"customer_address_line1"`
		CustomerAddressLine2 string `json:"customer_address_line2"`
		CustomerCity         string `json:"customer_city"`
		CustomerState        string `json:"customer_state"`
		CustomerPinCode      string `json:"customer_pin_code"`

		OrgAddress    string `json:"org_address"`
		OrgCity       string `json:"org_city"`
		OrgState      string `json:"org_state"`
		OrgPostalCode uint   `json:"org_postal_code"`

		OrganisationCode string `json:"organisation_code"`
		WebsiteUrl       string `json:"website_url"`
	}

	var results []CustomerOrgResponse

	err := db.DB.Table("customer_models AS cm").
		Select(`
			cm.id AS customer_id,
			cm.phone AS customer_phone,
			cm.email AS customer_email,
			cm.gstin AS customer_gstin,
			cm.customer_org,
			cm.address AS customer_address,
			cm.address_line1 AS customer_address_line1,
			cm.address_line2 AS customer_address_line2,
			cm.city AS customer_city,
			cm.state AS customer_state,
			cm.pin_code AS customer_pin_code,
			oa.address AS org_address,
			oa.city AS org_city,
			oa.state AS org_state,
			oa.postal_code AS org_postal_code,
			o.organisation_code,
			o.website_url
		`).
		Joins("JOIN organisations o ON o.id = cm.organisation_id").
		Joins("LEFT JOIN organisation_addresses oa ON oa.organisation_id = cm.organisation_id").
		Where("cm.organisation_id = ? AND cm.deleted_at IS NULL", orgID).
		Scan(&results).Error

	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{"data": results, "count": len(results)})
}

