package models

import (
	"time"

	"gorm.io/gorm"
)

// Coordinate represents a single lat/lng pair
type Coordinate struct {
	Latitude  float64 `json:"latitude" binding:"required"`
	Longitude float64 `json:"longitude" binding:"required"`
}

type RecommendationResponse struct {
	Recommendations []LocationRecommendation `json:"recommendations"`
	Timestamp       string                   `json:"timestamp"`
}

// Gemini API model------------
type GeminiRequest struct {
	Contents         []GeminiContent        `json:"contents"`
	GenerationConfig GeminiGenerationConfig `json:"generationConfig"`
}

type GeminiContent struct {
	Parts []GeminiPart `json:"parts"`
}

type GeminiPart struct {
	Text string `json:"text"`
}

type GeminiGenerationConfig struct {
	MaxOutputTokens int     `json:"maxOutputTokens"`
	Temperature     float64 `json:"temperature"`
}

type GeminiResponse struct {
	Candidates []GeminiCandidate `json:"candidates"`
}

type GeminiCandidate struct {
	Content GeminiContent `json:"content"`
}

type RecommendationRequest struct {
	Coordinates []Coordinate `json:"coordinates" binding:"required"`
	OrgId       int          `json:"org_id" binding:"required"`
	Token       string       `json:"token" binding:"required"`
}

// LocationTag---------
type LocationTag struct {
	ID             int     `json:"id"`
	OrganizationID int     `json:"organization_id"`
	UserID         int     `json:"user_id"`
	LocationName   string  `json:"location_name"`
	Description    string  `json:"description"`
	Latitude       float64 `json:"latitude"`
	Longitude      float64 `json:"longitude"`
	CreatedAt      string  `json:"created_at"`
}

type LocationTagsResponse struct {
	Data []LocationTag `json:"data"`
}

// NearbyLocationInfo----------
type NearbyLocationInfo struct {
	LocationTag LocationTag `json:"location_tag"`
	Distance    float64     `json:"distance_km"`
}

// Updated LocationRecommendation to include nearby location info-----------
type LocationRecommendation struct {
	Latitude          float64              `json:"latitude"`
	Longitude         float64              `json:"longitude"`
	CityName          string               `json:"city_name"`
	Recommendation    string               `json:"recommendation"`
	NearbyLocations   []NearbyLocationInfo `json:"nearby_locations,omitempty"`
	IsNearTaggedPlace bool                 `json:"is_near_tagged_place"`
}

// LLMRequest stores each recommendation request and response
type LLMRequest struct {
	gorm.Model
	OrganisationID   uint      `json:"organisation_id" gorm:"index"`
	RequestID        string    `json:"request_id" gorm:"uniqueIndex"`
	CoordinatesCount int       `json:"coordinates_count"`
	TimeContext      string    `json:"time_context"`
	TotalLocations   int       `json:"total_locations"`
	TaggedLocations  int       `json:"tagged_locations"`
	RequestTimestamp time.Time `json:"request_timestamp"`
	ProcessingTime   int64     `json:"processing_time_ms"` // in milliseconds
	Status           string    `json:"status"`             // success, error, partial
	ErrorMessage     string    `json:"error_message,omitempty"`
}

// LLMResponse stores individual location recommendations
type LLMResponse struct {
	gorm.Model
	RequestID         string  `json:"request_id" gorm:"index"`
	OrganisationID    uint    `json:"organisation_id" gorm:"index"`
	Latitude          float64 `json:"latitude"`
	Longitude         float64 `json:"longitude"`
	CityName          string  `json:"city_name"`
	Recommendation    string  `json:"recommendation" gorm:"type:text"`
	IsNearTaggedPlace bool    `json:"is_near_tagged_place"`
	NearbyLocationID  *uint   `json:"nearby_location_id,omitempty"`
	Distance          float64 `json:"distance_km"`
	LocationName      string  `json:"location_name,omitempty"`
}

// LLMStats provides aggregated statistics for an organization
type LLMStats struct {
	OrganisationID     uint       `json:"organisation_id"`
	TotalRequests      int64      `json:"total_requests"`
	TotalLocations     int64      `json:"total_locations"`
	TaggedLocations    int64      `json:"tagged_locations"`
	SuccessfulRequests int64      `json:"successful_requests"`
	FailedRequests     int64      `json:"failed_requests"`
	AvgProcessingTime  float64    `json:"avg_processing_time_ms"`
	LastRequestDate    *time.Time `json:"last_request_date"`
	FirstRequestDate   *time.Time `json:"first_request_date"`
}

// LLMRequestDetail provides detailed view of a single request
type LLMRequestDetail struct {
	LLMRequest
	Responses []LLMResponse `json:"responses"`
}

// LLMOrganisationSummary provides summary data for dashboard
type LLMOrganisationSummary struct {
	Stats          LLMStats            `json:"stats"`
	RecentRequests []LLMRequest        `json:"recent_requests"`
	TopCities      []CityUsageCount    `json:"top_cities"`
	RequestsByDay  []DailyRequestCount `json:"requests_by_day"`
}

// CityUsageCount for popular cities statistics
type CityUsageCount struct {
	CityName string `json:"city_name"`
	Count    int64  `json:"count"`
}

// DailyRequestCount for timeline statistics
type DailyRequestCount struct {
	Date  string `json:"date"`
	Count int64  `json:"count"`
}

// Request/Response models for API endpoints
type LLMStatsRequest struct {
	OrganisationID uint   `json:"organisation_id" binding:"required"`
	StartDate      string `json:"start_date,omitempty"`
	EndDate        string `json:"end_date,omitempty"`
}

type LLMRequestListRequest struct {
	OrganisationID uint   `json:"organisation_id" binding:"required"`
	Page           int    `json:"page,omitempty"`   // default 1
	Limit          int    `json:"limit,omitempty"`  // default 10
	Status         string `json:"status,omitempty"` // filter by status
}

