package location

import (
	"core-backend/m/v2/auth"
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"core-backend/m/v2/services"
	"encoding/json"
	"errors"
	"fmt"
	"log"
	"net/http"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt"
	"github.com/gorilla/websocket"
	"gorm.io/gorm"
)

var upgrader = websocket.Upgrader{
	CheckOrigin: func(r *http.Request) bool {
		return true
	},
	HandshakeTimeout: 10 * time.Second,
}

type LocationHandler struct {
	Firebase *services.FirebaseService
}

func (h *LocationHandler) SocketHandler(c *gin.Context) {
	conn, err := upgrader.Upgrade(c.Writer, c.Request, nil)
	if err != nil {
		return
	}
	defer conn.Close()
	log.Default().Println("WebSocket connection established")

	// Set read deadline to detect dead connections
	conn.SetReadDeadline(time.Now().Add(60 * time.Second))
	conn.SetPongHandler(func(string) error {
		conn.SetReadDeadline(time.Now().Add(60 * time.Second))
		return nil
	})

	// Start ping ticker for keepalive
	ticker := time.NewTicker(30 * time.Second)
	defer ticker.Stop()

	done := make(chan struct{})
	go func() {
		defer close(done)
		for {
			select {
			case <-ticker.C:
				if err := conn.WriteControl(websocket.PingMessage, []byte{}, time.Now().Add(10*time.Second)); err != nil {
					return
				}
			case <-done:
				return
			}
		}
	}()

	for {
		data := models.LocationRequest{}

		_, msg, err := conn.ReadMessage()

		if err != nil {
			if websocket.IsCloseError(err, websocket.CloseNormalClosure, websocket.CloseGoingAway) {
				log.Default().Println("WebSocket closed normally")
			} else {
				log.Default().Printf("Error reading message: %v", err)
			}
			break
		}

		// Reset read deadline on successful read
		conn.SetReadDeadline(time.Now().Add(60 * time.Second))

		if err := json.Unmarshal(msg, &data); err != nil {
			log.Default().Printf("Error unmarshalling JSON: %v", err)
			continue
		}
		if data.Token == "" {
			log.Default().Println("Invalid request: missing token")
			conn.WriteJSON(models.LocationResponse{
				Type:    "error",
				Message: "Invalid request: missing token",
			})

			continue
		}
		// log.Default().Println("Received data: ", data)
		token, err := jwt.Parse(data.Token, func(t *jwt.Token) (interface{}, error) {
			if _, ok := t.Method.(*jwt.SigningMethodRSA); !ok {
				return nil, fmt.Errorf("error")
			}
			return auth.PubKey(), nil
		})
		if err != nil {
			log.Default().Print(err)
			conn.WriteJSON(models.LocationResponse{
				Type:    "error",
				Message: err.Error(),
			})
			continue
		}

		if !token.Valid {
			log.Default().Print("Token validation failed")
			conn.WriteJSON(models.LocationResponse{
				Type:    "error",
				Message: "Invalid token",
			})
			continue
		}

		//getting token data (email,type of user)
		claims, ok := token.Claims.(jwt.MapClaims)
		if !ok {
			log.Default().Println("Error parsing token claims")
			conn.WriteJSON(models.LocationResponse{
				Type:    "error",
				Message: "Invalid token claims",
			})
			continue
		}
		idFloat, ok := claims["id"].(float64)
		if !ok {
			log.Default().Println("ID in token claims is not a number")
			conn.WriteJSON(models.LocationResponse{
				Type:    "error",
				Message: "ID in token claims is not a number",
			})
			continue
		}
		data.ID = uint(idFloat)

		log.Default().Println("Processing request of type:  ", data.Type)
		switch data.Type {
		case "locations":
			log.Default().Println("Storing bulk locations")
			if err := StoreBulkLoaction(data.Location, data.ID); err != nil {
				log.Default().Printf("Failed to store locations: %v", err)
				conn.WriteJSON(models.LocationResponse{
					Type:    "error",
					Message: "Failed to store locations: " + err.Error(),
				})
			} else {
				log.Default().Println("Locations stored successfully")
				conn.WriteJSON(models.LocationResponse{
					Type:    "success",
					Message: "Locations stored successfully",
				})
			}
		case "ping":
			log.Default().Println("Received ping, sending pong")
			conn.WriteJSON(models.LocationResponse{
				Type:    "pong",
				Message: "Pong",
			})
		default:
			log.Default().Printf("Unknown type received: %s", data.Type)
			conn.WriteJSON(models.LocationResponse{
				Type:    "error",
				Message: "Unknown type: " + (string)(data.Type),
			})
		}
	}
	log.Default().Println("WebSocket connection closed")
}

func StoreBulkLoaction(req []models.UserLocation, userID uint) error {
	log.Default().Printf("StoreBulkLoaction called with %d locations for user %v", len(req), userID)

	if len(req) == 0 {
		return errors.New("no locations provided")
	}

	// Get organization_id from user_id via organisation_users table
	var orgUser models.OrganisationUser
	var organizationID uint = 0
	if err := db.DB.Where("user_id = ? AND deleted_at IS NULL", userID).First(&orgUser).Error; err == nil {
		organizationID = orgUser.OrganisationId
		log.Default().Printf("Found organization_id %d for user_id %d", organizationID, userID)
	} else {
		log.Default().Printf("No organization found for user_id %d", userID)
	}

	var lastlocation models.UserLocation

	// Check last location entry
	if err := db.DB.Where("user_id = ?", userID).Order("id DESC").First(&lastlocation).Error; err != nil && !errors.Is(err, gorm.ErrRecordNotFound) {
		log.Default().Printf("Error fetching last location: %v", err)
		return err
	}

	// Helper to ensure RFC3339Nano with timezone
	parseRFC3339NanoWithTZ := func(ts time.Time) (time.Time, error) {
		str := ts.Format(time.RFC3339Nano)

		if len(str) >= 19 && (len(str) == 26 || len(str) == 29) && str[len(str)-1] != 'Z' && str[len(str)-6] != '+' && str[len(str)-6] != '-' {
			str += "Z"
		}
		return time.Parse(time.RFC3339Nano, str)
	}
	fetchAreaName := func(lat, lon float64, userID uint) string {
		// Get organization_id from user_id via organisation_users table
		var orgUser models.OrganisationUser
		var organizationID uint = 0
		if err := db.DB.Where("user_id = ? AND deleted_at IS NULL", userID).First(&orgUser).Error; err == nil {
			organizationID = orgUser.OrganisationId
			log.Default().Printf("Found organization_id %d for user_id %d", organizationID, userID)
		}

		// Use tolerance for coordinate matching (0.0001 degrees ≈ 11 meters)
		const tolerance = 0.0001
		var areaName string

		// PRIORITY 1: Check Location Tags (tagged locations) for the same organization
		// This is the HIGHEST priority - if coordinates match a tagged location, use that name
		if organizationID > 0 {
			var locationTag models.LocationTaggingData
			if err := db.DB.Where(
				"ABS(latitude - ?) < ? AND ABS(longitude - ?) < ? AND organization_id = ? AND deleted_at IS NULL",
				lat, tolerance, lon, tolerance, organizationID,
			).Order("created_at DESC").First(&locationTag).Error; err == nil {
				areaName = locationTag.LocationName
				log.Default().Printf("✅ Using tagged location name '%s' for coordinates (%.6f, %.6f) in org %d", areaName, lat, lon, organizationID)
				return areaName
			}
		}

		// PRIORITY 2: Check existing user_locations (if no tagged location found)
		// First check same org, then check all orgs (but skip location tag names)
		var existingLocation models.UserLocation

		// Priority 2a: Check same org first
		if organizationID > 0 {
			// Check for same user_id + same org_id + same coordinates (using direct organization_id field)
			if err := db.DB.Where("ABS(latitude - ?) < ? AND ABS(longitude - ?) < ? AND area_name != '' AND area_name IS NOT NULL AND user_id = ? AND organization_id = ?",
				lat, tolerance, lon, tolerance, userID, organizationID).
				Order("created_at DESC").First(&existingLocation).Error; err == nil {
				// Check if this area_name matches any location tag name in the same org
				var locationTagCheck models.LocationTaggingData
				if err := db.DB.Where("location_name = ? AND organization_id = ? AND deleted_at IS NULL", existingLocation.AreaName, organizationID).First(&locationTagCheck).Error; err == nil {
					log.Default().Printf("⚠️ Area name '%s' matches a location tag in org %d - NOT reusing", existingLocation.AreaName, organizationID)
					// Don't reuse - this area_name came from a location tag, continue to next check
				} else {
					// Safe to reuse - this area_name didn't come from a location tag
					log.Default().Printf("Reusing area name from same user+org: %s for coordinates (%.6f, %.6f) in org %d", existingLocation.AreaName, lat, lon, organizationID)
					return existingLocation.AreaName
				}
			}

			// Priority 2b: Check for same org_id + same coordinates (any user in same org)
			if err := db.DB.Where("ABS(latitude - ?) < ? AND ABS(longitude - ?) < ? AND area_name != '' AND area_name IS NOT NULL AND organization_id = ?",
				lat, tolerance, lon, tolerance, organizationID).
				Order("created_at DESC").First(&existingLocation).Error; err == nil {
				// Check if this area_name matches any location tag name in the same org
				var locationTagCheck models.LocationTaggingData
				if err := db.DB.Where("location_name = ? AND organization_id = ? AND deleted_at IS NULL", existingLocation.AreaName, organizationID).First(&locationTagCheck).Error; err == nil {
					log.Default().Printf("⚠️ Area name '%s' matches a location tag in org %d - NOT reusing", existingLocation.AreaName, organizationID)
					// Don't reuse - this area_name came from a location tag, continue to next check
				} else {
					// Safe to reuse - this area_name didn't come from a location tag
					log.Default().Printf("Reusing area name from same org: %s for coordinates (%.6f, %.6f) in org %d", existingLocation.AreaName, lat, lon, organizationID)
					return existingLocation.AreaName
				}
			}
		}

		// Priority 2c: Check ALL organizations (global check)
		// But skip any area_names that match location tag names in ANY organization
		if err := db.DB.Where(
			"ABS(latitude - ?) < ? AND ABS(longitude - ?) < ? AND area_name != '' AND area_name IS NOT NULL",
			lat, tolerance, lon, tolerance,
		).Order("created_at DESC").First(&existingLocation).Error; err == nil {
			// Check if this area_name matches any location tag name in ANY organization
			var locationTagCheck models.LocationTaggingData
			if err := db.DB.Where("location_name = ? AND deleted_at IS NULL", existingLocation.AreaName).First(&locationTagCheck).Error; err == nil {
				log.Default().Printf("⚠️ Area name '%s' matches a location tag in org %d - NOT reusing globally", existingLocation.AreaName, locationTagCheck.OrganizationID)
				// Don't reuse - this area_name came from a location tag (any org)
			} else {
				// Safe to reuse - this area_name didn't come from a location tag
				log.Default().Printf("Reusing global area name (not a location tag): %s for coordinates (%.6f, %.6f)", existingLocation.AreaName, lat, lon)
				return existingLocation.AreaName
			}
		}

		// Fetch from Nominatim API if not found in database or incomplete area_name
		client := &http.Client{Timeout: 10 * time.Second}
		resp, err := client.Get(fmt.Sprintf(
			"https://nominatim.openstreetmap.org/reverse?format=json&lat=%f&lon=%f&zoom=18&addressdetails=1",
			lat, lon))
		if err != nil {
			log.Default().Printf("Error fetching area name: %v", err)
			return ""
		}
		defer resp.Body.Close()

		var result map[string]interface{}
		if err := json.NewDecoder(resp.Body).Decode(&result); err != nil {
			log.Default().Printf("Error decoding Nominatim response: %v", err)
			return ""
		}

		if address, ok := result["address"].(map[string]interface{}); ok {
			neighbourhood := ""
			if n, ok := address["neighbourhood"].(string); ok {
				neighbourhood = n
			}
			suburb := ""
			if s, ok := address["suburb"].(string); ok {
				suburb = s
			}
			city := ""
			if ct, ok := address["city"].(string); ok {
				city = ct
			} else if t, ok := address["town"].(string); ok {
				city = t
			} else if v, ok := address["village"].(string); ok {
				city = v
			}
			postcode := ""
			if p, ok := address["postcode"].(string); ok {
				postcode = p
			}
			// Concatenate neighbourhood, suburb, city, and postcode with commas
			areaParts := []string{neighbourhood, suburb, city, postcode}
			var validParts []string
			for _, part := range areaParts {
				if part != "" {
					validParts = append(validParts, part)
				}
			}
			areaName := strings.Join(validParts, ",")
			if areaName == "" {
				log.Default().Printf("No area name found in Nominatim response for coordinates (%.6f, %.6f)", lat, lon)
			}
			return areaName
		}
		log.Default().Printf("No address found in Nominatim response for coordinates (%.6f, %.6f)", lat, lon)
		return ""
	}

	// Update existing record if same location
	if lastlocation.ID != 0 && lastlocation.Latitude == req[0].Latitude && lastlocation.Longitude == req[0].Longitude {
		log.Default().Println("Same location as last entry, updating EndTimestamp")
		end, err := parseRFC3339NanoWithTZ(time.Time(req[len(req)-1].EndTimestamp))
		if err != nil {
			log.Default().Printf("Error parsing EndTimestamp: %v", err)
			return err
		}
		lastlocation.EndTimestamp = models.LocationTime(end)
		lastlocation.OrganizationId = organizationID // Update organization_id
		// Reuse or fetch area name
		lastlocation.AreaName = fetchAreaName(lastlocation.Latitude, lastlocation.Longitude, userID)

		if err := db.DB.Save(&lastlocation).Error; err != nil {
			log.Default().Printf("Error saving updated location: %v", err)
			return err
		}

		log.Default().Println("Updated last location entry successfully")
		return nil
	}

	// Create new location entries
	for i, location := range req {
		start, err := parseRFC3339NanoWithTZ(time.Time(location.StartTimestamp))
		if err != nil {
			log.Default().Printf("Error parsing StartTimestamp for entry %d: %v", i, err)
			return err
		}
		end, err := parseRFC3339NanoWithTZ(time.Time(location.EndTimestamp))
		if err != nil {
			log.Default().Printf("Error parsing EndTimestamp for entry %d: %v", i, err)
			return err
		}

		areaName := fetchAreaName(location.Latitude, location.Longitude, userID)

		log.Default().Printf("Creating new location entry %d: UserId=%v, Lat=%v, Lng=%v, Area=%s", i, userID, location.Latitude, location.Longitude, areaName)
		if err := db.DB.Create(&models.UserLocation{
			UserId:         models.UserID(userID),
			OrganizationId: organizationID, // Store organization_id directly
			StartTimestamp: models.LocationTime(start),
			EndTimestamp:   models.LocationTime(end),
			Latitude:       location.Latitude,
			Longitude:      location.Longitude,
			AreaName:       areaName,
		}).Error; err != nil {
			log.Default().Printf("Error creating location entry %d: %v", i, err)
			return err
		}
	}

	log.Default().Println("All location entries created successfully")
	return nil
}

