package cache

import (
	"context"
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"encoding/json"
	"fmt"
	"log"
)

const (

	// Cache key prefixes
	DashboardTasksPrefix  = "dashboard:tasks:org:"
	DashboardLeavesPrefix = "dashboard:leaves:org:"
	DailyAttendancePrefix = "dashboard:daily-attendance:org:" // Add this new prefix

	// CRUD operation prefixes for more granular caching
	TasksCachePrefix  = "tasks:org:"
	LeavesCachePrefix = "leaves:org:"
)

// DashboardData represents the cached dashboard data structure
type DashboardData struct {
	Tasks  []models.Task      `json:"tasks"`
	Leaves []models.UserLeave `json:"leaves"`
}

// GetDashboardTasksFromCache retrieves tasks for an organization from Redis cache
func GetDashboardTasksFromCache(orgID uint) ([]models.Task, error) {
	ctx := context.Background()
	key := fmt.Sprintf("%s%d", DashboardTasksPrefix, orgID)

	val, err := db.RedisClient.Get(ctx, key).Result()
	if err != nil {
		return nil, err
	}

	var tasks []models.Task
	err = json.Unmarshal([]byte(val), &tasks)
	if err != nil {
		log.Printf("Error unmarshaling cached tasks for org %d: %v", orgID, err)
		return nil, err
	}

	return tasks, nil
}

// SetDashboardTasksToCache stores tasks for an organization in Redis cache
func SetDashboardTasksToCache(orgID uint, tasks []models.Task) error {
	ctx := context.Background()
	key := fmt.Sprintf("%s%d", DashboardTasksPrefix, orgID)

	data, err := json.Marshal(tasks)
	if err != nil {
		log.Printf("Error marshaling tasks for org %d: %v", orgID, err)
		return err
	}

	err = db.RedisClient.Set(ctx, key, data, db.RedisTTL.CRMRedis.DefaultTTL).Err()
	if err != nil {
		log.Printf("Error setting tasks cache for org %d: %v", orgID, err)
		return err
	}

	log.Printf("Successfully cached %d tasks for org %d", len(tasks), orgID)
	return nil
}

// GetDashboardLeavesFromCache retrieves leaves for an organization from Redis cache
func GetDashboardLeavesFromCache(orgID uint) ([]models.UserLeave, error) {
	ctx := context.Background()
	key := fmt.Sprintf("%s%d", DashboardLeavesPrefix, orgID)

	val, err := db.RedisClient.Get(ctx, key).Result()
	if err != nil {
		return nil, err
	}

	var leaves []models.UserLeave
	err = json.Unmarshal([]byte(val), &leaves)
	if err != nil {
		log.Printf("Error unmarshaling cached leaves for org %d: %v", orgID, err)
		return nil, err
	}

	return leaves, nil
}

// SetDashboardLeavesToCache stores leaves for an organization in Redis cache
func SetDashboardLeavesToCache(orgID uint, leaves []models.UserLeave) error {
	ctx := context.Background()
	key := fmt.Sprintf("%s%d", DashboardLeavesPrefix, orgID)

	data, err := json.Marshal(leaves)
	if err != nil {
		log.Printf("Error marshaling leaves for org %d: %v", orgID, err)
		return err
	}

	err = db.RedisClient.Set(ctx, key, data, db.RedisTTL.CRMRedis.DefaultTTL).Err()
	if err != nil {
		log.Printf("Error setting leaves cache for org %d: %v", orgID, err)
		return err
	}

	log.Printf("Successfully cached %d leaves for org %d", len(leaves), orgID)
	return nil
}

// GetDailyAttendanceFromCache retrieves daily attendance report for an organization from Redis cache
func GetDailyAttendanceFromCache(orgID string, date string) ([]map[string]interface{}, error) {
	ctx := context.Background()
	key := fmt.Sprintf("%s%s:%s", DailyAttendancePrefix, orgID, date)

	val, err := db.RedisClient.Get(ctx, key).Result()
	if err != nil {
		return nil, err
	}

	var attendance []map[string]interface{}
	err = json.Unmarshal([]byte(val), &attendance)
	if err != nil {
		log.Printf("Error unmarshaling cached daily attendance for org %s on %s: %v", orgID, date, err)
		return nil, err
	}

	log.Printf("Cache HIT for daily attendance - org: %s, date: %s", orgID, date)
	return attendance, nil
}

// SetDailyAttendanceToCache stores daily attendance report for an organization in Redis cache
func SetDailyAttendanceToCache(orgID string, date string, attendance []map[string]interface{}) error {
	ctx := context.Background()
	key := fmt.Sprintf("%s%s:%s", DailyAttendancePrefix, orgID, date)

	data, err := json.Marshal(attendance)
	if err != nil {
		log.Printf("Error marshaling daily attendance for org %s on %s: %v", orgID, date, err)
		return err
	}

	err = db.RedisClient.Set(ctx, key, data, db.RedisTTL.DashboardRedis.DefaultCacheTTL).Err()
	if err != nil {
		log.Printf("Error setting daily attendance cache for org %s on %s: %v", orgID, date, err)
		return err
	}

	log.Printf("Successfully cached daily attendance for org %s on %s (TTL: %v)", orgID, date, db.RedisTTL.DashboardRedis.DefaultCacheTTL)
	return nil
}

// InvalidateTaskCache invalidates all task-related cache for an organization
func InvalidateTaskCache(orgID uint) error {
	ctx := context.Background()

	// Invalidate dashboard tasks cache
	dashboardKey := fmt.Sprintf("%s%d", DashboardTasksPrefix, orgID)
	err := db.RedisClient.Del(ctx, dashboardKey).Err()
	if err != nil {
		log.Printf("Error invalidating dashboard tasks cache for org %d: %v", orgID, err)
		return err
	}

	// Invalidate general tasks cache if it exists
	tasksKey := fmt.Sprintf("%s%d", TasksCachePrefix, orgID)
	err = db.RedisClient.Del(ctx, tasksKey).Err()
	if err != nil {
		log.Printf("Error invalidating tasks cache for org %d: %v", orgID, err)
		return err
	}

	log.Printf("Successfully invalidated task caches for org %d", orgID)
	return nil
}

// InvalidateLeaveCache invalidates all leave-related cache for an organization
func InvalidateLeaveCache(orgID uint) error {
	ctx := context.Background()

	// Invalidate dashboard leaves cache
	dashboardKey := fmt.Sprintf("%s%d", DashboardLeavesPrefix, orgID)
	err := db.RedisClient.Del(ctx, dashboardKey).Err()
	if err != nil {
		log.Printf("Error invalidating dashboard leaves cache for org %d: %v", orgID, err)
		return err
	}

	// Invalidate general leaves cache if it exists
	leavesKey := fmt.Sprintf("%s%d", LeavesCachePrefix, orgID)
	err = db.RedisClient.Del(ctx, leavesKey).Err()
	if err != nil {
		log.Printf("Error invalidating leaves cache for org %d: %v", orgID, err)
		return err
	}

	log.Printf("Successfully invalidated leave caches for org %d", orgID)
	return nil
}

// GetUserOrganisation retrieves the organization ID for a given user ID
func GetUserOrganisation(userID uint) (uint, error) {
	var orgUser models.OrganisationUser
	err := db.DB.Where("user_id = ?", userID).First(&orgUser).Error
	if err != nil {
		return 0, err
	}
	return orgUser.OrganisationId, nil
}

// InvalidateAllDashboardCache invalidates both tasks and leaves cache for an organization
func InvalidateAllDashboardCache(orgID uint) error {
	var lastError error

	// Try to invalidate task cache
	if err := InvalidateTaskCache(orgID); err != nil {
		lastError = err
	}

	// Try to invalidate leave cache
	if err := InvalidateLeaveCache(orgID); err != nil {
		lastError = err
	}

	if lastError != nil {
		log.Printf("Some cache invalidation operations failed for org %d: %v", orgID, lastError)
		return lastError
	}

	log.Printf("Successfully invalidated all dashboard caches for org %d", orgID)
	return nil
}

// SetTasksToCache stores general tasks for an organization in Redis cache (for CRUD operations)
func SetTasksToCache(orgID uint, tasks []models.Task) error {
	ctx := context.Background()
	key := fmt.Sprintf("%s%d", TasksCachePrefix, orgID)

	data, err := json.Marshal(tasks)
	if err != nil {
		log.Printf("Error marshaling tasks for org %d: %v", orgID, err)
		return err
	}

	err = db.RedisClient.Set(ctx, key, data, db.RedisTTL.CRMRedis.DefaultTTL).Err()
	if err != nil {
		log.Printf("Error setting tasks cache for org %d: %v", orgID, err)
		return err
	}

	return nil
}

// GetTasksFromCache retrieves general tasks for an organization from Redis cache (for CRUD operations)
func GetTasksFromCache(orgID uint) ([]models.Task, error) {
	ctx := context.Background()
	key := fmt.Sprintf("%s%d", TasksCachePrefix, orgID)

	val, err := db.RedisClient.Get(ctx, key).Result()
	if err != nil {
		return nil, err
	}

	var tasks []models.Task
	err = json.Unmarshal([]byte(val), &tasks)
	if err != nil {
		log.Printf("Error unmarshaling cached tasks for org %d: %v", orgID, err)
		return nil, err
	}

	return tasks, nil
}

// SetLeavesToCache stores general leaves for an organization in Redis cache (for CRUD operations)
func SetLeavesToCache(orgID uint, leaves []models.UserLeave) error {
	ctx := context.Background()
	key := fmt.Sprintf("%s%d", LeavesCachePrefix, orgID)

	data, err := json.Marshal(leaves)
	if err != nil {
		log.Printf("Error marshaling leaves for org %d: %v", orgID, err)
		return err
	}

	err = db.RedisClient.Set(ctx, key, data, db.RedisTTL.CRMRedis.DefaultTTL).Err()
	if err != nil {
		log.Printf("Error setting leaves cache for org %d: %v", orgID, err)
		return err
	}

	return nil
}

// GetLeavesFromCache retrieves general leaves for an organization from Redis cache (for CRUD operations)
func GetLeavesFromCache(orgID uint) ([]models.UserLeave, error) {
	ctx := context.Background()
	key := fmt.Sprintf("%s%d", LeavesCachePrefix, orgID)

	val, err := db.RedisClient.Get(ctx, key).Result()
	if err != nil {
		return nil, err
	}

	var leaves []models.UserLeave
	err = json.Unmarshal([]byte(val), &leaves)
	if err != nil {
		log.Printf("Error unmarshaling cached leaves for org %d: %v", orgID, err)
		return nil, err
	}

	return leaves, nil
}

// InvalidateDailyAttendanceCache invalidates daily attendance cache for an organization on a specific date
func InvalidateDailyAttendanceCache(orgID string, date string) error {
	ctx := context.Background()
	key := fmt.Sprintf("%s%s:%s", DailyAttendancePrefix, orgID, date)

	err := db.RedisClient.Del(ctx, key).Err()
	if err != nil {
		log.Printf("Error invalidating daily attendance cache for org %s on %s: %v", orgID, date, err)
		return err
	}

	log.Printf("Successfully invalidated daily attendance cache for org %s on %s", orgID, date)
	return nil
}

// InvalidateAllDailyAttendanceForOrg invalidates all daily attendance cache entries for an organization
func InvalidateAllDailyAttendanceForOrg(orgID string) error {
	ctx := context.Background()
	pattern := fmt.Sprintf("%s%s:*", DailyAttendancePrefix, orgID)

	keys, err := db.RedisClient.Keys(ctx, pattern).Result()
	if err != nil {
		log.Printf("Error getting keys for pattern %s: %v", pattern, err)
		return err
	}

	if len(keys) == 0 {
		log.Printf("No daily attendance cache found for org %s", orgID)
		return nil
	}

	deleted, err := db.RedisClient.Del(ctx, keys...).Result()
	if err != nil {
		log.Printf("Error invalidating daily attendance caches for org %s: %v", orgID, err)
		return err
	}

	log.Printf("Successfully invalidated %d daily attendance cache entries for org %s", deleted, orgID)
	return nil
}

