package handlers

import (
	"bytes"
	"context"
	"core-backend/m/v2/cache"
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"core-backend/m/v2/services"
	"core-backend/m/v2/templates"
	"fmt"
	"html/template"
	"log"
	"net/http"
	"os"
	"strconv"

	"github.com/gin-gonic/gin"
	"gopkg.in/gomail.v2"
	"gorm.io/gorm"
)

type TaskHandler struct {
	Firebase *services.FirebaseService
}

func (h *TaskHandler) CreateTask(c *gin.Context) {
	var task models.Task
	if err := c.ShouldBindJSON(&task); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	// Check if the project exists if ProjectId is provided
	if task.ProjectId != nil && *task.ProjectId != 0 {
		if err := db.DB.Where("id = ?", task.ProjectId).First(&models.Project{}).Error; err != nil && err != gorm.ErrRecordNotFound {
			c.JSON(500, gin.H{"error": err, "msg": "Project Error"})
			return
		}
	} else {
		task.ProjectId = nil
	}

	if task.CustomerID != nil && *task.CustomerID != 0 {
		if err := db.DB.Where("id = ?", task.CustomerID).First(&models.Customer{}).Error; err != nil && err != gorm.ErrRecordNotFound {
			c.JSON(500, gin.H{"error": err, "msg": "Customer Error"})
			return
		}
	} else {
		task.CustomerID = nil
	}

	var assignee, assigned models.OrganisationUser

	// Get assignee and assigned by details and check if orgs match
	if err := db.DB.Where("user_id = ?", task.AssigneeID).First(&assignee).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Assignee not found"})
		return
	}

	if err := db.DB.Where("user_id = ?", task.AssignedByID).First(&assigned).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "AssignedBy user not found"})
		return
	}

	if assignee.OrganisationId == assigned.OrganisationId {
		if err := db.DB.Create(&task).Error; err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
			return
		}

		// Get user details for email notification
		var assigneeUser models.UserDetail
		var assignedByUser models.UserDetail

		if err := db.DB.Where("id = ?", task.AssigneeID).First(&assigneeUser).Error; err != nil {
			log.Println("Error fetching assignee details for email:", err)
		} else if err := db.DB.Where("id = ?", task.AssignedByID).First(&assignedByUser).Error; err != nil {
			log.Println("Error fetching assigner details for email:", err)
		} else {
			// If we have both user details, send the email notification
			go sendTaskNotificationEmail(&task, &assigneeUser, &assignedByUser, h.Firebase)
		}

		// Invalidate cache after task creation
		if err := cache.InvalidateTaskCache(assignee.OrganisationId); err != nil {
			log.Printf("Failed to invalidate task cache for org %d: %v", assignee.OrganisationId, err)
		}

		c.JSON(200, gin.H{"message": "Task created successfully", "task": task})
	} else {
		c.JSON(403, gin.H{"message": "The user is not from your org"})
	}
}

func sendTaskNotificationEmail(task *models.Task, assignee *models.UserDetail, assignedBy *models.UserDetail, firebaseService *services.FirebaseService) {
	// Don't block the main request with email sending
	// Parse the email template
	var notificationTitle, notificationBody string

	tmpl, err := template.New("taskEmail").Parse(templates.TaskNotificationTemplate)
	if err != nil {
		log.Println("Error parsing task email template:", err)
		return
	}

	// Get project name if available
	projectName := "Not assigned to any project"
	if task.ProjectId != nil && *task.ProjectId != 0 {
		var project models.Project
		if err := db.DB.Where("id = ?", *task.ProjectId).First(&project).Error; err == nil {
			projectName = project.Name
		}
	}

	customerName := "Not associated with any customer"
	if task.CustomerID != nil && *task.CustomerID != 0 {
		var customer models.Customer
		if err := db.DB.Where("id = ?", *task.CustomerID).First(&customer).Error; err == nil {
			customerName = customer.Fname + " " + customer.Lname
		}
	}

	// Format priority text and class
	priorityText := "Medium"
	priorityClass := "medium"
	switch task.Priority {
	case 0:
		priorityText = "Low"
		priorityClass = "low"
	case 1:
		priorityText = "Medium"
		priorityClass = "medium"
	case 2:
		priorityText = "High"
		priorityClass = "high"
	case 3:
		priorityText = "Unknown"
		priorityClass = "medium"
	}

	// Format dates (handling null values)
	startDateText := "Not specified"
	if task.StartDate != nil {
		startDateText = task.StartDate.Format("Jan 2, 2006 3:04 PM")
	}

	dueDateText := "Not specified"
	if task.DueDate != nil {
		dueDateText = task.DueDate.Format("Jan 2, 2006 3:04 PM")
	}

	description := task.Description
	if description == "" {
		description = "No description provided"
	}

	// Status text
	statusText := "Not Started"
	switch task.Status {
	case 0:
		statusText = "Not Started"
	case 1:
		statusText = "In Progress"
	case 2:
		statusText = "Completed"
	}

	// Prepare template data
	templateData := struct {
		AssigneeName   string
		TaskName       string
		Description    string
		AssignedByName string
		ProjectName    string
		CustomerName   string
		PriorityText   string
		PriorityClass  string
		StatusText     string
		StartDate      string
		DueDate        string
		TaskID         uint
	}{
		AssigneeName:   fmt.Sprintf("%s %s", assignee.FirstName, assignee.LastName),
		TaskName:       task.TaskName,
		Description:    description,
		AssignedByName: fmt.Sprintf("%s %s", assignedBy.FirstName, assignedBy.LastName),
		ProjectName:    projectName,
		CustomerName:   customerName,
		PriorityText:   priorityText,
		PriorityClass:  priorityClass,
		StatusText:     statusText,
		StartDate:      startDateText,
		DueDate:        dueDateText,
		TaskID:         task.ID,
	}

	// Execute template
	var body bytes.Buffer
	if err := tmpl.Execute(&body, templateData); err != nil {
		log.Println("Error executing task email template:", err)
		return
	}

	// Only send email if we have a valid email for assignee
	if assignee.Email == "" {
		log.Println("Assignee email is empty, cannot send notification")
		return
	}

	// Configure email message
	m := gomail.NewMessage()
	m.SetAddressHeader("From", os.Getenv("MAIL_FROM"), "dHub Task Notification")
	m.SetHeader("To", assignee.Email)
	m.SetHeader("Subject", "New Task Assignment: "+task.TaskName)
	m.SetBody("text/html", body.String())

	// Send the email
	port, _ := strconv.ParseInt(os.Getenv("MAIL_PORT"), 10, 0)
	dialer := gomail.NewDialer(
		os.Getenv("MAIL_HOST"),
		int(port),
		os.Getenv("MAIL_FROM"),
		os.Getenv("MAIL_PASSWORD"),
	)

	//notification content for new task
	if task.DueDate == nil {
		notificationTitle = "New Task Assigned"
		notificationBody = "You have a new task"
	} else {
		formatedDate := task.DueDate.Format("02 Jan 2006")
		notificationTitle = "New Task Assigned"
		notificationBody = fmt.Sprintf("You have a new task,Due date %s.", formatedDate)
	}

	log.Println(assignee)
	//notification for new task
	if err := firebaseService.SendNotificationToUser(context.Background(), *task.AssigneeID, notificationTitle, notificationBody); err != nil {
		log.Printf("[CronJob][FCM] Error sending push notification to user %d: %v", task.AssigneeID, err)
	} else {
		log.Printf("[CronJob][FCM] Consolidated push notification sent to user: %d", task.AssigneeID)
	}

	if err := dialer.DialAndSend(m); err != nil {
		log.Printf("Error sending task notification email: %v", err)
	} else {
		log.Printf("Task notification email sent to: %s", assignee.Email)
	}
}

