func GetAllTasks(c *gin.Context) {
	orgid := c.Param("id")
	id, err := strconv.ParseUint(orgid, 10, 64)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid org ID"})
		return
	}

	// Try to get tasks from cache first
	tasks, err := cache.GetTasksFromCache(uint(id))
	if err != nil {
		log.Printf("Tasks not found in cache for org %d, fetching from DB: %v", id, err)

		// Fetch from database if not cached
		var users []models.OrganisationUser
		db.DB.Where("organisation_id = ?", id).Find(&users)

		tasks = []models.Task{}
		for _, user := range users {
			var usertasks []models.Task
			if err := db.DB.Preload("Project").Preload("Assignee").Preload("AssignedBy").
				Where("assignee_id = ?", user.UserId).Find(&usertasks).Error; err != nil {
				c.JSON(404, err.Error())
				return
			}
			tasks = append(tasks, usertasks...)
		}

		// Cache the result
		err = cache.SetTasksToCache(uint(id), tasks)
		if err != nil {
			log.Printf("Failed to cache tasks for org %d: %v", id, err)
		}
	}

	c.JSON(200, tasks)
}

func StreamAllTasks(c *gin.Context) {
	orgID := c.Param("id")

	// Set headers for SSE
	c.Writer.Header().Set("Content-Type", "text/event-stream")
	c.Writer.Header().Set("Cache-Control", "no-cache")
	c.Writer.Header().Set("Connection", "keep-alive")
	c.Writer.Flush()

	// Query organisation users
	var users []models.OrganisationUser
	if err := db.DB.Where("organisation_id = ?", orgID).Find(&users).Error; err != nil {
		c.SSEvent("error", gin.H{"error": err.Error()})
		return
	}

	// Stream tasks for each user
	for _, user := range users {
		rows, err := db.DB.Model(&models.Task{}).
			Preload("Project").
			Preload("Assignee").
			Preload("AssignedBy").
			Where("assignee_id = ?", user.UserId).
			Rows()
		if err != nil {
			c.SSEvent("error", gin.H{"error": err.Error()})
			return
		}
		defer rows.Close()

		// Iterate through rows and stream tasks
		for rows.Next() {
			var task models.Task
			if err := db.DB.ScanRows(rows, &task); err != nil {
				c.SSEvent("error", gin.H{"error": err.Error()})
				return
			}
			c.SSEvent("task", task)
			c.Writer.Flush() // Flush after each task
		}
	}

	c.SSEvent("done", "streaming completed")
}

