package main

import (
	"core-backend/m/v2/db"
	"fmt"
	"log"

	"github.com/joho/godotenv"
)

func main() {
	log.Println("Starting customer_models migration...")

	envErr := godotenv.Load(".env")
	if envErr != nil {
		log.Fatal("Error loading .env file")
	}

	db.InitDB()
	defer db.CloseDB()

	// Check if columns exist before adding (MySQL doesn't support IF NOT EXISTS in ADD COLUMN)
	type ColumnCheck struct {
		ColumnName string
	}

	columnsToAdd := map[string]string{
		"address_line1": "VARCHAR(255)",
		"address_line2": "VARCHAR(255)",
		"city":          "VARCHAR(255)",
		"state":         "VARCHAR(255)",
		"pin_code":      "VARCHAR(20)",
	}

	for columnName, columnType := range columnsToAdd {
		var result ColumnCheck
		err := db.DB.Raw(`
			SELECT COLUMN_NAME 
			FROM INFORMATION_SCHEMA.COLUMNS 
			WHERE TABLE_SCHEMA = DATABASE() 
			AND TABLE_NAME = 'customer_models' 
			AND COLUMN_NAME = ?
		`, columnName).Scan(&result).Error

		if err != nil || result.ColumnName == "" {
			// Column doesn't exist, add it
			sql := fmt.Sprintf("ALTER TABLE customer_models ADD COLUMN %s %s", columnName, columnType)
			if err := db.DB.Exec(sql).Error; err != nil {
				log.Printf("Error adding column %s: %v\n", columnName, err)
			} else {
				log.Printf("Added column: %s\n", columnName)
			}
		} else {
			log.Printf("Column already exists: %s\n", columnName)
		}
	}

}

