      children: [
        const SizedBox(height: 4),
        Text(
          '${AppTexts.time}: ${DateFormatter.formatDateTime(rec.time)}',
        ),
        if (foodName != null && foodName.isNotEmpty)
          Text(
            '${AppTexts.food}: $foodName',
            style: TextStyle(
