package handlers

import (
	"core-backend/m/v2/auth"
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"log"
	"net/http"

	"github.com/gin-gonic/gin"
	"gorm.io/gorm"
)

// {"access_token":"ya29.a0ARW5m74moP-Z2L8Q6NFLKp1LE6skWoQtO0Wx1qwFKYG7LGvhI1bBU2apP
// SHJb_kFXvh8w-L4iapfMNJVAtQ_20aR976Td_vx22lTvFHIfCRU4RPIwIUSdOM4B9_kfPyjx4-GZejbDh
// OJCfmbVsyvo1AA4G4WpzFJz1P3baCSaCgYKAc8SARASFQHGX2MiqOaoj-maUsO1RnxFcACgaA0175",
// "token_type":"Bearer","expires_in":3599,"scope":"email profile
// https://www.googleapis.com/auth/userinfo.email
// https://www.googleapis.com/auth/contacts.readonly
// https://www.googleapis.com/auth/userinfo.profile
// openid","authuser":"0","prompt":"consent"}

type GoogleUserRequest struct {
	FirstName    string `json:"first_name"`
	LastName     string `json:"last_name"`
	Email        string `json:"email"`
	PhotoURL     string `json:"photoURL"`
	ProviderID   string `json:"providerId"`
	UID          string `json:"uid"`
	RefreshToken string `json:"refreshToken"`
	IsVerified   bool   `json:"isEmailVerified"` // Fixed JSON tag
}

func CreateUserGoogle(c *gin.Context) {
	var GUserRequest GoogleUserRequest
	log.Println("Received Google user:", GUserRequest.FirstName)

	// Bind the JSON request to GoogleUserRequest struct
	if err := c.ShouldBindJSON(&GUserRequest); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid request payload"})
		return
	}

	// Check for user details in UserDetail
	var userDetail models.UserDetail
	result := db.DB.Where("email = ?", GUserRequest.Email).First(&userDetail)

	if result.Error != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Database error while fetching user details"})
		return
	}

	// If user details exist, generate JWT
	if result.Error == nil {
		token := auth.GenerateJWT(userDetail.Email)
		if token == "error" {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "Failed to generate token"})
			return
		}
		c.JSON(http.StatusOK, gin.H{
			"token": token,
		})
		return
	}

	// If user details are not found
	if result.Error == gorm.ErrRecordNotFound {
		c.JSON(http.StatusOK, gin.H{
			"message": "New User",
		})
		return
	}

	// If user is not in organisationUser
	c.JSON(http.StatusUnauthorized, gin.H{
		"error": "No user with this email. Contact your admin to add you to the organisation.",
	})
}

