package services

import (
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"

	"gorm.io/gorm"
)

// FetchSteelQuotationForRender fetches everything needed to render the steel quotation template.
//
// Includes:
// - SteelQuotation core fields
// - CustomerModel
// - Items
// - Organisation (for branding)
// - OrganisationAddress (for address block)
func FetchSteelQuotationForRender(tx *gorm.DB, quotationID uint) (models.SteelQuotation, models.Organisation, models.OrganisationAddress, error) {
	if tx == nil {
		tx = db.DB
	}

	var q models.SteelQuotation
	if err := tx.
		Preload("CustomerModel").
		Preload("Items").
		First(&q, quotationID).Error; err != nil {
		return models.SteelQuotation{}, models.Organisation{}, models.OrganisationAddress{}, err
	}

	var org models.Organisation
	if err := tx.First(&org, q.OrganisationID).Error; err != nil {
		return models.SteelQuotation{}, models.Organisation{}, models.OrganisationAddress{}, err
	}

	// Address model is referenced by your view mapper signature (models.OrganisationAddress).
	// Pick the "primary/latest" address for now. Adjust ordering/where once your schema rules are clear.
	var addr models.OrganisationAddress
	_ = tx.
		Where("organisation_id = ?", q.OrganisationID).
		Order("id desc").
		First(&addr).Error

	return q, org, addr, nil
}

