package handlers

import (
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	structure "core-backend/m/v2/openapi_structure"
	"fmt"
	"log"
	"net/http"

	"github.com/gin-gonic/gin"
)

func GetUserListWithSearch(c *gin.Context) {
	var orgUsers []models.OrganisationUser // Organisation users
	orgID := c.Param("id")
	query := c.Param("query") // Get the search query from query parameters
	fmt.Println(orgUsers)
	fmt.Println(query)

	var users []models.UserDetail // Users matching the organisation and search criteria

	// Perform the query using GORM
	if query != "" {
		// If a search query is provided, filter users based on first_name or last_name
		err := db.DB.
			Joins("JOIN organisation_users ON user_details.id = organisation_users.user_id").
			Where("organisation_users.organisation_id = ?", orgID).
			Where("user_details.first_name LIKE ? OR user_details.last_name LIKE ?", "%"+query+"%", "%"+query+"%").
			Find(&users).Error
		fmt.Println(err)
		if err != nil {
			log.Fatalf("Error fetching users: %v", err)
		}
	}

	var response []structure.UserListOrganisation

	// Iterate through users and prepare the response
	for _, user := range users {
		fullName := user.FirstName + " " + user.LastName
		response = append(response, structure.UserListOrganisation{
			Id:   user.ID,
			Name: fullName,
			// Add any other fields you want to include in the response
		})
	}

	// Check if the response is empty
	if len(response) == 0 {
		// If the response is empty, return an error message
		c.JSON(http.StatusNotFound, gin.H{"error": "No users found for the given organisation and query"})
		return
	}

	// Send out the response
	c.JSON(http.StatusOK, response)
	log.Default().Println("Executed GetUserList by id: ", orgID, " with query: ", query) 
}

