func getSteelQuotationTemplate() (*template.Template, error) {
	steelQuotationOnce.Do(func() {
		steelQuotationTmpl, steelQuotationErr = template.New("quotation.html").
			Funcs(SteelQuotationTemplateFuncs()).
			ParseFS(templates.EmbeddedFS, "quotation.html")
	})
	return steelQuotationTmpl, steelQuotationErr
}

// RenderSteelQuotationHTML renders templates/quotation.html using the provided view model.
func RenderSteelQuotationHTML(data models.SteelQuotationViewModel) ([]byte, error) {
	tmpl, err := getSteelQuotationTemplate()
	if err != nil {
		return nil, err
	}

	var buf bytes.Buffer
	if err := tmpl.Execute(&buf, data); err != nil {
		return nil, err
	}
	return buf.Bytes(), nil
}

