)

func UploadImage(c *gin.Context) {
	// Retrieve the user ID from the request

	userID := c.MustGet("id").(uint)

	// Retrieve the uploaded image file from the form
	file, header, err := c.Request.FormFile("image")
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}
	defer file.Close()

	// Read the image data
	imageData, err := io.ReadAll(file)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Create a new File instance
	newFile := models.File{
		Name:   header.Filename,
		Data:   imageData,
		Type:   header.Header.Get("Content-Type"),
		Use:    "example_use", // Set the appropriate use for your file
		UserId: userID,        // Assign the user ID
	}

	// Insert file details into the database
	if err := db.DB.Create(&newFile).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Return success response
	c.JSON(http.StatusOK, gin.H{"message": "File uploaded successfully", "file_id": newFile.ID})
}

func UpdateUserImage(c *gin.Context) {
	// Parse user ID from URL parameters
	userID := c.MustGet("id")

	// Retrieve the user detail from the database
	var userDetail models.UserDetail
	result := db.DB.Where("id=?", userID).First(&userDetail)
	if result.Error != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "User not found"})
		return
	}

	// Retrieve the uploaded image file from the form
	file, _, err := c.Request.FormFile("image")
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}
	defer file.Close()

	// Read the image data
	imageData, err := io.ReadAll(file)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Update the image data in the user detail
	userDetail.ImageData = imageData

	// Save the updated user detail to the database
	if err := db.DB.Save(&userDetail).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Return success response
	c.JSON(http.StatusOK, gin.H{"message": "User image updated successfully"})
}

func GetUserImage(c *gin.Context) {
	// Parse user ID from URL parameters
	userIDStr := c.Param("user_id")
	userID, err := strconv.ParseUint(userIDStr, 10, 64)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid user ID"})
		return
	}

	// Retrieve the user detail from the database
	var userDetail models.UserDetail
	result := db.DB.Where("id = ?", userID).First(&userDetail)
	if result.Error != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "User not found"})
		return
	}

	// Check if the user has an image
	if len(userDetail.ImageData) == 0 {
		c.JSON(http.StatusNotFound, gin.H{"error": "User image not found"})
		return
	}

	// Set Content-Type header to indicate image data
	c.Header("Content-Type", "image/jpeg") // Change "image/jpeg" to the appropriate image format

	// Return the image data as the response body
	c.Data(http.StatusOK, "image/jpeg", userDetail.ImageData) // Change "image/jpeg" to the appropriate image format
}
func UploadTaskFile(c *gin.Context) {
	// Retrieve the uploaded file
	file, err := c.FormFile("file")
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}
	AssigneeId, err := strconv.ParseUint(c.PostForm("assignee_id"), 10, 64)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid assignee ID"})
		return
	}

	// Read the file content
	fileContent, err := file.Open()
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}
	defer fileContent.Close()

	data, err := io.ReadAll(fileContent)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Save the file record
	newFile := models.File{
		Name:   file.Filename,
		Data:   data,
		Type:   file.Header.Get("Content-Type"),
		Use:    "task_attachment",
		UserId: uint(AssigneeId),
	}

	if err := db.DB.Create(&newFile).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Optionally wrap inside TaskFile table if you need
	taskFile := models.TaskFile{FileID: newFile.ID}
	if err := db.DB.Create(&taskFile).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Respond with FileID
	c.JSON(http.StatusOK, gin.H{
		"message": "File uploaded successfully",
		"file_id": newFile.ID,
	})
}
func GetTaskFiles(c *gin.Context) {
	taskID := c.Param("task_id")

	// Fetch the task
	var task models.Task
	if err := db.DB.First(&task, taskID).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "Task not found"})
		return
	}

	// Ensure the task has files
	if len(task.Files) == 0 {
		c.JSON(http.StatusOK, gin.H{
			"task_id": taskID,
			"files":   []map[string]interface{}{},
		})
		return
	}

	fmt.Printf("Found %d files for task %s\n", len(task.Files), taskID)

	// Convert FileIDs to []interface{} for GORM IN clause
	fileIDs := make([]interface{}, len(task.Files))
	for i, id := range task.Files {
		fileIDs[i] = id
	}

	// Fetch all files in one query
	var files []models.File
	if err := db.DB.Where("id IN ?", fileIDs).Find(&files).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	// Transform response
	resp := make([]map[string]interface{}, len(files))
	for i, f := range files {
		resp[i] = map[string]interface{}{
			"id":    f.ID,
			"name":  f.Name,
			"type":  f.Type,
			"user":  f.UserId,
			"added": f.CreatedAt,
		}
	}

	fmt.Println(resp)
	c.JSON(http.StatusOK, gin.H{
		"task_id": taskID,
		"files":   resp,
	})
}

// Download a specific file by FileID
func DownloadTaskFile(c *gin.Context) {
	fileID := c.Param("file_id")

	var file models.File
	if err := db.DB.First(&file, fileID).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "File not found"})
		return
	}

	// Set headers for download
	c.Header("Content-Disposition", fmt.Sprintf("attachment; filename=%s", file.Name))
