}

func UploadChatFiles(c *gin.Context) {
	messageID := c.Param("messageID")
	log.Printf("Received upload request for messageID: %s", messageID)
	log.Printf("Request headers: %v", c.Request.Header)
	log.Printf("Request form: %v", c.Request.Form)

	// Parse multipart form with 64MB limit
	if err := c.Request.ParseMultipartForm(64 << 20); err != nil {
		log.Printf("Error parsing multipart form: %v", err)
		c.JSON(http.StatusBadRequest, gin.H{"error": "Failed to parse multipart form"})
		return
	}

	// Retrieve the file
	file, header, err := c.Request.FormFile("file")
	if err != nil {
		log.Printf("Error retrieving file under key 'file': %v", err)
		c.JSON(http.StatusBadRequest, gin.H{"error": "No file found in request"})
		return
	}
	defer file.Close()
	log.Printf("File found: %s, size: %d bytes", header.Filename, header.Size)

	// Validate file type
	fileType := c.Request.FormValue("fileType")
	log.Printf("File type: %s", fileType)
	allowedTypes := map[string]bool{
		"application/pdf": true,
		"image/jpeg":      true,
		"image/jpg":       true,
		"image/png":       true,
		"application/zip": true,
	}
	if !allowedTypes[fileType] {
		log.Printf("Invalid file type: %s", fileType)
		c.JSON(http.StatusBadRequest, gin.H{"error": "Unsupported file type"})
		return
	}

	// Read file data
	fileData, err := io.ReadAll(file)
	if err != nil {
		log.Printf("Error reading file: %v", err)
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to read file"})
		return
	}

	// Save to database
	chatFiles := models.ChatFiles{
		MessageId: messageID,
		Data:      fileData,
		Type:      fileType,
	}
	if err := db.DB.Create(&chatFiles).Error; err != nil {
		log.Printf("Error saving to database: %v", err)
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to save file"})
		return
	}

	log.Printf("File uploaded successfully for messageID: %s", messageID)
	c.JSON(http.StatusOK, gin.H{"message": "File uploaded successfully"})
}

func GetChatFiles(c *gin.Context) {
	messageID := c.Param("messageID")
	var chatFile models.ChatFiles

	image := db.DB.Where("message_id = ?", messageID).First(&chatFile)

	if err := image.Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}
	// Set Content-Type header to indicate image data
	c.Header("Content-Type", chatFile.Type)
	// Change "image/jpeg" to the appropriate image format

	// Return the image data as the response body
	c.Data(http.StatusOK, chatFile.Type, chatFile.Data)

}

