package handlers

import (
	"context"
	"core-backend/m/v2/cache"
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"os"
	"time"

	"github.com/gin-gonic/gin"
	"golang.org/x/oauth2/google"

	"firebase.google.com/go/v4/messaging"
)

// GetAccessToken generates an OAuth2 access token for Firebase using the service account key.
func GetAccessToken(c *gin.Context) {
	// Fetch required environment variables
	notificationData, err := cache.GetNotificationCache()
	if err == nil {
		c.JSON(http.StatusOK, gin.H{
			"access_token": notificationData["access_token"],
			"expires_in":   notificationData["expires_in"],
		})
		return
	}
	_type := "service_account"
	_client_email := os.Getenv("NOTIFICATION_CLIENT_EMAIL")
	data, err := os.ReadFile("RSA/ooc-notification.pem")

	if err != nil {
		log.Println("Environment variables are missing", err.Error())
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Missing required environment variables", "message": err.Error()})
		return
	}
	if _type == "" || _client_email == "" {
		log.Println("Environment variables are missing")
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Missing required environment variables"})
		return
	}

	privat := string(data)
	// Create a service account key JSON dynamically
	serviceAccountKey := map[string]interface{}{
		"type":         _type,
		"client_email": _client_email,
		"private_key":  privat,
		"token_uri":    "https://oauth2.googleapis.com/token",
	}

	// Marshal the service account key to JSON format
	serviceAccountJSON, err := json.Marshal(serviceAccountKey)
	if err != nil {
		log.Printf("Error marshalling service account key: %v", err)
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to create service account JSON"})
		return
	}

	// Define scopes for Firebase messaging and other Google APIs
	scopes := []string{
		"https://www.googleapis.com/auth/firebase.messaging",
		"https://www.googleapis.com/auth/userinfo.email",
		"https://www.googleapis.com/auth/firebase.database",
	}

	// Authenticate and generate a credentials token
	ctx := context.Background()
	creds, err := google.CredentialsFromJSON(ctx, serviceAccountJSON, scopes...)
	if err != nil {
		log.Printf("Error creating credentials: %v", err)
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to generate credentials"})
		return
	}

	// Use the credentials to obtain a token
	token, err := creds.TokenSource.Token()
	if err != nil {
		log.Printf("Error fetching token: %v", err)
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Failed to fetch access token", "err": err.Error()})
		return
	}
	cache.SetNotificationCache(gin.H{
		"access_token": token.AccessToken,
		"expires_in":   token.Expiry,
	})

	// Return the access token as a JSON response
	c.JSON(http.StatusOK, gin.H{
		"access_token": token.AccessToken,
		"expires_in":   token.Expiry,
	})
}

func SendCheckInNotifications(FcmClient *messaging.Client) {
	now := time.Now()

	targetTime := now.Add(15 * time.Minute)
	targetHM := targetTime.Format("15:04:00")
	orgIDs, err := getOrgIDsForTargetTime("check_in", targetHM)
	if err != nil {
		log.Printf("Error fetching org IDs for check-in: %v", err)
		return
	}

	if len(orgIDs) == 0 {
		log.Println("No organizations need check-in notification now.")
		return
	}

	// Fetch Devices belonging to these Organizations
	tokens, err := fetchTokensByOrgIDs(orgIDs)
	if err != nil {
		log.Printf("Error fetching tokens for check-in: %v", err)
		return
	}

	if len(tokens) > 0 {
		sendBatchFCM(tokens, "Check-in Reminder", "Please mark your attendance.", FcmClient)
	}
}

// SendCheckoutNotifications sends reminders 15 minutes before the scheduled CheckOut time.
func SendCheckoutNotifications(FcmClient *messaging.Client) {
	now := time.Now()

	// Target the CheckOut time that is 15 minutes from now.
	targetTime := now.Add(15 * time.Minute)
	targetHM := targetTime.Format("15:04:00")

	// Find all Organization IDs where the CheckOut time is exactly 15 minutes from now.
	orgIDs, err := getOrgIDsForTargetTime("check_out", targetHM)
	if err != nil {
		log.Printf("Error fetching org IDs for checkout: %v", err)
		return
	}

	if len(orgIDs) == 0 {
		log.Println("No organizations need checkout notification now.")
		return
	}

	// Fetch Devices belonging to these Organizations
	tokens, err := fetchTokensByOrgIDs(orgIDs)
	if err != nil {
		log.Printf("Error fetching tokens for checkout: %v", err)
		return
	}

	if len(tokens) > 0 {
		sendBatchFCM(tokens, "Checkout Reminder", "Your work day ends in 15 minutes. Don't forget to checkout!", FcmClient)
	}
}

// --- NEW HELPER FUNCTIONS ---

// getOrgIDsForTargetTime queries OrganisationTime for organizations with a specific time in the target field.
func getOrgIDsForTargetTime(fieldName string, targetTimeHM string) ([]uint, error) {
	var orgIDs []uint

	if fieldName != "check_in" && fieldName != "check_out" {
		return nil, fmt.Errorf("invalid field name: %s", fieldName)
	}

	err := db.DB.Model(&models.OrganisationTime{}).
		Where(fieldName+" = ?", targetTimeHM).
		Distinct("organisation_id").
		Pluck("organisation_id", &orgIDs).Error

	if err != nil {
		return nil, err
	}

	return orgIDs, nil
}

// fetchTokensByOrgIDs fetches distinct FCM tokens for devices belonging to the given organization IDs.
func fetchTokensByOrgIDs(orgIDs []uint) ([]string, error) {
	var tokens []string

	err := db.DB.Model(&models.DeviceInfo{}).
		Where("organisation_id IN (?) AND fcm_token IS NOT NULL AND fcm_token != ''", orgIDs).
		Distinct("fcm_token").
		Pluck("fcm_token", &tokens).Error

	if err != nil {
		return nil, err
	}

	return tokens, nil
}

// --- SEND BATCH FCM (REMAINS UNCHANGED) ---

func sendBatchFCM(tokens []string, title, body string, FcmClient *messaging.Client) {
	// Firebase allows sending up to 500 tokens per batch.
	batchSize := 500

	for i := 0; i < len(tokens); i += batchSize {
		end := i + batchSize
		if end > len(tokens) {
			end = len(tokens)
		}

		batchTokens := tokens[i:end]

		message := &messaging.MulticastMessage{
			Tokens: batchTokens,
			Notification: &messaging.Notification{
				Title: title,
				Body:  body,
			},
		}

		br, err := FcmClient.SendEachForMulticast(context.Background(), message)
		if err != nil {
			log.Printf("Error sending batch: %v", err)
			continue
		}

		if br.FailureCount > 0 {
			log.Printf("%d messages failed out of %d", br.FailureCount, len(batchTokens))
		} else {
			log.Printf("Sent %d notifications successfully", br.SuccessCount)
		}
	}
}

