                fontStyle: FontStyle.italic,
              ),
              maxLines: 2,
              overflow: TextOverflow.ellipsis,
            ),
          ],
        );
      },
      detailRowsBuilder: (r, ctx) => [
        HealthRecordDetailRow(
          label: 'Exercise Type',
          value: r.exerciseType.name,
        ),
        if (r.title?.isNotEmpty ?? false)
          HealthRecordDetailRow(
            label: 'Title',
            value: r.title,
          ),
        if (r.notes?.isNotEmpty ?? false)
          HealthRecordDetailRow(
            label: AppTexts.notes,
            value: r.notes,
          ),
