package handlers

import (
	"core-backend/m/v2/db"
	"core-backend/m/v2/models"
	structure "core-backend/m/v2/openapi_structure"
	"core-backend/m/v2/utils"
	"encoding/json"
	"errors"
	"fmt"
	"log"
	"math"
	"net/http"
	"strconv"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
	"gorm.io/gorm"
)

// calculateDistance computes the distance between two points using the Haversine formula (in meters)
func calculateDistance(lat1, lon1, lat2, lon2 float64) float64 {
	const p = 0.017453292519943295 // Math.PI / 180
	const earthRadius = 6371000    // Earth's radius in meters

	a := 0.5 - math.Cos((lat2-lat1)*p)/2 +
		math.Cos(lat1*p)*math.Cos(lat2*p)*(1-math.Cos((lon2-lon1)*p))/2

	return earthRadius * 2 * math.Asin(math.Sqrt(a))
}

// GPS drift: points that are very close together (< 2m) with large time gaps (> 10 minutes) = user was stationary
func filterGPSDriftBasic(locations []models.UserLocation) []models.UserLocation {
	if len(locations) < 2 {
		return locations
	}

	filtered := []models.UserLocation{locations[0]}
	const maxRealisticSpeedKmh = 1000.0
	const maxRealisticSpeedMs = maxRealisticSpeedKmh * 1000 / 3600
	const minDistanceForDrift = 2.0 // Less than 2m = potential drift
	const maxTimeForDrift = 600.0   // More than 10 minutes = likely stationary

	for i := 1; i < len(locations); i++ {
		current := locations[i]
		previous := filtered[len(filtered)-1]

		prevTime := previous.StartTimestamp
		currTime := current.StartTimestamp

		timeDiffSeconds := time.Time(currTime).Sub(time.Time(prevTime)).Seconds()

		if timeDiffSeconds < 1 {
			continue
		}

		distance := calculateDistance(
			previous.Latitude, previous.Longitude,
			current.Latitude, current.Longitude,
		)

		// Filter obvious GPS drift: very small distance (< 2m) with large time gap (> 10 min) = user was stationary
		if distance < minDistanceForDrift && timeDiffSeconds > maxTimeForDrift {
			continue
		}

		speed := distance / timeDiffSeconds

		if speed <= maxRealisticSpeedMs {
			filtered = append(filtered, current)
		}
	}

	return filtered
}

// calculateJourneyDistance computes the total distance traveled across filtered locations
func calculateJourneyDistance(locations []models.UserLocation) float64 {
	if len(locations) < 2 {
		fmt.Printf("Not enough points for distance calculation: %d\n", len(locations))
		return 0.0
	}

	filteredLocations := filterGPSDriftBasic(locations)

	if len(filteredLocations) < 2 {
		fmt.Printf("Not enough filtered points for distance calculation: %d\n", len(filteredLocations))
		return 0.0
	}

	totalDistance := 0.0
	for i := 0; i < len(filteredLocations)-1; i++ {
		segmentDistance := calculateDistance(
			filteredLocations[i].Latitude,
			filteredLocations[i].Longitude,
			filteredLocations[i+1].Latitude,
			filteredLocations[i+1].Longitude,
		)
		// Ignore small GPS jitter (< 10 meters)
		if segmentDistance < 10.0 {
			continue
		}
		totalDistance += segmentDistance
		fmt.Printf("Segment %d to %d: Distance %.2f m\n", i, i+1, segmentDistance)
	}
	fmt.Printf("Calculated total distance: %.2f km\n", totalDistance/1000)
	return totalDistance / 1000 // Return in kilometers
}

// Journey represents a single journey segment
type Journey struct {
	JourneyNumber int                              `json:"journey_number"`
	StartTime     string                           `json:"start_time"`
	EndTime       string                           `json:"end_time"`
	Distance      string                           `json:"distance"`
	Duration      string                           `json:"duration"`
	Locations     []structure.UserLocationResponse `json:"locations"`
	Status        string                           `json:"status"`
}

// segmentIntoJourneys splits locations into separate journeys based on movement and inactivity periods
// Journey starts when user begins moving, ends when user is stationary for more than 10 minutes
func segmentIntoJourneys(locations []models.UserLocation) [][]models.UserLocation {
	if len(locations) < 2 {
		if len(locations) == 1 {
			return [][]models.UserLocation{locations}
		}
		return [][]models.UserLocation{}
	}

	const maxInactivityMinutes = 10.0 // Journey ends if stationary for more than 10 minutes
	const minMovementDistance = 10.0  // Minimum distance in meters to consider it movement

	var journeys [][]models.UserLocation
	var currentJourney []models.UserLocation
	inJourney := false

	for i := 0; i < len(locations); i++ {
		current := locations[i]
		currentTime := time.Time(current.StartTimestamp)

		if i == 0 {

			currentJourney = []models.UserLocation{current}
			inJourney = false
			continue
		}

		previous := locations[i-1]
		previousTime := time.Time(previous.StartTimestamp)

		// Calculate time difference in minutes
		timeDiff := currentTime.Sub(previousTime).Minutes()

		// Calculate distance between previous and current location (in meters)
		// calculateDistance already returns meters
		distanceMeters := calculateDistance(
			previous.Latitude, previous.Longitude,
			current.Latitude, current.Longitude,
		)

		// Check if user has moved (distance > minimum threshold)
		hasMoved := distanceMeters >= minMovementDistance

		if !inJourney {
			// Not currently in a journey
			if hasMoved {
				// User started moving - begin journey with previous and current location
				currentJourney = []models.UserLocation{previous, current}
				inJourney = true
				fmt.Printf("Point %d: Movement detected (%.2f m), starting new journey\n", i, distanceMeters)
			} else {
				// User still stationary - update last location in current segment
				if len(currentJourney) > 0 {
					currentJourney[len(currentJourney)-1] = current
				} else {
					currentJourney = []models.UserLocation{current}
				}
			}
		} else {
			// Currently in a journey
			if hasMoved {
				// User is moving - continue journey
				currentJourney = append(currentJourney, current)
				fmt.Printf("Point %d: Moving (%.2f m), continuing journey\n", i, distanceMeters)
			} else if timeDiff > maxInactivityMinutes {
				// User has been stationary for more than 10 minutes - end journey
				if len(currentJourney) > 0 {
					journeys = append(journeys, currentJourney)
					fmt.Printf("Journey ended at point %d due to inactivity (%.2f mins, %.2f m moved)\n", i-1, timeDiff, distanceMeters)
				}
				// Reset for potential new journey
				currentJourney = []models.UserLocation{current}
				inJourney = false
			} else {
				// User is stationary but within 10 minutes - continue journey (might be waiting at traffic light, etc.)
				currentJourney = append(currentJourney, current)
				fmt.Printf("Point %d: Stationary (%.2f m) but within time limit (%.2f mins), continuing journey\n", i, distanceMeters, timeDiff)
			}
		}
	}

	// Add the last journey if it has data and was actually a journey (user moved)
	if len(currentJourney) > 0 && inJourney {
		journeys = append(journeys, currentJourney)
	}

	fmt.Printf("Total journeys identified: %d\n", len(journeys))
	return journeys
}

// formatDuration formats duration in a readable format
func formatDuration(start, end time.Time) string {
	duration := end.Sub(start)
	hours := int(duration.Hours())
	minutes := int(duration.Minutes()) % 60

	if hours > 0 {
		return fmt.Sprintf("%d hrs %d mins", hours, minutes)
	}
	return fmt.Sprintf("%d mins", minutes)
}

// determineJourneyStatus determines if a journey is active or completed
func determineJourneyStatus(endTime time.Time) string {
	now := time.Now().UTC()
	diff := now.Sub(endTime).Minutes()

	if diff < 20 {
		return "Active"
	}
	return "Completed"
}

func GetLocationHistory(c *gin.Context) {
