	// Getting user ID from token claims
	userID := c.MustGet("id")

	// Query database to fetch location history based on user ID
	db.DB.Where("user_id = ?", userID).Find(&locations)

	// Create a slice of UserLocationResponse to hold the transformed data
	var response []structure.UserLocationResponse

	// Populate the response slice with the required fields
	for _, location := range locations {
