func storeLoaction(c *gin.Context) {
	var req struct {
		ID             uint    `json:"id"`
		UserId         uint    `json:"user_id"`
		Latitude       float64 `json:"latitude"`
		Longitude      float64 `json:"longitude"`
		StartTimestamp string  `json:"start_timestamp"`
		EndTimestamp   string  `json:"end_timestamp"`
		AreaName       string  `json:"area_name"`
	}

	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	loc, _ := time.LoadLocation("UTC")
	start, err := time.ParseInLocation(time.RFC3339Nano, req.StartTimestamp, loc)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid start_timestamp format"})
		return
	}

	// Get organization_id from user_id via organisation_users table
	var orgUser models.OrganisationUser
	var organizationID uint = 0
	if err := db.DB.Where("user_id = ? AND deleted_at IS NULL", req.UserId).First(&orgUser).Error; err == nil {
		organizationID = orgUser.OrganisationId
		log.Default().Printf("Found organization_id %d for user_id %d", organizationID, req.UserId)
	} else {
		log.Default().Printf("No organization found for user_id %d, will use global area_name lookup", req.UserId)
	}

	// Check for area_name with priority:
	// 1) Location Tags (tagged locations) - HIGHEST PRIORITY
	// 2) Existing user_locations in same org
	// 3) OpenStreetMap API (if nothing found)
	var areaName string
	// Use tolerance for coordinate matching (0.001 degrees ≈ 111 meters)
	// Increased from 0.0001 to improve address reuse hit rate
	const tolerance = 0.001

	// PRIORITY 0: User Provided Area Name
	if req.AreaName != "" {
		areaName = req.AreaName
		log.Default().Printf("Using client provided area name: %s", areaName)
	}

	// PRIORITY 1: Check Location Tags (tagged locations) for the same organization
	// This is the HIGHEST priority - if coordinates match a tagged location, use that name
	if organizationID > 0 {
		var locationTag models.LocationTaggingData
		if err := db.DB.Where(
			"ABS(latitude - ?) < ? AND ABS(longitude - ?) < ? AND organization_id = ? AND deleted_at IS NULL",
			req.Latitude, tolerance, req.Longitude, tolerance, organizationID,
		).Order("created_at DESC").First(&locationTag).Error; err == nil {
			areaName = locationTag.LocationName
			log.Default().Printf("✅ Using tagged location name '%s' for coordinates (%.6f, %.6f) in org %d", areaName, req.Latitude, req.Longitude, organizationID)
		}
	}

	// PRIORITY 2: Check existing user_locations (if no tagged location found)
	// First check same org, then check all orgs (but skip location tag names)
	if areaName == "" {
		var existingLocation models.UserLocation

		// Priority 2a: Check same org first
		if organizationID > 0 {
			// Check for same user_id + same org_id + same coordinates (using direct organization_id field)
			if err := db.DB.Where("ABS(latitude - ?) < ? AND ABS(longitude - ?) < ? AND area_name != '' AND area_name IS NOT NULL AND user_id = ? AND organization_id = ?",
				req.Latitude, tolerance, req.Longitude, tolerance, req.UserId, organizationID).
				Order("created_at DESC").First(&existingLocation).Error; err == nil {
				// Check if this area_name matches any location tag name in the same org
				var locationTagCheck models.LocationTaggingData
				if err := db.DB.Where("location_name = ? AND organization_id = ? AND deleted_at IS NULL", existingLocation.AreaName, organizationID).First(&locationTagCheck).Error; err == nil {
					log.Default().Printf("⚠️ Area name '%s' matches a location tag in org %d - NOT reusing", existingLocation.AreaName, organizationID)
					// Don't reuse - this area_name came from a location tag
				} else {
					// Safe to reuse - this area_name didn't come from a location tag
					areaName = existingLocation.AreaName
					log.Default().Printf("Reusing area name from same user+org: %s for coordinates (%.6f, %.6f) in org %d", areaName, req.Latitude, req.Longitude, organizationID)
				}
			}

			// Priority 2b: Check for same org_id + same coordinates (any user in same org) - only if still no areaName
			if areaName == "" {
				if err := db.DB.Where("ABS(latitude - ?) < ? AND ABS(longitude - ?) < ? AND area_name != '' AND area_name IS NOT NULL AND organization_id = ?",
					req.Latitude, tolerance, req.Longitude, tolerance, organizationID).
					Order("created_at DESC").First(&existingLocation).Error; err == nil {
					// Check if this area_name matches any location tag name in the same org
					var locationTagCheck models.LocationTaggingData
					if err := db.DB.Where("location_name = ? AND organization_id = ? AND deleted_at IS NULL", existingLocation.AreaName, organizationID).First(&locationTagCheck).Error; err == nil {
						log.Default().Printf("⚠️ Area name '%s' matches a location tag in org %d - NOT reusing", existingLocation.AreaName, organizationID)
						// Don't reuse - this area_name came from a location tag
					} else {
						// Safe to reuse - this area_name didn't come from a location tag
						areaName = existingLocation.AreaName
						log.Default().Printf("Reusing area name from same org: %s for coordinates (%.6f, %.6f) in org %d", areaName, req.Latitude, req.Longitude, organizationID)
					}
				}
			}
		}

		// Priority 2c: Check ALL organizations (global check) - only if still no areaName
		// But skip any area_names that match location tag names in ANY organization
		if areaName == "" {
			if err := db.DB.Where(
				"ABS(latitude - ?) < ? AND ABS(longitude - ?) < ? AND area_name != '' AND area_name IS NOT NULL",
				req.Latitude, tolerance, req.Longitude, tolerance,
			).Order("created_at DESC").First(&existingLocation).Error; err == nil {
				// Check if this area_name matches any location tag name in ANY organization
				var locationTagCheck models.LocationTaggingData
				if err := db.DB.Where("location_name = ? AND deleted_at IS NULL", existingLocation.AreaName).First(&locationTagCheck).Error; err == nil {
					log.Default().Printf("⚠️ Area name '%s' matches a location tag in org %d - NOT reusing globally", existingLocation.AreaName, locationTagCheck.OrganizationID)
					// Don't reuse - this area_name came from a location tag (any org)
				} else {
					// Safe to reuse - this area_name didn't come from a location tag
					areaName = existingLocation.AreaName
					log.Default().Printf("Reusing global area name (not a location tag): %s for coordinates (%.6f, %.6f)", areaName, req.Latitude, req.Longitude)
				}
			}
		}
	}

	// PRIORITY 3: Fetch from OpenStreetMap API if no tagged location and no existing area_name found
	if areaName == "" {
		// Fetch area name from Nominatim API if not found in database or incomplete area_name
		client := &http.Client{Timeout: 10 * time.Second}
		url := fmt.Sprintf("https://nominatim.openstreetmap.org/reverse?format=json&lat=%f&lon=%f&zoom=18&addressdetails=1", req.Latitude, req.Longitude)

		apiReq, err := http.NewRequest("GET", url, nil)
		if err != nil {
			log.Default().Printf("Error creating Nominatim request: %v", err)
		} else {
			// CRITICAL: Nominatim requires a valid User-Agent identifying the application
			apiReq.Header.Set("User-Agent", "SecEntApp/1.0 (internal-usage)")

			resp, err := client.Do(apiReq)
			if err != nil {
				log.Default().Printf("Error fetching area name: %v", err)
				// Continue without area name if API call fails
			} else {

				defer resp.Body.Close()
				var result map[string]interface{}
				if err := json.NewDecoder(resp.Body).Decode(&result); err == nil {
					if address, ok := result["address"].(map[string]interface{}); ok {
						neighbourhood := ""
						if n, ok := address["neighbourhood"].(string); ok {
							neighbourhood = n
						}
						suburb := ""
						if s, ok := address["suburb"].(string); ok {
							suburb = s
						}
						city := ""
						if ct, ok := address["city"].(string); ok {
							city = ct
						} else if t, ok := address["town"].(string); ok {
							city = t
						} else if v, ok := address["village"].(string); ok {
							city = v
						}
						postcode := ""
						if p, ok := address["postcode"].(string); ok {
							postcode = p
						}
						// Concatenate neighbourhood, suburb, city, and postcode with commas
						areaParts := []string{neighbourhood, suburb, city, postcode}
						var validParts []string
						for _, part := range areaParts {
							if part != "" {
								validParts = append(validParts, part)
							}
						}
						areaName = strings.Join(validParts, ",")
					}
				} else {
					log.Default().Printf("Error decoding Nominatim response: %v", err)
				}
			}
		}
	}

	if areaName == "" {
		log.Default().Printf("No area name found for coordinates (%.6f, %.6f)", req.Latitude, req.Longitude)
	}

	// Store IST timestamps directly (no timezone conversion needed)
	// Frontend now sends IST timestamps directly

	if req.ID != 0 {
		var update models.UserLocation
		if err := db.DB.First(&update, req.ID).Error; err != nil {
			if errors.Is(err, gorm.ErrRecordNotFound) {
				c.JSON(http.StatusNotFound, gin.H{"error": "location record not found"})
			} else {
				c.JSON(http.StatusInternalServerError, gin.H{"error": "database error"})
			}
			return
		}

		// Only update end_timestamp if it's provided
		if req.EndTimestamp != "" {
			end, err := time.ParseInLocation(time.RFC3339Nano, req.EndTimestamp, loc)
			if err != nil {
				c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid end_timestamp format"})
				return
			}
			// FIX: Cast time.Time to models.LocationTime for GORM update
			db.DB.Model(&update).Updates(map[string]interface{}{
				"end_timestamp":   (end),
				"area_name":       areaName,
				"organization_id": organizationID, // Update organization_id
			})
		}
		c.JSON(http.StatusOK, gin.H{"result": update})
		return
	}

	location := models.UserLocation{
		UserId:         models.UserID(req.UserId),
		OrganizationId: organizationID, // Store organization_id directly
		// FIX: Cast time.Time to models.LocationTime for struct initialization
		StartTimestamp: models.LocationTime(start),
		Latitude:       req.Latitude,
		Longitude:      req.Longitude,
		AreaName:       areaName,
	}

	// Only set EndTimestamp if it's provided
	if req.EndTimestamp != "" {
		end, err := time.ParseInLocation(time.RFC3339Nano, req.EndTimestamp, loc)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid end_timestamp format"})
			return
		}
		// FIX: Cast time.Time to models.LocationTime for assignment
		location.EndTimestamp = models.LocationTime(end)
	}

	if err := db.DB.Create(&location).Error; err != nil {
