		return
	}

	c.JSON(http.StatusOK, gin.H{"id": location.ID})
}

func GetLocationBetweenTimes(c *gin.Context) {
	var locations []models.UserLocation
	userID := c.Param("id")
	startTimeStr := c.Query("start_time")
	endTimeStr := c.Query("end_time")

	// Timestamps are already stored in IST, no offset needed

	var startTime, endTime time.Time
	var err error

	// If dates are given in query, parse them
	if startTimeStr != "" && endTimeStr != "" {
		fmt.Printf("Parsing start_time: %s\n", startTimeStr)
		// Frontend sends IST-formatted times with timezone offset already included
		// Try RFC3339Nano first (handles fractional seconds like .000)
		startTime, err = time.Parse(time.RFC3339Nano, startTimeStr)
		if err != nil {
			// Fallback to RFC3339 without fractional seconds
			startTime, err = time.Parse(time.RFC3339, startTimeStr)
			if err != nil {
				// If still fails, try appending +05:30 (for backward compatibility)
				startTime, err = time.Parse(time.RFC3339Nano, startTimeStr+"+05:30")
				if err != nil {
					startTime, err = time.Parse(time.RFC3339, startTimeStr+"+05:30")
					if err != nil {
						fmt.Printf("Error parsing start_time: %v\n", err)
						c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("Invalid start_time format: %v", err)})
						return
					}
				}
			}
		}

		fmt.Printf("Parsing end_time: %s\n", endTimeStr)
		endTime, err = time.Parse(time.RFC3339Nano, endTimeStr)
		if err != nil {
			// Fallback to RFC3339 without fractional seconds
			endTime, err = time.Parse(time.RFC3339, endTimeStr)
			if err != nil {
				// If still fails, try appending +05:30 (for backward compatibility)
				endTime, err = time.Parse(time.RFC3339Nano, endTimeStr+"+05:30")
				if err != nil {
					endTime, err = time.Parse(time.RFC3339, endTimeStr+"+05:30")
					if err != nil {
						fmt.Printf("Error parsing end_time: %v\n", err)
						c.JSON(http.StatusBadRequest, gin.H{"error": fmt.Sprintf("Invalid end_time format: %v", err)})
						return
					}
				}
			}
		}
	} else {
		// Default: today
		now := time.Now()
		startTime = now
		endTime = now
	}

	fmt.Printf("Querying by DATE: user_id=%s, start_date=%s, end_date=%s\n",
		userID, startTime.Format("2006-01-02"), endTime.Format("2006-01-02"))

	// Query ignoring time part (MySQL DATE function)
	result := db.DB.Where(`
		user_id = ?
		AND DATE(start_timestamp) >= DATE(?)
		AND DATE(start_timestamp) <= DATE(?)`,
		userID, startTime, endTime,
	).Order("start_timestamp asc").Find(&locations)

	if result.Error != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "Database error: " + result.Error.Error()})
		return
	}

	// Segment locations into separate journeys
	journeySegments := segmentIntoJourneys(locations)

	if len(journeySegments) == 0 {
		c.JSON(http.StatusOK, gin.H{
			"data":           []structure.UserLocationResponse{},
			"total_distance": "0.00",
			"journeys":       []Journey{},
			"total_journeys": 0,
		})
		return
	}

	// Process each journey segment
	var journeys []Journey
	var totalDistanceAllJourneys float64 = 0.0
	journeyNumber := 1

	for _, segment := range journeySegments {
		if len(segment) < 1 {
			continue
		}

		// Calculate distance for this journey
		journeyDistance := calculateJourneyDistance(segment)

		// Only include journeys with distance > 0 (user actually moved)
		if journeyDistance <= 0.0 {
			fmt.Printf("Skipping journey with 0km distance\n")
			continue
		}

		totalDistanceAllJourneys += journeyDistance

		// Convert locations to response format
		var journeyLocations []structure.UserLocationResponse
		for _, location := range segment {
			// Format timestamps in IST
			StartTimestamp := time.Time(location.StartTimestamp)
			EndTimestamp := time.Time(location.EndTimestamp)
			startTimestamp := utils.FormatIST(&StartTimestamp)
			endTimestamp := utils.FormatIST(&EndTimestamp)

			journeyLocations = append(journeyLocations, structure.UserLocationResponse{
				UserId:         location.UserId,
				StartTimestamp: startTimestamp,
				EndTimestamp:   endTimestamp,
				Latitude:       location.Latitude,
				Longitude:      location.Longitude,
				AreaName:       location.AreaName,
			})
		}

		// Create journey object
		// Timestamps are already in IST, no conversion needed
		startTime := segment[0].StartTimestamp
		endTime := segment[len(segment)-1].StartTimestamp
		if !time.Time(segment[len(segment)-1].EndTimestamp).IsZero() {
			endTime = segment[len(segment)-1].EndTimestamp
		}
		startTimestamp := time.Time(startTime)
		endTimestamp := time.Time(endTime)
		journey := Journey{
			JourneyNumber: journeyNumber,
			StartTime:     utils.FormatIST(&startTimestamp),
			EndTime:       utils.FormatIST(&endTimestamp),
			Distance:      fmt.Sprintf("%.2f", journeyDistance),
			Duration:      formatDuration(startTimestamp, endTimestamp),
			Locations:     journeyLocations,
			Status:        determineJourneyStatus(time.Time(segment[len(segment)-1].EndTimestamp)),
		}

		journeys = append(journeys, journey)
		journeyNumber++
	}

	// Prepare legacy response format (all locations combined)
	var allLocationsResponse []structure.UserLocationResponse
	for _, location := range locations {
		StartTimestamp := time.Time(location.StartTimestamp)
		EndTimestamp := time.Time(location.EndTimestamp)
		// Format timestamps in IST
		startTimestamp := utils.FormatIST(&StartTimestamp)
		endTimestamp := utils.FormatIST(&EndTimestamp)

		allLocationsResponse = append(allLocationsResponse, structure.UserLocationResponse{
			UserId:         location.UserId,
			StartTimestamp: startTimestamp,
			EndTimestamp:   endTimestamp,
			Latitude:       location.Latitude,
			Longitude:      location.Longitude,
			AreaName:       location.AreaName,
		})
	}

	c.JSON(http.StatusOK, gin.H{
		"data":           allLocationsResponse, // Legacy format for backward compatibility
		"total_distance": fmt.Sprintf("%.2f", totalDistanceAllJourneys),
		"journeys":       journeys,
		"total_journeys": len(journeys),
	})
}

