func GetEmployeesLiveLocations(c *gin.Context) {
	orgId := c.Param("orgId")

	type LatestLocationResult struct {
		UserId         uint       `json:"user_id"`
		FirstName      string     `json:"first_name"`
		LastName       string     `json:"last_name"`
		Email          string     `json:"email"`
		Latitude       float64    `json:"latitude"`
		Longitude      float64    `json:"longitude"`
		StartTimestamp time.Time  `json:"start_timestamp"`
		EndTimestamp   time.Time  `json:"end_timestamp"`
		AreaName       string     `json:"area_name"`
		IsCheckedIn    bool       `json:"is_checked_in"`
		CheckInTime    *time.Time `json:"check_in_time"`
	}

	var results []LatestLocationResult

	// Get today's date boundaries for check-in filtering
	now := time.Now()
	todayStart := time.Date(now.Year(), now.Month(), now.Day(), 0, 0, 0, 0, now.Location())
	todayEnd := todayStart.Add(24 * time.Hour)

	// Single optimized query to get latest location for each user in the organization
	// AND their check-in status for today
	query := `
		SELECT
			ud.id as user_id,
			ud.first_name,
			ud.last_name,
			ud.email,
			ul.latitude,
			ul.longitude,
			ul.start_timestamp,
			ul.end_timestamp,
			ul.area_name,
			CASE WHEN ua.id IS NOT NULL THEN 1 ELSE 0 END as is_checked_in,
			ua.check_in as check_in_time
		FROM organisation_users ou
		JOIN user_details ud ON ou.user_id = ud.id
		JOIN (
			SELECT DISTINCT
				ul1.user_id,
				ul1.latitude,
				ul1.longitude,
				ul1.start_timestamp,
				ul1.end_timestamp,
				ul1.area_name
			FROM user_locations ul1
			INNER JOIN (
				SELECT user_id, MAX(start_timestamp) as max_timestamp
				FROM user_locations
				WHERE deleted_at IS NULL
				GROUP BY user_id
			) ul2 ON ul1.user_id = ul2.user_id AND ul1.start_timestamp = ul2.max_timestamp
			WHERE ul1.deleted_at IS NULL
		) ul ON ud.id = ul.user_id
		LEFT JOIN user_attendances ua ON ud.id = ua.user_id
			AND ua.check_in >= ?
			AND ua.check_in < ?
			AND ua.deleted_at IS NULL
		WHERE ou.organisation_id = ?
		 AND ou.deleted_at IS NULL
		 AND ud.deleted_at IS NULL
	`

	if err := db.DB.Raw(query, todayStart, todayEnd, orgId).Scan(&results).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": "Failed to fetch latest employee locations: " + err.Error(),
		})
		return
	}

	fmt.Printf("Organisation ID: %s\n", orgId)
	fmt.Printf("Found %d users with latest location data\n", len(results))

	type EmployeeLiveLocation struct {
		UserId         uint    `json:"user_id"`
		FirstName      string  `json:"first_name"`
		LastName       string  `json:"last_name"`
		Email          string  `json:"email"`
		Latitude       float64 `json:"latitude"`
		Longitude      float64 `json:"longitude"`
		StartTimestamp string  `json:"start_timestamp"`
		EndTimestamp   string  `json:"end_timestamp"`
		LastUpdated    string  `json:"last_updated"`
		AreaName       string  `json:"area_name"`
		IsCheckedIn    bool    `json:"is_checked_in"`
		CheckInTime    string  `json:"check_in_time"`
	}

	var finalResult []EmployeeLiveLocation
	// Format timestamps in IST

	for _, result := range results {
		startTimestamp := utils.FormatIST(&result.StartTimestamp)
		endTimestamp := utils.FormatIST(&result.EndTimestamp)
		checkInTime := ""
		if result.CheckInTime != nil {
			checkInTime = utils.FormatIST(result.CheckInTime)
		}

		finalResult = append(finalResult, EmployeeLiveLocation{
			UserId:         result.UserId,
			FirstName:      result.FirstName,
			LastName:       result.LastName,
			Email:          result.Email,
			Latitude:       result.Latitude,
			Longitude:      result.Longitude,
			StartTimestamp: startTimestamp,
			EndTimestamp:   endTimestamp,
			LastUpdated:    startTimestamp,
			AreaName:       result.AreaName,
			IsCheckedIn:    result.IsCheckedIn,
			CheckInTime:    checkInTime,
		})

		checkInStatus := "not checked in"
		if result.IsCheckedIn {
			checkInStatus = "checked in"
		}
		fmt.Printf("Latest location - User %d (%s %s): lat=%.6f, lng=%.6f, area=%s, time=%s, status=%s\n",
			result.UserId, result.FirstName, result.LastName,
			result.Latitude, result.Longitude, result.AreaName,
			result.StartTimestamp.Format("2006-01-02 15:04:05"), checkInStatus)
	}

	c.JSON(http.StatusOK, gin.H{
		"data":                          finalResult,
		"total_employees_with_location": len(finalResult),
		"message":                       "Latest location coordinates returned for each employee with check-in status",
	})
}

// GetLocationNameByCoordinates queries the database for location name by coordinates
// This allows the frontend to check the database first before calling OpenStreetMap
// Priority: 1) Same user + same org, 2) Same org, 3) Global (any org)
func GetLocationNameByCoordinates(c *gin.Context) {
	latStr := c.Query("lat")
	lonStr := c.Query("lon")
	userIDStr := c.Query("user_id")
	orgIDStr := c.Query("org_id")

	if latStr == "" || lonStr == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "lat and lon query parameters are required"})
		return
	}

	var lat, lon float64
	var err error
	if lat, err = strconv.ParseFloat(latStr, 64); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid lat parameter"})
		return
	}
	if lon, err = strconv.ParseFloat(lonStr, 64); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid lon parameter"})
		return
	}

	// Use tolerance for coordinate matching (0.0001 degrees ≈ 11 meters)
	const tolerance = 0.0001

	// PRIORITY 1: Check Location Tags (tagged locations) for the same organization
	// This is the HIGHEST priority - if coordinates match a tagged location, use that name
	if orgIDStr != "" {
		orgID, err := strconv.ParseUint(orgIDStr, 10, 32)
		if err == nil {
			var locationTag models.LocationTaggingData
			if err := db.DB.Where(
				"ABS(latitude - ?) < ? AND ABS(longitude - ?) < ? AND organization_id = ? AND deleted_at IS NULL",
				lat, tolerance, lon, tolerance, uint(orgID),
			).Order("created_at DESC").First(&locationTag).Error; err == nil {
				c.JSON(http.StatusOK, gin.H{
					"area_name": locationTag.LocationName,
					"found":     true,
					"source":    "location_tag",
				})
				return
			}
		}
	}

	// PRIORITY 2: Check existing user_locations in the same organization
	// IMPORTANT: Don't reuse area_names that came from location tags
	var existingLocation models.UserLocation
	var areaName string
	var source string

	// Priority 2a: Check for same user_id + same org_id + same coordinates
	if userIDStr != "" && orgIDStr != "" {
		userID, err1 := strconv.ParseUint(userIDStr, 10, 32)
		orgID, err2 := strconv.ParseUint(orgIDStr, 10, 32)
		if err1 == nil && err2 == nil {
			if err := db.DB.Joins("JOIN organisation_users ou ON user_locations.user_id = ou.user_id").
				Where("ABS(user_locations.latitude - ?) < ? AND ABS(user_locations.longitude - ?) < ? AND user_locations.area_name != '' AND user_locations.area_name IS NOT NULL AND user_locations.user_id = ? AND ou.organisation_id = ? AND ou.deleted_at IS NULL",
					lat, tolerance, lon, tolerance, uint(userID), uint(orgID)).
				Order("user_locations.created_at DESC").First(&existingLocation).Error; err == nil {
				// Check if this area_name matches any location tag name in the same org
				var locationTagCheck models.LocationTaggingData
				if err := db.DB.Where("location_name = ? AND organization_id = ? AND deleted_at IS NULL", existingLocation.AreaName, uint(orgID)).First(&locationTagCheck).Error; err == nil {
					// Don't reuse - this area_name came from a location tag
					// Continue to next check
				} else {
					// Safe to reuse - this area_name didn't come from a location tag
					areaName = existingLocation.AreaName
					source = "user_org"
				}
			}
		}
	}

	// Priority 2b: Check for same org_id + same coordinates (any user in same org) - only if still no areaName
	if areaName == "" && orgIDStr != "" {
		orgID, err := strconv.ParseUint(orgIDStr, 10, 32)
		if err == nil {
			if err := db.DB.Joins("JOIN organisation_users ou ON user_locations.user_id = ou.user_id").
				Where("ABS(user_locations.latitude - ?) < ? AND ABS(user_locations.longitude - ?) < ? AND user_locations.area_name != '' AND user_locations.area_name IS NOT NULL AND ou.organisation_id = ? AND ou.deleted_at IS NULL",
					lat, tolerance, lon, tolerance, uint(orgID)).
				Order("user_locations.created_at DESC").First(&existingLocation).Error; err == nil {
				// Check if this area_name matches any location tag name in the same org
				var locationTagCheck models.LocationTaggingData
				if err := db.DB.Where("location_name = ? AND organization_id = ? AND deleted_at IS NULL", existingLocation.AreaName, uint(orgID)).First(&locationTagCheck).Error; err == nil {
					// Don't reuse - this area_name came from a location tag
					// Continue to next check
				} else {
					// Safe to reuse - this area_name didn't come from a location tag
					areaName = existingLocation.AreaName
					source = "org"
				}
			}
		}
	}

	// Priority 3: Check globally (any coordinates match, any org) - only if still no areaName
	if areaName == "" {
		if err := db.DB.Where(
			"ABS(latitude - ?) < ? AND ABS(longitude - ?) < ? AND area_name != '' AND area_name IS NOT NULL",
			lat, tolerance, lon, tolerance,
		).Order("created_at DESC").First(&existingLocation).Error; err == nil {
			areaName = existingLocation.AreaName
			source = "global"
		}
	}

	if areaName != "" {
		c.JSON(http.StatusOK, gin.H{
			"area_name": areaName,
			"found":     true,
			"source":    source,
		})
		return
	}

	// Not found in database
	c.JSON(http.StatusOK, gin.H{
		"area_name": "",
		"found":     false,
	})
}

