package db

import (
	"context"
	"fmt"
	"log"
	"os"
	"strconv"
	"time"

	"github.com/redis/go-redis/v9"
)

type CRMRedisTTL struct {
	DefaultTTL         time.Duration
	ShortTTL           time.Duration
	LongTTL            time.Duration
	ProductCachedTTL   time.Duration
	CustomerCachedTTL  time.Duration
	QuotationCachedTTL time.Duration
}

type DashboardRedisTTL struct {
	DefaultCacheTTL time.Duration
}
type NotificationRedisTTL struct {
	NotificationRedisTTL time.Duration
}

type RedisTTLs struct {
	CRMRedis          CRMRedisTTL
	DashboardRedis    DashboardRedisTTL
	NotificationRedis NotificationRedisTTL
}

var RedisClient *redis.Client
var RedisTTL *RedisTTLs

func InitRedis(ctx context.Context) {

	DB := 0
	if os.Getenv("REDIS_DB") == "Dev" {
		DB = 0
	} else if os.Getenv("REDIS_DB") == "Prod" {
		DB = 1
	} else {

		DB, err := strconv.Atoi(os.Getenv("REDIS_DB"))
		if err != nil {
			log.Default().Println("Invalid REDIS DB value")
			return
		}
		log.Default().Println("Using REDIS DB:", DB)
	}

	RedisClient = redis.NewClient(&redis.Options{

		Addr:     os.Getenv("REDIS_ADDR"),
		Password: os.Getenv("REDIS_PASSWORD"),
		OnConnect: func(ctx context.Context, cn *redis.Conn) error {
			err := ctx.Err()
			if err != nil {

				log.Default().Println("REDIS CLIENT IS NOT CONNECTED")
				return fmt.Errorf("error: %v", err.Error())
			}

			return nil
		},
		DB: DB})
	if err := RedisClient.Ping(ctx).Err(); err != nil {
		log.Default().Println("REDIS CLIENT IS NOT CONNECTED")
		log.Default().Println("ERR:", err.Error())
	} else {

		log.Default().Println("REDIS CLIENT IS CONNECTED")
	}
	log.Default().Println("FETCHING TTLs FOR REDIS")
	RedisTTL = LoadRedisTTLs()

}

func getDurationEnv(key string, defaultValue time.Duration) time.Duration {
	val, ok := os.LookupEnv(key)
	if !ok {
		return defaultValue
	}

	duration, err := time.ParseDuration(val)
	if err != nil {
		log.Default().Printf("Warning: Invalid duration format for %s ('%s'). Using default: %v\n", key, val, defaultValue)
		return defaultValue
	}
	return duration
}

func LoadRedisTTLs() *RedisTTLs {

	const defaultCRM = 30 * time.Minute
	const defaultDashboard = 5 * time.Minute
	const defaultNotification = 24 * time.Hour

	// Load CRM Redis TTLs
	crmConfig := CRMRedisTTL{
		DefaultTTL:         getDurationEnv("REDIS_TTLS_CRM_DEFAULT_TTL", defaultCRM),
		ShortTTL:           getDurationEnv("REDIS_TTLS_CRM_SHORT_TTL", 10*time.Minute),
		LongTTL:            getDurationEnv("REDIS_TTLS_CRM_LONG_TTL", 2*defaultCRM),
		ProductCachedTTL:   getDurationEnv("REDIS_TTLS_CRM_PRODUCT_CACHED_TTL", 6*time.Hour),
		CustomerCachedTTL:  getDurationEnv("REDIS_TTLS_CRM_CUSTOMER_CACHED_TTL", 1*time.Hour),
		QuotationCachedTTL: getDurationEnv("REDIS_TTLS_CRM_QUOTATION_CACHED_TTL", 3*time.Hour),
	}

	//Load Dashboard Redis TTLs
	dashboardConfig := DashboardRedisTTL{
		DefaultCacheTTL: getDurationEnv("REDIS_TTLS_DASHBOARD_DEFAULT_CACHE_TTL", defaultDashboard),
	}

	//Load Notification Redis TTLs
	notificationConfig := NotificationRedisTTL{
		NotificationRedisTTL: getDurationEnv("REDIS_TTLS_NOTIFICATION_REDIS_TTL", defaultNotification),
	}

	//Combine into the top-level struct
	return &RedisTTLs{
		CRMRedis:          crmConfig,
		DashboardRedis:    dashboardConfig,
		NotificationRedis: notificationConfig,
	}
}

