package services

import (
	"bytes"
	"core-backend/m/v2/LLM_part/models"
	"encoding/json"
	"fmt"
	"io"
	"math"
	"net/http"
	"sync"
	"time"
)

type GeminiService struct {
	apiKey          string
	client          *http.Client
	openCageAPIKey  string
	trackingService *LLMTrackingService
}

func NewGeminiService(geminiAPIKey, openCageAPIKey string) *GeminiService {
	fmt.Printf("[DEBUG] Creating Gemini service with API key: %s...\n", geminiAPIKey[:10]+"***")
	return &GeminiService{
		apiKey:          geminiAPIKey,
		client:          &http.Client{},
		openCageAPIKey:  openCageAPIKey,
		trackingService: NewLLMTrackingService(),
	}
}

func (s *GeminiService) GetRecommendations(coordinates []models.Coordinate, timeContext string, orgId int, token string) ([]models.LocationRecommendation, error) {
	startTime := time.Now()

	fmt.Printf("[DEBUG] GetRecommendations called with %d coordinates, time: %s, orgId: %d\n", len(coordinates), timeContext, orgId)

	// Create tracking request
	llmRequest, err := s.trackingService.CreateRequest(uint(orgId), len(coordinates), timeContext)
	if err != nil {
		fmt.Printf("[WARNING] Failed to create tracking request: %v\n", err)
		// Continue processing even if tracking fails
	}

	// First, fetch location tags for the organization
	locationTags, err := s.fetchLocationTags(orgId, token)
	if err != nil {
		fmt.Printf("[WARNING] Failed to fetch location tags: %v\n", err)
		locationTags = []models.LocationTag{} // Continue without location tags
	}

	var recommendations []models.LocationRecommendation
	var wg sync.WaitGroup
	var mu sync.Mutex
	var processingError error

	// Process each coordinate concurrently
	for i, coord := range coordinates {
		wg.Add(1)
		go func(index int, coordinate models.Coordinate) {
			defer wg.Done()

			// Check for nearby tagged locations
			nearbyLocations := s.findNearbyLocations(coordinate, locationTags, 5.0) // 5km radius

			var recommendation string
			var cityName string
			isNearTaggedPlace := len(nearbyLocations) > 0

			if isNearTaggedPlace {
				// Generate recommendation for tagged location
				recommendation, cityName = s.generateTaggedLocationRecommendation(coordinate, nearbyLocations, timeContext)
			} else {
				// For non-tagged locations, return empty recommendation
				cityName, err := s.GetCityName(coordinate.Latitude, coordinate.Longitude)
				if err != nil {
					fmt.Printf("[WARNING] Reverse geocoding failed for coordinate %d, using fallback location\n", index)
					cityName = "your area"
				}
				fmt.Printf("[INFO] Detected city name for coordinate %d: %s (no tagged location nearby)\n", index, cityName)
				recommendation = "" // Empty recommendation for non-tagged locations
			}

			locationRec := models.LocationRecommendation{
				Latitude:          coordinate.Latitude,
				Longitude:         coordinate.Longitude,
				CityName:          cityName,
				Recommendation:    recommendation,
				NearbyLocations:   nearbyLocations,
				IsNearTaggedPlace: isNearTaggedPlace,
			}

			mu.Lock()
			recommendations = append(recommendations, locationRec)
			mu.Unlock()
		}(i, coord)
	}

	wg.Wait()

	// Calculate processing time
	processingTime := time.Since(startTime).Milliseconds()

	// Update tracking information
	if llmRequest != nil {
		status := "success"
		errorMsg := ""
		if processingError != nil {
			status = "error"
			errorMsg = processingError.Error()
		}

		taggedCount := 0
		for _, rec := range recommendations {
			if rec.IsNearTaggedPlace {
				taggedCount++
			}
		}

		// Update request status
		if err := s.trackingService.UpdateRequestStatus(
			llmRequest.RequestID,
			status,
			processingTime,
			len(recommendations),
			taggedCount,
			errorMsg,
		); err != nil {
			fmt.Printf("[WARNING] Failed to update request status: %v\n", err)
		}

		// Save responses
		if len(recommendations) > 0 {
			if err := s.trackingService.SaveResponses(llmRequest.RequestID, uint(orgId), recommendations); err != nil {
				fmt.Printf("[WARNING] Failed to save responses: %v\n", err)
			}
		}
	}

	if processingError != nil {
		return nil, processingError
	}

	return recommendations, nil
}

// Rest of the methods remain the same...

// Fetch location tags from the API
func (s *GeminiService) fetchLocationTags(orgId int, token string) ([]models.LocationTag, error) {
	url := fmt.Sprintf("https://dhub-backend-dev.onlyoncloud.com/location-tags/org/%d", orgId)

	req, err := http.NewRequest("GET", url, nil)
	if err != nil {
		return nil, err
	}

	req.Header.Set("Authorization", token)

	resp, err := s.client.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("API returned status code: %d", resp.StatusCode)
	}

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, err
	}

	var response models.LocationTagsResponse
	if err := json.Unmarshal(body, &response); err != nil {
		return nil, err
	}

	return response.Data, nil
}

// Calculate distance between two points
func (s *GeminiService) calculateDistance(lat1, lon1, lat2, lon2 float64) float64 {
	const R = 6371 // Earth's radius in kilometers

	lat1Rad := lat1 * math.Pi / 180
	lat2Rad := lat2 * math.Pi / 180
	deltaLat := (lat2 - lat1) * math.Pi / 180
	deltaLon := (lon2 - lon1) * math.Pi / 180

	a := math.Sin(deltaLat/2)*math.Sin(deltaLat/2) +
		math.Cos(lat1Rad)*math.Cos(lat2Rad)*
			math.Sin(deltaLon/2)*math.Sin(deltaLon/2)
	c := 2 * math.Atan2(math.Sqrt(a), math.Sqrt(1-a))

	return R * c
}

// Find nearby tagged locations within the specified radius
func (s *GeminiService) findNearbyLocations(coordinate models.Coordinate, locationTags []models.LocationTag, radiusKm float64) []models.NearbyLocationInfo {
	var nearbyLocations []models.NearbyLocationInfo

	for _, tag := range locationTags {
		distance := s.calculateDistance(
			coordinate.Latitude,
			coordinate.Longitude,
			tag.Latitude,
			tag.Longitude,
		)

		if distance <= radiusKm {
			nearbyLocations = append(nearbyLocations, models.NearbyLocationInfo{
				LocationTag: tag,
				Distance:    distance,
			})
		}
	}

	return nearbyLocations
}

// Generate recommendation for a tagged location
func (s *GeminiService) generateTaggedLocationRecommendation(coordinate models.Coordinate, nearbyLocations []models.NearbyLocationInfo, timeContext string) (string, string) {
	// Sort by distance to get the closest location
	closest := nearbyLocations[0]
	for _, loc := range nearbyLocations {
		if loc.Distance < closest.Distance {
			closest = loc
		}
	}

	locationName := closest.LocationTag.LocationName
	description := closest.LocationTag.Description
	distanceText := ""

	if closest.Distance < 0.1 {
		distanceText = "right at"
	} else if closest.Distance < 0.5 {
		distanceText = "very close to"
	} else if closest.Distance < 2.0 {
		distanceText = "near"
	} else {
		distanceText = fmt.Sprintf("about %.1f km from", closest.Distance)
	}
	locationContext := fmt.Sprintf("You are %s %s.", distanceText, locationName)

	prompt := fmt.Sprintf(`%s

Location Details: %s
Exact Coordinates: %.6f, %.6f
Distance from you: %.1f km

Current Time: %s

You are near "%s" at the coordinates provided above. Please provide specific, confident recommendations for:

🍽️ **Restaurants & Cafes:** 
- Popular dining spots and cafes within walking distance
- Best options for the current time of day
- Local specialties and must-try places

🎯 **Local Attractions:**
- Nearby shopping areas and markets  
- Entertainment venues and recreational spots
- Popular landmarks or points of interest

⭐ **Activities for Right Now:**
- What's perfect to do at this time
- Quick activities within 10-15 minutes walk
- Local experiences you shouldn't miss

📍 **Practical Tips:**
- Transportation options from this location
- Best routes to popular areas nearby
- Local insights and helpful tips

Be specific and confident in your recommendations. You have the exact location coordinates, so provide actionable suggestions that someone can immediately act upon near "%s".(only give with in 2 lines in first line say "you are near %s then continue with the recommendation)")`,
		locationContext, description, closest.LocationTag.Latitude, closest.LocationTag.Longitude, closest.Distance, timeContext, locationName, locationName, locationName)

	completePrompt := fmt.Sprintf("You are a knowledgeable local guide with precise location data. Someone is near '%s' and needs great recommendations. Be confident, specific, and helpful - you know exactly where they are!\n\n%s", locationName, prompt)

	recommendation := s.callGeminiAPI(completePrompt, 180)

	return recommendation, locationName
}

// Helper method to call Gemini API
func (s *GeminiService) callGeminiAPI(prompt string, maxTokens int) string {
	reqBody := models.GeminiRequest{
		Contents: []models.GeminiContent{
			{
				Parts: []models.GeminiPart{
					{
						Text: prompt,
					},
				},
			},
		},
		GenerationConfig: models.GeminiGenerationConfig{
			MaxOutputTokens: maxTokens,
			Temperature:     0.7,
		},
	}

	jsonData, err := json.Marshal(reqBody)
	if err != nil {
		return "I'm having trouble generating recommendations right now. Please try again!"
	}

	url := fmt.Sprintf("https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=%s", s.apiKey)
	req, err := http.NewRequest("POST", url, bytes.NewBuffer(jsonData))
	if err != nil {
		return "I'm having trouble generating recommendations right now. Please try again!"
	}

	req.Header.Set("Content-Type", "application/json")

	resp, err := s.client.Do(req)
	if err != nil {
		return "I'm having trouble generating recommendations right now. Please try again!"
	}
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return "I'm having trouble generating recommendations right now. Please try again!"
	}

	var geminiResp models.GeminiResponse
	if err := json.Unmarshal(body, &geminiResp); err != nil {
		return "I'm having trouble generating recommendations right now. Please try again!"
	}

	if len(geminiResp.Candidates) == 0 || len(geminiResp.Candidates[0].Content.Parts) == 0 {
		return "I'm having trouble finding recommendations right now. Please try again!"
	}

	return geminiResp.Candidates[0].Content.Parts[0].Text
}

func (s *GeminiService) GetCityName(lat, lng float64) (string, error) {
	url := fmt.Sprintf("https://api.opencagedata.com/geocode/v1/json?q=%f+%f&key=%s", lat, lng, s.openCageAPIKey)

	resp, err := http.Get(url)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return "", err
	}

	var result struct {
		Results []struct {
			Components struct {
				City    string `json:"city"`
				Town    string `json:"town"`
				Village string `json:"village"`
				County  string `json:"county"`
			} `json:"components"`
		} `json:"results"`
	}

	if err := json.Unmarshal(body, &result); err != nil {
		return "", err
	}

	if len(result.Results) > 0 {
		c := result.Results[0].Components
		if c.City != "" {
			return c.City, nil
		} else if c.Town != "" {
			return c.Town, nil
		} else if c.Village != "" {
			return c.Village, nil
		} else if c.County != "" {
			return c.County, nil
		}
	}

	return "", fmt.Errorf("no location found")
}

