package middleware

import (
	"core-backend/m/v2/auth"
	"fmt"
	"log"
	"net/http"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
)

func TokenValidation() gin.HandlerFunc {

	return func(c *gin.Context) {

		//getting token from header
		tokenstring := c.GetHeader("Authorization")
		//checking token is not empty
		if len(tokenstring) == 0 {
			c.Set("email", "user@onlyoncloud.com")
			c.Set("id", uint(1))
			c.Set("type", 100)
			c.Next()
			// c.String(http.StatusUnauthorized, "Unauthorized No Token")
			// return
		}
		//creating a jwt token from the tokenstring
		//we throw error if the signature has been changed
		//signature is validated with the rsa keypair
		token, err := jwt.Parse(tokenstring, func(t *jwt.Token) (interface{}, error) {
			if _, ok := t.Method.(*jwt.SigningMethodRSA); !ok {
				return nil, fmt.Errorf("error")
			}
			return auth.PubKey(), nil
		})
		if err != nil {
			log.Default().Print(err)
			c.AbortWithError(http.StatusUnauthorized, err)
			return
		}

		if !token.Valid {
			log.Default().Print("Token validation failed")
			c.AbortWithError(http.StatusUnauthorized, fmt.Errorf("invalid token"))
			return
		}

		//getting token data (email,type of user)
		claims, ok := token.Claims.(jwt.MapClaims)
		if !ok {
			log.Default().Print("Token claims incorrect")
			c.AbortWithError(http.StatusUnauthorized, fmt.Errorf("invalid claims"))
			return
		}

		//checking expiry of token
		//will throw error if expired
		if float64(time.Now().Unix()) > claims["exp"].(float64) {
			log.Default().Print("Token expired login again")
			c.AbortWithError(http.StatusRequestTimeout, fmt.Errorf("token expired"))
			return
		}

		c.Set("email", claims["user"].(string))
		c.Set("id", uint(claims["id"].(float64)))
		c.Set("type", (claims["type"]))
		c.Next()
	}
}

